window.CB = {"cats":[{"id":"entry","name":{"en":"Entry & Entry Summary","es":"Entrada y resumen de entrada","ru":"Ввоз и итоговая декларация","tr":"Giriş ve Giriş Özeti","hi":"प्रवेश और एंट्री सारांश","ar":"الإدخال وملخص الإدخال"},"blurb":{"en":"Entry types, CBP Forms 3461/7501, deadlines, liquidation and recordkeeping.","es":"Tipos de entrada, formularios CBP 3461/7501, plazos, liquidación y registros.","ru":"Типы ввоза, формы CBP 3461/7501, сроки, ликвидация и хранение записей.","tr":"Giriş türleri, CBP Form 3461/7501, süreler, kesinleştirme ve kayıt tutma.","hi":"प्रवेश प्रकार, CBP फॉर्म 3461/7501, समय-सीमा, परिसमापन और रिकॉर्ड-कीपिंग।","ar":"أنواع الإدخال، ونماذج CBP 3461/7501، والمواعيد النهائية، والتصفية، وحفظ السجلات."}},{"id":"classification","name":{"en":"Classification (HTSUS)","es":"Clasificación (HTSUS)","ru":"Классификация (HTSUS)","tr":"Sınıflandırma (HTSUS)","hi":"वर्गीकरण (HTSUS)","ar":"التصنيف (HTSUS)"},"blurb":{"en":"The General Rules of Interpretation (GRI 1–6) and tariff structure.","es":"Las Reglas Generales de Interpretación (GRI 1–6) y la estructura arancelaria.","ru":"Основные правила интерпретации (GRI 1–6) и структура тарифа.","tr":"Genel Yorum Kuralları (GRI 1–6) ve tarife yapısı.","hi":"व्याख्या के सामान्य नियम (GRI 1–6) और टैरिफ संरचना।","ar":"القواعد العامة للتفسير (GRI 1–6) وبنية التعريفة."}},{"id":"valuation","name":{"en":"Customs Valuation","es":"Valoración aduanera","ru":"Таможенная оценка","tr":"Gümrük Kıymeti","hi":"सीमा शुल्क मूल्यांकन","ar":"التقييم الجمركي"},"blurb":{"en":"Transaction value, additions, assists, and the appraisement hierarchy.","es":"Valor de transacción, adiciones, assists y la jerarquía de valoración.","ru":"Стоимость сделки, добавления, assists и иерархия методов оценки.","tr":"İşlem değeri, eklemeler, asistler ve kıymet tespiti hiyerarşisi.","hi":"लेनदेन मूल्य, परिवर्धन, assists, और मूल्यांकन पदानुक्रम।","ar":"قيمة المعاملة، والإضافات، والمساعدات (assists)، وتسلسل التقييم."}},{"id":"duties","name":{"en":"Duties, Fees & Drawback","es":"Derechos, tasas y drawback","ru":"Пошлины, сборы и возврат","tr":"Vergiler, Ücretler ve Drawback","hi":"शुल्क, फीस और ड्रॉबैक","ar":"الرسوم والرسوم والاسترداد"},"blurb":{"en":"Duty calculation, MPF & HMF, ADD/CVD, quotas and drawback.","es":"Cálculo de derechos, MPF y HMF, ADD/CVD, cuotas y drawback.","ru":"Расчёт пошлин, MPF и HMF, ADD/CVD, квоты и возврат пошлин.","tr":"Vergi hesaplama, MPF ve HMF, ADD/CVD, kotalar ve drawback.","hi":"शुल्क गणना, MPF और HMF, ADD/CVD, कोटा और ड्रॉबैक।","ar":"حساب الرسوم، وMPF وHMF، وADD/CVD، والحصص، والاسترداد."}},{"id":"compliance","name":{"en":"Broker Compliance (19 CFR 111)","es":"Cumplimiento del agente (19 CFR 111)","ru":"Соответствие брокера (19 CFR 111)","tr":"Müşavir Uyumu (19 CFR 111)","hi":"ब्रोकर अनुपालन (19 CFR 111)","ar":"امتثال الوسيط (19 CFR 111)"},"blurb":{"en":"Licensing, powers of attorney, recordkeeping, supervision and penalties.","es":"Licencias, poderes notariales, registros, supervisión y sanciones.","ru":"Лицензирование, доверенности, хранение записей, надзор и штрафы.","tr":"Lisanslama, vekâletnameler, kayıt tutma, denetim ve cezalar.","hi":"लाइसेंसिंग, पावर ऑफ अटॉर्नी, रिकॉर्ड-कीपिंग, पर्यवेक्षण और दंड।","ar":"الترخيص، والتوكيلات، وحفظ السجلات، والإشراف، والعقوبات."}},{"id":"trade","name":{"en":"Trade Programs & Marking","es":"Programas comerciales y marcado","ru":"Торговые программы и маркировка","tr":"Ticaret Programları ve İşaretleme","hi":"व्यापार कार्यक्रम और अंकन","ar":"البرامج التجارية والوسم"},"blurb":{"en":"Marking, USMCA, FTZs, bonds, PGAs, IPR and prior disclosure.","es":"Marcado, USMCA, FTZ, fianzas, PGA, IPR y divulgación previa.","ru":"Маркировка, USMCA, FTZ, гарантии, PGA, IPR и предварительное раскрытие.","tr":"İşaretleme, USMCA, FTZ, teminatlar, PGA, IPR ve ön açıklama.","hi":"अंकन, USMCA, FTZ, बॉन्ड, PGA, IPR और पूर्व प्रकटीकरण।","ar":"الوسم، وUSMCA، وFTZ، وسندات الضمان، وPGA، وIPR، والإفصاح المسبق."}}],"q":[{"cat":"entry","a":0,"q":{"en":"An importer's broker files CBP Form 3461 and obtains conditional release of a shipment of consumer electronics. Absent any extension or special arrangement, within how long after the time of entry must the entry summary (CBP Form 7501) be filed and the estimated duties deposited?","es":"El agente aduanal (broker) de un importador presenta el CBP Form 3461 y obtiene la liberación condicional de un embarque de electrónicos de consumo. En ausencia de cualquier prórroga o arreglo especial, ¿dentro de cuánto tiempo después del momento de la entrada debe presentarse el resumen de entrada (CBP Form 7501) y depositarse los derechos estimados?","ru":"Брокер импортёра подаёт CBP Form 3461 и получает условный выпуск партии бытовой электроники. При отсутствии какого-либо продления или особой договорённости в течение какого срока после момента ввоза должна быть подана итоговая декларация (CBP Form 7501) и внесены расчётные пошлины?","tr":"Bir ithalatçının gümrük müşaviri CBP Form 3461'i sunar ve bir tüketici elektroniği sevkiyatının koşullu olarak serbest bırakılmasını sağlar. Herhangi bir uzatma veya özel düzenleme olmaksızın, giriş anından sonra giriş özeti (CBP Form 7501) en geç ne kadar süre içinde sunulmalı ve tahmini vergiler yatırılmalıdır?","hi":"एक आयातक का ब्रोकर CBP Form 3461 दाखिल करता है और उपभोक्ता इलेक्ट्रॉनिक्स के एक शिपमेंट की सशर्त रिलीज प्राप्त करता है। किसी भी विस्तार या विशेष व्यवस्था के अभाव में, प्रवेश के समय के बाद कितने समय के भीतर एंट्री सारांश (CBP Form 7501) दाखिल किया जाना चाहिए और अनुमानित शुल्क जमा किए जाने चाहिए?","ar":"يقوم وسيط المستورد بتقديم CBP Form 3461 ويحصل على الإفراج المشروط عن شحنة من الإلكترونيات الاستهلاكية. في غياب أي تمديد أو ترتيب خاص، خلال أي مدة بعد وقت الإدخال يجب تقديم ملخص الإدخال (CBP Form 7501) وإيداع الرسوم التقديرية؟"},"o":[{"en":"Within 10 working days after the time of entry","es":"Dentro de los 10 días hábiles posteriores al momento de la entrada","ru":"В течение 10 рабочих дней после момента ввоза","tr":"Giriş anından sonra 10 iş günü içinde","hi":"प्रवेश के समय के बाद 10 कार्य दिवसों के भीतर","ar":"خلال 10 أيام عمل بعد وقت الإدخال"},{"en":"Within 15 calendar days after the time of entry","es":"Dentro de los 15 días naturales posteriores al momento de la entrada","ru":"В течение 15 календарных дней после момента ввоза","tr":"Giriş anından sonra 15 takvim günü içinde","hi":"प्रवेश के समय के बाद 15 कैलेंडर दिनों के भीतर","ar":"خلال 15 يومًا تقويميًا بعد وقت الإدخال"},{"en":"Within 10 calendar days after the time of entry","es":"Dentro de los 10 días naturales posteriores al momento de la entrada","ru":"В течение 10 календарных дней после момента ввоза","tr":"Giriş anından sonra 10 takvim günü içinde","hi":"प्रवेश के समय के बाद 10 कैलेंडर दिनों के भीतर","ar":"خلال 10 أيام تقويمية بعد وقت الإدخال"},{"en":"Within 30 calendar days after the time of entry","es":"Dentro de los 30 días naturales posteriores al momento de la entrada","ru":"В течение 30 календарных дней после момента ввоза","tr":"Giriş anından sonra 30 takvim günü içinde","hi":"प्रवेश के समय के बाद 30 कैलेंडर दिनों के भीतर","ar":"خلال 30 يومًا تقويميًا بعد وقت الإدخال"}],"e":{"en":"The entry summary for consumption merchandise must be filed, and estimated duties deposited, within 10 working days after the time of entry. See 19 CFR 142.12(b) (cross-referenced by 19 CFR 142.16).","es":"El resumen de entrada de mercancía para consumo debe presentarse, y los derechos estimados depositarse, dentro de los 10 días hábiles posteriores al momento de la entrada. Véase 19 CFR 142.12(b) (con referencia cruzada en 19 CFR 142.16).","ru":"Итоговая декларация на товары для потребления должна быть подана, а расчётные пошлины внесены, в течение 10 рабочих дней после момента ввоза. См. 19 CFR 142.12(b) (с перекрёстной ссылкой на 19 CFR 142.16).","tr":"Tüketim malları için giriş özeti, giriş anından sonra 10 iş günü içinde sunulmalı ve tahmini vergiler yatırılmalıdır. Bkz. 19 CFR 142.12(b) (19 CFR 142.16 ile çapraz referans verilmiştir).","hi":"उपभोग माल के लिए एंट्री सारांश प्रवेश के समय के बाद 10 कार्य दिवसों के भीतर दाखिल किया जाना चाहिए, और अनुमानित शुल्क जमा किए जाने चाहिए। देखें 19 CFR 142.12(b) (19 CFR 142.16 द्वारा क्रॉस-संदर्भित)।","ar":"يجب تقديم ملخص الإدخال الخاص ببضائع الاستهلاك، وإيداع الرسوم التقديرية، خلال 10 أيام عمل بعد وقت الإدخال. انظر 19 CFR 142.12(b) (مع الإحالة المرجعية في 19 CFR 142.16)."}},{"cat":"entry","a":1,"q":{"en":"Imported merchandise for which entry is required arrives and is landed from the importing vessel. Within what period must entry be made before the merchandise is treated as unclaimed and sent to a general-order warehouse?","es":"Llega y se descarga del buque importador mercancía para la cual se requiere entrada. ¿Dentro de qué plazo debe efectuarse la entrada antes de que la mercancía sea tratada como no reclamada y enviada a un almacén de orden general (general-order warehouse)?","ru":"Импортируемые товары, по которым требуется таможенная декларация, прибывают и выгружаются с ввозящего судна. В течение какого срока должна быть оформлена таможенная декларация, прежде чем товары будут считаться невостребованными и отправлены на склад общего хранения (general-order warehouse)?","tr":"Giriş beyanı gerektiren ithal mallar gelir ve ithalat gemisinden boşaltılır. Mallar sahipsiz olarak değerlendirilip bir general-order (genel ambar) deposuna gönderilmeden önce, giriş beyanı en geç hangi süre içinde yapılmalıdır?","hi":"वह आयातित माल जिसके लिए प्रवेश आवश्यक है, आता है और आयात करने वाले जहाज से उतारा जाता है। माल को लावारिस माना जाए और जनरल-ऑर्डर वेयरहाउस भेजा जाए, उससे पहले किस अवधि के भीतर प्रवेश किया जाना चाहिए?","ar":"تصل البضائع المستوردة التي يُشترط لها بيان الإدخال ويتم تفريغها من السفينة المستوردة. خلال أي مدة يجب إجراء الإدخال قبل أن تُعامل البضائع على أنها غير مطالَب بها وتُرسَل إلى مستودع الأمر العام (general-order warehouse)؟"},"o":[{"en":"Within 5 working days after landing","es":"Dentro de los 5 días hábiles posteriores a la descarga","ru":"В течение 5 рабочих дней после выгрузки","tr":"Boşaltmadan sonra 5 iş günü içinde","hi":"उतारने के बाद 5 कार्य दिवसों के भीतर","ar":"خلال 5 أيام عمل بعد التفريغ"},{"en":"Within 15 calendar days after landing","es":"Dentro de los 15 días naturales posteriores a la descarga","ru":"В течение 15 календарных дней после выгрузки","tr":"Boşaltmadan sonra 15 takvim günü içinde","hi":"उतारने के बाद 15 कैलेंडर दिनों के भीतर","ar":"خلال 15 يومًا تقويميًا بعد التفريغ"},{"en":"Within 10 working days after landing","es":"Dentro de los 10 días hábiles posteriores a la descarga","ru":"В течение 10 рабочих дней после выгрузки","tr":"Boşaltmadan sonra 10 iş günü içinde","hi":"उतारने के बाद 10 कार्य दिवसों के भीतर","ar":"خلال 10 أيام عمل بعد التفريغ"},{"en":"Within 20 calendar days after landing","es":"Dentro de los 20 días naturales posteriores a la descarga","ru":"В течение 20 календарных дней после выгрузки","tr":"Boşaltmadan sonra 20 takvim günü içinde","hi":"उतारने के बाद 20 कैलेंडर दिनों के भीतर","ar":"خلال 20 يومًا تقويميًا بعد التفريغ"}],"e":{"en":"Merchandise for which entry is required must be entered within 15 calendar days after landing from a vessel, aircraft, or vehicle (or after arrival at the port of destination for in-bond merchandise). See 19 CFR 141.5 and 19 CFR 142.2(a).","es":"La mercancía para la cual se requiere entrada debe entrarse dentro de los 15 días naturales posteriores a la descarga de un buque, aeronave o vehículo (o posteriores a la llegada al puerto de destino para mercancía en tránsito aduanero, in-bond). Véase 19 CFR 141.5 y 19 CFR 142.2(a).","ru":"Товары, по которым требуется таможенная декларация, должны быть задекларированы в течение 15 календарных дней после выгрузки с судна, воздушного судна или транспортного средства (либо после прибытия в порт назначения для товаров, перемещаемых под таможенным контролем in-bond). См. 19 CFR 141.5 и 19 CFR 142.2(a).","tr":"Giriş beyanı gerektiren mallar, bir gemiden, uçaktan veya araçtan boşaltıldıktan sonra (veya in-bond mallar için varış limanına ulaştıktan sonra) 15 takvim günü içinde giriş beyanına tabi tutulmalıdır. Bkz. 19 CFR 141.5 ve 19 CFR 142.2(a).","hi":"जिस माल के लिए प्रवेश आवश्यक है, उसका प्रवेश जहाज, विमान या वाहन से उतारने के बाद 15 कैलेंडर दिनों के भीतर (या इन-बॉन्ड माल के लिए गंतव्य बंदरगाह पर आगमन के बाद) किया जाना चाहिए। देखें 19 CFR 141.5 और 19 CFR 142.2(a)।","ar":"يجب إدخال البضائع التي يُشترط لها بيان الإدخال خلال 15 يومًا تقويميًا بعد التفريغ من سفينة أو طائرة أو مركبة (أو بعد الوصول إلى ميناء الوجهة بالنسبة للبضائع المنقولة بموجب سند (in-bond)). انظر 19 CFR 141.5 و 19 CFR 142.2(a)."}},{"cat":"entry","a":2,"q":{"en":"Which document set most accurately reflects the function of CBP Form 3461 versus CBP Form 7501 in the entry process?","es":"¿Qué conjunto de documentos refleja con mayor precisión la función del CBP Form 3461 frente al CBP Form 7501 en el proceso de entrada?","ru":"Какой набор документов наиболее точно отражает функцию CBP Form 3461 по сравнению с CBP Form 7501 в процессе ввоза?","tr":"Hangi belge takımı, giriş sürecinde CBP Form 3461'in CBP Form 7501'e karşı işlevini en doğru şekilde yansıtır?","hi":"कौन सा दस्तावेज समूह प्रवेश प्रक्रिया में CBP Form 3461 बनाम CBP Form 7501 के कार्य को सबसे सटीक रूप से दर्शाता है?","ar":"أي مجموعة من المستندات تعكس بأكبر دقة وظيفة CBP Form 3461 مقابل CBP Form 7501 في عملية الإدخال؟"},"o":[{"en":"Form 3461 is the entry summary used to assess duties; Form 7501 is the entry used to obtain release","es":"El Form 3461 es el resumen de entrada usado para determinar derechos; el Form 7501 es la entrada usada para obtener la liberación","ru":"Form 3461 — это итоговая декларация, используемая для начисления пошлин; Form 7501 — это декларация для получения выпуска","tr":"Form 3461, vergileri tahakkuk ettirmek için kullanılan giriş özetidir; Form 7501, serbest bırakmayı sağlamak için kullanılan giriş beyanıdır","hi":"Form 3461 शुल्क निर्धारण के लिए उपयोग किया जाने वाला एंट्री सारांश है; Form 7501 रिलीज प्राप्त करने के लिए उपयोग की जाने वाली एंट्री है","ar":"Form 3461 هو ملخص الإدخال المستخدم لتقدير الرسوم؛ وForm 7501 هو بيان الإدخال المستخدم للحصول على الإفراج"},{"en":"Both forms are entry summaries, with Form 3461 used for formal and Form 7501 for informal entries","es":"Ambos formularios son resúmenes de entrada, usándose el Form 3461 para entradas formales y el Form 7501 para entradas informales","ru":"Обе формы являются итоговыми декларациями: Form 3461 используется для формального, а Form 7501 — для неформального ввоза","tr":"Her iki form da giriş özetidir; Form 3461 resmi (formal) girişler, Form 7501 ise gayri resmi (informal) girişler için kullanılır","hi":"दोनों फॉर्म एंट्री सारांश हैं, जिसमें Form 3461 औपचारिक के लिए और Form 7501 अनौपचारिक प्रवेशों के लिए उपयोग किया जाता है","ar":"كلا النموذجين عبارة عن ملخصات إدخال، حيث يُستخدم Form 3461 للإدخالات الرسمية وForm 7501 للإدخالات غير الرسمية"},{"en":"Form 3461 is the entry used to obtain release of merchandise; Form 7501 is the entry summary used to assess duties and collect statistics","es":"El Form 3461 es la entrada usada para obtener la liberación de la mercancía; el Form 7501 es el resumen de entrada usado para determinar derechos y recopilar estadísticas","ru":"Form 3461 — это декларация для получения выпуска товаров; Form 7501 — это итоговая декларация для начисления пошлин и сбора статистики","tr":"Form 3461, malların serbest bırakılmasını sağlamak için kullanılan giriş beyanıdır; Form 7501, vergileri tahakkuk ettirmek ve istatistik toplamak için kullanılan giriş özetidir","hi":"Form 3461 माल की रिलीज प्राप्त करने के लिए उपयोग की जाने वाली एंट्री है; Form 7501 शुल्क निर्धारण और आंकड़े एकत्र करने के लिए उपयोग किया जाने वाला एंट्री सारांश है","ar":"Form 3461 هو بيان الإدخال المستخدم للحصول على الإفراج عن البضائع؛ وForm 7501 هو ملخص الإدخال المستخدم لتقدير الرسوم وجمع الإحصاءات"},{"en":"Form 3461 is the carrier's certificate; Form 7501 is the immediate delivery application","es":"El Form 3461 es el certificado del transportista; el Form 7501 es la solicitud de entrega inmediata","ru":"Form 3461 — это сертификат перевозчика; Form 7501 — это заявление о немедленной доставке","tr":"Form 3461 taşıyıcının sertifikasıdır; Form 7501 acil teslim başvurusudur","hi":"Form 3461 वाहक का प्रमाणपत्र है; Form 7501 तत्काल वितरण आवेदन है","ar":"Form 3461 هو شهادة الناقل؛ وForm 7501 هو طلب التسليم الفوري"}],"e":{"en":"The 'entry' (CBP Form 3461 or its electronic equivalent) secures release of merchandise from CBP custody, while the 'entry summary' (CBP Form 7501) provides the data to assess duties and collect statistics. See 19 CFR 141.0a(a) and (b), 142.3, and 142.11.","es":"La 'entrada' (CBP Form 3461 o su equivalente electrónico) asegura la liberación de la mercancía de la custodia de CBP, mientras que el 'resumen de entrada' (CBP Form 7501) aporta los datos para determinar derechos y recopilar estadísticas. Véase 19 CFR 141.0a(a) y (b), 142.3 y 142.11.","ru":"«Декларация» (CBP Form 3461 или её электронный эквивалент) обеспечивает выпуск товаров из-под контроля CBP, тогда как «итоговая декларация» (CBP Form 7501) предоставляет данные для начисления пошлин и сбора статистики. См. 19 CFR 141.0a(a) и (b), 142.3 и 142.11.","tr":"'Giriş beyanı' (CBP Form 3461 veya elektronik eşdeğeri) malların CBP gözetiminden serbest bırakılmasını sağlar; 'giriş özeti' (CBP Form 7501) ise vergileri tahakkuk ettirmek ve istatistik toplamak için gereken verileri sağlar. Bkz. 19 CFR 141.0a(a) ve (b), 142.3 ve 142.11.","hi":"'एंट्री' (CBP Form 3461 या इसका इलेक्ट्रॉनिक समकक्ष) CBP अभिरक्षा से माल की रिलीज सुरक्षित करती है, जबकि 'एंट्री सारांश' (CBP Form 7501) शुल्क निर्धारण और आंकड़े एकत्र करने हेतु डेटा प्रदान करता है। देखें 19 CFR 141.0a(a) और (b), 142.3, और 142.11।","ar":"إن \"بيان الإدخال\" (CBP Form 3461 أو ما يعادله إلكترونيًا) يضمن الإفراج عن البضائع من عهدة CBP، بينما يوفّر \"ملخص الإدخال\" (CBP Form 7501) البيانات اللازمة لتقدير الرسوم وجمع الإحصاءات. انظر 19 CFR 141.0a(a) و(b) و142.3 و142.11."}},{"cat":"entry","a":1,"q":{"en":"Merchandise admitted under a temporary importation under bond (TIB) entry is not for sale and must ultimately be exported or destroyed. Counting the initial period plus all permissible extensions, what is the maximum total period the merchandise may remain in the United States?","es":"La mercancía admitida bajo una entrada de importación temporal con fianza (TIB) no es para venta y debe finalmente ser exportada o destruida. Contando el período inicial más todas las prórrogas permitidas, ¿cuál es el período total máximo que la mercancía puede permanecer en los Estados Unidos?","ru":"Товары, ввезённые по декларации временного ввоза под таможенную гарантию (TIB), не предназначены для продажи и в конечном итоге должны быть вывезены или уничтожены. С учётом первоначального срока плюс всех допустимых продлений, какой максимальный общий срок товары могут оставаться в Соединённых Штатах?","tr":"Bir temporary importation under bond (TIB - teminat altında geçici ithalat) girişi kapsamında kabul edilen mallar satışa konu değildir ve nihayetinde ihraç edilmeli veya imha edilmelidir. İlk süre artı izin verilen tüm uzatmalar sayıldığında, malların Amerika Birleşik Devletleri'nde kalabileceği azami toplam süre nedir?","hi":"बॉन्ड के तहत अस्थायी आयात (TIB) एंट्री के अंतर्गत प्रवेश दिया गया माल बिक्री के लिए नहीं है और अंततः निर्यात या नष्ट किया जाना चाहिए। प्रारंभिक अवधि और सभी अनुमेय विस्तारों को गिनते हुए, माल संयुक्त राज्य अमेरिका में अधिकतम कुल कितनी अवधि तक रह सकता है?","ar":"البضائع المدخلة بموجب بيان إدخال الاستيراد المؤقت بضمان (TIB) ليست معروضة للبيع ويجب في النهاية تصديرها أو إتلافها. باحتساب المدة الأولية بالإضافة إلى جميع التمديدات المسموح بها، ما هي أقصى مدة إجمالية يجوز أن تبقى فيها البضائع داخل الولايات المتحدة؟"},"o":[{"en":"Two years from the date of importation","es":"Dos años a partir de la fecha de importación","ru":"Два года с даты импортирования","tr":"İthalat tarihinden itibaren iki yıl","hi":"आयात की तारीख से दो वर्ष","ar":"سنتان من تاريخ الاستيراد"},{"en":"Three years from the date of importation","es":"Tres años a partir de la fecha de importación","ru":"Три года с даты импортирования","tr":"İthalat tarihinden itibaren üç yıl","hi":"आयात की तारीख से तीन वर्ष","ar":"ثلاث سنوات من تاريخ الاستيراد"},{"en":"One year from the date of importation, with no extension permitted","es":"Un año a partir de la fecha de importación, sin prórroga permitida","ru":"Один год с даты импортирования, без права продления","tr":"İthalat tarihinden itibaren bir yıl, herhangi bir uzatmaya izin verilmeksizin","hi":"आयात की तारीख से एक वर्ष, बिना किसी विस्तार की अनुमति के","ar":"سنة واحدة من تاريخ الاستيراد، دون السماح بأي تمديد"},{"en":"Five years from the date of importation","es":"Cinco años a partir de la fecha de importación","ru":"Пять лет с даты импортирования","tr":"İthalat tarihinden itibaren beş yıl","hi":"आयात की तारीख से पांच वर्ष","ar":"خمس سنوات من تاريخ الاستيراد"}],"e":{"en":"TIB merchandise is admitted for one year and the bond period may be extended for not more than two further one-year periods, for a maximum total of three years from the date of importation. See 19 CFR 10.31(g) and 10.37.","es":"La mercancía bajo TIB se admite por un año y el período de la fianza puede prorrogarse por no más de dos períodos adicionales de un año cada uno, para un total máximo de tres años a partir de la fecha de importación. Véase 19 CFR 10.31(g) y 10.37.","ru":"Товары по TIB допускаются на один год, и срок действия таможенной гарантии может быть продлён не более чем на два дополнительных одногодичных периода, что в сумме составляет максимум три года с даты импортирования. См. 19 CFR 10.31(g) и 10.37.","tr":"TIB malları bir yıl süreyle kabul edilir ve teminat süresi, her biri bir yıl olan ikiden fazla olmayan ilave dönem için uzatılabilir; bu da ithalat tarihinden itibaren azami toplam üç yıl eder. Bkz. 19 CFR 10.31(g) ve 10.37.","hi":"TIB माल को एक वर्ष के लिए प्रवेश दिया जाता है और बॉन्ड अवधि को अधिकतम दो और एक-वर्षीय अवधियों के लिए बढ़ाया जा सकता है, जिससे आयात की तारीख से अधिकतम कुल तीन वर्ष बनते हैं। देखें 19 CFR 10.31(g) और 10.37।","ar":"تُدخَل بضائع TIB لمدة سنة واحدة ويجوز تمديد مدة السند لما لا يزيد على فترتين إضافيتين مدة كل منهما سنة، بحد أقصى إجمالي قدره ثلاث سنوات من تاريخ الاستيراد. انظر 19 CFR 10.31(g) و10.37."}},{"cat":"entry","a":2,"q":{"en":"For a temporary importation under bond (TIB) entry of merchandise not entitled to the reduced-rate categories, what is the standard amount of the bond required?","es":"Para una entrada de importación temporal con fianza (TIB) de mercancía no acreedora a las categorías de tasa reducida, ¿cuál es el monto estándar de la fianza requerida?","ru":"Для декларации временного ввоза под таможенную гарантию (TIB) на товары, не относящиеся к категориям с пониженной ставкой, каков стандартный размер требуемой таможенной гарантии?","tr":"İndirimli oran kategorilerine hak kazanmayan malların temporary importation under bond (TIB - teminat altında geçici ithalat) girişi için gereken standart teminat tutarı nedir?","hi":"उस माल की बॉन्ड के तहत अस्थायी आयात (TIB) एंट्री के लिए जो घटी-दर श्रेणियों का हकदार नहीं है, आवश्यक बॉन्ड की मानक राशि क्या है?","ar":"بالنسبة لبيان إدخال الاستيراد المؤقت بضمان (TIB) لبضائع غير مؤهلة لفئات المعدل المخفّض، ما هو المقدار القياسي للسند المطلوب؟"},"o":[{"en":"An amount equal to the estimated duties and fees","es":"Un monto igual a los derechos y cargos estimados","ru":"Сумма, равная расчётным пошлинам и сборам","tr":"Tahmini vergi ve harçlara eşit bir tutar","hi":"अनुमानित शुल्कों और शुल्कों के बराबर राशि","ar":"مقدار يساوي الرسوم والمصاريف التقديرية"},{"en":"An amount equal to 110 percent of the estimated duties and fees","es":"Un monto igual al 110 por ciento de los derechos y cargos estimados","ru":"Сумма, равная 110 процентам расчётных пошлин и сборов","tr":"Tahmini vergi ve harçların yüzde 110'una eşit bir tutar","hi":"अनुमानित शुल्कों और शुल्कों के 110 प्रतिशत के बराबर राशि","ar":"مقدار يساوي 110 بالمئة من الرسوم والمصاريف التقديرية"},{"en":"An amount equal to double the duties and fees that would otherwise accrue","es":"Un monto igual al doble de los derechos y cargos que de otro modo se causarían","ru":"Сумма, равная удвоенному размеру пошлин и сборов, которые в противном случае подлежали бы уплате","tr":"Aksi halde tahakkuk edecek vergi ve harçların iki katına eşit bir tutar","hi":"उन शुल्कों और फीस के दोगुने के बराबर राशि जो अन्यथा उपार्जित होती","ar":"مقدار يساوي ضعف الرسوم والمصاريف التي كانت ستُستحَق لولا ذلك"},{"en":"An amount equal to the appraised value of the merchandise","es":"Un monto igual al valor de avalúo de la mercancía","ru":"Сумма, равная оценочной стоимости товаров","tr":"Malların takdir edilen (appraised) değerine eşit bir tutar","hi":"माल के मूल्यांकित मूल्य के बराबर राशि","ar":"مقدار يساوي القيمة المقدّرة للبضائع"}],"e":{"en":"A TIB bond is generally given in an amount equal to double the duties and fees that it is estimated would accrue had the merchandise been entered for consumption (certain categories such as samples and professional equipment require only 110 percent). See 19 CFR 10.31(f).","es":"Una fianza TIB generalmente se otorga por un monto igual al doble de los derechos y cargos que se estima se habrían causado si la mercancía hubiera sido entrada para consumo (ciertas categorías, como muestras y equipo profesional, requieren solo el 110 por ciento). Véase 19 CFR 10.31(f).","ru":"Таможенная гарантия по TIB, как правило, предоставляется в сумме, равной удвоенному размеру пошлин и сборов, которые, по оценке, подлежали бы уплате, если бы товары были задекларированы для потребления (для отдельных категорий, таких как образцы и профессиональное оборудование, требуется только 110 процентов). См. 19 CFR 10.31(f).","tr":"Bir TIB teminatı genel olarak, mallar tüketim için giriş beyanına tabi tutulsaydı tahakkuk edeceği tahmin edilen vergi ve harçların iki katına eşit bir tutarda verilir (numuneler ve profesyonel ekipman gibi belirli kategoriler yalnızca yüzde 110 gerektirir). Bkz. 19 CFR 10.31(f).","hi":"TIB बॉन्ड आम तौर पर उन शुल्कों और फीस के दोगुने के बराबर राशि में दिया जाता है, जिनके बारे में अनुमान है कि वे उपार्जित होतीं यदि माल को उपभोग के लिए प्रवेश दिया गया होता (कुछ श्रेणियों जैसे नमूने और पेशेवर उपकरण के लिए केवल 110 प्रतिशत आवश्यक है)। देखें 19 CFR 10.31(f)।","ar":"يُقدَّم سند TIB عمومًا بمقدار يساوي ضعف الرسوم والمصاريف التي يُقدَّر أنها كانت ستُستحَق لو أُدخِلت البضائع للاستهلاك (تتطلب فئات معينة مثل العينات والمعدات المهنية 110 بالمئة فقط). انظر 19 CFR 10.31(f)."}},{"cat":"entry","a":1,"q":{"en":"Merchandise is placed in a bonded warehouse under a warehouse entry. Under the current regulation, what is the maximum period the merchandise may remain in the bonded warehouse measured from the date of importation?","es":"Se coloca mercancía en un almacén afianzado (bonded warehouse) bajo una entrada de almacén. Conforme a la regulación vigente, ¿cuál es el período máximo que la mercancía puede permanecer en el almacén afianzado, medido a partir de la fecha de importación?","ru":"Товары помещены на таможенный склад (bonded warehouse) по складской декларации. Согласно действующему нормативному акту, каков максимальный срок, в течение которого товары могут оставаться на таможенном складе, отсчитываемый с даты импортирования?","tr":"Mallar bir antrepo girişi (warehouse entry) kapsamında teminatlı bir antrepoya konulur. Mevcut yönetmeliğe göre, ithalat tarihinden ölçülerek, malların teminatlı antrepoda kalabileceği azami süre nedir?","hi":"माल को वेयरहाउस एंट्री के तहत बॉन्डेड वेयरहाउस में रखा जाता है। वर्तमान विनियमन के तहत, आयात की तारीख से मापा जाए तो माल अधिकतम कितनी अवधि तक बॉन्डेड वेयरहाउस में रह सकता है?","ar":"تُوضَع البضائع في مستودع جمركي مضمون (bonded warehouse) بموجب بيان إدخال مستودعي. بموجب اللائحة الحالية، ما هي أقصى مدة يجوز أن تبقى فيها البضائع في المستودع الجمركي المضمون مقيسةً من تاريخ الاستيراد؟"},"o":[{"en":"3 years from the date of importation","es":"3 años a partir de la fecha de importación","ru":"3 года с даты импортирования","tr":"İthalat tarihinden itibaren 3 yıl","hi":"आयात की तारीख से 3 वर्ष","ar":"3 سنوات من تاريخ الاستيراد"},{"en":"5 years from the date of importation","es":"5 años a partir de la fecha de importación","ru":"5 лет с даты импортирования","tr":"İthalat tarihinden itibaren 5 yıl","hi":"आयात की तारीख से 5 वर्ष","ar":"5 سنوات من تاريخ الاستيراد"},{"en":"1 year from the date of importation","es":"1 año a partir de la fecha de importación","ru":"1 год с даты импортирования","tr":"İthalat tarihinden itibaren 1 yıl","hi":"आयात की तारीख से 1 वर्ष","ar":"سنة واحدة من تاريخ الاستيراد"},{"en":"5 years from the date of the warehouse entry","es":"5 años a partir de la fecha de la entrada de almacén","ru":"5 лет с даты складской декларации","tr":"Antrepo girişi tarihinden itibaren 5 yıl","hi":"वेयरहाउस एंट्री की तारीख से 5 वर्ष","ar":"5 سنوات من تاريخ بيان الإدخال المستودعي"}],"e":{"en":"Merchandise may remain in a bonded warehouse for a period of 5 years from the date of importation. See 19 CFR 144.5.","es":"La mercancía puede permanecer en un almacén afianzado por un período de 5 años a partir de la fecha de importación. Véase 19 CFR 144.5.","ru":"Товары могут оставаться на таможенном складе в течение 5 лет с даты импортирования. См. 19 CFR 144.5.","tr":"Mallar, ithalat tarihinden itibaren 5 yıl süreyle teminatlı bir antrepoda kalabilir. Bkz. 19 CFR 144.5.","hi":"माल आयात की तारीख से 5 वर्ष की अवधि तक बॉन्डेड वेयरहाउस में रह सकता है। देखें 19 CFR 144.5।","ar":"يجوز أن تبقى البضائع في المستودع الجمركي المضمون لمدة 5 سنوات من تاريخ الاستيراد. انظر 19 CFR 144.5."}},{"cat":"entry","a":1,"q":{"en":"A foreign shipment arrives at the port of Long Beach but is destined to be exported to Mexico without entering U.S. commerce. The goods will move in bond from Long Beach to the export port. Which type of entry and form applies?","es":"Un embarque extranjero llega al puerto de Long Beach pero está destinado a ser exportado a México sin ingresar al comercio de los EE. UU. Las mercancías se moverán en tránsito aduanero (in bond) desde Long Beach hasta el puerto de exportación. ¿Qué tipo de entrada y formulario aplica?","ru":"Иностранная партия прибывает в порт Лонг-Бич, но предназначена для вывоза в Мексику без поступления в торговый оборот США. Товары будут перемещаться под таможенным контролем (in bond) из Лонг-Бич в порт вывоза. Какой тип декларации и форма применяются?","tr":"Yabancı bir sevkiyat Long Beach limanına gelir, ancak ABD ticaretine girmeden Meksika'ya ihraç edilmek üzere yola çıkacaktır. Mallar Long Beach'ten ihracat limanına in-bond olarak taşınacaktır. Hangi tür giriş ve form geçerlidir?","hi":"एक विदेशी शिपमेंट लॉन्ग बीच के बंदरगाह पर पहुंचता है, लेकिन इसे अमेरिकी वाणिज्य में प्रवेश किए बिना मेक्सिको को निर्यात किया जाना है। माल लॉन्ग बीच से निर्यात बंदरगाह तक इन बॉन्ड स्थानांतरित होगा। किस प्रकार की एंट्री और फॉर्म लागू होता है?","ar":"تصل شحنة أجنبية إلى ميناء لونغ بيتش لكنها مخصصة للتصدير إلى المكسيك دون الدخول في التجارة الأمريكية. ستنتقل البضائع بموجب سند (in bond) من لونغ بيتش إلى ميناء التصدير. أي نوع من بيانات الإدخال والنماذج ينطبق؟"},"o":[{"en":"Immediate transportation (IT) entry on CBP Form 3461","es":"Entrada de transporte inmediato (IT) en el CBP Form 3461","ru":"Декларация немедленной транспортировки (IT) по CBP Form 3461","tr":"CBP Form 3461 üzerinde immediate transportation (IT - acil taşıma) girişi","hi":"CBP Form 3461 पर तत्काल परिवहन (IT) एंट्री","ar":"بيان إدخال النقل الفوري (IT) على CBP Form 3461"},{"en":"Transportation and exportation (T&E) entry on CBP Form 7512","es":"Entrada de transporte y exportación (T&E) en el CBP Form 7512","ru":"Декларация транспортировки и вывоза (T&E) по CBP Form 7512","tr":"CBP Form 7512 üzerinde transportation and exportation (T&E - taşıma ve ihracat) girişi","hi":"CBP Form 7512 पर परिवहन और निर्यात (T&E) एंट्री","ar":"بيان إدخال النقل والتصدير (T&E) على CBP Form 7512"},{"en":"Warehouse entry on CBP Form 7501","es":"Entrada de almacén en el CBP Form 7501","ru":"Складская декларация по CBP Form 7501","tr":"CBP Form 7501 üzerinde antrepo girişi (warehouse entry)","hi":"CBP Form 7501 पर वेयरहाउस एंट्री","ar":"بيان إدخال مستودعي على CBP Form 7501"},{"en":"Consumption entry on CBP Form 7501","es":"Entrada de consumo en el CBP Form 7501","ru":"Декларация для потребления по CBP Form 7501","tr":"CBP Form 7501 üzerinde tüketim girişi (consumption entry)","hi":"CBP Form 7501 पर उपभोग एंट्री","ar":"بيان إدخال للاستهلاك على CBP Form 7501"}],"e":{"en":"Merchandise moving in bond through the United States for exportation at another port is entered as a transportation and exportation (T&E) entry on CBP Form 7512. See 19 CFR 18.20 et seq.; 19 CFR 141.0a.","es":"La mercancía que se mueve en tránsito aduanero a través de los Estados Unidos para su exportación en otro puerto se entra como una entrada de transporte y exportación (T&E) en el CBP Form 7512. Véase 19 CFR 18.20 y siguientes; 19 CFR 141.0a.","ru":"Товары, перемещаемые под таможенным контролем через территорию Соединённых Штатов для вывоза в другом порту, декларируются как декларация транспортировки и вывоза (T&E) по CBP Form 7512. См. 19 CFR 18.20 и далее; 19 CFR 141.0a.","tr":"Amerika Birleşik Devletleri içinden başka bir limanda ihraç edilmek üzere in-bond olarak taşınan mallar, CBP Form 7512 üzerinde bir transportation and exportation (T&E - taşıma ve ihracat) girişi olarak giriş beyanına tabi tutulur. Bkz. 19 CFR 18.20 vd.; 19 CFR 141.0a.","hi":"दूसरे बंदरगाह पर निर्यात के लिए संयुक्त राज्य अमेरिका के माध्यम से इन बॉन्ड स्थानांतरित होने वाला माल CBP Form 7512 पर परिवहन और निर्यात (T&E) एंट्री के रूप में प्रवेश किया जाता है। देखें 19 CFR 18.20 et seq.; 19 CFR 141.0a।","ar":"البضائع المنقولة بموجب سند عبر الولايات المتحدة بغرض التصدير من ميناء آخر تُدخَل كبيان إدخال نقل وتصدير (T&E) على CBP Form 7512. انظر 19 CFR 18.20 وما يليها؛ 19 CFR 141.0a."}},{"cat":"entry","a":0,"q":{"en":"A shipment of merchandise has an aggregate value of $2,200 and is not subject to any special restriction requiring formal entry. Which statement best describes its eligibility for informal entry?","es":"Un embarque de mercancía tiene un valor agregado de $2,200 y no está sujeto a ninguna restricción especial que requiera entrada formal. ¿Qué afirmación describe mejor su elegibilidad para entrada informal?","ru":"Партия товаров имеет совокупную стоимость $2,200 и не подпадает под какие-либо особые ограничения, требующие формального ввоза. Какое утверждение лучше всего описывает её право на неформальный ввоз?","tr":"Bir mal sevkiyatının toplam değeri $2,200'dür ve resmi giriş gerektiren herhangi bir özel kısıtlamaya tabi değildir. Hangi ifade, gayri resmi giriş (informal entry) için uygunluğunu en iyi şekilde tanımlar?","hi":"एक माल शिपमेंट का कुल मूल्य $2,200 है और यह किसी भी विशेष प्रतिबंध के अधीन नहीं है जिसके लिए औपचारिक प्रवेश आवश्यक हो। कौन सा कथन अनौपचारिक प्रवेश के लिए इसकी पात्रता का सबसे अच्छा वर्णन करता है?","ar":"تبلغ القيمة الإجمالية لشحنة من البضائع $2,200 وهي غير خاضعة لأي قيد خاص يتطلب الإدخال الرسمي. أي عبارة تصف بأفضل شكل أهليتها للإدخال غير الرسمي؟"},"o":[{"en":"It is eligible for informal entry because the value does not exceed $2,500","es":"Es elegible para entrada informal porque el valor no excede $2,500","ru":"Она имеет право на неформальный ввоз, поскольку стоимость не превышает $2,500","tr":"Gayri resmi giriş için uygundur, çünkü değeri $2,500'ü aşmamaktadır","hi":"यह अनौपचारिक प्रवेश के लिए पात्र है क्योंकि मूल्य $2,500 से अधिक नहीं है","ar":"هي مؤهلة للإدخال غير الرسمي لأن القيمة لا تتجاوز $2,500"},{"en":"It is ineligible for informal entry because it exceeds $800","es":"No es elegible para entrada informal porque excede $800","ru":"Она не имеет права на неформальный ввоз, поскольку превышает $800","tr":"Gayri resmi giriş için uygun değildir, çünkü $800'ü aşmaktadır","hi":"यह अनौपचारिक प्रवेश के लिए अपात्र है क्योंकि यह $800 से अधिक है","ar":"هي غير مؤهلة للإدخال غير الرسمي لأنها تتجاوز $800"},{"en":"It is eligible for informal entry only if the value does not exceed $2,000","es":"Es elegible para entrada informal solo si el valor no excede $2,000","ru":"Она имеет право на неформальный ввоз, только если стоимость не превышает $2,000","tr":"Yalnızca değeri $2,000'i aşmaması halinde gayri resmi giriş için uygundur","hi":"यह अनौपचारिक प्रवेश के लिए केवल तभी पात्र है जब मूल्य $2,000 से अधिक न हो","ar":"هي مؤهلة للإدخال غير الرسمي فقط إذا كانت القيمة لا تتجاوز $2,000"},{"en":"It must be formally entered because all commercial shipments require formal entry","es":"Debe entrarse formalmente porque todos los embarques comerciales requieren entrada formal","ru":"Она должна быть задекларирована формально, поскольку все коммерческие партии требуют формального ввоза","tr":"Resmi olarak giriş beyanına tabi tutulmalıdır, çünkü tüm ticari sevkiyatlar resmi giriş gerektirir","hi":"इसे औपचारिक रूप से प्रवेश किया जाना चाहिए क्योंकि सभी वाणिज्यिक शिपमेंट के लिए औपचारिक प्रवेश आवश्यक है","ar":"يجب إدخالها رسميًا لأن جميع الشحنات التجارية تتطلب الإدخال الرسمي"}],"e":{"en":"Shipments of merchandise not exceeding $2,500 in value generally may be entered under informal entry (subject to stated exceptions, such as certain Chapter 99 articles). See 19 CFR 143.21(a).","es":"Los embarques de mercancía cuyo valor no exceda $2,500 generalmente pueden entrarse bajo entrada informal (sujeto a las excepciones establecidas, como ciertos artículos del Capítulo 99). Véase 19 CFR 143.21(a).","ru":"Партии товаров стоимостью не более $2,500, как правило, могут декларироваться в порядке неформального ввоза (с учётом указанных исключений, таких как отдельные товары главы 99). См. 19 CFR 143.21(a).","tr":"Değeri $2,500'ü aşmayan mal sevkiyatları genel olarak gayri resmi giriş (informal entry) kapsamında giriş beyanına tabi tutulabilir (belirli Bölüm 99 ürünleri gibi belirtilen istisnalara tabi). Bkz. 19 CFR 143.21(a).","hi":"$2,500 मूल्य से अधिक नहीं वाले माल के शिपमेंट को आम तौर पर अनौपचारिक प्रवेश के तहत प्रवेश किया जा सकता है (बताए गए अपवादों के अधीन, जैसे कुछ Chapter 99 वस्तुएं)। देखें 19 CFR 143.21(a)।","ar":"الشحنات من البضائع التي لا تتجاوز قيمتها $2,500 يجوز عمومًا إدخالها بموجب الإدخال غير الرسمي (مع مراعاة الاستثناءات المذكورة، مثل بعض المواد في الفصل 99). انظر 19 CFR 143.21(a)."}},{"cat":"entry","a":3,"q":{"en":"Goods imported by a common carrier are consigned 'to order.' Which of the following will satisfy the evidence of the right to make entry for the consignee?","es":"Mercancía importada por un transportista público (common carrier) está consignada 'a la orden' (to order). ¿Cuál de los siguientes satisface la prueba del derecho a efectuar la entrada para el consignatario?","ru":"Товары, ввезённые общественным перевозчиком (common carrier), отгружены «по приказу» (to order). Что из перечисленного будет служить доказательством права на оформление таможенной декларации для грузополучателя?","tr":"Ortak bir taşıyıcı (common carrier) tarafından ithal edilen mallar 'to order' (emre) konsinye edilmiştir. Aşağıdakilerden hangisi, alıcı (consignee) için giriş beyanı yapma hakkının kanıtını sağlar?","hi":"एक सामान्य वाहक द्वारा आयातित माल 'टू ऑर्डर' परेषित किया गया है। निम्नलिखित में से कौन सा परेषिती के लिए प्रवेश करने के अधिकार के साक्ष्य को संतुष्ट करेगा?","ar":"البضائع المستوردة بواسطة ناقل عام تكون مرسَلة \"لأمر\" (to order). أي مما يلي يفي بإثبات حق إجراء الإدخال لصالح المرسَل إليه؟"},"o":[{"en":"A commercial invoice signed by the foreign seller","es":"Una factura comercial firmada por el vendedor extranjero","ru":"Коммерческий счёт-фактура, подписанный иностранным продавцом","tr":"Yabancı satıcı tarafından imzalanmış bir ticari fatura","hi":"विदेशी विक्रेता द्वारा हस्ताक्षरित एक वाणिज्यिक चालान","ar":"فاتورة تجارية موقّعة من البائع الأجنبي"},{"en":"Mere physical possession of the merchandise at the time of arrival","es":"La mera posesión física de la mercancía al momento de la llegada","ru":"Простое физическое владение товарами на момент прибытия","tr":"Varış anında malların yalnızca fiziksel zilyetliği","hi":"आगमन के समय माल का मात्र भौतिक कब्जा","ar":"مجرد الحيازة المادية للبضائع وقت الوصول"},{"en":"A power of attorney filed with the entry summary","es":"Un poder (power of attorney) presentado junto con el resumen de entrada","ru":"Доверенность (POA), поданная вместе с итоговой декларацией","tr":"Giriş özeti ile birlikte sunulan bir vekâletname (power of attorney)","hi":"एंट्री सारांश के साथ दाखिल की गई एक POA","ar":"توكيل رسمي (POA) مقدَّم مع ملخص الإدخال"},{"en":"A properly endorsed bill of lading or a carrier's certificate naming the consignee","es":"Un conocimiento de embarque debidamente endosado o un certificado del transportista (carrier's certificate) que nombre al consignatario","ru":"Надлежащим образом индоссированный коносамент или сертификат перевозчика с указанием грузополучателя","tr":"Alıcıyı (consignee) adlandıran, usulüne uygun ciro edilmiş bir konşimento veya taşıyıcı sertifikası","hi":"परेषिती को स्वामी या परेषिती के रूप में नामित करते हुए एक उचित रूप से पृष्ठांकित लदान बिल या वाहक का प्रमाणपत्र","ar":"بوليصة شحن مظهَّرة على النحو الصحيح أو شهادة ناقل تسمّي المرسَل إليه"}],"e":{"en":"For merchandise carried by a common carrier, the right to make entry is evidenced by a properly endorsed bill of lading or air waybill, or a carrier's certificate, naming the consignee as owner or consignee. See 19 CFR 141.11(a).","es":"Para mercancía transportada por un transportista público, el derecho a efectuar la entrada se acredita mediante un conocimiento de embarque o guía aérea debidamente endosado, o un certificado del transportista, que nombre al consignatario como propietario o consignatario. Véase 19 CFR 141.11(a).","ru":"Для товаров, перевозимых общественным перевозчиком, право на оформление таможенной декларации подтверждается надлежащим образом индоссированным коносаментом или авианакладной, либо сертификатом перевозчика, с указанием грузополучателя в качестве владельца или получателя. См. 19 CFR 141.11(a).","tr":"Ortak bir taşıyıcı tarafından taşınan mallar için, giriş beyanı yapma hakkı, alıcıyı (consignee) malik veya alıcı olarak adlandıran, usulüne uygun ciro edilmiş bir konşimento veya hava konşimentosu ya da bir taşıyıcı sertifikası ile kanıtlanır. Bkz. 19 CFR 141.11(a).","hi":"सामान्य वाहक द्वारा ले जाए गए माल के लिए, प्रवेश करने का अधिकार उचित रूप से पृष्ठांकित लदान बिल या एयर वेबिल, या वाहक के प्रमाणपत्र द्वारा प्रमाणित होता है, जो परेषिती को स्वामी या परेषिती के रूप में नामित करता है। देखें 19 CFR 141.11(a)।","ar":"بالنسبة للبضائع المنقولة بواسطة ناقل عام، يُثبَت حق إجراء الإدخال ببوليصة شحن أو وثيقة شحن جوي مظهَّرة على النحو الصحيح، أو بشهادة ناقل، تسمّي المرسَل إليه بصفته المالك أو المرسَل إليه. انظر 19 CFR 141.11(a)."}},{"cat":"entry","a":0,"q":{"en":"An entry is filed and the merchandise is released, but CBP neither liquidates the entry nor suspends or extends liquidation. By operation of law, when is the entry deemed liquidated?","es":"Se presenta una entrada y la mercancía se libera, pero CBP ni liquida la entrada ni suspende o prorroga la liquidación. Por ministerio de ley, ¿cuándo se considera liquidada la entrada?","ru":"Таможенная декларация подана, и товары выпущены, но CBP не производит ликвидацию (окончательный расчёт пошлин) декларации и не приостанавливает и не продлевает ликвидацию. В силу закона, когда декларация считается ликвидированной?","tr":"Bir giriş beyanı sunulur ve mallar serbest bırakılır, ancak CBP girişi ne kesinleştirir (liquidate eder) ne de kesinleştirmeyi askıya alır ya da uzatır. Kanun gereği, giriş ne zaman kesinleşmiş (liquidated) sayılır?","hi":"एक एंट्री दाखिल की जाती है और माल रिलीज कर दिया जाता है, लेकिन CBP न तो एंट्री का परिसमापन करता है और न ही परिसमापन को निलंबित या विस्तारित करता है। कानून के संचालन से, एंट्री को कब परिसमापित माना जाता है?","ar":"يُقدَّم بيان إدخال ويُفرَج عن البضائع، لكن CBP لا تُجري التصفية للبيان ولا تعلّق أو تمدّد التصفية. بحكم القانون، متى يُعتبر البيان مصفّى؟"},"o":[{"en":"One year from the date of entry, at the rate and amount asserted by the importer","es":"Un año a partir de la fecha de entrada, a la tasa y monto declarados por el importador","ru":"Через один год с даты ввоза, по ставке и в размере, заявленным импортёром","tr":"Giriş tarihinden itibaren bir yıl sonra, ithalatçı tarafından beyan edilen oran ve tutar üzerinden","hi":"प्रवेश की तारीख से एक वर्ष, आयातक द्वारा प्रतिपादित दर और राशि पर","ar":"بعد سنة واحدة من تاريخ الإدخال، بالمعدل والمقدار اللذين أكّدهما المستورد"},{"en":"90 days from the date of release, at the rate asserted by CBP","es":"90 días a partir de la fecha de liberación, a la tasa declarada por CBP","ru":"Через 90 дней с даты выпуска, по ставке, заявленной CBP","tr":"Serbest bırakma tarihinden itibaren 90 gün sonra, CBP tarafından beyan edilen oran üzerinden","hi":"रिलीज की तारीख से 90 दिन, CBP द्वारा प्रतिपादित दर पर","ar":"بعد 90 يومًا من تاريخ الإفراج، بالمعدل الذي أكّدته CBP"},{"en":"Four years from the date of entry, at the rate asserted by the importer","es":"Cuatro años a partir de la fecha de entrada, a la tasa declarada por el importador","ru":"Через четыре года с даты ввоза, по ставке, заявленной импортёром","tr":"Giriş tarihinden itibaren dört yıl sonra, ithalatçı tarafından beyan edilen oran üzerinden","hi":"प्रवेश की तारीख से चार वर्ष, आयातक द्वारा प्रतिपादित दर पर","ar":"بعد أربع سنوات من تاريخ الإدخال، بالمعدل الذي أكّده المستورد"},{"en":"Six months from the date the entry summary is filed","es":"Seis meses a partir de la fecha en que se presenta el resumen de entrada","ru":"Через шесть месяцев с даты подачи итоговой декларации","tr":"Giriş özetinin sunulduğu tarihten itibaren altı ay sonra","hi":"एंट्री सारांश दाखिल होने की तारीख से छह माह","ar":"بعد ستة أشهر من تاريخ تقديم ملخص الإدخال"}],"e":{"en":"An entry not liquidated within one year from the date of entry is deemed liquidated by operation of law at the rate, value, quantity, and amount of duties asserted by the importer, unless liquidation is properly extended or suspended. See 19 CFR 159.11(a).","es":"Una entrada no liquidada dentro de un año a partir de la fecha de entrada se considera liquidada por ministerio de ley a la tasa, valor, cantidad y monto de derechos declarados por el importador, a menos que la liquidación sea debidamente prorrogada o suspendida. Véase 19 CFR 159.11(a).","ru":"Декларация, не ликвидированная в течение одного года с даты ввоза, считается ликвидированной в силу закона по ставке, стоимости, количеству и размеру пошлин, заявленным импортёром, если только ликвидация не была надлежащим образом продлена или приостановлена. См. 19 CFR 159.11(a).","tr":"Giriş tarihinden itibaren bir yıl içinde kesinleştirilmeyen bir giriş, kesinleştirme usulüne uygun olarak uzatılmadıkça veya askıya alınmadıkça, ithalatçı tarafından beyan edilen oran, değer, miktar ve vergi tutarı üzerinden kanun gereği kesinleşmiş (liquidated) sayılır. Bkz. 19 CFR 159.11(a).","hi":"प्रवेश की तारीख से एक वर्ष के भीतर परिसमापित नहीं की गई एंट्री को कानून के संचालन से आयातक द्वारा प्रतिपादित दर, मूल्य, मात्रा और शुल्क की राशि पर परिसमापित माना जाता है, जब तक कि परिसमापन को उचित रूप से विस्तारित या निलंबित न किया गया हो। देखें 19 CFR 159.11(a)।","ar":"البيان الذي لا تتم تصفيته خلال سنة واحدة من تاريخ الإدخال يُعتبر مصفّى بحكم القانون بالمعدل والقيمة والكمية ومقدار الرسوم التي أكّدها المستورد، ما لم تُمدَّد التصفية أو تُعلَّق على النحو الصحيح. انظر 19 CFR 159.11(a)."}},{"cat":"entry","a":1,"q":{"en":"CBP extends the liquidation period on an entry because needed appraisement information is unavailable. Including the original period and all permitted extensions, what is the outside time limit after which the entry will be deemed liquidated by operation of law (absent a statutory suspension or court order)?","es":"CBP prorroga el período de liquidación de una entrada porque la información de avalúo necesaria no está disponible. Incluyendo el período original y todas las prórrogas permitidas, ¿cuál es el límite máximo de tiempo después del cual la entrada se considerará liquidada por ministerio de ley (en ausencia de una suspensión legal u orden judicial)?","ru":"CBP продлевает срок ликвидации по декларации, поскольку отсутствует необходимая информация для оценки. С учётом первоначального срока и всех допустимых продлений, каков предельный срок, по истечении которого декларация будет считаться ликвидированной в силу закона (при отсутствии приостановления, предусмотренного законом, или судебного постановления)?","tr":"Gerekli takdir (appraisement) bilgileri mevcut olmadığından CBP, bir girişteki kesinleştirme (liquidation) süresini uzatır. Orijinal süre ve izin verilen tüm uzatmalar dahil olmak üzere, girişin (yasal bir askıya alma veya mahkeme kararı olmaksızın) kanun gereği kesinleşmiş sayılacağı azami süre sınırı nedir?","hi":"आवश्यक मूल्यांकन जानकारी अनुपलब्ध होने के कारण CBP एक एंट्री पर परिसमापन अवधि को विस्तारित करता है। मूल अवधि और सभी अनुमत विस्तारों सहित, वह बाहरी समय सीमा क्या है जिसके बाद एंट्री को कानून के संचालन से परिसमापित माना जाएगा (किसी वैधानिक निलंबन या अदालती आदेश के अभाव में)?","ar":"تُمدِّد CBP مدة التصفية لبيان إدخال لأن المعلومات اللازمة للتقدير غير متاحة. بما في ذلك المدة الأصلية وجميع التمديدات المسموح بها، ما هو الحد الزمني الأقصى الذي يُعتبر بعده البيان مصفّى بحكم القانون (في غياب تعليق قانوني أو أمر محكمة)؟"},"o":[{"en":"Three years from the date of entry","es":"Tres años a partir de la fecha de entrada","ru":"Три года с даты ввоза","tr":"Giriş tarihinden itibaren üç yıl","hi":"प्रवेश की तारीख से तीन वर्ष","ar":"ثلاث سنوات من تاريخ الإدخال"},{"en":"Four years from the date of entry","es":"Cuatro años a partir de la fecha de entrada","ru":"Четыре года с даты ввоза","tr":"Giriş tarihinden itibaren dört yıl","hi":"प्रवेश की तारीख से चार वर्ष","ar":"أربع سنوات من تاريخ الإدخال"},{"en":"Two years from the date of entry","es":"Dos años a partir de la fecha de entrada","ru":"Два года с даты ввоза","tr":"Giriş tarihinden itibaren iki yıl","hi":"प्रवेश की तारीख से दो वर्ष","ar":"سنتان من تاريخ الإدخال"},{"en":"Five years from the date of entry","es":"Cinco años a partir de la fecha de entrada","ru":"Пять лет с даты ввоза","tr":"Giriş tarihinden itibaren beş yıl","hi":"प्रवेश की तारीख से पांच वर्ष","ar":"خمس سنوات من تاريخ الإدخال"}],"e":{"en":"Liquidation may be extended for additional periods, but an entry not liquidated within four years from the date of entry is deemed liquidated by operation of law unless suspension is required by statute or court order. See 19 CFR 159.12(e) and (f).","es":"La liquidación puede prorrogarse por períodos adicionales, pero una entrada no liquidada dentro de cuatro años a partir de la fecha de entrada se considera liquidada por ministerio de ley, a menos que la suspensión sea requerida por ley u orden judicial. Véase 19 CFR 159.12(e) y (f).","ru":"Ликвидация может быть продлена на дополнительные периоды, но декларация, не ликвидированная в течение четырёх лет с даты ввоза, считается ликвидированной в силу закона, если только приостановление не требуется по закону или по судебному постановлению. См. 19 CFR 159.12(e) и (f).","tr":"Kesinleştirme ilave dönemler için uzatılabilir, ancak giriş tarihinden itibaren dört yıl içinde kesinleştirilmeyen bir giriş, kanun veya mahkeme kararı ile askıya alma gerekmedikçe kanun gereği kesinleşmiş sayılır. Bkz. 19 CFR 159.12(e) ve (f).","hi":"परिसमापन को अतिरिक्त अवधियों के लिए विस्तारित किया जा सकता है, लेकिन प्रवेश की तारीख से चार वर्ष के भीतर परिसमापित नहीं की गई एंट्री को कानून के संचालन से परिसमापित माना जाता है, जब तक कि क़ानून या अदालती आदेश द्वारा निलंबन आवश्यक न हो। देखें 19 CFR 159.12(e) और (f)।","ar":"يجوز تمديد التصفية لفترات إضافية، لكن البيان الذي لا تتم تصفيته خلال أربع سنوات من تاريخ الإدخال يُعتبر مصفّى بحكم القانون ما لم يكن التعليق مطلوبًا بموجب قانون أو أمر محكمة. انظر 19 CFR 159.12(e) و(f)."}},{"cat":"entry","a":1,"q":{"en":"Records pertaining to an importation that are subject to the recordkeeping requirements (the (a)(1)(A) list) must be retained by the importer for what period?","es":"Los registros relativos a una importación que están sujetos a los requisitos de conservación de registros (la lista (a)(1)(A)) deben ser conservados por el importador, ¿por cuánto tiempo?","ru":"Документы, относящиеся к импортированию, на которые распространяются требования о хранении документации (перечень (a)(1)(A)), должны храниться импортёром в течение какого срока?","tr":"Kayıt tutma gerekliliklerine (the (a)(1)(A) list) tabi olan, bir ithalata ilişkin kayıtlar, ithalatçı tarafından ne kadar süre saklanmalıdır?","hi":"रिकॉर्डकीपिंग आवश्यकताओं ((a)(1)(A) सूची) के अधीन किसी आयात से संबंधित रिकॉर्ड को आयातक द्वारा कितनी अवधि तक रखा जाना चाहिए?","ar":"السجلات المتعلقة بعملية استيراد والخاضعة لمتطلبات حفظ السجلات (قائمة (a)(1)(A)) يجب أن يحتفظ بها المستورد لأي مدة؟"},"o":[{"en":"3 years from the date of entry","es":"3 años a partir de la fecha de entrada","ru":"3 года с даты ввоза","tr":"Giriş tarihinden itibaren 3 yıl","hi":"प्रवेश की तारीख से 3 वर्ष","ar":"3 سنوات من تاريخ الإدخال"},{"en":"5 years from the date of entry","es":"5 años a partir de la fecha de entrada","ru":"5 лет с даты ввоза","tr":"Giriş tarihinden itibaren 5 yıl","hi":"प्रवेश की तारीख से 5 वर्ष","ar":"5 سنوات من تاريخ الإدخال"},{"en":"5 years from the date of liquidation","es":"5 años a partir de la fecha de liquidación","ru":"5 лет с даты ликвидации","tr":"Kesinleştirme (liquidation) tarihinden itibaren 5 yıl","hi":"परिसमापन की तारीख से 5 वर्ष","ar":"5 سنوات من تاريخ التصفية"},{"en":"7 years from the date of importation","es":"7 años a partir de la fecha de importación","ru":"7 лет с даты импортирования","tr":"İthalat tarihinden itibaren 7 yıl","hi":"आयात की तारीख से 7 वर्ष","ar":"7 سنوات من تاريخ الاستيراد"}],"e":{"en":"Records relating to an entry generally must be kept for 5 years from the date of entry (drawback records are measured differently). See 19 CFR 163.4(a).","es":"Los registros relativos a una entrada generalmente deben conservarse por 5 años a partir de la fecha de entrada (los registros de drawback se miden de forma diferente). Véase 19 CFR 163.4(a).","ru":"Документы, относящиеся к таможенной декларации, как правило, должны храниться в течение 5 лет с даты ввоза (для документов по возврату пошлин (drawback) срок исчисляется иначе). См. 19 CFR 163.4(a).","tr":"Bir girişe ilişkin kayıtlar genel olarak giriş tarihinden itibaren 5 yıl süreyle saklanmalıdır (drawback - gümrük vergisi iadesi kayıtları farklı şekilde ölçülür). Bkz. 19 CFR 163.4(a).","hi":"किसी एंट्री से संबंधित रिकॉर्ड आम तौर पर प्रवेश की तारीख से 5 वर्ष तक रखे जाने चाहिए (ड्रॉबैक (शुल्क वापसी) रिकॉर्ड को अलग ढंग से मापा जाता है)। देखें 19 CFR 163.4(a)।","ar":"يجب عمومًا حفظ السجلات المتعلقة ببيان الإدخال لمدة 5 سنوات من تاريخ الإدخال (تُقاس سجلات استرداد الرسوم (drawback) بشكل مختلف). انظر 19 CFR 163.4(a)."}},{"cat":"entry","a":0,"q":{"en":"When an entry summary is filed at the time of entry and serves as both the entry and the entry summary documentation, when does the 'time of entry' occur?","es":"Cuando un resumen de entrada se presenta al momento de la entrada y sirve como documentación tanto de la entrada como del resumen de entrada, ¿cuándo ocurre el 'momento de la entrada' (time of entry)?","ru":"Когда итоговая декларация подаётся в момент ввоза и служит одновременно и декларацией, и документацией итоговой декларации, когда наступает «момент ввоза»?","tr":"Bir giriş özeti giriş anında sunulduğunda ve hem giriş beyanı hem de giriş özeti belgesi olarak hizmet ettiğinde, 'giriş anı' ne zaman gerçekleşir?","hi":"जब एंट्री सारांश प्रवेश के समय दाखिल किया जाता है और एंट्री तथा एंट्री सारांश दस्तावेज़ीकरण दोनों के रूप में कार्य करता है, तो 'प्रवेश का समय' कब होता है?","ar":"عندما يُقدَّم ملخص الإدخال وقت الإدخال ويُستخدَم بوصفه مستند بيان الإدخال وملخص الإدخال معًا، متى يقع \"وقت الإدخال\"؟"},"o":[{"en":"When the entry summary is filed in proper form with estimated duties attached","es":"Cuando el resumen de entrada se presenta en debida forma con los derechos estimados adjuntos","ru":"Когда итоговая декларация подана в надлежащей форме с приложенными расчётными пошлинами","tr":"Giriş özeti, tahmini vergiler ekli olarak usulüne uygun biçimde sunulduğunda","hi":"जब एंट्री सारांश अनुमानित शुल्कों के साथ उचित रूप में दाखिल किया जाता है","ar":"عندما يُقدَّم ملخص الإدخال بالصيغة الصحيحة مع إرفاق الرسوم التقديرية"},{"en":"When the merchandise physically arrives within the limits of the port","es":"Cuando la mercancía llega físicamente dentro de los límites del puerto","ru":"Когда товары физически прибывают в пределы порта","tr":"Mallar fiziksel olarak liman sınırları içine vardığında","hi":"जब माल भौतिक रूप से बंदरगाह की सीमाओं के भीतर पहुंचता है","ar":"عندما تصل البضائع ماديًا إلى داخل حدود الميناء"},{"en":"When CBP authorizes release of the merchandise on Form 3461","es":"Cuando CBP autoriza la liberación de la mercancía en el Form 3461","ru":"Когда CBP разрешает выпуск товаров по Form 3461","tr":"CBP, Form 3461 üzerinde malların serbest bırakılmasına izin verdiğinde","hi":"जब CBP Form 3461 पर माल की रिलीज को अधिकृत करता है","ar":"عندما تأذن CBP بالإفراج عن البضائع على Form 3461"},{"en":"When the carrier files the manifest with CBP","es":"Cuando el transportista presenta el manifiesto ante CBP","ru":"Когда перевозчик подаёт манифест в CBP","tr":"Taşıyıcı manifestoyu CBP'ye sunduğunda","hi":"जब वाहक CBP के पास मेनिफेस्ट दाखिल करता है","ar":"عندما يقدّم الناقل البيان الجمركي (manifest) إلى CBP"}],"e":{"en":"When the entry summary serves as both entry and entry summary documentation under 19 CFR 142.3(b), the time of entry is when the entry summary is filed in proper form with estimated duties attached. See 19 CFR 141.68(b).","es":"Cuando el resumen de entrada sirve como documentación tanto de la entrada como del resumen de entrada conforme a 19 CFR 142.3(b), el momento de la entrada es cuando el resumen de entrada se presenta en debida forma con los derechos estimados adjuntos. Véase 19 CFR 141.68(b).","ru":"Когда итоговая декларация служит одновременно декларацией и документацией итоговой декларации согласно 19 CFR 142.3(b), моментом ввоза является момент подачи итоговой декларации в надлежащей форме с приложенными расчётными пошлинами. См. 19 CFR 141.68(b).","tr":"Giriş özeti, 19 CFR 142.3(b) kapsamında hem giriş beyanı hem de giriş özeti belgesi olarak hizmet ettiğinde, giriş anı, giriş özetinin tahmini vergiler ekli olarak usulüne uygun biçimde sunulduğu andır. Bkz. 19 CFR 141.68(b).","hi":"जब एंट्री सारांश 19 CFR 142.3(b) के तहत एंट्री और एंट्री सारांश दस्तावेज़ीकरण दोनों के रूप में कार्य करता है, तो प्रवेश का समय वह होता है जब एंट्री सारांश अनुमानित शुल्कों के साथ उचित रूप में दाखिल किया जाता है। देखें 19 CFR 141.68(b)।","ar":"عندما يُستخدَم ملخص الإدخال بوصفه مستند بيان الإدخال وملخص الإدخال معًا بموجب 19 CFR 142.3(b)، يكون وقت الإدخال هو وقت تقديم ملخص الإدخال بالصيغة الصحيحة مع إرفاق الرسوم التقديرية. انظر 19 CFR 141.68(b)."}},{"cat":"entry","a":3,"q":{"en":"Which of the following is NOT among the documentation generally required to be filed to obtain release of merchandise under an entry (CBP Form 3461)?","es":"¿Cuál de los siguientes NO está entre la documentación que generalmente se requiere presentar para obtener la liberación de mercancía bajo una entrada (CBP Form 3461)?","ru":"Что из перечисленного НЕ входит в число документов, которые, как правило, требуется подать для получения выпуска товаров по таможенной декларации (CBP Form 3461)?","tr":"Aşağıdakilerden hangisi, bir giriş (CBP Form 3461) kapsamında malların serbest bırakılmasını sağlamak için genel olarak sunulması gereken belgeler arasında YER ALMAZ?","hi":"निम्नलिखित में से कौन सा उस दस्तावेज़ीकरण में शामिल नहीं है जो आम तौर पर एंट्री (CBP Form 3461) के तहत माल की रिलीज प्राप्त करने के लिए दाखिल करना आवश्यक है?","ar":"أي مما يلي ليس من بين المستندات المطلوب عمومًا تقديمها للحصول على الإفراج عن البضائع بموجب بيان الإدخال (CBP Form 3461)؟"},"o":[{"en":"Evidence of the right to make entry","es":"Prueba del derecho a efectuar la entrada","ru":"Доказательство права на оформление таможенной декларации","tr":"Giriş beyanı yapma hakkının kanıtı","hi":"प्रवेश करने के अधिकार का साक्ष्य","ar":"إثبات حق إجراء الإدخال"},{"en":"A commercial invoice or an acceptable substitute","es":"Una factura comercial o un sustituto aceptable","ru":"Коммерческий счёт-фактура или приемлемая замена","tr":"Bir ticari fatura veya kabul edilebilir bir muadili","hi":"एक वाणिज्यिक चालान या एक स्वीकार्य विकल्प","ar":"فاتورة تجارية أو بديل مقبول عنها"},{"en":"Packing list, where appropriate","es":"Lista de empaque, cuando corresponda","ru":"Упаковочный лист, где это уместно","tr":"Uygun olduğu hallerde çeki listesi (packing list)","hi":"पैकिंग सूची, जहां उपयुक्त हो","ar":"قائمة التعبئة، حيثما كان ذلك مناسبًا"},{"en":"A final, paid record of the actual ocean freight charges","es":"Un registro final y pagado de los cargos reales de flete marítimo","ru":"Окончательная, оплаченная запись о фактических расходах на морской фрахт","tr":"Gerçek deniz navlun masraflarının nihai, ödenmiş kaydı","hi":"वास्तविक समुद्री माल भाड़ा शुल्कों का एक अंतिम, भुगतान किया गया रिकॉर्ड","ar":"سجل نهائي مدفوع لرسوم الشحن البحري الفعلية"}],"e":{"en":"Entry documentation required for release includes the entry form, evidence of the right to make entry, a commercial invoice (or acceptable substitute), a packing list where appropriate, and other required documents; a paid record of actual freight charges is not required for release. See 19 CFR 142.3(a).","es":"La documentación de entrada requerida para la liberación incluye el formulario de entrada, la prueba del derecho a efectuar la entrada, una factura comercial (o sustituto aceptable), una lista de empaque cuando corresponda y otros documentos requeridos; un registro pagado de los cargos reales de flete no se requiere para la liberación. Véase 19 CFR 142.3(a).","ru":"Документация для получения выпуска включает форму декларации, доказательство права на оформление таможенной декларации, коммерческий счёт-фактуру (или приемлемую замену), упаковочный лист, где это уместно, и другие необходимые документы; оплаченная запись о фактических расходах на фрахт для выпуска не требуется. См. 19 CFR 142.3(a).","tr":"Serbest bırakma için gereken giriş belgeleri arasında giriş formu, giriş beyanı yapma hakkının kanıtı, bir ticari fatura (veya kabul edilebilir muadili), uygun olduğu hallerde bir çeki listesi ve diğer gerekli belgeler bulunur; gerçek navlun masraflarının ödenmiş kaydı serbest bırakma için gerekli değildir. Bkz. 19 CFR 142.3(a).","hi":"रिलीज के लिए आवश्यक एंट्री दस्तावेज़ीकरण में एंट्री फॉर्म, प्रवेश करने के अधिकार का साक्ष्य, एक वाणिज्यिक चालान (या स्वीकार्य विकल्प), जहां उपयुक्त हो वहां पैकिंग सूची, और अन्य आवश्यक दस्तावेज़ शामिल हैं; वास्तविक माल भाड़ा शुल्कों का भुगतान किया गया रिकॉर्ड रिलीज के लिए आवश्यक नहीं है। देखें 19 CFR 142.3(a)।","ar":"تشمل مستندات الإدخال المطلوبة للإفراج نموذج الإدخال، وإثبات حق إجراء الإدخال، وفاتورة تجارية (أو بديل مقبول)، وقائمة تعبئة حيثما كان ذلك مناسبًا، وغيرها من المستندات المطلوبة؛ أما السجل المدفوع لرسوم الشحن الفعلية فليس مطلوبًا للإفراج. انظر 19 CFR 142.3(a)."}},{"cat":"entry","a":2,"q":{"en":"A broker transmits entry data to CBP through the Automated Broker Interface (ABI). Which statement best characterizes ABI and ACE in the entry process?","es":"Un agente aduanal transmite datos de entrada a CBP a través de la Automated Broker Interface (ABI). ¿Qué afirmación caracteriza mejor a ABI y ACE en el proceso de entrada?","ru":"Брокер передаёт данные таможенной декларации в CBP через автоматизированный брокерский интерфейс (ABI). Какое утверждение лучше всего характеризует ABI и ACE в процессе ввоза?","tr":"Bir gümrük müşaviri, giriş verilerini Automated Broker Interface (ABI) aracılığıyla CBP'ye iletir. Hangi ifade, giriş sürecinde ABI ve ACE'yi en iyi şekilde tanımlar?","hi":"एक ब्रोकर Automated Broker Interface (ABI) के माध्यम से CBP को एंट्री डेटा प्रेषित करता है। कौन सा कथन प्रवेश प्रक्रिया में ABI और ACE की सबसे अच्छी विशेषता बताता है?","ar":"يرسل وسيط بيانات الإدخال إلى CBP عبر واجهة الوسيط الآلية (ABI). أي عبارة تصف بأفضل شكل ABI وACE في عملية الإدخال؟"},"o":[{"en":"ABI is a paper-only backup used when ACE is unavailable","es":"ABI es un respaldo solo en papel que se usa cuando ACE no está disponible","ru":"ABI — это только бумажный резерв, используемый, когда ACE недоступен","tr":"ABI, yalnızca ACE kullanılamadığında kullanılan, kağıt tabanlı bir yedektir","hi":"ABI एक केवल-कागज वाला बैकअप है जिसका उपयोग तब किया जाता है जब ACE अनुपलब्ध हो","ar":"ABI هو نسخة احتياطية ورقية فقط تُستخدَم عندما يكون ACE غير متاح"},{"en":"ABI may be used only for informal entries, while ACE handles formal entries","es":"ABI puede usarse solo para entradas informales, mientras que ACE maneja las entradas formales","ru":"ABI может использоваться только для неформального ввоза, тогда как ACE обрабатывает формальный ввоз","tr":"ABI yalnızca gayri resmi girişler için kullanılabilir, ACE ise resmi girişleri ele alır","hi":"ABI का उपयोग केवल अनौपचारिक प्रवेशों के लिए किया जा सकता है, जबकि ACE औपचारिक प्रवेशों को संभालता है","ar":"يمكن استخدام ABI للإدخالات غير الرسمية فقط، بينما يتولى ACE الإدخالات الرسمية"},{"en":"ABI is the electronic system through which entry and entry summary data are transmitted to CBP, and ACE is CBP's system of record for processing that data","es":"ABI es el sistema electrónico a través del cual los datos de entrada y de resumen de entrada se transmiten a CBP, y ACE es el sistema de registro (system of record) de CBP para procesar esos datos","ru":"ABI — это электронная система, через которую данные декларации и итоговой декларации передаются в CBP, а ACE — это система учёта CBP для обработки этих данных","tr":"ABI, giriş ve giriş özeti verilerinin CBP'ye iletildiği elektronik sistemdir; ACE ise bu verilerin işlenmesi için CBP'nin kayıt sistemidir","hi":"ABI वह इलेक्ट्रॉनिक प्रणाली है जिसके माध्यम से एंट्री और एंट्री सारांश डेटा CBP को प्रेषित किया जाता है, और ACE उस डेटा के प्रसंस्करण के लिए CBP की रिकॉर्ड प्रणाली है","ar":"ABI هو النظام الإلكتروني الذي تُرسَل من خلاله بيانات الإدخال وملخص الإدخال إلى CBP، وACE هو نظام السجل لدى CBP لمعالجة تلك البيانات"},{"en":"ABI and ACE are interchangeable names for the carrier's manifest system","es":"ABI y ACE son nombres intercambiables del sistema de manifiestos del transportista","ru":"ABI и ACE — взаимозаменяемые названия системы манифестов перевозчика","tr":"ABI ve ACE, taşıyıcının manifesto sistemi için birbirinin yerine kullanılan adlardır","hi":"ABI और ACE वाहक की मेनिफेस्ट प्रणाली के लिए परस्पर बदले जा सकने वाले नाम हैं","ar":"ABI وACE اسمان مترادفان لنظام البيان الجمركي (manifest) الخاص بالناقل"}],"e":{"en":"The Automated Broker Interface (ABI) is the electronic interface filers use to transmit entry and entry summary data to CBP's Automated Commercial Environment (ACE), CBP's system of record. See 19 CFR 143.0 et seq. (Part 143, Subpart A) and 19 CFR 141.0a (electronic submission references).","es":"La Automated Broker Interface (ABI) es la interfaz electrónica que los declarantes usan para transmitir datos de entrada y de resumen de entrada al Automated Commercial Environment (ACE) de CBP, el sistema de registro de CBP. Véase 19 CFR 143.0 y siguientes (Parte 143, Subparte A) y 19 CFR 141.0a (referencias de presentación electrónica).","ru":"Автоматизированный брокерский интерфейс (ABI) — это электронный интерфейс, который податели используют для передачи данных декларации и итоговой декларации в автоматизированную коммерческую среду (ACE) CBP — систему учёта CBP. См. 19 CFR 143.0 и далее (часть 143, подраздел A) и 19 CFR 141.0a (ссылки на электронную подачу).","tr":"Automated Broker Interface (ABI), beyan sahiplerinin giriş ve giriş özeti verilerini CBP'nin kayıt sistemi olan Automated Commercial Environment (ACE) ortamına iletmek için kullandıkları elektronik arayüzdür. Bkz. 19 CFR 143.0 vd. (Part 143, Subpart A) ve 19 CFR 141.0a (elektronik sunum referansları).","hi":"Automated Broker Interface (ABI) वह इलेक्ट्रॉनिक इंटरफ़ेस है जिसका उपयोग फाइलर्स CBP के Automated Commercial Environment (ACE), जो CBP की रिकॉर्ड प्रणाली है, को एंट्री और एंट्री सारांश डेटा प्रेषित करने के लिए करते हैं। देखें 19 CFR 143.0 et seq. (Part 143, Subpart A) और 19 CFR 141.0a (इलेक्ट्रॉनिक प्रस्तुति संदर्भ)।","ar":"إن واجهة الوسيط الآلية (ABI) هي الواجهة الإلكترونية التي يستخدمها مقدّمو البيانات لإرسال بيانات الإدخال وملخص الإدخال إلى البيئة التجارية الآلية لدى CBP (ACE)، وهو نظام السجل لدى CBP. انظر 19 CFR 143.0 وما يليها (Part 143, Subpart A) و19 CFR 141.0a (مراجع التقديم الإلكتروني)."}},{"cat":"classification","a":0,"q":{"en":"When classifying goods under the HTSUS, in what order must the General Rules of Interpretation (GRI 1 through 6) generally be applied?","es":"Al clasificar mercancías bajo el HTSUS, ¿en qué orden deben aplicarse generalmente las Reglas Generales de Interpretación (GRI 1 a 6)?","ru":"При классификации товаров по HTSUS в каком порядке, как правило, должны применяться Основные правила интерпретации (GRI с 1 по 6)?","tr":"HTSUS kapsamında malları sınıflandırırken, Yorum Genel Kuralları (GRI 1 ila 6) genel olarak hangi sırada uygulanmalıdır?","hi":"HTSUS के तहत माल को वर्गीकृत करते समय, व्याख्या के सामान्य नियम (GRI 1 से 6) आम तौर पर किस क्रम में लागू किए जाने चाहिए?","ar":"عند تصنيف البضائع بموجب HTSUS، بأي ترتيب يجب عمومًا تطبيق القواعد العامة للتفسير (GRI 1 إلى 6)؟"},"o":[{"en":"In sequential order, so a later rule is reached only when the preceding rules do not resolve the classification","es":"En orden secuencial, de modo que se llega a una regla posterior solo cuando las reglas precedentes no resuelven la clasificación","ru":"В последовательном порядке, так что последующее правило применяется только тогда, когда предыдущие правила не разрешают классификацию","tr":"Sıralı düzende, böylece sonraki bir kurala ancak önceki kurallar sınıflandırmayı çözmediğinde başvurulur","hi":"अनुक्रमिक क्रम में, ताकि बाद के नियम तक तभी पहुंचा जाए जब पूर्ववर्ती नियम वर्गीकरण का समाधान न करें","ar":"بترتيب تسلسلي، بحيث لا يُلجأ إلى قاعدة لاحقة إلا عندما لا تحسم القواعد السابقة التصنيف"},{"en":"In any order, choosing whichever rule produces the lowest duty rate","es":"En cualquier orden, eligiendo la regla que produzca la tasa de derecho más baja","ru":"В любом порядке, выбирая то правило, которое даёт наименьшую ставку пошлины","tr":"Herhangi bir sırada, en düşük vergi oranını üreten kural seçilerek","hi":"किसी भी क्रम में, जो भी नियम सबसे कम शुल्क दर उत्पन्न करे उसे चुनते हुए","ar":"بأي ترتيب، باختيار القاعدة التي تنتج أدنى معدل رسوم"},{"en":"Beginning with GRI 3(b) because essential character is the most common basis for classification","es":"Comenzando con la GRI 3(b) porque el carácter esencial es la base más común de clasificación","ru":"Начиная с GRI 3(b), поскольку основной характер является наиболее распространённым основанием для классификации","tr":"En sık karşılaşılan sınıflandırma temeli esas nitelik olduğundan GRI 3(b) ile başlanarak","hi":"GRI 3(b) से शुरू करते हुए क्योंकि आवश्यक चरित्र वर्गीकरण का सबसे आम आधार है","ar":"بدءًا من GRI 3(b) لأن الطابع الأساسي هو الأساس الأكثر شيوعًا للتصنيف"},{"en":"GRI 6 first to fix the subheading, then GRI 1 through 5 to confirm the heading","es":"La GRI 6 primero para fijar la subpartida, luego la GRI 1 a 5 para confirmar la partida","ru":"Сначала GRI 6, чтобы определить субпозицию, затем GRI с 1 по 5, чтобы подтвердить позицию","tr":"Önce alt pozisyonu (subheading) belirlemek için GRI 6, ardından pozisyonu (heading) teyit etmek için GRI 1 ila 5","hi":"पहले GRI 6 शीर्षक उपशीर्षक तय करने के लिए, फिर GRI 1 से 5 शीर्षक की पुष्टि करने के लिए","ar":"GRI 6 أولًا لتحديد البند الفرعي، ثم GRI 1 إلى 5 لتأكيد البند"}],"e":{"en":"The GRIs are hierarchical and applied in sequence; one moves to the next rule only if the prior rule does not settle the matter. GRI 1 is applied first, and the others are reached only as needed. (GRI 1; structure of the General Rules of Interpretation.)","es":"Las GRI son jerárquicas y se aplican en secuencia; se pasa a la siguiente regla solo si la regla anterior no resuelve el asunto. La GRI 1 se aplica primero, y las demás se alcanzan solo según sea necesario. (GRI 1; estructura de las Reglas Generales de Interpretación.)","ru":"Правила GRI имеют иерархический характер и применяются последовательно; к следующему правилу переходят только в том случае, если предыдущее правило не разрешает вопрос. GRI 1 применяется первым, а остальные применяются только по мере необходимости. (GRI 1; структура Основных правил интерпретации.)","tr":"GRI'lar hiyerarşiktir ve sırayla uygulanır; bir sonraki kurala ancak önceki kural meseleyi çözmediğinde geçilir. Önce GRI 1 uygulanır ve diğerlerine yalnızca gerektiğinde başvurulur. (GRI 1; Yorum Genel Kuralları'nın yapısı.)","hi":"GRI पदानुक्रमिक हैं और क्रम में लागू किए जाते हैं; अगले नियम पर तभी जाया जाता है जब पूर्व नियम मामले को सुलझाता नहीं है। GRI 1 पहले लागू किया जाता है, और अन्य तक केवल आवश्यकता पड़ने पर ही पहुंचा जाता है। (GRI 1; व्याख्या के सामान्य नियमों की संरचना।)","ar":"إن قواعد GRI هرمية وتُطبَّق بالتسلسل؛ ولا يُنتقل إلى القاعدة التالية إلا إذا لم تحسم القاعدة السابقة المسألة. تُطبَّق GRI 1 أولًا، ولا يُلجأ إلى الأخرى إلا عند الحاجة. (GRI 1؛ بنية القواعد العامة للتفسير.)"}},{"cat":"classification","a":3,"q":{"en":"Under GRI 1, what controls classification at the four-digit heading level?","es":"Bajo la GRI 1, ¿qué rige la clasificación a nivel de partida de cuatro dígitos?","ru":"Согласно GRI 1, что определяет классификацию на уровне четырёхзначной позиции?","tr":"GRI 1 kapsamında, dört haneli pozisyon (heading) düzeyinde sınıflandırmayı ne belirler?","hi":"GRI 1 के तहत, चार-अंकीय शीर्षक स्तर पर वर्गीकरण को क्या नियंत्रित करता है?","ar":"بموجب GRI 1، ما الذي يتحكم في التصنيف عند مستوى البند المكوّن من أربعة أرقام؟"},"o":[{"en":"The commercial name the importer assigns to the merchandise on the commercial invoice","es":"El nombre comercial que el importador asigna a la mercancía en la factura comercial","ru":"Коммерческое название, которое импортёр присваивает товарам в коммерческом счёте-фактуре","tr":"İthalatçının ticari faturada mallara atadığı ticari isim","hi":"वह वाणिज्यिक नाम जो आयातक वाणिज्यिक चालान पर माल को निर्दिष्ट करता है","ar":"الاسم التجاري الذي يطلقه المستورد على البضائع في الفاتورة التجارية"},{"en":"The essential character of the article as determined by its most valuable component","es":"El carácter esencial del artículo determinado por su componente más valioso","ru":"Основной характер изделия, определяемый его наиболее ценным компонентом","tr":"Ürünün en değerli bileşeniyle belirlenen esas niteliği","hi":"सबसे मूल्यवान घटक द्वारा निर्धारित वस्तु का आवश्यक चरित्र","ar":"الطابع الأساسي للصنف كما يحدده مكوّنه الأعلى قيمةً"},{"en":"The principal use of goods of the same class or kind in the United States","es":"El uso principal de mercancías de la misma clase o tipo en los Estados Unidos","ru":"Основное использование товаров того же класса или вида в Соединённых Штатах","tr":"Aynı sınıf veya türdeki malların Amerika Birleşik Devletleri'ndeki başlıca kullanımı (principal use)","hi":"संयुक्त राज्य अमेरिका में समान वर्ग या प्रकार के माल का प्रमुख उपयोग","ar":"الاستخدام الرئيسي للبضائع من نفس الصنف أو النوع في الولايات المتحدة"},{"en":"The terms of the headings and any relative section or chapter notes","es":"Los términos de las partidas y cualquier nota relativa de sección o capítulo","ru":"Тексты позиций и любые относящиеся к ним примечания к разделам или главам","tr":"Pozisyonların (heading) ifadeleri ve ilgili herhangi bir bölüm veya fasıl notu","hi":"शीर्षकों की शर्तें और कोई भी संबंधित खंड या अध्याय टिप्पणियां","ar":"نصوص البنود وأي ملاحظات أقسام أو فصول ذات صلة"}],"e":{"en":"GRI 1 states that classification is determined according to the terms of the headings and any relative section or chapter notes; titles of sections, chapters and subchapters are provided for ease of reference only and have no legal force. (GRI 1.)","es":"La GRI 1 establece que la clasificación se determina conforme a los términos de las partidas y cualquier nota relativa de sección o capítulo; los títulos de secciones, capítulos y subcapítulos se proporcionan solo para facilitar la consulta y no tienen fuerza legal. (GRI 1.)","ru":"GRI 1 устанавливает, что классификация определяется в соответствии с текстами позиций и любыми относящимися к ним примечаниями к разделам или главам; названия разделов, глав и подглав приводятся только для удобства ссылок и не имеют юридической силы. (GRI 1.)","tr":"GRI 1, sınıflandırmanın pozisyonların (heading) ifadelerine ve ilgili herhangi bir bölüm veya fasıl notuna göre belirlendiğini belirtir; bölümlerin, fasılların ve alt fasılların başlıkları yalnızca kolay referans amacıyla verilmiştir ve hukuki bir bağlayıcılığı yoktur. (GRI 1.)","hi":"GRI 1 कहता है कि वर्गीकरण शीर्षकों की शर्तों और किसी भी संबंधित खंड या अध्याय टिप्पणियों के अनुसार निर्धारित होता है; खंडों, अध्यायों और उप-अध्यायों के शीर्षक केवल संदर्भ की सुविधा के लिए प्रदान किए जाते हैं और उनका कोई कानूनी बल नहीं है। (GRI 1.)","ar":"تنص GRI 1 على أن التصنيف يُحدَّد وفقًا لنصوص البنود وأي ملاحظات أقسام أو فصول ذات صلة؛ أما عناوين الأقسام والفصول والفصول الفرعية فهي مقدَّمة لسهولة الإحالة فقط وليست لها قوة قانونية. (GRI 1.)"}},{"cat":"classification","a":2,"q":{"en":"A complete bicycle is imported disassembled in a single shipment, with all frame tubes, wheels, chain, and handlebars packed together but not yet bolted together. Which rule directs that this unassembled article be classified as if it were a complete, assembled bicycle?","es":"Una bicicleta completa se importa desarmada en un solo embarque, con todos los tubos del cuadro, ruedas, cadena y manubrios empacados juntos pero aún no atornillados entre sí. ¿Qué regla dispone que este artículo sin armar se clasifique como si fuera una bicicleta completa y armada?","ru":"Полный велосипед импортируется в разобранном виде одной партией: все трубы рамы, колёса, цепь и руль упакованы вместе, но ещё не скреплены болтами. Какое правило предписывает классифицировать это несобранное изделие так, как если бы это был полный, собранный велосипед?","tr":"Eksiksiz bir bisiklet, tüm kadro boruları, tekerlekleri, zinciri ve gidonu birlikte paketlenmiş ancak henüz cıvatalarla birleştirilmemiş halde, tek bir sevkiyatta sökülmüş olarak ithal edilir. Hangi kural, bu monte edilmemiş ürünün eksiksiz, monte edilmiş bir bisiklet gibi sınıflandırılmasını gerektirir?","hi":"एक पूर्ण साइकिल एक ही शिपमेंट में अलग-अलग करके आयात की जाती है, जिसमें सभी फ्रेम ट्यूब, पहिए, चेन और हैंडलबार एक साथ पैक किए गए हैं लेकिन अभी तक एक साथ बोल्ट नहीं किए गए हैं। कौन सा नियम निर्देशित करता है कि इस बिना जोड़ी गई वस्तु को एक पूर्ण, जुड़ी हुई साइकिल के रूप में वर्गीकृत किया जाए?","ar":"تُستورَد دراجة كاملة مفككة في شحنة واحدة، مع تعبئة جميع أنابيب الإطار والعجلات والسلسلة والمقود معًا لكن دون ربطها بعد. أي قاعدة تقضي بتصنيف هذا الصنف غير المجمَّع كما لو كان دراجة كاملة مجمَّعة؟"},"o":[{"en":"GRI 3(b), on the basis of the essential character of the assembled article","es":"GRI 3(b), con base en el carácter esencial del artículo armado","ru":"GRI 3(b), на основании основного характера собранного изделия","tr":"GRI 3(b), monte edilmiş ürünün esas niteliği temelinde","hi":"GRI 3(b), जुड़ी हुई वस्तु के आवश्यक चरित्र के आधार पर","ar":"GRI 3(b)، استنادًا إلى الطابع الأساسي للصنف المجمَّع"},{"en":"GRI 5(a), as goods presented with a fitted container","es":"GRI 5(a), como mercancías presentadas con un estuche ajustado","ru":"GRI 5(a), как товары, представленные с подогнанной тарой","tr":"GRI 5(a), kendine özel bir kap ile birlikte sunulan mallar olarak","hi":"GRI 5(a), एक फिट किए गए कंटेनर के साथ प्रस्तुत माल के रूप में","ar":"GRI 5(a)، باعتبارها بضائع مقدَّمة مع حاوية مُجهَّزة لها"},{"en":"GRI 2(a), which extends a heading to articles presented unassembled or disassembled","es":"GRI 2(a), que extiende una partida a artículos presentados sin armar o desarmados","ru":"GRI 2(a), которое распространяет позицию на изделия, представленные несобранными или разобранными","tr":"GRI 2(a), bir pozisyonu monte edilmemiş veya sökülmüş olarak sunulan ürünlere genişleten kural","hi":"GRI 2(a), जो किसी शीर्षक को बिना जोड़े या अलग करके प्रस्तुत की गई वस्तुओं तक विस्तारित करता है","ar":"GRI 2(a)، التي توسّع البند ليشمل الأصناف المقدَّمة غير مجمَّعة أو مفككة"},{"en":"GRI 4, as goods most akin to an assembled bicycle","es":"GRI 4, como mercancías más afines a una bicicleta armada","ru":"GRI 4, как товары, наиболее сходные с собранным велосипедом","tr":"GRI 4, monte edilmiş bir bisiklete en çok benzeyen mallar olarak","hi":"GRI 4, एक जुड़ी हुई साइकिल से सबसे समान माल के रूप में","ar":"GRI 4، باعتبارها بضائع أقرب ما تكون إلى دراجة مجمَّعة"}],"e":{"en":"GRI 2(a) provides that a reference to an article includes that article presented unassembled or disassembled (and incomplete or unfinished articles having the essential character of the complete article). The disassembled bicycle is classified as a complete bicycle. (GRI 2(a).)","es":"La GRI 2(a) dispone que una referencia a un artículo incluye ese artículo presentado sin armar o desarmado (y los artículos incompletos o sin terminar que tengan el carácter esencial del artículo completo). La bicicleta desarmada se clasifica como una bicicleta completa. (GRI 2(a).)","ru":"GRI 2(a) предусматривает, что ссылка на изделие включает это изделие, представленное несобранным или разобранным (а также некомплектные или незавершённые изделия, обладающие основным характером комплектного изделия). Разобранный велосипед классифицируется как полный велосипед. (GRI 2(a).)","tr":"GRI 2(a), bir ürüne yapılan atfın, o ürünü monte edilmemiş veya sökülmüş halde sunulan haliyle de kapsadığını öngörür (ve eksiksiz ürünün esas niteliğine sahip olan tamamlanmamış veya bitmemiş ürünleri de). Sökülmüş bisiklet, eksiksiz bir bisiklet olarak sınıflandırılır. (GRI 2(a).)","hi":"GRI 2(a) प्रावधान करता है कि किसी वस्तु का संदर्भ उस वस्तु को बिना जोड़े या अलग करके प्रस्तुत किए जाने को शामिल करता है (और अपूर्ण या अधूरी वस्तुएं जिनमें पूर्ण वस्तु का आवश्यक चरित्र हो)। अलग की गई साइकिल को एक पूर्ण साइकिल के रूप में वर्गीकृत किया जाता है। (GRI 2(a).)","ar":"تنص GRI 2(a) على أن الإشارة إلى صنف ما تشمل ذلك الصنف مقدَّمًا غير مجمَّع أو مفككًا (والأصناف غير الكاملة أو غير المنتهية التي لها الطابع الأساسي للصنف الكامل). فتُصنَّف الدراجة المفككة على أنها دراجة كاملة. (GRI 2(a).)"}},{"cat":"classification","a":0,"q":{"en":"GRI 2(a) extends a heading covering a complete article to an incomplete or unfinished article only when the incomplete or unfinished article has which attribute?","es":"La GRI 2(a) extiende una partida que comprende un artículo completo a un artículo incompleto o sin terminar solo cuando el artículo incompleto o sin terminar tiene ¿cuál atributo?","ru":"GRI 2(a) распространяет позицию, охватывающую комплектное изделие, на некомплектное или незавершённое изделие только тогда, когда некомплектное или незавершённое изделие обладает каким признаком?","tr":"GRI 2(a), eksiksiz bir ürünü kapsayan bir pozisyonu, tamamlanmamış veya bitmemiş bir ürüne yalnızca o ürün hangi özelliğe sahip olduğunda genişletir?","hi":"GRI 2(a) किसी पूर्ण वस्तु को कवर करने वाले शीर्षक को किसी अपूर्ण या अधूरी वस्तु तक केवल तभी विस्तारित करता है जब अपूर्ण या अधूरी वस्तु में कौन सी विशेषता हो?","ar":"توسّع GRI 2(a) البند الذي يشمل صنفًا كاملًا ليشمل صنفًا غير كامل أو غير منتهٍ فقط عندما يكون لهذا الصنف غير الكامل أو غير المنتهي أي صفة؟"},"o":[{"en":"The essential character of the complete or finished article as presented","es":"El carácter esencial del artículo completo o terminado tal como se presenta","ru":"Основным характером комплектного или завершённого изделия в представленном виде","tr":"Sunulduğu haliyle eksiksiz veya bitmiş ürünün esas niteliğine sahip olduğunda","hi":"प्रस्तुत किए जाने पर पूर्ण या तैयार वस्तु का आवश्यक चरित्र","ar":"الطابع الأساسي للصنف الكامل أو المنتهي كما هو مقدَّم"},{"en":"A value at least equal to half the value of the finished article","es":"Un valor al menos igual a la mitad del valor del artículo terminado","ru":"Стоимостью не менее половины стоимости завершённого изделия","tr":"Bitmiş ürünün değerinin en az yarısına eşit bir değere sahip olduğunda","hi":"तैयार वस्तु के मूल्य के कम से कम आधे के बराबर मूल्य","ar":"قيمة تساوي على الأقل نصف قيمة الصنف المنتهي"},{"en":"A principal use identical to that of the finished article in the United States","es":"Un uso principal idéntico al del artículo terminado en los Estados Unidos","ru":"Основным использованием, идентичным использованию завершённого изделия в Соединённых Штатах","tr":"Amerika Birleşik Devletleri'nde bitmiş ürünle aynı başlıca kullanıma (principal use) sahip olduğunda","hi":"संयुक्त राज्य अमेरिका में तैयार वस्तु के समान एक प्रमुख उपयोग","ar":"استخدام رئيسي مطابق لاستخدام الصنف المنتهي في الولايات المتحدة"},{"en":"The same six-digit subheading classification as the finished article","es":"La misma clasificación de subpartida de seis dígitos que el artículo terminado","ru":"Той же шестизначной классификацией субпозиции, что и завершённое изделие","tr":"Bitmiş ürünle aynı altı haneli alt pozisyon (subheading) sınıflandırmasına sahip olduğunda","hi":"तैयार वस्तु के समान छह-अंकीय उपशीर्षक वर्गीकरण","ar":"نفس تصنيف البند الفرعي المكوّن من ستة أرقام للصنف المنتهي"}],"e":{"en":"GRI 2(a) extends a heading to an incomplete or unfinished article provided that, as presented, it has the essential character of the complete or finished article (e.g., a blank that already has the approximate shape of the finished part). (GRI 2(a).)","es":"La GRI 2(a) extiende una partida a un artículo incompleto o sin terminar siempre que, tal como se presenta, tenga el carácter esencial del artículo completo o terminado (por ejemplo, un esbozo que ya tiene la forma aproximada de la pieza terminada). (GRI 2(a).)","ru":"GRI 2(a) распространяет позицию на некомплектное или незавершённое изделие при условии, что в представленном виде оно обладает основным характером комплектного или завершённого изделия (например, заготовка, уже имеющая приблизительную форму готовой детали). (GRI 2(a).)","tr":"GRI 2(a), bir pozisyonu tamamlanmamış veya bitmemiş bir ürüne, sunulduğu haliyle eksiksiz veya bitmiş ürünün esas niteliğine sahip olması koşuluyla genişletir (örneğin, halihazırda bitmiş parçanın yaklaşık şekline sahip bir taslak). (GRI 2(a).)","hi":"GRI 2(a) किसी शीर्षक को अपूर्ण या अधूरी वस्तु तक तब विस्तारित करता है, बशर्ते कि प्रस्तुत किए जाने पर उसमें पूर्ण या तैयार वस्तु का आवश्यक चरित्र हो (उदाहरण के लिए, एक ब्लैंक जिसमें पहले से ही तैयार भाग का अनुमानित आकार हो)। (GRI 2(a).)","ar":"توسّع GRI 2(a) البند ليشمل صنفًا غير كامل أو غير منتهٍ شريطة أن يكون له، كما هو مقدَّم، الطابع الأساسي للصنف الكامل أو المنتهي (مثل قالب أولي (blank) له بالفعل الشكل التقريبي للقطعة المنتهية). (GRI 2(a).)"}},{"cat":"classification","a":0,"q":{"en":"Goods that are, prima facie, classifiable under two or more headings are addressed by GRI 3. What is the FIRST test applied under GRI 3?","es":"Las mercancías que, prima facie, son clasificables en dos o más partidas se abordan en la GRI 3. ¿Cuál es la PRIMERA prueba que se aplica bajo la GRI 3?","ru":"Товары, которые prima facie могут быть классифицированы по двум или более позициям, рассматриваются согласно GRI 3. Какой тест применяется ПЕРВЫМ согласно GRI 3?","tr":"İlk bakışta (prima facie) iki veya daha fazla pozisyon (heading) altında sınıflandırılabilen mallar GRI 3 ile ele alınır. GRI 3 kapsamında uygulanan İLK test nedir?","hi":"वह माल जो प्रथम दृष्टया दो या अधिक शीर्षकों के तहत वर्गीकृत होने योग्य है, उसे GRI 3 द्वारा संबोधित किया जाता है। GRI 3 के तहत लागू किया जाने वाला पहला परीक्षण क्या है?","ar":"البضائع التي يمكن تصنيفها مبدئيًا (prima facie) تحت بندين أو أكثر تتناولها GRI 3. ما هو الاختبار الأول المطبَّق بموجب GRI 3؟"},"o":[{"en":"GRI 3(a): the heading providing the most specific description is preferred over headings providing a more general description","es":"GRI 3(a): se prefiere la partida que ofrezca la descripción más específica sobre las partidas que ofrezcan una descripción más general","ru":"GRI 3(a): позиция, дающая наиболее конкретное описание, имеет предпочтение перед позициями, дающими более общее описание","tr":"GRI 3(a): en spesifik tanımı sağlayan pozisyon, daha genel bir tanım sağlayan pozisyonlara tercih edilir","hi":"GRI 3(a): सबसे विशिष्ट विवरण प्रदान करने वाले शीर्षक को अधिक सामान्य विवरण प्रदान करने वाले शीर्षकों पर प्राथमिकता दी जाती है","ar":"GRI 3(a): يُفضَّل البند الذي يقدّم الوصف الأكثر تحديدًا على البنود التي تقدّم وصفًا أكثر عمومية"},{"en":"GRI 3(b): the component giving the goods their essential character determines the classification","es":"GRI 3(b): el componente que da a las mercancías su carácter esencial determina la clasificación","ru":"GRI 3(b): компонент, придающий товарам их основной характер, определяет классификацию","tr":"GRI 3(b): mallara esas niteliğini veren bileşen sınıflandırmayı belirler","hi":"GRI 3(b): माल को उसका आवश्यक चरित्र प्रदान करने वाला घटक वर्गीकरण निर्धारित करता है","ar":"GRI 3(b): المكوّن الذي يمنح البضائع طابعها الأساسي يحدد التصنيف"},{"en":"GRI 3(c): the heading occurring last in numerical order among those equally meriting consideration","es":"GRI 3(c): la partida que se ubique en último lugar en orden numérico entre las que igualmente merezcan consideración","ru":"GRI 3(c): позиция, последняя в порядке возрастания нумерации среди тех, что в равной степени заслуживают рассмотрения","tr":"GRI 3(c): eşit derecede dikkate alınmayı hak edenler arasında numara sırasında en sonda yer alan pozisyon","hi":"GRI 3(c): समान रूप से विचार के योग्य शीर्षकों में से संख्यात्मक क्रम में अंतिम स्थान पर आने वाला शीर्षक","ar":"GRI 3(c): البند الذي يأتي أخيرًا في الترتيب العددي بين البنود التي تستحق الاعتبار بالتساوي"},{"en":"GRI 4: the heading appropriate to the goods to which they are most akin","es":"GRI 4: la partida apropiada a las mercancías con las que tengan mayor afinidad","ru":"GRI 4: позиция, соответствующая товарам, наиболее сходным с ними","tr":"GRI 4: malların en çok benzediği mallara uygun pozisyon","hi":"GRI 4: उस माल के लिए उपयुक्त शीर्षक जिससे वे सबसे अधिक समान हैं","ar":"GRI 4: البند المناسب للبضائع التي تكون هي أقرب ما تكون إليها"}],"e":{"en":"GRI 3 is applied in the order (a), (b), (c). GRI 3(a) is tried first: the heading with the most specific description prevails over one with a more general description. Only if 3(a) does not resolve the issue does one proceed to 3(b), then 3(c). (GRI 3(a).)","es":"La GRI 3 se aplica en el orden (a), (b), (c). La GRI 3(a) se prueba primero: la partida con la descripción más específica prevalece sobre una con una descripción más general. Solo si la 3(a) no resuelve el asunto se procede a la 3(b), luego a la 3(c). (GRI 3(a).)","ru":"GRI 3 применяется в порядке (a), (b), (c). GRI 3(a) применяется первым: позиция с наиболее конкретным описанием имеет преимущество перед позицией с более общим описанием. Только если 3(a) не разрешает вопрос, переходят к 3(b), затем к 3(c). (GRI 3(a).)","tr":"GRI 3, (a), (b), (c) sırasıyla uygulanır. Önce GRI 3(a) denenir: en spesifik tanıma sahip pozisyon, daha genel bir tanıma sahip olana karşı üstün gelir. Yalnızca 3(a) meseleyi çözmediğinde 3(b)'ye, ardından 3(c)'ye geçilir. (GRI 3(a).)","hi":"GRI 3 को क्रम (a), (b), (c) में लागू किया जाता है। GRI 3(a) पहले आजमाया जाता है: सबसे विशिष्ट विवरण वाला शीर्षक अधिक सामान्य विवरण वाले शीर्षक पर प्रबल होता है। केवल यदि 3(a) मुद्दे को हल नहीं करता, तो 3(b), फिर 3(c) पर आगे बढ़ा जाता है। (GRI 3(a).)","ar":"تُطبَّق GRI 3 بالترتيب (a) و(b) و(c). تُجرَّب GRI 3(a) أولًا: البند ذو الوصف الأكثر تحديدًا يسود على البند ذي الوصف الأكثر عمومية. ولا يُنتقَل إلى 3(b) ثم 3(c) إلا إذا لم تحسم 3(a) المسألة. (GRI 3(a).)"}},{"cat":"classification","a":2,"q":{"en":"Under GRI 3(a), when two headings each refer to only PART of the materials in a mixture or composite good, or to only part of the items in a set put up for retail sale, how are those headings regarded?","es":"Bajo la GRI 3(a), cuando dos partidas se refieren cada una a solo PARTE de los materiales de una mezcla o de una mercancía compuesta, o a solo parte de los artículos de un surtido acondicionado para la venta al por menor, ¿cómo se consideran esas partidas?","ru":"Согласно GRI 3(a), когда каждая из двух позиций относится только к ЧАСТИ материалов в смеси или составном товаре, либо только к части предметов в наборе для розничной продажи, как рассматриваются эти позиции?","tr":"GRI 3(a) kapsamında, iki pozisyonun (heading) her biri bir karışım veya bileşik bir maldaki malzemelerin yalnızca BİR KISMINA ya da perakende satış için hazırlanmış bir setteki ürünlerin yalnızca bir kısmına atıfta bulunduğunda, bu pozisyonlar nasıl değerlendirilir?","hi":"GRI 3(a) के तहत, जब दो शीर्षक प्रत्येक किसी मिश्रण या मिश्रित माल में सामग्री के केवल एक भाग, या खुदरा बिक्री के लिए प्रस्तुत सेट में वस्तुओं के केवल एक भाग को संदर्भित करते हैं, तो उन शीर्षकों को कैसे माना जाता है?","ar":"بموجب GRI 3(a)، عندما يشير بندان كلٌّ منهما إلى جزء فقط من المواد في مزيج أو في بضائع مركّبة، أو إلى جزء فقط من الأصناف في مجموعة مُعدَّة للبيع بالتجزئة، كيف يُنظَر إلى هذين البندين؟"},"o":[{"en":"The heading with the lower numerical value is automatically treated as more specific","es":"La partida con el valor numérico más bajo se trata automáticamente como más específica","ru":"Позиция с меньшим числовым значением автоматически считается более конкретной","tr":"Daha düşük numara değerine sahip pozisyon otomatik olarak daha spesifik kabul edilir","hi":"कम संख्यात्मक मूल्य वाले शीर्षक को स्वचालित रूप से अधिक विशिष्ट माना जाता है","ar":"يُعامَل البند ذو القيمة العددية الأدنى تلقائيًا على أنه الأكثر تحديدًا"},{"en":"The heading describing the most valuable material is treated as the most specific","es":"La partida que describe el material más valioso se trata como la más específica","ru":"Позиция, описывающая наиболее ценный материал, считается наиболее конкретной","tr":"En değerli malzemeyi tanımlayan pozisyon en spesifik olarak kabul edilir","hi":"सबसे मूल्यवान सामग्री का वर्णन करने वाले शीर्षक को सबसे विशिष्ट माना जाता है","ar":"يُعامَل البند الذي يصف المادة الأعلى قيمةً على أنه الأكثر تحديدًا"},{"en":"They are regarded as equally specific, even if one gives a more complete or precise description","es":"Se consideran igualmente específicas, aunque una ofrezca una descripción más completa o precisa","ru":"Они считаются в равной степени конкретными, даже если одна даёт более полное или точное описание","tr":"Biri daha eksiksiz veya daha kesin bir tanım verse bile, eşit derecede spesifik kabul edilirler","hi":"उन्हें समान रूप से विशिष्ट माना जाता है, भले ही उनमें से एक अधिक पूर्ण या सटीक विवरण देता हो","ar":"يُعتبران متساويين في التحديد، حتى لو قدّم أحدهما وصفًا أكثر اكتمالًا أو دقة"},{"en":"Neither heading may be used, and classification falls directly to GRI 4","es":"Ninguna de las partidas puede usarse, y la clasificación recae directamente en la GRI 4","ru":"Ни одна из позиций не может использоваться, и классификация переходит непосредственно к GRI 4","tr":"Hiçbir pozisyon kullanılamaz ve sınıflandırma doğrudan GRI 4'e geçer","hi":"किसी भी शीर्षक का उपयोग नहीं किया जा सकता, और वर्गीकरण सीधे GRI 4 पर चला जाता है","ar":"لا يجوز استخدام أي من البندين، وينتقل التصنيف مباشرةً إلى GRI 4"}],"e":{"en":"GRI 3(a) provides that when two or more headings each refer to part only of the materials in mixed or composite goods, or to part only of the items in a retail set, those headings are to be regarded as equally specific, even if one gives a more complete description. The tie then moves the analysis to GRI 3(b). (GRI 3(a).)","es":"La GRI 3(a) dispone que cuando dos o más partidas se refieren cada una a solo parte de los materiales en mercancías mezcladas o compuestas, o a solo parte de los artículos de un surtido para venta al por menor, esas partidas deben considerarse igualmente específicas, aunque una ofrezca una descripción más completa. El empate entonces lleva el análisis a la GRI 3(b). (GRI 3(a).)","ru":"GRI 3(a) предусматривает, что когда каждая из двух или более позиций относится только к части материалов в смешанных или составных товарах либо только к части предметов в розничном наборе, эти позиции должны рассматриваться как в равной степени конкретные, даже если одна даёт более полное описание. Тогда анализ переходит к GRI 3(b). (GRI 3(a).)","tr":"GRI 3(a), iki veya daha fazla pozisyonun her birinin, karışık veya bileşik mallardaki malzemelerin yalnızca bir kısmına ya da perakende bir setteki ürünlerin yalnızca bir kısmına atıfta bulunduğu durumlarda, biri daha eksiksiz bir tanım verse bile bu pozisyonların eşit derecede spesifik kabul edilmesi gerektiğini öngörür. Eşitlik durumu, analizi GRI 3(b)'ye taşır. (GRI 3(a).)","hi":"GRI 3(a) प्रावधान करता है कि जब दो या अधिक शीर्षक प्रत्येक मिश्रित या मिश्रित माल में सामग्री के केवल एक भाग, या खुदरा सेट में वस्तुओं के केवल एक भाग को संदर्भित करते हैं, तो उन शीर्षकों को समान रूप से विशिष्ट माना जाना है, भले ही उनमें से एक अधिक पूर्ण विवरण देता हो। तब यह बराबरी विश्लेषण को GRI 3(b) पर ले जाती है। (GRI 3(a).)","ar":"تنص GRI 3(a) على أنه عندما يشير بندان أو أكثر كلٌّ منهما إلى جزء فقط من المواد في بضائع مخلوطة أو مركّبة، أو إلى جزء فقط من الأصناف في مجموعة تجزئة، فإن هذه البنود تُعتبر متساوية في التحديد، حتى لو قدّم أحدها وصفًا أكثر اكتمالًا. عندئذٍ يَنقل التعادل التحليل إلى GRI 3(b). (GRI 3(a).)"}},{"cat":"classification","a":0,"q":{"en":"A retail-packaged gift set contains a stainless-steel manicure scissor and a small leather pouch, sold together as a set put up for retail sale. The scissor and the pouch fall in different headings, and GRI 3(a) does not resolve the classification. Which rule is applied next, and on what basis?","es":"Un surtido de regalo en empaque para venta al por menor contiene unas tijeras de manicura de acero inoxidable y un pequeño estuche de cuero, vendidos juntos como un surtido acondicionado para la venta al por menor. Las tijeras y el estuche caen en partidas distintas, y la GRI 3(a) no resuelve la clasificación. ¿Qué regla se aplica a continuación, y sobre qué base?","ru":"Подарочный набор в розничной упаковке содержит маникюрные ножницы из нержавеющей стали и небольшой кожаный чехол, продаваемые вместе как набор для розничной продажи. Ножницы и чехол относятся к разным позициям, и GRI 3(a) не разрешает классификацию. Какое правило применяется следующим и на каком основании?","tr":"Perakende ambalajlı bir hediye seti, paslanmaz çelik bir manikür makası ve küçük bir deri kese içerir; bunlar perakende satış için hazırlanmış bir set olarak birlikte satılır. Makas ve kese farklı pozisyonlara (heading) düşer ve GRI 3(a) sınıflandırmayı çözmez. Bir sonraki uygulanan kural hangisidir ve hangi temele dayanır?","hi":"एक खुदरा-पैक उपहार सेट में एक स्टेनलेस-स्टील मैनीक्योर कैंची और एक छोटा चमड़े का थैला होता है, जिसे खुदरा बिक्री के लिए प्रस्तुत सेट के रूप में एक साथ बेचा जाता है। कैंची और थैला अलग-अलग शीर्षकों में आते हैं, और GRI 3(a) वर्गीकरण का समाधान नहीं करता। इसके बाद कौन सा नियम लागू किया जाता है, और किस आधार पर?","ar":"تحتوي مجموعة هدية معبأة للتجزئة على مقص عناية بالأظافر من الفولاذ المقاوم للصدأ وحقيبة جلدية صغيرة، تُباعان معًا بوصفهما مجموعة مُعدَّة للبيع بالتجزئة. يقع المقص والحقيبة في بندين مختلفين، ولا تحسم GRI 3(a) التصنيف. أي قاعدة تُطبَّق بعد ذلك، وعلى أي أساس؟"},"o":[{"en":"GRI 3(b), classifying the set by the component that imparts its essential character","es":"GRI 3(b), clasificando el surtido por el componente que le confiere su carácter esencial","ru":"GRI 3(b), классифицируя набор по компоненту, придающему ему основной характер","tr":"GRI 3(b), seti esas niteliğini veren bileşene göre sınıflandırarak","hi":"GRI 3(b), सेट को उस घटक द्वारा वर्गीकृत करते हुए जो इसका आवश्यक चरित्र प्रदान करता है","ar":"GRI 3(b)، بتصنيف المجموعة وفق المكوّن الذي يمنحها طابعها الأساسي"},{"en":"GRI 3(c), classifying the set under the heading last in numerical order","es":"GRI 3(c), clasificando el surtido bajo la partida que se ubique en último lugar en orden numérico","ru":"GRI 3(c), классифицируя набор по позиции, последней в порядке возрастания нумерации","tr":"GRI 3(c), seti numara sırasında en sonda yer alan pozisyon altında sınıflandırarak","hi":"GRI 3(c), सेट को संख्यात्मक क्रम में अंतिम शीर्षक के तहत वर्गीकृत करते हुए","ar":"GRI 3(c)، بتصنيف المجموعة تحت البند الأخير في الترتيب العددي"},{"en":"GRI 5(a), classifying the pouch and scissor together as a fitted case","es":"GRI 5(a), clasificando el estuche y las tijeras juntos como un estuche ajustado","ru":"GRI 5(a), классифицируя чехол и ножницы вместе как подогнанный футляр","tr":"GRI 5(a), keseyi ve makası kendine özel bir kutu olarak birlikte sınıflandırarak","hi":"GRI 5(a), थैले और कैंची को एक फिट किए गए केस के रूप में एक साथ वर्गीकृत करते हुए","ar":"GRI 5(a)، بتصنيف الحقيبة والمقص معًا كعلبة مُجهَّزة"},{"en":"GRI 2(b), classifying the set by the material of greatest bulk","es":"GRI 2(b), clasificando el surtido por el material de mayor volumen","ru":"GRI 2(b), классифицируя набор по материалу наибольшего объёма","tr":"GRI 2(b), seti en büyük hacme sahip malzemeye göre sınıflandırarak","hi":"GRI 2(b), सेट को सबसे अधिक मात्रा की सामग्री द्वारा वर्गीकृत करते हुए","ar":"GRI 2(b)، بتصنيف المجموعة وفق المادة الأكبر حجمًا"}],"e":{"en":"For mixtures, composite goods, and goods put up in sets for retail sale that cannot be classified under GRI 3(a), GRI 3(b) classifies them by the material or component that gives them their essential character. Only if essential character cannot be determined does one reach GRI 3(c). (GRI 3(b).)","es":"Para las mezclas, las mercancías compuestas y las mercancías acondicionadas en surtidos para la venta al por menor que no pueden clasificarse bajo la GRI 3(a), la GRI 3(b) las clasifica por el material o componente que les confiere su carácter esencial. Solo si el carácter esencial no puede determinarse se llega a la GRI 3(c). (GRI 3(b).)","ru":"Для смесей, составных товаров и товаров, представленных в наборах для розничной продажи, которые не могут быть классифицированы согласно GRI 3(a), GRI 3(b) классифицирует их по материалу или компоненту, придающему им основной характер. Только если основной характер не может быть определён, переходят к GRI 3(c). (GRI 3(b).)","tr":"GRI 3(a) kapsamında sınıflandırılamayan karışımlar, bileşik mallar ve perakende satış için setler halinde hazırlanmış mallar için GRI 3(b), bunları esas niteliğini veren malzeme veya bileşene göre sınıflandırır. Esas nitelik belirlenemediği takdirde GRI 3(c)'ye başvurulur. (GRI 3(b).)","hi":"मिश्रण, मिश्रित माल, और खुदरा बिक्री के लिए सेट में प्रस्तुत माल के लिए जिन्हें GRI 3(a) के तहत वर्गीकृत नहीं किया जा सकता, GRI 3(b) उन्हें उस सामग्री या घटक द्वारा वर्गीकृत करता है जो उन्हें उनका आवश्यक चरित्र प्रदान करता है। केवल यदि आवश्यक चरित्र निर्धारित नहीं किया जा सकता, तभी GRI 3(c) तक पहुंचा जाता है। (GRI 3(b).)","ar":"بالنسبة للمخاليط والبضائع المركّبة والبضائع المعدَّة في مجموعات للبيع بالتجزئة التي لا يمكن تصنيفها بموجب GRI 3(a)، تصنّفها GRI 3(b) وفق المادة أو المكوّن الذي يمنحها طابعها الأساسي. ولا يُلجأ إلى GRI 3(c) إلا إذا تعذّر تحديد الطابع الأساسي. (GRI 3(b).)"}},{"cat":"classification","a":3,"q":{"en":"Goods are classifiable under two headings that equally merit consideration, and the essential character cannot be determined under GRI 3(b). Heading 3924 and heading 7013 both apply equally. How does GRI 3(c) resolve this?","es":"Las mercancías son clasificables en dos partidas que igualmente merecen consideración, y el carácter esencial no puede determinarse bajo la GRI 3(b). La partida 3924 y la partida 7013 aplican por igual. ¿Cómo lo resuelve la GRI 3(c)?","ru":"Товары могут быть классифицированы по двум позициям, которые в равной степени заслуживают рассмотрения, и основной характер не может быть определён согласно GRI 3(b). Позиция 3924 и позиция 7013 применимы в равной степени. Как GRI 3(c) разрешает этот вопрос?","tr":"Mallar, eşit derecede dikkate alınmayı hak eden iki pozisyon (heading) altında sınıflandırılabilir ve esas nitelik GRI 3(b) kapsamında belirlenemez. 3924 pozisyonu ve 7013 pozisyonu eşit derecede uygulanır. GRI 3(c) bunu nasıl çözer?","hi":"माल दो शीर्षकों के तहत वर्गीकृत होने योग्य है जो समान रूप से विचार के योग्य हैं, और GRI 3(b) के तहत आवश्यक चरित्र निर्धारित नहीं किया जा सकता। शीर्षक 3924 और शीर्षक 7013 दोनों समान रूप से लागू होते हैं। GRI 3(c) इसका समाधान कैसे करता है?","ar":"يمكن تصنيف البضائع تحت بندين يستحقان الاعتبار بالتساوي، ولا يمكن تحديد الطابع الأساسي بموجب GRI 3(b). ينطبق البند 3924 والبند 7013 بالتساوي. كيف تحسم GRI 3(c) هذا الأمر؟"},"o":[{"en":"Classify under heading 3924, because it occurs first in numerical order","es":"Clasificar bajo la partida 3924, porque se ubica primero en orden numérico","ru":"Классифицировать по позиции 3924, поскольку она стоит первой в порядке возрастания нумерации","tr":"3924 pozisyonu altında sınıflandırılır, çünkü numara sırasında en başta yer alır","hi":"शीर्षक 3924 के तहत वर्गीकृत करें, क्योंकि यह संख्यात्मक क्रम में पहले आता है","ar":"التصنيف تحت البند 3924، لأنه يأتي أولًا في الترتيب العددي"},{"en":"Classify under whichever heading carries the higher rate of duty","es":"Clasificar bajo la partida que tenga la tasa de derecho más alta","ru":"Классифицировать по той позиции, которая имеет более высокую ставку пошлины","tr":"Daha yüksek vergi oranı taşıyan pozisyon altında sınıflandırılır","hi":"जो भी शीर्षक उच्च शुल्क दर वहन करता है उसके तहत वर्गीकृत करें","ar":"التصنيف تحت البند الذي يحمل معدل الرسوم الأعلى"},{"en":"Classify under heading 3924, because plastics generally precede glass in the schedule","es":"Clasificar bajo la partida 3924, porque los plásticos generalmente preceden al vidrio en la nomenclatura","ru":"Классифицировать по позиции 3924, поскольку пластмассы обычно предшествуют стеклу в номенклатуре","tr":"3924 pozisyonu altında sınıflandırılır, çünkü plastikler cetvelde genel olarak camdan önce gelir","hi":"शीर्षक 3924 के तहत वर्गीकृत करें, क्योंकि अनुसूची में प्लास्टिक आम तौर पर कांच से पहले आता है","ar":"التصنيف تحت البند 3924، لأن المواد البلاستيكية تسبق عمومًا الزجاج في الجدول"},{"en":"Classify under heading 7013, because it occurs last in numerical order","es":"Clasificar bajo la partida 7013, porque se ubica en último lugar en orden numérico","ru":"Классифицировать по позиции 7013, поскольку она стоит последней в порядке возрастания нумерации","tr":"7013 pozisyonu altında sınıflandırılır, çünkü numara sırasında en sonda yer alır","hi":"शीर्षक 7013 के तहत वर्गीकृत करें, क्योंकि यह संख्यात्मक क्रम में अंतिम आता है","ar":"التصنيف تحت البند 7013، لأنه يأتي أخيرًا في الترتيب العددي"}],"e":{"en":"GRI 3(c) provides that when goods cannot be classified by reference to 3(a) or 3(b), they are classified under the heading which occurs last in numerical order among those which equally merit consideration. Between 3924 and 7013, the last is 7013. (GRI 3(c).)","es":"La GRI 3(c) dispone que cuando las mercancías no pueden clasificarse por referencia a la 3(a) o la 3(b), se clasifican bajo la partida que se ubique en último lugar en orden numérico entre las que igualmente merezcan consideración. Entre 3924 y 7013, la última es 7013. (GRI 3(c).)","ru":"GRI 3(c) предусматривает, что когда товары не могут быть классифицированы со ссылкой на 3(a) или 3(b), они классифицируются по позиции, последней в порядке возрастания нумерации среди тех, что в равной степени заслуживают рассмотрения. Между 3924 и 7013 последней является 7013. (GRI 3(c).)","tr":"GRI 3(c), malların 3(a) veya 3(b)'ye başvurularak sınıflandırılamadığı durumlarda, eşit derecede dikkate alınmayı hak edenler arasında numara sırasında en sonda yer alan pozisyon altında sınıflandırılacağını öngörür. 3924 ile 7013 arasında en sonda yer alan 7013'tür. (GRI 3(c).)","hi":"GRI 3(c) प्रावधान करता है कि जब माल को 3(a) या 3(b) के संदर्भ से वर्गीकृत नहीं किया जा सकता, तो उन्हें उस शीर्षक के तहत वर्गीकृत किया जाता है जो समान रूप से विचार के योग्य शीर्षकों में संख्यात्मक क्रम में अंतिम आता है। 3924 और 7013 के बीच, अंतिम 7013 है। (GRI 3(c).)","ar":"تنص GRI 3(c) على أنه عندما لا يمكن تصنيف البضائع بالرجوع إلى 3(a) أو 3(b)، تُصنَّف تحت البند الذي يأتي أخيرًا في الترتيب العددي بين البنود التي تستحق الاعتبار بالتساوي. وبين 3924 و7013، الأخير هو 7013. (GRI 3(c).)"}},{"cat":"classification","a":2,"q":{"en":"A specially shaped and fitted hard case, of a kind normally sold with the article it contains and suitable for long-term use, is imported containing the camera it is designed to hold. Absent a section or chapter note to the contrary, how is the fitted case classified?","es":"Un estuche rígido especialmente moldeado y ajustado, del tipo que normalmente se vende con el artículo que contiene y apto para uso prolongado, se importa conteniendo la cámara para la que está diseñado. En ausencia de una nota de sección o capítulo en contrario, ¿cómo se clasifica el estuche ajustado?","ru":"Специально сформированный и подогнанный жёсткий футляр, такого рода, который обычно продаётся вместе с изделием, которое он содержит, и пригодный для длительного использования, импортируется содержащим фотоаппарат, для которого он предназначен. При отсутствии примечания к разделу или главе об обратном, как классифицируется подогнанный футляр?","tr":"İçindeki ürünle birlikte normalde satılan türden, uzun süreli kullanıma uygun, özel şekilli ve kendine özel sert bir kutu, taşımak üzere tasarlandığı kamerayı içerir halde ithal edilir. Aksine bir bölüm veya fasıl notu olmaması durumunda, bu kendine özel kutu nasıl sınıflandırılır?","hi":"एक विशेष रूप से आकार दिया गया और फिट किया गया सख्त केस, जो आम तौर पर उस वस्तु के साथ बेचा जाता है जिसे वह रखता है और दीर्घकालिक उपयोग के लिए उपयुक्त है, उस कैमरे को रखते हुए आयात किया जाता है जिसे रखने के लिए इसे डिज़ाइन किया गया है। इसके विपरीत किसी खंड या अध्याय टिप्पणी के अभाव में, फिट किए गए केस को कैसे वर्गीकृत किया जाता है?","ar":"تُستورَد علبة صلبة مُشكَّلة ومُجهَّزة خصيصًا، من نوع يُباع عادةً مع الصنف الذي تحتويه وصالحة للاستخدام طويل الأمد، وهي تحتوي على الكاميرا المصممة لاحتوائها. في غياب ملاحظة قسم أو فصل تقضي بخلاف ذلك، كيف تُصنَّف العلبة المُجهَّزة؟"},"o":[{"en":"Separately, under the heading for cases of its constituent material","es":"Por separado, bajo la partida para estuches de su material constitutivo","ru":"Отдельно, по позиции для футляров из составляющего его материала","tr":"Ayrı olarak, yapımında kullanılan malzemeden kutular için olan pozisyon altında","hi":"अलग से, इसकी घटक सामग्री के केसों के शीर्षक के तहत","ar":"بشكل منفصل، تحت البند الخاص بالعلب من مادتها المكوّنة"},{"en":"Under GRI 3(b), by determining the essential character of case and camera together","es":"Bajo la GRI 3(b), determinando el carácter esencial del estuche y la cámara en conjunto","ru":"Согласно GRI 3(b), путём определения основного характера футляра и фотоаппарата вместе","tr":"GRI 3(b) kapsamında, kutu ve kameranın esas niteliğini birlikte belirleyerek","hi":"GRI 3(b) के तहत, केस और कैमरे का एक साथ आवश्यक चरित्र निर्धारित करते हुए","ar":"بموجب GRI 3(b)، بتحديد الطابع الأساسي للعلبة والكاميرا معًا"},{"en":"With the camera, under GRI 5(a) covering fitted cases presented with their articles","es":"Junto con la cámara, bajo la GRI 5(a) que comprende los estuches ajustados presentados con sus artículos","ru":"Вместе с фотоаппаратом, согласно GRI 5(a), охватывающему подогнанные футляры, представленные с их изделиями","tr":"Kamerayla birlikte, kendine özel kutuları içindeki ürünleriyle birlikte kapsayan GRI 5(a) kapsamında","hi":"कैमरे के साथ, GRI 5(a) के तहत जो फिट किए गए केसों को उनकी वस्तुओं के साथ प्रस्तुत किए जाने को कवर करता है","ar":"مع الكاميرا، بموجب GRI 5(a) التي تشمل العلب المُجهَّزة المقدَّمة مع أصنافها"},{"en":"Under GRI 4, as goods most akin to a camera accessory","es":"Bajo la GRI 4, como mercancías más afines a un accesorio de cámara","ru":"Согласно GRI 4, как товары, наиболее сходные с принадлежностью к фотоаппарату","tr":"GRI 4 kapsamında, bir kamera aksesuarına en çok benzeyen mallar olarak","hi":"GRI 4 के तहत, कैमरा एक्सेसरी से सबसे समान माल के रूप में","ar":"بموجب GRI 4، باعتبارها بضائع أقرب ما تكون إلى ملحق كاميرا"}],"e":{"en":"GRI 5(a) provides that camera cases, instrument cases, and similar containers, specially shaped or fitted for a specific article, suitable for long-term use, and presented with the article, are classified with that article when of a kind normally sold therewith. (GRI 5(a).)","es":"La GRI 5(a) dispone que los estuches para cámaras, estuches para instrumentos y contenedores similares, especialmente moldeados o ajustados para un artículo específico, aptos para uso prolongado y presentados con el artículo, se clasifican junto con ese artículo cuando sean del tipo que normalmente se vende con él. (GRI 5(a).)","ru":"GRI 5(a) предусматривает, что футляры для фотоаппаратов, футляры для инструментов и аналогичные контейнеры, специально сформированные или подогнанные для конкретного изделия, пригодные для длительного использования и представленные вместе с изделием, классифицируются вместе с этим изделием, если они такого рода, который обычно продаётся вместе с ним. (GRI 5(a).)","tr":"GRI 5(a), belirli bir ürün için özel şekilli veya kendine özel olarak yapılmış, uzun süreli kullanıma uygun ve ürünle birlikte sunulan kamera kutuları, alet kutuları ve benzeri kapların, normalde o ürünle birlikte satılan türden olduğunda o ürünle birlikte sınıflandırılacağını öngörür. (GRI 5(a).)","hi":"GRI 5(a) प्रावधान करता है कि कैमरा केस, उपकरण केस, और समान कंटेनर, जो किसी विशिष्ट वस्तु के लिए विशेष रूप से आकार दिए गए या फिट किए गए हैं, दीर्घकालिक उपयोग के लिए उपयुक्त हैं, और वस्तु के साथ प्रस्तुत किए जाते हैं, उस वस्तु के साथ वर्गीकृत किए जाते हैं जब वे ऐसे प्रकार के हों जो आम तौर पर उसके साथ बेचे जाते हैं। (GRI 5(a).)","ar":"تنص GRI 5(a) على أن علب الكاميرات وعلب الأدوات والحاويات المماثلة، المُشكَّلة أو المُجهَّزة خصيصًا لصنف محدد، والصالحة للاستخدام طويل الأمد، والمقدَّمة مع الصنف، تُصنَّف مع ذلك الصنف عندما تكون من نوع يُباع عادةً معه. (GRI 5(a).)"}},{"cat":"classification","a":3,"q":{"en":"Subject to GRI 5(a), how does GRI 5(b) treat packing materials and packing containers presented with the goods they contain?","es":"Sujeto a la GRI 5(a), ¿cómo trata la GRI 5(b) los materiales de empaque y los envases de empaque presentados con las mercancías que contienen?","ru":"С учётом GRI 5(a), как GRI 5(b) рассматривает упаковочные материалы и упаковочные контейнеры, представленные вместе с товарами, которые они содержат?","tr":"GRI 5(a)'ya tabi olarak, GRI 5(b), içerdikleri mallarla birlikte sunulan ambalaj malzemelerini ve ambalaj kaplarını nasıl ele alır?","hi":"GRI 5(a) के अधीन, GRI 5(b) उनके द्वारा रखे गए माल के साथ प्रस्तुत पैकिंग सामग्री और पैकिंग कंटेनरों के साथ कैसा व्यवहार करता है?","ar":"مع مراعاة GRI 5(a)، كيف تعامل GRI 5(b) مواد التعبئة وحاويات التعبئة المقدَّمة مع البضائع التي تحتويها؟"},"o":[{"en":"They are always classified separately under the heading for their constituent material","es":"Siempre se clasifican por separado bajo la partida correspondiente a su material constitutivo","ru":"Они всегда классифицируются отдельно по позиции для составляющего их материала","tr":"Her zaman, yapımında kullanılan malzemeden olan pozisyon altında ayrı olarak sınıflandırılırlar","hi":"उन्हें हमेशा उनकी घटक सामग्री के शीर्षक के तहत अलग से वर्गीकृत किया जाता है","ar":"تُصنَّف دائمًا بشكل منفصل تحت البند الخاص بمادتها المكوّنة"},{"en":"They are classified under GRI 3(c) as occurring last in numerical order","es":"Se clasifican bajo la GRI 3(c) por ubicarse en último lugar en orden numérico","ru":"Они классифицируются согласно GRI 3(c) как последние в порядке возрастания нумерации","tr":"Numara sırasında en sonda yer aldığı için GRI 3(c) kapsamında sınıflandırılırlar","hi":"उन्हें GRI 3(c) के तहत संख्यात्मक क्रम में अंतिम आने के रूप में वर्गीकृत किया जाता है","ar":"تُصنَّف بموجب GRI 3(c) باعتبارها تأتي أخيرًا في الترتيب العددي"},{"en":"They are classified with the goods only if they impart the essential character of the shipment","es":"Se clasifican junto con las mercancías solo si confieren el carácter esencial del embarque","ru":"Они классифицируются вместе с товарами только в том случае, если придают основной характер партии","tr":"Yalnızca sevkiyatın esas niteliğini vermeleri halinde mallarla birlikte sınıflandırılırlar","hi":"उन्हें माल के साथ केवल तभी वर्गीकृत किया जाता है जब वे शिपमेंट का आवश्यक चरित्र प्रदान करते हैं","ar":"تُصنَّف مع البضائع فقط إذا منحت الشحنة طابعها الأساسي"},{"en":"They are classified with the goods if of a kind normally used for packing them, unless clearly suitable for repetitive use","es":"Se clasifican junto con las mercancías si son del tipo normalmente usado para empacarlas, salvo que sean claramente aptos para uso repetido","ru":"Они классифицируются вместе с товарами, если они такого рода, который обычно используется для упаковки таких товаров, кроме случаев, когда они явно пригодны для повторного использования","tr":"Bu tür malları ambalajlamak için normalde kullanılan türden iseler, açıkça tekrarlı kullanıma uygun olmadıkça mallarla birlikte sınıflandırılırlar","hi":"उन्हें माल के साथ वर्गीकृत किया जाता है यदि वे उन्हें पैक करने के लिए आम तौर पर उपयोग किए जाने वाले प्रकार के हों, जब तक कि वे स्पष्ट रूप से बार-बार उपयोग के लिए उपयुक्त न हों","ar":"تُصنَّف مع البضائع إذا كانت من نوع يُستخدَم عادةً لتعبئتها، ما لم تكن صالحة بوضوح للاستخدام المتكرر"}],"e":{"en":"GRI 5(b) provides that packing materials and containers presented with the goods are classified with the goods if they are of a kind normally used for packing such goods; this does not apply to packing clearly suitable for repetitive use. (GRI 5(b).)","es":"La GRI 5(b) dispone que los materiales de empaque y los envases presentados con las mercancías se clasifican junto con las mercancías si son del tipo normalmente usado para empacar tales mercancías; esto no aplica a los empaques claramente aptos para uso repetido. (GRI 5(b).)","ru":"GRI 5(b) предусматривает, что упаковочные материалы и контейнеры, представленные вместе с товарами, классифицируются вместе с товарами, если они такого рода, который обычно используется для упаковки таких товаров; это не применяется к упаковке, явно пригодной для повторного использования. (GRI 5(b).)","tr":"GRI 5(b), mallarla birlikte sunulan ambalaj malzemeleri ve kaplarının, bu tür malları ambalajlamak için normalde kullanılan türden olmaları halinde mallarla birlikte sınıflandırılacağını öngörür; bu durum, açıkça tekrarlı kullanıma uygun ambalajlar için geçerli değildir. (GRI 5(b).)","hi":"GRI 5(b) प्रावधान करता है कि माल के साथ प्रस्तुत पैकिंग सामग्री और कंटेनरों को माल के साथ वर्गीकृत किया जाता है यदि वे ऐसे माल को पैक करने के लिए आम तौर पर उपयोग किए जाने वाले प्रकार के हों; यह उस पैकिंग पर लागू नहीं होता जो स्पष्ट रूप से बार-बार उपयोग के लिए उपयुक्त हो। (GRI 5(b).)","ar":"تنص GRI 5(b) على أن مواد التعبئة والحاويات المقدَّمة مع البضائع تُصنَّف مع البضائع إذا كانت من نوع يُستخدَم عادةً لتعبئة هذه البضائع؛ ولا ينطبق ذلك على التعبئة الصالحة بوضوح للاستخدام المتكرر. (GRI 5(b).)"}},{"cat":"classification","a":0,"q":{"en":"Under GRI 6, comparison of subheadings within a heading to determine the correct six-digit (or further) classification may be made only between which subheadings?","es":"Bajo la GRI 6, la comparación de subpartidas dentro de una partida para determinar la clasificación correcta de seis dígitos (o más detallada) solo puede hacerse entre ¿cuáles subpartidas?","ru":"Согласно GRI 6, сравнение субпозиций в пределах одной позиции для определения правильной шестизначной (или более детальной) классификации может производиться только между какими субпозициями?","tr":"GRI 6 kapsamında, doğru altı haneli (veya daha ileri) sınıflandırmayı belirlemek için bir pozisyon (heading) içindeki alt pozisyonların (subheading) karşılaştırılması yalnızca hangi alt pozisyonlar arasında yapılabilir?","hi":"GRI 6 के तहत, सही छह-अंकीय (या उससे आगे) वर्गीकरण निर्धारित करने के लिए किसी शीर्षक के भीतर उपशीर्षकों की तुलना केवल किन उपशीर्षकों के बीच की जा सकती है?","ar":"بموجب GRI 6، لا تجوز مقارنة البنود الفرعية داخل بند ما لتحديد التصنيف الصحيح المكوّن من ستة أرقام (أو أكثر) إلا بين أي بنود فرعية؟"},"o":[{"en":"Subheadings at the same level (e.g., one-dash with one-dash, two-dash with two-dash)","es":"Subpartidas del mismo nivel (por ejemplo, una raya con una raya, dos rayas con dos rayas)","ru":"Субпозициями одного уровня (например, одно-дефисными с одно-дефисными, двух-дефисными с двух-дефисными)","tr":"Aynı düzeydeki alt pozisyonlar arasında (örneğin, tek tireli ile tek tireli, çift tireli ile çift tireli)","hi":"समान स्तर के उपशीर्षक (उदाहरण के लिए, एक-डैश के साथ एक-डैश, दो-डैश के साथ दो-डैश)","ar":"البنود الفرعية عند المستوى نفسه (مثل ذات الشرطة الواحدة مع ذات الشرطة الواحدة، وذات الشرطتين مع ذات الشرطتين)"},{"en":"Subheadings of any heading within the same chapter","es":"Subpartidas de cualquier partida dentro del mismo capítulo","ru":"Субпозициями любой позиции в пределах той же главы","tr":"Aynı fasıl içindeki herhangi bir pozisyonun alt pozisyonları arasında","hi":"समान अध्याय के भीतर किसी भी शीर्षक के उपशीर्षक","ar":"البنود الفرعية لأي بند ضمن الفصل نفسه"},{"en":"Subheadings carrying the same general rate of duty","es":"Subpartidas que tengan la misma tasa general de derecho","ru":"Субпозициями, имеющими одинаковую общую ставку пошлины","tr":"Aynı genel vergi oranını taşıyan alt pozisyonlar arasında","hi":"समान सामान्य शुल्क दर वहन करने वाले उपशीर्षक","ar":"البنود الفرعية التي تحمل معدل الرسوم العام نفسه"},{"en":"Subheadings that share the same statistical suffix","es":"Subpartidas que compartan el mismo sufijo estadístico","ru":"Субпозициями, имеющими одинаковый статистический суффикс","tr":"Aynı istatistiksel son eki paylaşan alt pozisyonlar arasında","hi":"समान सांख्यिकीय प्रत्यय साझा करने वाले उपशीर्षक","ar":"البنود الفرعية التي تشترك في اللاحقة الإحصائية نفسها"}],"e":{"en":"GRI 6 directs that classification at the subheading level is determined by the terms of the subheadings and any related subheading notes, and that only subheadings at the same level are comparable. The GRIs apply mutatis mutandis at the subheading level. (GRI 6.)","es":"La GRI 6 dispone que la clasificación a nivel de subpartida se determina por los términos de las subpartidas y cualquier nota de subpartida relacionada, y que solo las subpartidas del mismo nivel son comparables. Las GRI aplican mutatis mutandis a nivel de subpartida. (GRI 6.)","ru":"GRI 6 предписывает, что классификация на уровне субпозиций определяется текстами субпозиций и любыми относящимися к ним примечаниями к субпозициям, и что сравнимы только субпозиции одного уровня. Правила GRI применяются mutatis mutandis на уровне субпозиций. (GRI 6.)","tr":"GRI 6, alt pozisyon düzeyindeki sınıflandırmanın, alt pozisyonların ifadelerine ve ilgili herhangi bir alt pozisyon notuna göre belirlendiğini ve yalnızca aynı düzeydeki alt pozisyonların karşılaştırılabilir olduğunu öngörür. GRI'lar, alt pozisyon düzeyinde gerekli değişikliklerle (mutatis mutandis) uygulanır. (GRI 6.)","hi":"GRI 6 निर्देशित करता है कि उपशीर्षक स्तर पर वर्गीकरण उपशीर्षकों की शर्तों और किसी भी संबंधित उपशीर्षक टिप्पणियों द्वारा निर्धारित होता है, और केवल समान स्तर के उपशीर्षक तुलनीय हैं। GRI उपशीर्षक स्तर पर mutatis mutandis लागू होते हैं। (GRI 6.)","ar":"تقضي GRI 6 بأن التصنيف عند مستوى البند الفرعي يُحدَّد بنصوص البنود الفرعية وأي ملاحظات بنود فرعية ذات صلة، وأن البنود الفرعية عند المستوى نفسه فقط هي القابلة للمقارنة. وتُطبَّق قواعد GRI مع ما يلزم من تعديل (mutatis mutandis) عند مستوى البند الفرعي. (GRI 6.)"}},{"cat":"classification","a":1,"q":{"en":"Which statement best describes the legal force of section, chapter, and subchapter TITLES in the HTSUS, compared with section and chapter NOTES?","es":"¿Qué afirmación describe mejor la fuerza legal de los TÍTULOS de sección, capítulo y subcapítulo en el HTSUS, en comparación con las NOTAS de sección y capítulo?","ru":"Какое утверждение лучше всего описывает юридическую силу НАЗВАНИЙ разделов, глав и подглав в HTSUS по сравнению с ПРИМЕЧАНИЯМИ к разделам и главам?","tr":"HTSUS'taki bölüm, fasıl ve alt fasıl BAŞLIKLARININ hukuki bağlayıcılığını, bölüm ve fasıl NOTLARI ile karşılaştırıldığında, hangi ifade en iyi şekilde tanımlar?","hi":"कौन सा कथन HTSUS में खंड, अध्याय और उप-अध्याय शीर्षकों के कानूनी बल का खंड और अध्याय टिप्पणियों की तुलना में सबसे अच्छा वर्णन करता है?","ar":"أي عبارة تصف بأفضل شكل القوة القانونية لعناوين الأقسام والفصول والفصول الفرعية في HTSUS، مقارنةً بملاحظات الأقسام والفصول؟"},"o":[{"en":"Both titles and notes are provided for ease of reference only and have no legal force","es":"Tanto los títulos como las notas se proporcionan solo para facilitar la consulta y no tienen fuerza legal","ru":"И названия, и примечания приводятся только для удобства ссылок и не имеют юридической силы","tr":"Hem başlıklar hem de notlar yalnızca kolay referans amacıyla verilmiştir ve hukuki bağlayıcılığı yoktur","hi":"शीर्षक और टिप्पणियां दोनों केवल संदर्भ की सुविधा के लिए प्रदान किए जाते हैं और उनका कोई कानूनी बल नहीं है","ar":"كل من العناوين والملاحظات مقدَّمة لسهولة الإحالة فقط وليست لها قوة قانونية"},{"en":"Titles are provided for ease of reference only and have no legal force, whereas section and chapter notes are legally binding and control classification","es":"Los títulos se proporcionan solo para facilitar la consulta y no tienen fuerza legal, mientras que las notas de sección y capítulo son legalmente vinculantes y rigen la clasificación","ru":"Названия приводятся только для удобства ссылок и не имеют юридической силы, тогда как примечания к разделам и главам юридически обязательны и определяют классификацию","tr":"Başlıklar yalnızca kolay referans amacıyla verilmiştir ve hukuki bağlayıcılığı yoktur, oysa bölüm ve fasıl notları hukuken bağlayıcıdır ve sınıflandırmayı belirler","hi":"शीर्षक केवल संदर्भ की सुविधा के लिए प्रदान किए जाते हैं और उनका कोई कानूनी बल नहीं है, जबकि खंड और अध्याय टिप्पणियां कानूनी रूप से बाध्यकारी हैं और वर्गीकरण को नियंत्रित करती हैं","ar":"العناوين مقدَّمة لسهولة الإحالة فقط وليست لها قوة قانونية، بينما ملاحظات الأقسام والفصول ملزِمة قانونًا وتتحكم في التصنيف"},{"en":"Titles control classification, while notes are merely explanatory and advisory","es":"Los títulos rigen la clasificación, mientras que las notas son meramente explicativas y orientativas","ru":"Названия определяют классификацию, а примечания носят лишь пояснительный и рекомендательный характер","tr":"Başlıklar sınıflandırmayı belirler, notlar ise yalnızca açıklayıcı ve tavsiye niteliğindedir","hi":"शीर्षक वर्गीकरण को नियंत्रित करते हैं, जबकि टिप्पणियां केवल व्याख्यात्मक और सलाहकारी हैं","ar":"العناوين تتحكم في التصنيف، بينما الملاحظات مجرد إيضاحية واستشارية"},{"en":"Both titles and notes are legally binding to the same degree under GRI 1","es":"Tanto los títulos como las notas son legalmente vinculantes en igual grado bajo la GRI 1","ru":"И названия, и примечания юридически обязательны в одинаковой степени согласно GRI 1","tr":"Hem başlıklar hem de notlar, GRI 1 kapsamında aynı ölçüde hukuken bağlayıcıdır","hi":"शीर्षक और टिप्पणियां दोनों GRI 1 के तहत समान रूप से कानूनी रूप से बाध्यकारी हैं","ar":"كل من العناوين والملاحظات ملزِمة قانونًا بالدرجة نفسها بموجب GRI 1"}],"e":{"en":"Under GRI 1, the titles of sections, chapters and subchapters are provided for ease of reference only and have no legal force; classification is determined by the terms of the headings and any relative section or chapter notes, which are legally binding. (GRI 1.)","es":"Bajo la GRI 1, los títulos de secciones, capítulos y subcapítulos se proporcionan solo para facilitar la consulta y no tienen fuerza legal; la clasificación se determina por los términos de las partidas y cualquier nota relativa de sección o capítulo, que son legalmente vinculantes. (GRI 1.)","ru":"Согласно GRI 1, названия разделов, глав и подглав приводятся только для удобства ссылок и не имеют юридической силы; классификация определяется текстами позиций и любыми относящимися к ним примечаниями к разделам или главам, которые юридически обязательны. (GRI 1.)","tr":"GRI 1 kapsamında, bölümlerin, fasılların ve alt fasılların başlıkları yalnızca kolay referans amacıyla verilmiştir ve hukuki bağlayıcılığı yoktur; sınıflandırma, hukuken bağlayıcı olan pozisyonların ifadelerine ve ilgili herhangi bir bölüm veya fasıl notuna göre belirlenir. (GRI 1.)","hi":"GRI 1 के तहत, खंडों, अध्यायों और उप-अध्यायों के शीर्षक केवल संदर्भ की सुविधा के लिए प्रदान किए जाते हैं और उनका कोई कानूनी बल नहीं है; वर्गीकरण शीर्षकों की शर्तों और किसी भी संबंधित खंड या अध्याय टिप्पणियों द्वारा निर्धारित होता है, जो कानूनी रूप से बाध्यकारी हैं। (GRI 1.)","ar":"بموجب GRI 1، عناوين الأقسام والفصول والفصول الفرعية مقدَّمة لسهولة الإحالة فقط وليست لها قوة قانونية؛ ويُحدَّد التصنيف بنصوص البنود وأي ملاحظات أقسام أو فصول ذات صلة، وهي ملزِمة قانونًا. (GRI 1.)"}},{"cat":"classification","a":2,"q":{"en":"In the ten-digit HTSUS number 6109.10.0040, which component identifies the internationally harmonized six-digit subheading, and which is the U.S. statistical suffix?","es":"En el número HTSUS de diez dígitos 6109.10.0040, ¿qué componente identifica la subpartida armonizada internacionalmente de seis dígitos, y cuál es el sufijo estadístico de los EE. UU.?","ru":"В десятизначном номере HTSUS 6109.10.0040 какой компонент обозначает международно гармонизированную шестизначную субпозицию, а какой является статистическим суффиксом США?","tr":"6109.10.0040 on haneli HTSUS numarasında, uluslararası uyumlaştırılmış altı haneli alt pozisyonu (subheading) hangi bileşen belirtir ve ABD istatistiksel son eki (statistical suffix) hangisidir?","hi":"दस-अंकीय HTSUS संख्या 6109.10.0040 में, कौन सा घटक अंतरराष्ट्रीय रूप से सामंजस्यपूर्ण छह-अंकीय उपशीर्षक की पहचान करता है, और कौन सा अमेरिकी सांख्यिकीय प्रत्यय है?","ar":"في الرقم العشاري المكوّن من عشرة أرقام في HTSUS وهو 6109.10.0040، أي مكوّن يحدّد البند الفرعي المنسَّق دوليًا المكوّن من ستة أرقام، وأي مكوّن هو اللاحقة الإحصائية الأمريكية؟"},"o":[{"en":"6109 is the subheading and 10.0040 is the statistical suffix","es":"6109 es la subpartida y 10.0040 es el sufijo estadístico","ru":"6109 — это субпозиция, а 10.0040 — статистический суффикс","tr":"6109 alt pozisyondur ve 10.0040 istatistiksel son ektir","hi":"6109 उपशीर्षक है और 10.0040 सांख्यिकीय प्रत्यय है","ar":"6109 هو البند الفرعي و10.0040 هو اللاحقة الإحصائية"},{"en":"6109.10.00 is the international subheading and 40 alone is the statistical suffix established by the WCO","es":"6109.10.00 es la subpartida internacional y solo 40 es el sufijo estadístico establecido por la WCO","ru":"6109.10.00 — это международная субпозиция, а только 40 — статистический суффикс, установленный WCO","tr":"6109.10.00 uluslararası alt pozisyondur ve tek başına 40, WCO tarafından belirlenen istatistiksel son ektir","hi":"6109.10.00 अंतरराष्ट्रीय उपशीर्षक है और अकेला 40 WCO द्वारा स्थापित सांख्यिकीय प्रत्यय है","ar":"6109.10.00 هو البند الفرعي الدولي و40 وحده هو اللاحقة الإحصائية المقرَّرة من قبل WCO"},{"en":"6109.10 is the international six-digit subheading and 0040 is the U.S. statistical suffix","es":"6109.10 es la subpartida internacional de seis dígitos y 0040 es el sufijo estadístico de los EE. UU.","ru":"6109.10 — это международная шестизначная субпозиция, а 0040 — статистический суффикс США","tr":"6109.10 uluslararası altı haneli alt pozisyondur ve 0040 ABD istatistiksel son ekidir","hi":"6109.10 अंतरराष्ट्रीय छह-अंकीय उपशीर्षक है और 0040 अमेरिकी सांख्यिकीय प्रत्यय है","ar":"6109.10 هو البند الفرعي الدولي المكوّن من ستة أرقام و0040 هو اللاحقة الإحصائية الأمريكية"},{"en":"610 is the heading and 9.10.0040 is the statistical suffix","es":"610 es la partida y 9.10.0040 es el sufijo estadístico","ru":"610 — это позиция, а 9.10.0040 — статистический суффикс","tr":"610 pozisyondur ve 9.10.0040 istatistiksel son ektir","hi":"610 शीर्षक है और 9.10.0040 सांख्यिकीय प्रत्यय है","ar":"610 هو البند و9.10.0040 هو اللاحقة الإحصائية"}],"e":{"en":"In HTSUS structure, the first four digits are the heading (6109), the first six digits form the internationally harmonized subheading (6109.10), the eighth digit completes the U.S. legal rate line, and the ninth and tenth digits (here 40, shown as 0040) are the U.S. statistical reporting suffix. (HTSUS structure; statistical suffixes.)","es":"En la estructura del HTSUS, los primeros cuatro dígitos son la partida (6109), los primeros seis dígitos forman la subpartida armonizada internacionalmente (6109.10), el octavo dígito completa la línea de tasa legal de los EE. UU., y los dígitos noveno y décimo (aquí 40, mostrados como 0040) son el sufijo estadístico de reporte de los EE. UU. (Estructura del HTSUS; sufijos estadísticos.)","ru":"В структуре HTSUS первые четыре цифры — это позиция (6109), первые шесть цифр образуют международно гармонизированную субпозицию (6109.10), восьмая цифра завершает законодательную строку ставки США, а девятая и десятая цифры (здесь 40, показанные как 0040) являются статистическим отчётным суффиксом США. (Структура HTSUS; статистические суффиксы.)","tr":"HTSUS yapısında, ilk dört hane pozisyonu (6109), ilk altı hane uluslararası uyumlaştırılmış alt pozisyonu (6109.10), sekizinci hane ABD yasal oran satırını tamamlar ve dokuzuncu ile onuncu haneler (burada 40, 0040 olarak gösterilir) ABD istatistiksel raporlama son ekidir. (HTSUS yapısı; istatistiksel son ekler.)","hi":"HTSUS संरचना में, पहले चार अंक शीर्षक (6109) हैं, पहले छह अंक अंतरराष्ट्रीय रूप से सामंजस्यपूर्ण उपशीर्षक (6109.10) बनाते हैं, आठवां अंक अमेरिकी कानूनी दर रेखा को पूरा करता है, और नौवां तथा दसवां अंक (यहां 40, 0040 के रूप में दिखाया गया) अमेरिकी सांख्यिकीय रिपोर्टिंग प्रत्यय हैं। (HTSUS संरचना; सांख्यिकीय प्रत्यय।)","ar":"في بنية HTSUS، الأرقام الأربعة الأولى هي البند (6109)، والأرقام الستة الأولى تشكّل البند الفرعي المنسَّق دوليًا (6109.10)، والرقم الثامن يُكمل سطر المعدل القانوني الأمريكي، والرقمان التاسع والعاشر (هنا 40، الموضّحان كـ 0040) هما اللاحقة الإحصائية الأمريكية للإبلاغ. (بنية HTSUS؛ اللواحق الإحصائية.)"}},{"cat":"classification","a":1,"q":{"en":"A heading is described as a 'principal use' provision (a use provision other than actual use). Under the Additional U.S. Rules of Interpretation, how is classification under such a provision controlled?","es":"Una partida se describe como una disposición de 'uso principal' (principal use), es decir, una disposición de uso distinta del uso real (actual use). Bajo las Additional U.S. Rules of Interpretation, ¿cómo se rige la clasificación bajo tal disposición?","ru":"Позиция описывается как положение об «основном использовании» (положение об использовании, отличное от фактического использования). Согласно Дополнительным правилам интерпретации США, как контролируется классификация по такому положению?","tr":"Bir pozisyon (heading), bir 'principal use' (başlıca kullanım) hükmü (gerçek kullanım dışında bir kullanım hükmü) olarak tanımlanır. Additional U.S. Rules of Interpretation (Ek ABD Yorum Kuralları) kapsamında, böyle bir hüküm altındaki sınıflandırma nasıl belirlenir?","hi":"एक शीर्षक को 'प्रमुख उपयोग' प्रावधान (वास्तविक उपयोग के अलावा एक उपयोग प्रावधान) के रूप में वर्णित किया गया है। व्याख्या के अतिरिक्त अमेरिकी नियमों के तहत, ऐसे प्रावधान के तहत वर्गीकरण को कैसे नियंत्रित किया जाता है?","ar":"يُوصَف بند ما بأنه حكم \"الاستخدام الرئيسي\" (principal use) (حكم استخدام غير الاستخدام الفعلي). بموجب القواعد الأمريكية الإضافية للتفسير، كيف يُتحكَّم في التصنيف بموجب هذا الحكم؟"},"o":[{"en":"By the actual use to which the specific imported article is later put, proven within three years","es":"Por el uso real al que se destina posteriormente el artículo importado específico, probado dentro de tres años","ru":"По фактическому использованию, которому впоследствии подвергается конкретное импортированное изделие, доказанному в течение трёх лет","tr":"Üç yıl içinde kanıtlanmak üzere, belirli ithal ürünün sonradan tabi tutulduğu gerçek kullanıma göre","hi":"उस वास्तविक उपयोग द्वारा जिसमें विशिष्ट आयातित वस्तु को बाद में लगाया जाता है, जो तीन वर्षों के भीतर सिद्ध हो","ar":"بالاستخدام الفعلي الذي يُوضَع فيه الصنف المستورد المحدد لاحقًا، بشرط إثباته خلال ثلاث سنوات"},{"en":"By the use in the United States, at or immediately prior to importation, of goods of the class or kind to which the imported goods belong; the controlling use is the principal use","es":"Por el uso en los Estados Unidos, en el momento de la importación o inmediatamente antes de ella, de las mercancías de la clase o tipo a la que pertenecen las mercancías importadas; el uso que rige es el uso principal","ru":"По использованию в Соединённых Штатах, в момент импортирования или непосредственно перед ним, товаров того класса или вида, к которому относятся импортируемые товары; контролирующим является основное использование","tr":"İthal malların ait olduğu sınıf veya türdeki malların, Amerika Birleşik Devletleri'nde, ithalat sırasında veya hemen öncesindeki kullanımına göre; belirleyici kullanım, başlıca kullanımdır","hi":"संयुक्त राज्य अमेरिका में, आयात के समय या उससे ठीक पहले, उस वर्ग या प्रकार के माल के उपयोग द्वारा जिससे आयातित माल संबंधित है; नियंत्रक उपयोग प्रमुख उपयोग है","ar":"بالاستخدام في الولايات المتحدة، في وقت الاستيراد أو قبله مباشرةً، للبضائع من الصنف أو النوع الذي تنتمي إليه البضائع المستوردة؛ والاستخدام المتحكِّم هو الاستخدام الرئيسي"},{"en":"By the use the importer subjectively intends for the article at the time of entry","es":"Por el uso que el importador subjetivamente pretende para el artículo al momento de la entrada","ru":"По использованию, которое импортёр субъективно предполагает для изделия в момент ввоза","tr":"İthalatçının giriş anında ürün için öznel olarak amaçladığı kullanıma göre","hi":"प्रवेश के समय वस्तु के लिए आयातक जो उपयोग व्यक्तिपरक रूप से इरादा रखता है उसके द्वारा","ar":"بالاستخدام الذي يقصده المستورد ذاتيًا للصنف وقت الإدخال"},{"en":"By the most specific description available under GRI 3(a)","es":"Por la descripción más específica disponible bajo la GRI 3(a)","ru":"По наиболее конкретному описанию, доступному согласно GRI 3(a)","tr":"GRI 3(a) kapsamında mevcut en spesifik tanıma göre","hi":"GRI 3(a) के तहत उपलब्ध सबसे विशिष्ट विवरण द्वारा","ar":"بالوصف الأكثر تحديدًا المتاح بموجب GRI 3(a)"}],"e":{"en":"Additional U.S. Rule of Interpretation 1(a): a tariff classification controlled by use (other than actual use) is determined by the use in the United States, at or immediately prior to importation, of goods of that class or kind; the controlling use is the principal use. (Additional U.S. Rule of Interpretation 1(a).)","es":"Additional U.S. Rule of Interpretation 1(a): una clasificación arancelaria regida por el uso (distinto del uso real) se determina por el uso en los Estados Unidos, en el momento de la importación o inmediatamente antes de ella, de las mercancías de esa clase o tipo; el uso que rige es el uso principal. (Additional U.S. Rule of Interpretation 1(a).)","ru":"Дополнительное правило интерпретации США 1(a): тарифная классификация, контролируемая использованием (отличным от фактического использования), определяется по использованию в Соединённых Штатах, в момент импортирования или непосредственно перед ним, товаров того класса или вида; контролирующим является основное использование. (Дополнительное правило интерпретации США 1(a).)","tr":"Additional U.S. Rule of Interpretation 1(a): kullanım (gerçek kullanım dışında) ile belirlenen bir tarife sınıflandırması, o sınıf veya türdeki malların Amerika Birleşik Devletleri'nde, ithalat sırasında veya hemen öncesindeki kullanımına göre belirlenir; belirleyici kullanım, başlıca kullanımdır. (Additional U.S. Rule of Interpretation 1(a).)","hi":"व्याख्या का अतिरिक्त अमेरिकी नियम 1(a): उपयोग द्वारा नियंत्रित एक टैरिफ वर्गीकरण (वास्तविक उपयोग के अलावा) संयुक्त राज्य अमेरिका में, आयात के समय या उससे ठीक पहले, उस वर्ग या प्रकार के माल के उपयोग द्वारा निर्धारित होता है; नियंत्रक उपयोग प्रमुख उपयोग है। (व्याख्या का अतिरिक्त अमेरिकी नियम 1(a)।)","ar":"القاعدة الأمريكية الإضافية للتفسير 1(a): التصنيف الجمركي المتحكَّم فيه بالاستخدام (غير الاستخدام الفعلي) يُحدَّد بالاستخدام في الولايات المتحدة، في وقت الاستيراد أو قبله مباشرةً، للبضائع من ذلك الصنف أو النوع؛ والاستخدام المتحكِّم هو الاستخدام الرئيسي. (القاعدة الأمريكية الإضافية للتفسير 1(a).)"}},{"cat":"classification","a":3,"q":{"en":"An imported article is solely and principally used as a part of a machine, but there is also a specific HTSUS provision that eo nomine (by name) describes that very article. Under the Additional U.S. Rules of Interpretation, how should it be classified?","es":"Un artículo importado se usa única y principalmente como parte de una máquina, pero existe también una disposición específica del HTSUS que eo nomine (por su nombre) describe ese mismo artículo. Bajo las Additional U.S. Rules of Interpretation, ¿cómo debe clasificarse?","ru":"Импортированное изделие используется исключительно и преимущественно как часть машины, но при этом существует конкретное положение HTSUS, которое eo nomine (по наименованию) описывает именно это изделие. Согласно Дополнительным правилам интерпретации США, как его следует классифицировать?","tr":"İthal edilen bir ürün, yalnızca ve esas olarak bir makinenin parçası olarak kullanılır, ancak aynı zamanda o ürünü adıyla (eo nomine) tanımlayan spesifik bir HTSUS hükmü de vardır. Additional U.S. Rules of Interpretation (Ek ABD Yorum Kuralları) kapsamında nasıl sınıflandırılmalıdır?","hi":"एक आयातित वस्तु का उपयोग पूरी तरह से और मुख्य रूप से किसी मशीन के एक भाग के रूप में किया जाता है, लेकिन एक विशिष्ट HTSUS प्रावधान भी है जो eo nomine (नाम से) उसी वस्तु का वर्णन करता है। व्याख्या के अतिरिक्त अमेरिकी नियमों के तहत, इसे कैसे वर्गीकृत किया जाना चाहिए?","ar":"يُستخدَم صنف مستورد حصريًا وبشكل رئيسي كجزء من آلة، لكن يوجد أيضًا حكم محدد في HTSUS يصف هذا الصنف بعينه بالاسم (eo nomine). بموجب القواعد الأمريكية الإضافية للتفسير، كيف ينبغي تصنيفه؟"},"o":[{"en":"Under the parts provision for the machine, because principal use as a part always controls","es":"Bajo la disposición de partes para la máquina, porque el uso principal como parte siempre rige","ru":"По положению о частях для машины, поскольку основное использование в качестве части всегда является контролирующим","tr":"Makineye ilişkin parçalar hükmü altında, çünkü parça olarak başlıca kullanım her zaman belirleyicidir","hi":"मशीन के लिए पुर्जे प्रावधान के तहत, क्योंकि एक भाग के रूप में प्रमुख उपयोग हमेशा नियंत्रित करता है","ar":"تحت حكم الأجزاء الخاص بالآلة، لأن الاستخدام الرئيسي كجزء يتحكم دائمًا"},{"en":"Under whichever provision occurs last in numerical order, per GRI 3(c)","es":"Bajo la disposición que se ubique en último lugar en orden numérico, conforme a la GRI 3(c)","ru":"По тому положению, которое стоит последним в порядке возрастания нумерации, согласно GRI 3(c)","tr":"GRI 3(c) uyarınca, numara sırasında en sonda yer alan hüküm altında","hi":"जो भी प्रावधान संख्यात्मक क्रम में अंतिम आता है उसके तहत, GRI 3(c) के अनुसार","ar":"تحت البند الذي يأتي أخيرًا في الترتيب العددي، وفق GRI 3(c)"},{"en":"Under GRI 4, as goods most akin to a part","es":"Bajo la GRI 4, como mercancías más afines a una parte","ru":"Согласно GRI 4, как товары, наиболее сходные с частью","tr":"GRI 4 kapsamında, bir parçaya en çok benzeyen mallar olarak","hi":"GRI 4 के तहत, एक भाग से सबसे समान माल के रूप में","ar":"تحت GRI 4، باعتباره بضائع أقرب ما تكون إلى جزء"},{"en":"Under the specific eo nomine provision, because a 'parts' provision does not prevail over a specific provision for the article","es":"Bajo la disposición específica eo nomine, porque una disposición de 'partes' no prevalece sobre una disposición específica para el artículo","ru":"По конкретному положению eo nomine, поскольку положение о «частях» не имеет преимущества перед конкретным положением для данного изделия","tr":"Spesifik eo nomine (adıyla) hüküm altında, çünkü bir 'parçalar' hükmü, ürüne ilişkin spesifik bir hükme karşı üstün gelmez","hi":"विशिष्ट eo nomine प्रावधान के तहत, क्योंकि एक 'पुर्जे' प्रावधान वस्तु के लिए एक विशिष्ट प्रावधान पर प्रबल नहीं होता","ar":"تحت الحكم المحدد بالاسم (eo nomine)، لأن حكم \"الأجزاء\" لا يسود على حكم محدد للصنف"}],"e":{"en":"Additional U.S. Rule of Interpretation 1(c): a provision for 'parts' or 'parts and accessories' does not prevail over a specific provision for the part or accessory. A specific (eo nomine) provision controls over a general parts provision. (Additional U.S. Rule of Interpretation 1(c).)","es":"Additional U.S. Rule of Interpretation 1(c): una disposición para 'partes' o 'partes y accesorios' no prevalece sobre una disposición específica para la parte o accesorio. Una disposición específica (eo nomine) rige sobre una disposición general de partes. (Additional U.S. Rule of Interpretation 1(c).)","ru":"Дополнительное правило интерпретации США 1(c): положение о «частях» или «частях и принадлежностях» не имеет преимущества перед конкретным положением для данной части или принадлежности. Конкретное (eo nomine) положение имеет преимущество перед общим положением о частях. (Дополнительное правило интерпретации США 1(c).)","tr":"Additional U.S. Rule of Interpretation 1(c): 'parçalar' veya 'parçalar ve aksesuarlar' için bir hüküm, o parça veya aksesuar için spesifik bir hükme karşı üstün gelmez. Spesifik (eo nomine) bir hüküm, genel bir parçalar hükmüne karşı belirleyicidir. (Additional U.S. Rule of Interpretation 1(c).)","hi":"व्याख्या का अतिरिक्त अमेरिकी नियम 1(c): 'पुर्जे' या 'पुर्जे और एक्सेसरीज' के लिए एक प्रावधान उस भाग या एक्सेसरी के लिए एक विशिष्ट प्रावधान पर प्रबल नहीं होता। एक विशिष्ट (eo nomine) प्रावधान एक सामान्य पुर्जे प्रावधान पर नियंत्रित करता है। (व्याख्या का अतिरिक्त अमेरिकी नियम 1(c)।)","ar":"القاعدة الأمريكية الإضافية للتفسير 1(c): حكم \"الأجزاء\" أو \"الأجزاء واللوازم\" لا يسود على حكم محدد للجزء أو اللازمة. فالحكم المحدد (eo nomine) يتحكم على حكم الأجزاء العام. (القاعدة الأمريكية الإضافية للتفسير 1(c).)"}},{"cat":"valuation","a":1,"q":{"en":"Under the customs appraisement statute and regulations, which basis of appraisement is the PREFERRED method that must be considered first when determining the value of imported merchandise?","es":"Bajo la ley y las regulaciones de avalúo aduanero, ¿qué base de avalúo es el método PREFERIDO que debe considerarse primero al determinar el valor de la mercancía importada?","ru":"Согласно статуту и нормативным актам о таможенной оценке, какая основа оценки является ПРЕДПОЧТИТЕЛЬНЫМ методом, который должен рассматриваться первым при определении стоимости импортируемых товаров?","tr":"Gümrük takdir (appraisement) kanunu ve yönetmelikleri kapsamında, ithal malların değerini belirlerken ilk olarak değerlendirilmesi gereken TERCİH EDİLEN takdir yöntemi hangisidir?","hi":"सीमा शुल्क मूल्यांकन क़ानून और विनियमों के तहत, मूल्यांकन का कौन सा आधार पसंदीदा विधि है जिस पर आयातित माल के मूल्य का निर्धारण करते समय पहले विचार किया जाना चाहिए?","ar":"بموجب قانون ولوائح التقدير الجمركي، أي أساس للتقدير هو الطريقة المُفضَّلة التي يجب النظر فيها أولًا عند تحديد قيمة البضائع المستوردة؟"},"o":[{"en":"Computed value","es":"Valor calculado (computed value)","ru":"Расчётная стоимость","tr":"Hesaplanmış değer (computed value)","hi":"परिकलित मूल्य","ar":"القيمة المحسوبة"},{"en":"Transaction value of the imported merchandise","es":"Valor de transacción de la mercancía importada","ru":"Стоимость сделки с импортируемыми товарами","tr":"İthal malların işlem değeri (transaction value)","hi":"आयातित माल का लेनदेन मूल्य","ar":"قيمة المعاملة للبضائع المستوردة"},{"en":"Deductive value","es":"Valor deductivo (deductive value)","ru":"Дедуктивная стоимость","tr":"İndirgenmiş değer (deductive value)","hi":"कटौती मूल्य","ar":"القيمة الاستنتاجية"},{"en":"Transaction value of similar merchandise","es":"Valor de transacción de mercancía similar","ru":"Стоимость сделки с аналогичными товарами","tr":"Benzer malların işlem değeri","hi":"समान माल का लेनदेन मूल्य","ar":"قيمة المعاملة لبضائع مشابهة"}],"e":{"en":"Transaction value of the imported merchandise is the primary basis of appraisement and must be used unless it cannot be determined or applied; the other methods are used only in the prescribed sequence when transaction value is unavailable. See 19 CFR 152.101(b) and 152.103.","es":"El valor de transacción de la mercancía importada es la base primaria de avalúo y debe usarse a menos que no pueda determinarse o aplicarse; los demás métodos se usan solo en la secuencia prescrita cuando el valor de transacción no está disponible. Véase 19 CFR 152.101(b) y 152.103.","ru":"Стоимость сделки с импортируемыми товарами является первичной основой оценки и должна использоваться, если только она не может быть определена или применена; другие методы используются только в предписанной последовательности, когда стоимость сделки недоступна. См. 19 CFR 152.101(b) и 152.103.","tr":"İthal malların işlem değeri (transaction value), birincil takdir yöntemidir ve belirlenemediği veya uygulanamadığı durumlar haricinde kullanılmalıdır; diğer yöntemler yalnızca işlem değeri mevcut olmadığında öngörülen sırayla kullanılır. Bkz. 19 CFR 152.101(b) ve 152.103.","hi":"आयातित माल का लेनदेन मूल्य मूल्यांकन का प्राथमिक आधार है और इसका उपयोग तब तक किया जाना चाहिए जब तक इसे निर्धारित या लागू नहीं किया जा सकता; अन्य विधियों का उपयोग केवल निर्धारित क्रम में तब किया जाता है जब लेनदेन मूल्य अनुपलब्ध हो। देखें 19 CFR 152.101(b) और 152.103।","ar":"قيمة المعاملة للبضائع المستوردة هي الأساس الأساسي للتقدير ويجب استخدامها ما لم يتعذّر تحديدها أو تطبيقها؛ ولا تُستخدَم الطرق الأخرى إلا بالتسلسل المقرَّر عندما تكون قيمة المعاملة غير متاحة. انظر 19 CFR 152.101(b) و152.103."}},{"cat":"valuation","a":0,"q":{"en":"Transaction value is the 'price actually paid or payable' for the merchandise when sold for exportation to the United States. Which statement BEST describes the 'price actually paid or payable'?","es":"El valor de transacción es el 'precio realmente pagado o por pagar' (price actually paid or payable) por la mercancía cuando se vende para exportación a los Estados Unidos. ¿Qué afirmación describe MEJOR el 'precio realmente pagado o por pagar'?","ru":"Стоимость сделки — это «цена, фактически уплаченная или подлежащая уплате» за товары при их продаже на экспорт в Соединённые Штаты. Какое утверждение НАИЛУЧШИМ образом описывает «цену, фактически уплаченную или подлежащую уплате»?","tr":"İşlem değeri (transaction value), mallar Amerika Birleşik Devletleri'ne ihracat için satıldığında mallar için 'fiilen ödenen veya ödenecek fiyat'tır. Hangi ifade, 'fiilen ödenen veya ödenecek fiyatı' EN İYİ şekilde tanımlar?","hi":"लेनदेन मूल्य माल के लिए 'वास्तव में भुगतान की गई या देय कीमत' है जब इसे संयुक्त राज्य अमेरिका को निर्यात के लिए बेचा जाता है। कौन सा कथन 'वास्तव में भुगतान की गई या देय कीमत' का सबसे अच्छा वर्णन करता है?","ar":"قيمة المعاملة هي \"السعر المدفوع فعليًا أو المستحَق الدفع\" عن البضائع عند بيعها للتصدير إلى الولايات المتحدة. أي عبارة تصف بأفضل شكل \"السعر المدفوع فعليًا أو المستحَق الدفع\"؟"},"o":[{"en":"The total payment made or to be made for the imported merchandise by the buyer to, or for the benefit of, the seller","es":"El pago total realizado o por realizar por la mercancía importada por el comprador al vendedor, o en beneficio de este","ru":"Общий платёж, произведённый или подлежащий произведению за импортированные товары покупателем продавцу или в пользу продавца","tr":"İthal mallar için alıcı tarafından satıcıya veya satıcı yararına yapılan ya da yapılacak toplam ödeme","hi":"खरीदार द्वारा विक्रेता को, या विक्रेता के लाभ के लिए, आयातित माल के लिए किया गया या किया जाने वाला कुल भुगतान","ar":"إجمالي المبلغ المدفوع أو المستحَق الدفع عن البضائع المستوردة من المشتري إلى البائع أو لمصلحته"},{"en":"Only the amount paid by wire transfer directly to the seller before the date of importation","es":"Solo el monto pagado por transferencia bancaria directamente al vendedor antes de la fecha de importación","ru":"Только сумма, уплаченная банковским переводом непосредственно продавцу до даты импортирования","tr":"Yalnızca, ithalat tarihinden önce doğrudan satıcıya havale yoluyla ödenen tutar","hi":"केवल वह राशि जो आयात की तारीख से पहले सीधे विक्रेता को वायर ट्रांसफर द्वारा भुगतान की गई","ar":"فقط المبلغ المدفوع بحوالة بنكية مباشرةً إلى البائع قبل تاريخ الاستيراد"},{"en":"The price shown on the commercial invoice, reduced by any quantity discount","es":"El precio que figura en la factura comercial, reducido por cualquier descuento por cantidad","ru":"Цена, указанная в коммерческом счёте-фактуре, уменьшенная на любую скидку за количество","tr":"Ticari faturada gösterilen fiyatın, herhangi bir miktar indirimi düşülerek azaltılmış hali","hi":"वाणिज्यिक चालान पर दिखाई गई कीमत, किसी भी मात्रा छूट से घटाई गई","ar":"السعر المبيَّن في الفاتورة التجارية، مخفّضًا بأي خصم كمية"},{"en":"The fair market value of the merchandise in the country of exportation on the date of export","es":"El valor justo de mercado de la mercancía en el país de exportación en la fecha de exportación","ru":"Справедливая рыночная стоимость товаров в стране вывоза на дату экспорта","tr":"Malların ihracat ülkesindeki, ihracat tarihindeki adil piyasa değeri","hi":"निर्यात की तारीख पर निर्यात देश में माल का उचित बाजार मूल्य","ar":"القيمة السوقية العادلة للبضائع في بلد التصدير في تاريخ التصدير"}],"e":{"en":"The price actually paid or payable is the total payment (whether or not made directly to the seller) made or to be made for the imported merchandise by the buyer to, or for the benefit of, the seller, exclusive of international freight and insurance. See 19 CFR 152.102(f) and 152.103(a)(1).","es":"El precio realmente pagado o por pagar es el pago total (ya sea hecho directamente al vendedor o no) realizado o por realizar por la mercancía importada por el comprador al vendedor, o en beneficio de este, excluyendo el flete y el seguro internacionales. Véase 19 CFR 152.102(f) y 152.103(a)(1).","ru":"Цена, фактически уплаченная или подлежащая уплате, — это общий платёж (независимо от того, произведён ли он непосредственно продавцу), произведённый или подлежащий произведению за импортированные товары покупателем продавцу или в пользу продавца, за исключением международного фрахта и страхования. См. 19 CFR 152.102(f) и 152.103(a)(1).","tr":"Fiilen ödenen veya ödenecek fiyat, ithal mallar için alıcı tarafından satıcıya veya satıcı yararına (doğrudan satıcıya yapılıp yapılmadığına bakılmaksızın) yapılan ya da yapılacak toplam ödemedir; uluslararası navlun ve sigorta hariçtir. Bkz. 19 CFR 152.102(f) ve 152.103(a)(1).","hi":"वास्तव में भुगतान की गई या देय कीमत वह कुल भुगतान है (चाहे सीधे विक्रेता को किया गया हो या नहीं) जो खरीदार द्वारा विक्रेता को, या विक्रेता के लाभ के लिए, आयातित माल के लिए किया गया या किया जाने वाला है, अंतरराष्ट्रीय माल भाड़े और बीमा को छोड़कर। देखें 19 CFR 152.102(f) और 152.103(a)(1)।","ar":"السعر المدفوع فعليًا أو المستحَق الدفع هو إجمالي المبلغ (سواء دُفِع مباشرةً إلى البائع أم لا) المدفوع أو المستحَق الدفع عن البضائع المستوردة من المشتري إلى البائع أو لمصلحته، باستثناء الشحن والتأمين الدوليين. انظر 19 CFR 152.102(f) و152.103(a)(1)."}},{"cat":"valuation","a":2,"q":{"en":"When determining transaction value, certain amounts are ADDED to the price actually paid or payable to the extent not already included. Which of the following is NOT one of the statutory additions?","es":"Al determinar el valor de transacción, ciertos montos se SUMAN al precio realmente pagado o por pagar en la medida en que no estén ya incluidos. ¿Cuál de los siguientes NO es una de las adiciones legales?","ru":"При определении стоимости сделки определённые суммы ДОБАВЛЯЮТСЯ к цене, фактически уплаченной или подлежащей уплате, в той мере, в какой они ещё не включены. Что из перечисленного НЕ является одним из предусмотренных законом добавлений?","tr":"İşlem değerini (transaction value) belirlerken, henüz dahil edilmemiş olması ölçüsünde fiilen ödenen veya ödenecek fiyata belirli tutarlar EKLENİR. Aşağıdakilerden hangisi yasal ilavelerden biri DEĞİLDİR?","hi":"लेनदेन मूल्य निर्धारित करते समय, कुछ राशियां वास्तव में भुगतान की गई या देय कीमत में जोड़ी जाती हैं, इस सीमा तक कि वे पहले से शामिल न हों। निम्नलिखित में से कौन सी वैधानिक वृद्धियों में से एक नहीं है?","ar":"عند تحديد قيمة المعاملة، تُضاف مبالغ معينة إلى السعر المدفوع فعليًا أو المستحَق الدفع بالقدر غير المُدرَج أصلًا. أي مما يلي ليس من الإضافات القانونية؟"},"o":[{"en":"Packing costs incurred by the buyer","es":"Los costos de empaque incurridos por el comprador","ru":"Расходы на упаковку, понесённые покупателем","tr":"Alıcı tarafından üstlenilen ambalaj masrafları","hi":"खरीदार द्वारा वहन की गई पैकिंग लागत","ar":"تكاليف التعبئة التي يتكبّدها المشتري"},{"en":"Any selling commission incurred by the buyer","es":"Cualquier comisión de venta incurrida por el comprador","ru":"Любая комиссия за продажу, понесённая покупателем","tr":"Alıcı tarafından üstlenilen herhangi bir satış komisyonu","hi":"खरीदार द्वारा वहन किया गया कोई भी विक्रय कमीशन","ar":"أي عمولة بيع يتكبّدها المشتري"},{"en":"The cost of international freight to transport the goods to the United States","es":"El costo del flete internacional para transportar las mercancías a los Estados Unidos","ru":"Стоимость международного фрахта для перевозки товаров в Соединённые Штаты","tr":"Malları Amerika Birleşik Devletleri'ne taşımak için uluslararası navlun masrafı","hi":"माल को संयुक्त राज्य अमेरिका तक पहुंचाने के लिए अंतरराष्ट्रीय माल भाड़े की लागत","ar":"تكلفة الشحن الدولي لنقل البضائع إلى الولايات المتحدة"},{"en":"Any royalty or license fee the buyer must pay as a condition of the sale for export","es":"Cualquier regalía o derecho de licencia que el comprador deba pagar como condición de la venta para exportación","ru":"Любой роялти или лицензионный платёж, который покупатель обязан уплатить как условие продажи на экспорт","tr":"Alıcının, ihracat için satışın bir koşulu olarak ödemek zorunda olduğu herhangi bir telif (royalty) veya lisans ücreti","hi":"कोई भी रॉयल्टी या लाइसेंस शुल्क जो खरीदार को निर्यात के लिए बिक्री की शर्त के रूप में भुगतान करना होगा","ar":"أي إتاوة أو رسم ترخيص يجب على المشتري دفعه كشرط للبيع للتصدير"}],"e":{"en":"The statutory additions are packing costs, selling commissions, the apportioned value of assists, royalties or license fees, and proceeds of subsequent resale accruing to the seller. International freight to the U.S. is excluded from the price actually paid or payable, not an addition. See 19 CFR 152.103(b)(1) and 152.103(i).","es":"Las adiciones legales son los costos de empaque, las comisiones de venta, el valor prorrateado de los assists (aportaciones), las regalías o derechos de licencia, y los productos de cualquier reventa posterior que reviertan al vendedor. El flete internacional a los EE. UU. se excluye del precio realmente pagado o por pagar, no es una adición. Véase 19 CFR 152.103(b)(1) y 152.103(i).","ru":"Предусмотренными законом добавлениями являются: расходы на упаковку, комиссии за продажу, распределённая стоимость assists, роялти или лицензионные платежи и поступления от последующей перепродажи, причитающиеся продавцу. Международный фрахт в США исключается из цены, фактически уплаченной или подлежащей уплате, и не является добавлением. См. 19 CFR 152.103(b)(1) и 152.103(i).","tr":"Yasal ilaveler şunlardır: ambalaj masrafları, satış komisyonları, asistlerin (assist) tahsis edilen değeri, telifler veya lisans ücretleri ve sonraki yeniden satıştan satıcıya tahakkuk eden gelirler. ABD'ye uluslararası navlun, fiilen ödenen veya ödenecek fiyattan hariç tutulur ve bir ilave değildir. Bkz. 19 CFR 152.103(b)(1) ve 152.103(i).","hi":"वैधानिक वृद्धियां हैं पैकिंग लागत, विक्रय कमीशन, सहायताओं (assists) का आबंटित मूल्य, रॉयल्टी या लाइसेंस शुल्क, और विक्रेता को उपार्जित होने वाली बाद की पुनर्विक्रय की आय। संयुक्त राज्य अमेरिका तक अंतरराष्ट्रीय माल भाड़ा वास्तव में भुगतान की गई या देय कीमत से बाहर रखा जाता है, यह एक वृद्धि नहीं है। देखें 19 CFR 152.103(b)(1) और 152.103(i)।","ar":"الإضافات القانونية هي تكاليف التعبئة، وعمولات البيع، والقيمة الموزَّعة للمساعدات (assists)، والإتاوات أو رسوم الترخيص، وعائدات إعادة البيع اللاحقة المستحَقة للبائع. أما الشحن الدولي إلى الولايات المتحدة فمستبعَد من السعر المدفوع فعليًا أو المستحَق الدفع، وليس إضافة. انظر 19 CFR 152.103(b)(1) و152.103(i)."}},{"cat":"valuation","a":3,"q":{"en":"Which of the following items, if separately identified, is EXCLUDED from transaction value (i.e., not part of the appraised value)?","es":"¿Cuál de los siguientes conceptos, si se identifica por separado, se EXCLUYE del valor de transacción (es decir, no forma parte del valor de avalúo)?","ru":"Что из перечисленного, если оно отдельно идентифицировано, ИСКЛЮЧАЕТСЯ из стоимости сделки (то есть не является частью оценочной стоимости)?","tr":"Aşağıdaki kalemlerden hangisi, ayrı olarak belirtilmesi halinde, işlem değerinden (transaction value) HARİÇ TUTULUR (yani takdir edilen değerin bir parçası değildir)?","hi":"निम्नलिखित में से कौन सी वस्तु, यदि अलग से पहचानी जाए, लेनदेन मूल्य से बाहर रखी जाती है (अर्थात, मूल्यांकित मूल्य का हिस्सा नहीं)?","ar":"أي من البنود التالية، إذا حُدِّد بشكل منفصل، يُستبعَد من قيمة المعاملة (أي ليس جزءًا من القيمة المقدّرة)؟"},"o":[{"en":"The apportioned value of a mold supplied free of charge by the buyer to the producer","es":"El valor prorrateado de un molde suministrado gratuitamente por el comprador al productor","ru":"Распределённая стоимость пресс-формы, предоставленной бесплатно покупателем производителю","tr":"Alıcı tarafından üreticiye ücretsiz olarak tedarik edilen bir kalıbın tahsis edilen değeri","hi":"उत्पादक को खरीदार द्वारा मुफ्त में आपूर्ति किए गए एक सांचे का आबंटित मूल्य","ar":"القيمة الموزَّعة لقالب يقدّمه المشتري مجانًا إلى المنتِج"},{"en":"A selling commission paid by the buyer to its agent abroad","es":"Una comisión de venta pagada por el comprador a su agente en el extranjero","ru":"Комиссия за продажу, уплаченная покупателем своему агенту за рубежом","tr":"Alıcı tarafından yurt dışındaki acentesine ödenen bir satış komisyonu","hi":"खरीदार द्वारा विदेश में अपने एजेंट को भुगतान किया गया एक विक्रय कमीशन","ar":"عمولة بيع يدفعها المشتري إلى وكيله في الخارج"},{"en":"The cost of cartons used to pack the goods for shipment to the United States","es":"El costo de las cajas usadas para empacar las mercancías para su embarque a los Estados Unidos","ru":"Стоимость коробок, используемых для упаковки товаров для отправки в Соединённые Штаты","tr":"Malları Amerika Birleşik Devletleri'ne sevk etmek üzere ambalajlamak için kullanılan kartonların maliyeti","hi":"संयुक्त राज्य अमेरिका को शिपमेंट के लिए माल पैक करने हेतु उपयोग किए गए कार्टन की लागत","ar":"تكلفة الكراتين المستخدمة لتعبئة البضائع لشحنها إلى الولايات المتحدة"},{"en":"U.S. customs duties and other Federal taxes payable on the imported merchandise","es":"Los derechos aduaneros de los EE. UU. y otros impuestos federales por pagar sobre la mercancía importada","ru":"Таможенные пошлины США и другие федеральные налоги, подлежащие уплате за импортированные товары","tr":"İthal mallar üzerinde ödenecek ABD gümrük vergileri ve diğer Federal vergiler","hi":"आयातित माल पर देय अमेरिकी सीमा शुल्क और अन्य संघीय कर","ar":"الرسوم الجمركية الأمريكية وغيرها من الضرائب الفيدرالية المستحَقة على البضائع المستوردة"}],"e":{"en":"Customs duties and other Federal taxes (and Federal excise taxes) on the imported merchandise are excluded from transaction value if identified separately. Assists, selling commissions, and packing costs are additions. See 19 CFR 152.103(i).","es":"Los derechos aduaneros y otros impuestos federales (e impuestos especiales federales) sobre la mercancía importada se excluyen del valor de transacción si se identifican por separado. Los assists (aportaciones), las comisiones de venta y los costos de empaque son adiciones. Véase 19 CFR 152.103(i).","ru":"Таможенные пошлины и другие федеральные налоги (а также федеральные акцизные сборы) на импортированные товары исключаются из стоимости сделки, если они идентифицированы отдельно. Assists, комиссии за продажу и расходы на упаковку являются добавлениями. См. 19 CFR 152.103(i).","tr":"İthal mallar üzerindeki gümrük vergileri ve diğer Federal vergiler (ve Federal tüketim vergileri), ayrı olarak belirtilmeleri halinde işlem değerinden hariç tutulur. Asistler (assist), satış komisyonları ve ambalaj masrafları ise ilavelerdir. Bkz. 19 CFR 152.103(i).","hi":"आयातित माल पर सीमा शुल्क और अन्य संघीय कर (और संघीय उत्पाद शुल्क) लेनदेन मूल्य से बाहर रखे जाते हैं यदि अलग से पहचाने जाएं। सहायताएं (assists), विक्रय कमीशन, और पैकिंग लागत वृद्धियां हैं। देखें 19 CFR 152.103(i)।","ar":"الرسوم الجمركية وغيرها من الضرائب الفيدرالية (وضرائب الإنتاج الفيدرالية) على البضائع المستوردة تُستبعَد من قيمة المعاملة إذا حُدِّدت بشكل منفصل. أما المساعدات (assists) وعمولات البيع وتكاليف التعبئة فهي إضافات. انظر 19 CFR 152.103(i)."}},{"cat":"valuation","a":2,"q":{"en":"An importer buys goods for a price actually paid or payable of $50,000. The buyer also paid a $4,000 selling commission to its buying-side commissionaire, paid $2,500 for ocean freight to the U.S., and supplied to the producer free of charge a special mold costing $9,000 that is being used to produce three equal shipments (this is the first of the three). What is the transaction value of this shipment?","es":"Un importador compra mercancías por un precio realmente pagado o por pagar de $50,000. El comprador también pagó una comisión de venta de $4,000 a su comisionista del lado de compra, pagó $2,500 por flete marítimo a los EE. UU., y suministró al productor gratuitamente un molde especial con un costo de $9,000 que se usa para producir tres embarques iguales (este es el primero de los tres). ¿Cuál es el valor de transacción de este embarque?","ru":"Импортёр покупает товары по цене, фактически уплаченной или подлежащей уплате, в размере $50,000. Покупатель также уплатил комиссию за продажу в размере $4,000 своему комиссионеру со стороны покупателя, уплатил $2,500 за морской фрахт в США и предоставил производителю бесплатно специальную пресс-форму стоимостью $9,000, которая используется для производства трёх равных партий (это первая из трёх). Какова стоимость сделки по этой партии?","tr":"Bir ithalatçı, fiilen ödenen veya ödenecek fiyatı $50,000 olan malları satın alır. Alıcı ayrıca, alım tarafındaki komisyoncusuna (commissionaire) $4,000 satış komisyonu ödemiş, ABD'ye deniz navlunu için $2,500 ödemiş ve üreticiye, üç eşit sevkiyatın üretilmesinde kullanılan, maliyeti $9,000 olan özel bir kalıbı ücretsiz olarak tedarik etmiştir (bu, üç sevkiyatın ilkidir). Bu sevkiyatın işlem değeri (transaction value) nedir?","hi":"एक आयातक माल को $50,000 की वास्तव में भुगतान की गई या देय कीमत पर खरीदता है। खरीदार ने अपने खरीद-पक्ष कमीशनेयर को $4,000 विक्रय कमीशन भी भुगतान किया, संयुक्त राज्य अमेरिका तक समुद्री माल भाड़े के लिए $2,500 भुगतान किया, और उत्पादक को मुफ्त में $9,000 लागत का एक विशेष सांचा आपूर्ति किया जो तीन समान शिपमेंट बनाने के लिए उपयोग किया जा रहा है (यह तीन में से पहला है)। इस शिपमेंट का लेनदेन मूल्य क्या है?","ar":"يشتري مستورد بضائع بسعر مدفوع فعليًا أو مستحَق الدفع قدره $50,000. كما دفع المشتري عمولة بيع قدرها $4,000 لوكيله بالعمولة من جانب الشراء، ودفع $2,500 للشحن البحري إلى الولايات المتحدة، وقدّم إلى المنتِج مجانًا قالبًا خاصًا تكلفته $9,000 يُستخدَم لإنتاج ثلاث شحنات متساوية (وهذه هي الأولى من الثلاث). ما هي قيمة المعاملة لهذه الشحنة؟"},"o":[{"en":"$54,000","es":"$54,000","ru":"$54,000","tr":"$54,000","hi":"$54,000","ar":"$54,000"},{"en":"$56,500","es":"$56,500","ru":"$56,500","tr":"$56,500","hi":"$56,500","ar":"$56,500"},{"en":"$57,000","es":"$57,000","ru":"$57,000","tr":"$57,000","hi":"$57,000","ar":"$57,000"},{"en":"$59,500","es":"$59,500","ru":"$59,500","tr":"$59,500","hi":"$59,500","ar":"$59,500"}],"e":{"en":"Transaction value = price ($50,000) + selling commission ($4,000) + apportioned assist ($9,000 / 3 = $3,000) = $57,000. Ocean freight to the U.S. is excluded. Note: a bona fide buying commission would not be added, but a selling commission is. See 19 CFR 152.103(b)(1).","es":"Valor de transacción = precio ($50,000) + comisión de venta ($4,000) + assist prorrateado ($9,000 / 3 = $3,000) = $57,000. El flete marítimo a los EE. UU. se excluye. Nota: una comisión de compra de buena fe no se sumaría, pero una comisión de venta sí. Véase 19 CFR 152.103(b)(1).","ru":"Стоимость сделки = цена ($50,000) + комиссия за продажу ($4,000) + распределённый assist ($9,000 / 3 = $3,000) = $57,000. Морской фрахт в США исключается. Примечание: добросовестная комиссия за покупку не добавлялась бы, но комиссия за продажу добавляется. См. 19 CFR 152.103(b)(1).","tr":"İşlem değeri = fiyat ($50,000) + satış komisyonu ($4,000) + tahsis edilen asist ($9,000 / 3 = $3,000) = $57,000. ABD'ye deniz navlunu hariç tutulur. Not: gerçek (bona fide) bir alım komisyonu eklenmezdi, ancak bir satış komisyonu eklenir. Bkz. 19 CFR 152.103(b)(1).","hi":"लेनदेन मूल्य = कीमत ($50,000) + विक्रय कमीशन ($4,000) + आबंटित सहायता ($9,000 / 3 = $3,000) = $57,000। संयुक्त राज्य अमेरिका तक समुद्री माल भाड़ा बाहर रखा जाता है। ध्यान दें: एक वास्तविक खरीद कमीशन नहीं जोड़ा जाता, लेकिन एक विक्रय कमीशन जोड़ा जाता है। देखें 19 CFR 152.103(b)(1)।","ar":"قيمة المعاملة = السعر ($50,000) + عمولة البيع ($4,000) + المساعدة الموزَّعة ($9,000 / 3 = $3,000) = $57,000. الشحن البحري إلى الولايات المتحدة مستبعَد. ملاحظة: عمولة الشراء الحقيقية لا تُضاف، لكن عمولة البيع تُضاف. انظر 19 CFR 152.103(b)(1)."}},{"cat":"valuation","a":0,"q":{"en":"Which of the following is the BEST definition of an 'assist' for customs valuation purposes?","es":"¿Cuál de las siguientes es la MEJOR definición de un 'assist' (aportación) para efectos de avalúo aduanero?","ru":"Что из перечисленного является НАИЛУЧШИМ определением «assist» (содействия) для целей таможенной оценки?","tr":"Gümrük değerlemesi amaçları açısından bir 'asist' (assist) için aşağıdakilerden hangisi EN İYİ tanımdır?","hi":"सीमा शुल्क मूल्यांकन प्रयोजनों के लिए 'सहायता' (assist) की सबसे अच्छी परिभाषा निम्नलिखित में से कौन सी है?","ar":"أي مما يلي هو أفضل تعريف لـ \"المساعدة\" (assist) لأغراض التقدير الجمركي؟"},"o":[{"en":"Items such as materials, tools, dies, or molds, or engineering done outside the U.S., supplied by the buyer free of charge or at reduced cost for use in producing the merchandise","es":"Conceptos tales como materiales, herramientas, troqueles o moldes, o trabajo de ingeniería realizado fuera de los EE. UU., suministrados por el comprador gratuitamente o a costo reducido para usarse en la producción de la mercancía","ru":"Такие предметы, как материалы, инструменты, штампы или пресс-формы, либо инженерные работы, выполненные за пределами США, предоставленные покупателем бесплатно или по сниженной стоимости для использования при производстве товаров","tr":"Malzemeler, takımlar, kalıplar gibi kalemler ya da ABD dışında yapılan mühendislik gibi, malların üretiminde kullanılmak üzere alıcı tarafından ücretsiz veya indirimli maliyetle tedarik edilen unsurlar","hi":"सामग्री, उपकरण, डाई, या सांचे जैसी वस्तुएं, या संयुक्त राज्य अमेरिका के बाहर किया गया इंजीनियरिंग कार्य, जो खरीदार द्वारा मुफ्त में या घटी हुई लागत पर माल के उत्पादन में उपयोग के लिए आपूर्ति की जाती हैं","ar":"بنود مثل المواد أو الأدوات أو القوالب الحدّية (dies) أو القوالب، أو الأعمال الهندسية المنجَزة خارج الولايات المتحدة، يقدّمها المشتري مجانًا أو بتكلفة مخفّضة للاستخدام في إنتاج البضائع"},{"en":"Any post-importation warranty service provided by the seller to the buyer at no charge","es":"Cualquier servicio de garantía posterior a la importación prestado por el vendedor al comprador sin cargo","ru":"Любое послеввозное гарантийное обслуживание, предоставляемое продавцом покупателю бесплатно","tr":"Satıcı tarafından alıcıya ücretsiz olarak sağlanan herhangi bir ithalat sonrası garanti hizmeti","hi":"विक्रेता द्वारा खरीदार को बिना किसी शुल्क के प्रदान की गई कोई भी आयात-पश्चात वारंटी सेवा","ar":"أي خدمة ضمان بعد الاستيراد يقدّمها البائع للمشتري دون مقابل"},{"en":"Financial assistance or credit extended by the seller to the buyer to facilitate the purchase","es":"Asistencia financiera o crédito otorgado por el vendedor al comprador para facilitar la compra","ru":"Финансовая помощь или кредит, предоставленные продавцом покупателю для облегчения покупки","tr":"Satın almayı kolaylaştırmak için satıcı tarafından alıcıya sağlanan mali yardım veya kredi","hi":"खरीद को सुगम बनाने के लिए विक्रेता द्वारा खरीदार को दी गई वित्तीय सहायता या ऋण","ar":"المساعدة المالية أو الائتمان الذي يقدّمه البائع للمشتري لتيسير الشراء"},{"en":"Any quantity discount granted by the seller because the buyer is a long-standing customer","es":"Cualquier descuento por cantidad otorgado por el vendedor porque el comprador es un cliente de larga data","ru":"Любая скидка за количество, предоставленная продавцом из-за того, что покупатель является давним клиентом","tr":"Alıcının uzun süredir devam eden bir müşteri olması nedeniyle satıcı tarafından verilen herhangi bir miktar indirimi","hi":"विक्रेता द्वारा दी गई कोई भी मात्रा छूट क्योंकि खरीदार एक दीर्घकालिक ग्राहक है","ar":"أي خصم كمية يمنحه البائع لأن المشتري عميل قديم"}],"e":{"en":"An assist is any of the following supplied directly or indirectly, and free of charge or at reduced cost, by the buyer for use in producing or selling the merchandise: (1) materials/components incorporated; (2) tools, dies, molds used in production; (3) merchandise consumed in production; and (4) engineering, development, artwork, design work, plans and sketches undertaken elsewhere than in the U.S. See 19 CFR 152.102(a)(1).","es":"Un assist (aportación) es cualquiera de los siguientes, suministrado directa o indirectamente, y gratuitamente o a costo reducido, por el comprador para usarse en la producción o venta de la mercancía: (1) materiales/componentes incorporados; (2) herramientas, troqueles, moldes usados en la producción; (3) mercancía consumida en la producción; y (4) ingeniería, desarrollo, trabajo artístico, diseño, planos y bocetos realizados fuera de los EE. UU. Véase 19 CFR 152.102(a)(1).","ru":"Assist — это любое из перечисленного, предоставленное прямо или косвенно, бесплатно или по сниженной стоимости, покупателем для использования при производстве или продаже товаров: (1) материалы/компоненты, включённые в товар; (2) инструменты, штампы, пресс-формы, используемые в производстве; (3) товары, потреблённые в производстве; и (4) инженерные работы, разработка, художественные работы, дизайн, планы и эскизы, выполненные за пределами США. См. 19 CFR 152.102(a)(1).","tr":"Bir asist (assist), malların üretiminde veya satışında kullanılmak üzere alıcı tarafından doğrudan veya dolaylı olarak ve ücretsiz ya da indirimli maliyetle tedarik edilen şunlardan herhangi biridir: (1) bünyeye dahil edilen malzemeler/bileşenler; (2) üretimde kullanılan takımlar, kalıplar; (3) üretimde tüketilen mallar; ve (4) ABD dışında bir yerde yürütülen mühendislik, geliştirme, sanat çalışması, tasarım çalışması, planlar ve eskizler. Bkz. 19 CFR 152.102(a)(1).","hi":"एक सहायता (assist) निम्नलिखित में से कोई भी है जो खरीदार द्वारा प्रत्यक्ष या अप्रत्यक्ष रूप से, और मुफ्त में या घटी हुई लागत पर, माल के उत्पादन या बिक्री में उपयोग के लिए आपूर्ति की जाती है: (1) शामिल की गई सामग्री/घटक; (2) उत्पादन में उपयोग किए गए उपकरण, डाई, सांचे; (3) उत्पादन में उपभोग किया गया माल; और (4) इंजीनियरिंग, विकास, कलाकृति, डिज़ाइन कार्य, योजनाएं और रेखाचित्र जो संयुक्त राज्य अमेरिका के अलावा कहीं और किए गए हों। देखें 19 CFR 152.102(a)(1)।","ar":"المساعدة (assist) هي أي مما يلي مقدَّمًا بشكل مباشر أو غير مباشر، ومجانًا أو بتكلفة مخفّضة، من قبل المشتري للاستخدام في إنتاج البضائع أو بيعها: (1) المواد/المكوّنات المُدمَجة؛ (2) الأدوات والقوالب الحدّية والقوالب المستخدمة في الإنتاج؛ (3) البضائع المستهلَكة في الإنتاج؛ و(4) الأعمال الهندسية والتطوير والأعمال الفنية وأعمال التصميم والخطط والرسومات المنجَزة في مكان غير الولايات المتحدة. انظر 19 CFR 152.102(a)(1)."}},{"cat":"valuation","a":0,"q":{"en":"A U.S. buyer provides, free of charge, design work to the foreign producer of imported merchandise. Under what circumstance is this design work NOT treated as a dutiable assist?","es":"Un comprador estadounidense proporciona, gratuitamente, trabajo de diseño al productor extranjero de la mercancía importada. ¿En qué circunstancia este trabajo de diseño NO se trata como un assist (aportación) sujeto a derechos?","ru":"Покупатель из США предоставляет бесплатно дизайнерские работы иностранному производителю импортированных товаров. При каком обстоятельстве эти дизайнерские работы НЕ рассматриваются как облагаемый пошлиной assist?","tr":"Bir ABD alıcısı, ithal malların yabancı üreticisine ücretsiz olarak tasarım çalışması sağlar. Bu tasarım çalışması hangi durumda vergiye tabi bir asist (assist) olarak değerlendirilMEZ?","hi":"एक अमेरिकी खरीदार आयातित माल के विदेशी उत्पादक को मुफ्त में डिज़ाइन कार्य प्रदान करता है। किस परिस्थिति में इस डिज़ाइन कार्य को शुल्क-योग्य सहायता (assist) के रूप में नहीं माना जाता?","ar":"يقدّم مشترٍ أمريكي، مجانًا، أعمال تصميم للمنتِج الأجنبي للبضائع المستوردة. في أي ظرف لا تُعامَل أعمال التصميم هذه كمساعدة خاضعة للرسوم؟"},"o":[{"en":"When the design work is performed by a person domiciled in the United States and is undertaken in the United States","es":"Cuando el trabajo de diseño es realizado por una persona domiciliada en los Estados Unidos y se realiza en los Estados Unidos","ru":"Когда дизайнерские работы выполняются лицом, имеющим постоянное местожительство в Соединённых Штатах, и осуществляются в Соединённых Штатах","tr":"Tasarım çalışması, Amerika Birleşik Devletleri'nde ikamet eden bir kişi tarafından yapıldığında ve Amerika Birleşik Devletleri'nde yürütüldüğünde","hi":"जब डिज़ाइन कार्य संयुक्त राज्य अमेरिका में अधिवासित किसी व्यक्ति द्वारा किया जाता है और संयुक्त राज्य अमेरिका में किया जाता है","ar":"عندما تُنجَز أعمال التصميم على يد شخص مقيم في الولايات المتحدة وتُجرى داخل الولايات المتحدة"},{"en":"When the design work was paid for by the buyer rather than the seller","es":"Cuando el trabajo de diseño fue pagado por el comprador en lugar del vendedor","ru":"Когда дизайнерские работы оплачены покупателем, а не продавцом","tr":"Tasarım çalışmasının satıcı yerine alıcı tarafından ödenmiş olması durumunda","hi":"जब डिज़ाइन कार्य के लिए विक्रेता के बजाय खरीदार द्वारा भुगतान किया गया हो","ar":"عندما يكون المشتري قد دفع ثمن أعمال التصميم بدلًا من البائع"},{"en":"When the value of the design work is less than ten percent of the entered value","es":"Cuando el valor del trabajo de diseño es menor al diez por ciento del valor entrado","ru":"Когда стоимость дизайнерских работ составляет менее десяти процентов заявленной стоимости","tr":"Tasarım çalışmasının değeri, giriş değerinin yüzde onundan az olduğunda","hi":"जब डिज़ाइन कार्य का मूल्य प्रवेश मूल्य के दस प्रतिशत से कम हो","ar":"عندما تكون قيمة أعمال التصميم أقل من عشرة بالمئة من القيمة المُدخَلة"},{"en":"When the design work relates only to packaging rather than to the merchandise itself","es":"Cuando el trabajo de diseño se refiere solo al empaque en lugar de a la mercancía misma","ru":"Когда дизайнерские работы относятся только к упаковке, а не к самим товарам","tr":"Tasarım çalışması, malların kendisiyle değil yalnızca ambalajla ilgili olduğunda","hi":"जब डिज़ाइन कार्य केवल पैकेजिंग से संबंधित हो, न कि स्वयं माल से","ar":"عندما تتعلق أعمال التصميم بالتعبئة فقط وليس بالبضائع ذاتها"}],"e":{"en":"Engineering, development, artwork, design work, and plans and sketches are an assist only if undertaken elsewhere than in the United States. Such work performed by a person domiciled in the U.S. and undertaken in the U.S. is not an assist. See 19 CFR 152.102(a)(1)(iv) and 152.102(a)(2).","es":"La ingeniería, el desarrollo, el trabajo artístico, el diseño, y los planos y bocetos son un assist solo si se realizan fuera de los Estados Unidos. Tal trabajo realizado por una persona domiciliada en los EE. UU. y realizado en los EE. UU. no es un assist. Véase 19 CFR 152.102(a)(1)(iv) y 152.102(a)(2).","ru":"Инженерные работы, разработка, художественные работы, дизайн, планы и эскизы являются assist только в том случае, если они выполнены за пределами Соединённых Штатов. Такие работы, выполненные лицом, имеющим постоянное местожительство в США, и осуществлённые в США, не являются assist. См. 19 CFR 152.102(a)(1)(iv) и 152.102(a)(2).","tr":"Mühendislik, geliştirme, sanat çalışması, tasarım çalışması ile planlar ve eskizler, yalnızca Amerika Birleşik Devletleri dışında bir yerde yürütüldüklerinde bir asisttir (assist). Amerika Birleşik Devletleri'nde ikamet eden bir kişi tarafından yapılan ve Amerika Birleşik Devletleri'nde yürütülen bu tür bir çalışma bir asist değildir. Bkz. 19 CFR 152.102(a)(1)(iv) ve 152.102(a)(2).","hi":"इंजीनियरिंग, विकास, कलाकृति, डिज़ाइन कार्य, और योजनाएं तथा रेखाचित्र केवल तभी एक सहायता (assist) हैं यदि वे संयुक्त राज्य अमेरिका के अलावा कहीं और किए गए हों। संयुक्त राज्य अमेरिका में अधिवासित किसी व्यक्ति द्वारा संयुक्त राज्य अमेरिका में किया गया ऐसा कार्य एक सहायता नहीं है। देखें 19 CFR 152.102(a)(1)(iv) और 152.102(a)(2)।","ar":"الأعمال الهندسية والتطوير والأعمال الفنية وأعمال التصميم والخطط والرسومات تكون مساعدة فقط إذا أُنجِزت في مكان غير الولايات المتحدة. أما هذه الأعمال المنجَزة على يد شخص مقيم في الولايات المتحدة والمُجراة داخلها فليست مساعدة. انظر 19 CFR 152.102(a)(1)(iv) و152.102(a)(2)."}},{"cat":"valuation","a":3,"q":{"en":"When the buyer and seller are related parties, the transaction value is acceptable for appraisement if which of the following is shown?","es":"Cuando el comprador y el vendedor son partes vinculadas (related parties), el valor de transacción es aceptable para avalúo si se demuestra ¿cuál de los siguientes?","ru":"Когда покупатель и продавец являются связанными сторонами, стоимость сделки приемлема для оценки, если показано что из следующего?","tr":"Alıcı ve satıcı ilişkili taraflar (related parties) olduğunda, işlem değeri (transaction value) takdir için aşağıdakilerden hangisi gösterildiğinde kabul edilebilir?","hi":"जब खरीदार और विक्रेता संबंधित पक्ष हों, तो मूल्यांकन के लिए लेनदेन मूल्य स्वीकार्य है यदि निम्नलिखित में से कौन सा दिखाया जाए?","ar":"عندما يكون المشتري والبائع طرفين مرتبطين، تكون قيمة المعاملة مقبولة للتقدير إذا تبيّن أي مما يلي؟"},"o":[{"en":"The merchandise is sold at a price that yields the seller a profit of at least ten percent","es":"La mercancía se vende a un precio que genera al vendedor una utilidad de al menos el diez por ciento","ru":"Товары продаются по цене, обеспечивающей продавцу прибыль не менее десяти процентов","tr":"Mallar, satıcıya en az yüzde on kâr sağlayan bir fiyattan satılır","hi":"माल एक ऐसी कीमत पर बेचा जाता है जो विक्रेता को कम से कम दस प्रतिशत का लाभ देती है","ar":"تُباع البضائع بسعر يحقق للبائع ربحًا لا يقل عن عشرة بالمئة"},{"en":"The related parties file a binding ruling request with CBP before each importation","es":"Las partes vinculadas presentan ante CBP una solicitud de resolución vinculante antes de cada importación","ru":"Связанные стороны подают в CBP запрос об обязывающем решении перед каждым импортированием","tr":"İlişkili taraflar, her ithalattan önce CBP'ye bağlayıcı bir görüş (ruling) talebinde bulunur","hi":"संबंधित पक्ष प्रत्येक आयात से पहले CBP के पास एक बाध्यकारी रूलिंग अनुरोध दाखिल करते हैं","ar":"يقدّم الطرفان المرتبطان طلب قرار مُلزِم إلى CBP قبل كل عملية استيراد"},{"en":"The buyer owns less than fifty percent of the seller's outstanding voting stock","es":"El comprador posee menos del cincuenta por ciento de las acciones con derecho a voto en circulación del vendedor","ru":"Покупатель владеет менее чем пятьюдесятью процентами голосующих акций продавца в обращении","tr":"Alıcı, satıcının ödenmiş oy hakkına sahip hisse senetlerinin yüzde ellisinden azına sahiptir","hi":"खरीदार के पास विक्रेता के बकाया मतदान स्टॉक के पचास प्रतिशत से कम का स्वामित्व है","ar":"يمتلك المشتري أقل من خمسين بالمئة من أسهم البائع القائمة ذات حق التصويت"},{"en":"An examination of the circumstances of the sale indicates the relationship did not influence the price, OR the transaction value closely approximates an acceptable test value","es":"Un examen de las circunstancias de la venta indica que la vinculación no influyó en el precio, O el valor de transacción se aproxima estrechamente a un valor de prueba aceptable","ru":"Изучение обстоятельств продажи показывает, что связь не повлияла на цену, ЛИБО стоимость сделки близко соответствует приемлемой проверочной стоимости (test value)","tr":"Satışın koşullarının incelenmesi ilişkinin fiyatı etkilemediğini gösterir VEYA işlem değeri, kabul edilebilir bir test değerine (test value) yakından yaklaşır","hi":"बिक्री की परिस्थितियों की जांच से संकेत मिलता है कि संबंध ने कीमत को प्रभावित नहीं किया, अथवा लेनदेन मूल्य किसी स्वीकार्य परीक्षण मूल्य के निकट है","ar":"يبيّن فحص ظروف البيع أن العلاقة لم تؤثر في السعر، أو أن قيمة المعاملة تقارب بشكل وثيق قيمة اختبار مقبولة"}],"e":{"en":"For related parties, transaction value is acceptable if examination of the circumstances of sale shows the relationship did not influence the price, or if the value closely approximates a 'test value' (e.g., transaction value of identical/similar merchandise to unrelated buyers, or deductive/computed value of such merchandise). See 19 CFR 152.103(j)(2) and 152.103(l).","es":"Para partes vinculadas, el valor de transacción es aceptable si el examen de las circunstancias de la venta muestra que la vinculación no influyó en el precio, o si el valor se aproxima estrechamente a un 'valor de prueba' (test value) (por ejemplo, el valor de transacción de mercancía idéntica/similar a compradores no vinculados, o el valor deductivo/calculado de tal mercancía). Véase 19 CFR 152.103(j)(2) y 152.103(l).","ru":"Для связанных сторон стоимость сделки приемлема, если изучение обстоятельств продажи показывает, что связь не повлияла на цену, либо если стоимость близко соответствует «проверочной стоимости» (test value) (например, стоимости сделки с идентичными/аналогичными товарами для несвязанных покупателей, либо дедуктивной или расчётной стоимости таких товаров). См. 19 CFR 152.103(j)(2) и 152.103(l).","tr":"İlişkili taraflar için işlem değeri, satış koşullarının incelenmesi ilişkinin fiyatı etkilemediğini gösteriyorsa veya değer bir 'test değerine' yakından yaklaşıyorsa (örneğin, ilişkisiz alıcılara satılan aynı/benzer malların işlem değeri ya da bu malların indirgenmiş/hesaplanmış değeri) kabul edilebilir. Bkz. 19 CFR 152.103(j)(2) ve 152.103(l).","hi":"संबंधित पक्षों के लिए, लेनदेन मूल्य स्वीकार्य है यदि बिक्री की परिस्थितियों की जांच से पता चले कि संबंध ने कीमत को प्रभावित नहीं किया, या यदि मूल्य किसी 'परीक्षण मूल्य' के निकट है (उदाहरण के लिए, असंबंधित खरीदारों को समान/समरूप माल का लेनदेन मूल्य, या ऐसे माल का कटौती/परिकलित मूल्य)। देखें 19 CFR 152.103(j)(2) और 152.103(l)।","ar":"بالنسبة للأطراف المرتبطة، تكون قيمة المعاملة مقبولة إذا بيّن فحص ظروف البيع أن العلاقة لم تؤثر في السعر، أو إذا كانت القيمة تقارب بشكل وثيق \"قيمة اختبار\" (مثل قيمة المعاملة لبضائع مطابقة/مشابهة لمشترين غير مرتبطين، أو القيمة الاستنتاجية/المحسوبة لهذه البضائع). انظر 19 CFR 152.103(j)(2) و152.103(l)."}},{"cat":"valuation","a":2,"q":{"en":"If the transaction value of the imported merchandise cannot be determined, what is the CORRECT order in which the remaining methods of appraisement are applied?","es":"Si el valor de transacción de la mercancía importada no puede determinarse, ¿cuál es el orden CORRECTO en que se aplican los métodos de avalúo restantes?","ru":"Если стоимость сделки с импортированными товарами не может быть определена, каков ПРАВИЛЬНЫЙ порядок применения остальных методов оценки?","tr":"İthal malların işlem değeri (transaction value) belirlenemezse, kalan takdir yöntemleri hangi DOĞRU sırayla uygulanır?","hi":"यदि आयातित माल का लेनदेन मूल्य निर्धारित नहीं किया जा सकता, तो शेष मूल्यांकन विधियों को लागू करने का सही क्रम क्या है?","ar":"إذا تعذّر تحديد قيمة المعاملة للبضائع المستوردة، ما هو الترتيب الصحيح الذي تُطبَّق به طرق التقدير المتبقية؟"},"o":[{"en":"Computed value, then deductive value, then transaction value of similar merchandise, then fallback","es":"Valor calculado, luego valor deductivo, luego valor de transacción de mercancía similar, luego valor de último recurso","ru":"Расчётная стоимость, затем дедуктивная стоимость, затем стоимость сделки с аналогичными товарами, затем резервный метод","tr":"Hesaplanmış değer, ardından indirgenmiş değer, ardından benzer malların işlem değeri, ardından fallback (geri dönüş)","hi":"परिकलित मूल्य, फिर कटौती मूल्य, फिर समान माल का लेनदेन मूल्य, फिर फॉलबैक","ar":"القيمة المحسوبة، ثم القيمة الاستنتاجية، ثم قيمة المعاملة لبضائع مشابهة، ثم الطريقة الاحتياطية"},{"en":"Deductive value, then computed value, then transaction value of identical merchandise, then of similar merchandise, then fallback","es":"Valor deductivo, luego valor calculado, luego valor de transacción de mercancía idéntica, luego de mercancía similar, luego valor de último recurso","ru":"Дедуктивная стоимость, затем расчётная стоимость, затем стоимость сделки с идентичными товарами, затем с аналогичными товарами, затем резервный метод","tr":"İndirgenmiş değer, ardından hesaplanmış değer, ardından özdeş malların işlem değeri, ardından benzer malların işlem değeri, ardından fallback","hi":"कटौती मूल्य, फिर परिकलित मूल्य, फिर एकसमान माल का लेनदेन मूल्य, फिर समान माल का, फिर फॉलबैक","ar":"القيمة الاستنتاجية، ثم القيمة المحسوبة، ثم قيمة المعاملة لبضائع مطابقة، ثم لبضائع مشابهة، ثم الطريقة الاحتياطية"},{"en":"Transaction value of identical merchandise, then of similar merchandise, then deductive value, then computed value, then fallback (derived) value","es":"Valor de transacción de mercancía idéntica, luego de mercancía similar, luego valor deductivo, luego valor calculado, luego valor de último recurso (derivado)","ru":"Стоимость сделки с идентичными товарами, затем с аналогичными товарами, затем дедуктивная стоимость, затем расчётная стоимость, затем резервная (производная) стоимость","tr":"Özdeş malların işlem değeri, ardından benzer malların işlem değeri, ardından indirgenmiş değer, ardından hesaplanmış değer, ardından fallback (türetilmiş) değer","hi":"एकसमान माल का लेनदेन मूल्य, फिर समान माल का, फिर कटौती मूल्य, फिर परिकलित मूल्य, फिर फॉलबैक (व्युत्पन्न) मूल्य","ar":"قيمة المعاملة لبضائع مطابقة، ثم لبضائع مشابهة، ثم القيمة الاستنتاجية، ثم القيمة المحسوبة، ثم القيمة الاحتياطية (المشتقة)"},{"en":"Fallback (derived) value, then deductive value, then computed value, then transaction value of identical merchandise","es":"Valor de último recurso (derivado), luego valor deductivo, luego valor calculado, luego valor de transacción de mercancía idéntica","ru":"Резервная (производная) стоимость, затем дедуктивная стоимость, затем расчётная стоимость, затем стоимость сделки с идентичными товарами","tr":"Fallback (türetilmiş) değer, ardından indirgenmiş değer, ardından hesaplanmış değer, ardından özdeş malların işlem değeri","hi":"फॉलबैक (व्युत्पन्न) मूल्य, फिर कटौती मूल्य, फिर परिकलित मूल्य, फिर एकसमान माल का लेनदेन मूल्य","ar":"القيمة الاحتياطية (المشتقة)، ثم القيمة الاستنتاجية، ثم القيمة المحسوبة، ثم قيمة المعاملة لبضائع مطابقة"}],"e":{"en":"The statutory hierarchy is: transaction value; transaction value of identical merchandise; transaction value of similar merchandise; deductive value; computed value; and finally the fallback (value derived from one of the prior methods adjusted as needed). See 19 CFR 152.101(b).","es":"La jerarquía legal es: valor de transacción; valor de transacción de mercancía idéntica; valor de transacción de mercancía similar; valor deductivo; valor calculado; y finalmente el valor de último recurso (valor derivado de uno de los métodos anteriores ajustado según sea necesario). Véase 19 CFR 152.101(b).","ru":"Установленная законом иерархия такова: стоимость сделки; стоимость сделки с идентичными товарами; стоимость сделки с аналогичными товарами; дедуктивная стоимость; расчётная стоимость; и, наконец, резервный метод (стоимость, производная от одного из предыдущих методов, скорректированная по мере необходимости). См. 19 CFR 152.101(b).","tr":"Yasal hiyerarşi şöyledir: işlem değeri; özdeş malların işlem değeri; benzer malların işlem değeri; indirgenmiş değer (deductive value); hesaplanmış değer (computed value); ve son olarak fallback (önceki yöntemlerden birinden türetilen ve gerektiği gibi düzeltilen değer). Bkz. 19 CFR 152.101(b).","hi":"वैधानिक पदानुक्रम है: लेनदेन मूल्य; एकसमान माल का लेनदेन मूल्य; समान माल का लेनदेन मूल्य; कटौती मूल्य; परिकलित मूल्य; और अंत में फॉलबैक (पूर्व विधियों में से एक से व्युत्पन्न मूल्य, आवश्यकतानुसार समायोजित)। देखें 19 CFR 152.101(b)।","ar":"التسلسل القانوني هو: قيمة المعاملة؛ ثم قيمة المعاملة لبضائع مطابقة؛ ثم قيمة المعاملة لبضائع مشابهة؛ ثم القيمة الاستنتاجية؛ ثم القيمة المحسوبة؛ وأخيرًا الطريقة الاحتياطية (قيمة مشتقة من إحدى الطرق السابقة مع تعديلها حسب الحاجة). انظر 19 CFR 152.101(b)."}},{"cat":"valuation","a":3,"q":{"en":"For appraisement under the transaction value of identical or similar merchandise, the merchandise compared must, among other requirements, have been:","es":"Para el avalúo bajo el valor de transacción de mercancía idéntica o similar, la mercancía comparada debe, entre otros requisitos, haber sido:","ru":"Для оценки по стоимости сделки с идентичными или аналогичными товарами сравниваемые товары должны, среди прочих требований, быть:","tr":"Özdeş veya benzer malların işlem değeri (transaction value) ile takdir için, karşılaştırılan malların, diğer gereklilikler arasında, şu özelliğe sahip olması gerekir:","hi":"एकसमान या समान माल के लेनदेन मूल्य के तहत मूल्यांकन के लिए, तुलना किया जाने वाला माल, अन्य आवश्यकताओं के साथ, ऐसा होना चाहिए जो:","ar":"للتقدير بموجب قيمة المعاملة لبضائع مطابقة أو مشابهة، يجب أن تكون البضائع المُقارَن بها، من بين متطلبات أخرى، قد:"},"o":[{"en":"Produced in any country, so long as it is the same class or kind of goods","es":"Producida en cualquier país, siempre que sea de la misma clase o tipo de mercancías","ru":"Произведены в любой стране, при условии что это товары того же класса или вида","tr":"Aynı sınıf veya türdeki mallar olması koşuluyla herhangi bir ülkede üretilmiş olması","hi":"किसी भी देश में उत्पादित हो, बशर्ते वह माल के समान वर्ग या प्रकार का हो","ar":"أُنتِجت في أي بلد، طالما أنها من الصنف أو النوع نفسه من البضائع"},{"en":"Sold to the same U.S. buyer as the merchandise being appraised","es":"Vendida al mismo comprador estadounidense que la mercancía que se está valuando","ru":"Проданы тому же покупателю в США, что и оцениваемые товары","tr":"Takdir edilen mallarla aynı ABD alıcısına satılmış olması","hi":"मूल्यांकित किए जा रहे माल के समान अमेरिकी खरीदार को बेचा गया हो","ar":"بِيعت لنفس المشتري الأمريكي الذي اشترى البضائع موضوع التقدير"},{"en":"Entered through the same U.S. port as the merchandise being appraised","es":"Entrada por el mismo puerto de los EE. UU. que la mercancía que se está valuando","ru":"Ввезены через тот же порт США, что и оцениваемые товары","tr":"Takdir edilen mallarla aynı ABD limanından giriş yapmış olması","hi":"मूल्यांकित किए जा रहे माल के समान अमेरिकी बंदरगाह के माध्यम से प्रवेश किया गया हो","ar":"أُدخِلت عبر نفس الميناء الأمريكي الذي أُدخِلت منه البضائع موضوع التقدير"},{"en":"Produced in the same country as, and by the same person as, the merchandise being appraised","es":"Producida en el mismo país que, y por la misma persona que, la mercancía que se está valuando","ru":"Произведены в той же стране и тем же лицом, что и оцениваемые товары","tr":"Takdir edilen mallarla aynı ülkede ve aynı kişi tarafından üretilmiş olması","hi":"मूल्यांकित किए जा रहे माल के समान देश में, और उसी व्यक्ति द्वारा उत्पादित हो","ar":"أُنتِجت في البلد نفسه، وعلى يد الشخص نفسه، الذي أنتَج البضائع موضوع التقدير"}],"e":{"en":"Identical merchandise means goods identical in all respects to, and produced in the same country and by the same person as, the merchandise being appraised; similar merchandise has the same country/producer requirement and must be like in characteristics and component material and commercially interchangeable (with limited provision for another producer in the same country if none exists from the same producer). See 19 CFR 152.102(d), 152.102(i), and 152.104.","es":"Mercancía idéntica significa mercancías idénticas en todos los aspectos a, y producidas en el mismo país y por la misma persona que, la mercancía que se está valuando; la mercancía similar tiene el mismo requisito de país/productor y debe ser semejante en características y material constitutivo, y comercialmente intercambiable (con una disposición limitada para otro productor en el mismo país si no existe del mismo productor). Véase 19 CFR 152.102(d), 152.102(i) y 152.104.","ru":"Идентичные товары означают товары, идентичные во всех отношениях оцениваемым товарам и произведённые в той же стране и тем же лицом; аналогичные товары имеют то же требование о стране/производителе и должны быть схожи по характеристикам и составляющему материалу и коммерчески взаимозаменяемы (с ограниченной возможностью использования другого производителя в той же стране, если товаров от того же производителя нет). См. 19 CFR 152.102(d), 152.102(i) и 152.104.","tr":"Özdeş mallar, takdir edilen mallarla her bakımdan özdeş olan ve onlarla aynı ülkede ve aynı kişi tarafından üretilen malları ifade eder; benzer mallar aynı ülke/üretici gerekliliğine sahiptir ve özellikler ile bileşen malzemesi bakımından benzer ve ticari olarak değiştirilebilir olmalıdır (aynı üreticiden hiç yoksa, aynı ülkedeki başka bir üreticiye yönelik sınırlı bir hükümle). Bkz. 19 CFR 152.102(d), 152.102(i) ve 152.104.","hi":"एकसमान माल का अर्थ है ऐसा माल जो सभी पहलुओं में मूल्यांकित किए जा रहे माल के समान हो, और उसी देश में तथा उसी व्यक्ति द्वारा उत्पादित हो; समान माल में वही देश/उत्पादक आवश्यकता होती है और इसे विशेषताओं तथा घटक सामग्री में जैसा होना चाहिए और वाणिज्यिक रूप से विनिमेय होना चाहिए (यदि उसी उत्पादक से कोई न हो तो उसी देश में किसी अन्य उत्पादक के लिए सीमित प्रावधान के साथ)। देखें 19 CFR 152.102(d), 152.102(i), और 152.104।","ar":"تعني البضائع المطابقة بضائع مطابقة من جميع النواحي، ومُنتَجة في البلد نفسه وعلى يد الشخص نفسه، للبضائع موضوع التقدير؛ أما البضائع المشابهة فلها متطلب البلد/المنتِج نفسه ويجب أن تكون متشابهة في الخصائص والمواد المكوّنة وقابلة للتبادل تجاريًا (مع حكم محدود لمنتِج آخر في البلد نفسه إذا لم يوجد منتِج من المنتِج نفسه). انظر 19 CFR 152.102(d) و152.102(i) و152.104."}},{"cat":"valuation","a":2,"q":{"en":"Computed value is being used to appraise imported merchandise. The producer's records show: cost or value of materials, fabrication, and processing of $30,000; an amount for profit and general expenses (consistent with sales of the same class or kind) of $6,000; an assist not otherwise included valued at $1,500; packing costs of $800; and international freight to the U.S. of $1,200. What is the computed value?","es":"Se está usando el valor calculado (computed value) para valuar mercancía importada. Los registros del productor muestran: costo o valor de los materiales, fabricación y procesamiento de $30,000; un monto por utilidad y gastos generales (consistente con las ventas de la misma clase o tipo) de $6,000; un assist no incluido de otra forma valuado en $1,500; costos de empaque de $800; y flete internacional a los EE. UU. de $1,200. ¿Cuál es el valor calculado?","ru":"Расчётная стоимость используется для оценки импортированных товаров. Записи производителя показывают: стоимость или цену материалов, изготовления и обработки в размере $30,000; сумму на прибыль и общие расходы (соответствующую продажам того же класса или вида) в размере $6,000; assist, не включённый иным образом, стоимостью $1,500; расходы на упаковку в размере $800; и международный фрахт в США в размере $1,200. Какова расчётная стоимость?","tr":"İthal malları takdir etmek için hesaplanmış değer (computed value) kullanılmaktadır. Üreticinin kayıtları şunları göstermektedir: malzemelerin, imalatın ve işlemenin maliyeti veya değeri $30,000; aynı sınıf veya türdeki mal satışlarıyla tutarlı bir kâr ve genel giderler tutarı $6,000; başka türlü dahil edilmemiş, değeri $1,500 olan bir asist (assist); ambalaj masrafları $800; ve ABD'ye uluslararası navlun $1,200. Hesaplanmış değer nedir?","hi":"आयातित माल का मूल्यांकन करने के लिए परिकलित मूल्य का उपयोग किया जा रहा है। उत्पादक के रिकॉर्ड दिखाते हैं: सामग्री, निर्माण, और प्रसंस्करण की लागत या मूल्य $30,000; लाभ और सामान्य खर्चों के लिए एक राशि (समान वर्ग या प्रकार की बिक्री के अनुरूप) $6,000; अन्यथा शामिल न की गई एक सहायता का मूल्य $1,500; पैकिंग लागत $800; और संयुक्त राज्य अमेरिका तक अंतरराष्ट्रीय माल भाड़ा $1,200। परिकलित मूल्य क्या है?","ar":"تُستخدَم القيمة المحسوبة لتقدير بضائع مستوردة. تُظهِر سجلات المنتِج ما يلي: تكلفة أو قيمة المواد والتصنيع والمعالجة قدرها $30,000؛ ومبلغ للربح والمصاريف العامة (متسق مع مبيعات الصنف أو النوع نفسه) قدره $6,000؛ ومساعدة غير مُدرَجة بطريقة أخرى قيمتها $1,500؛ وتكاليف تعبئة قدرها $800؛ وشحن دولي إلى الولايات المتحدة قدره $1,200. ما هي القيمة المحسوبة؟"},"o":[{"en":"$36,000","es":"$36,000","ru":"$36,000","tr":"$36,000","hi":"$36,000","ar":"$36,000"},{"en":"$37,500","es":"$37,500","ru":"$37,500","tr":"$37,500","hi":"$37,500","ar":"$37,500"},{"en":"$38,300","es":"$38,300","ru":"$38,300","tr":"$38,300","hi":"$38,300","ar":"$38,300"},{"en":"$39,500","es":"$39,500","ru":"$39,500","tr":"$39,500","hi":"$39,500","ar":"$39,500"}],"e":{"en":"Computed value = materials/fabrication/processing ($30,000) + profit and general expenses ($6,000) + assist not otherwise included ($1,500) + packing ($800) = $38,300. International freight to the U.S. is not a component of computed value. See 19 CFR 152.106(a) and (b).","es":"Valor calculado = materiales/fabricación/procesamiento ($30,000) + utilidad y gastos generales ($6,000) + assist no incluido de otra forma ($1,500) + empaque ($800) = $38,300. El flete internacional a los EE. UU. no es un componente del valor calculado. Véase 19 CFR 152.106(a) y (b).","ru":"Расчётная стоимость = материалы/изготовление/обработка ($30,000) + прибыль и общие расходы ($6,000) + assist, не включённый иным образом ($1,500) + упаковка ($800) = $38,300. Международный фрахт в США не является компонентом расчётной стоимости. См. 19 CFR 152.106(a) и (b).","tr":"Hesaplanmış değer = malzemeler/imalat/işleme ($30,000) + kâr ve genel giderler ($6,000) + başka türlü dahil edilmemiş asist ($1,500) + ambalaj ($800) = $38,300. ABD'ye uluslararası navlun, hesaplanmış değerin bir bileşeni değildir. Bkz. 19 CFR 152.106(a) ve (b).","hi":"परिकलित मूल्य = सामग्री/निर्माण/प्रसंस्करण ($30,000) + लाभ और सामान्य खर्च ($6,000) + अन्यथा शामिल न की गई सहायता ($1,500) + पैकिंग ($800) = $38,300। संयुक्त राज्य अमेरिका तक अंतरराष्ट्रीय माल भाड़ा परिकलित मूल्य का एक घटक नहीं है। देखें 19 CFR 152.106(a) और (b)।","ar":"القيمة المحسوبة = المواد/التصنيع/المعالجة ($30,000) + الربح والمصاريف العامة ($6,000) + المساعدة غير المُدرَجة بطريقة أخرى ($1,500) + التعبئة ($800) = $38,300. الشحن الدولي إلى الولايات المتحدة ليس مكوّنًا من مكوّنات القيمة المحسوبة. انظر 19 CFR 152.106(a) و(b)."}},{"cat":"valuation","a":0,"q":{"en":"Under the deductive value method, imported merchandise (not further processed) is appraised based on the price at which it is sold in the United States in the greatest aggregate quantity. Which of the following is a permitted DEDUCTION from that U.S. selling price?","es":"Bajo el método de valor deductivo, la mercancía importada (sin procesamiento adicional) se valúa con base en el precio al que se vende en los Estados Unidos en la mayor cantidad agregada (greatest aggregate quantity). ¿Cuál de los siguientes es una DEDUCCIÓN permitida de ese precio de venta en los EE. UU.?","ru":"При методе дедуктивной стоимости импортированные товары (не подвергнутые дальнейшей обработке) оцениваются на основе цены, по которой они продаются в Соединённых Штатах в наибольшем совокупном количестве. Что из перечисленного является допустимым ВЫЧЕТОМ из этой цены продажи в США?","tr":"İndirgenmiş değer (deductive value) yöntemi kapsamında, ithal mallar (daha fazla işlenmemiş), Amerika Birleşik Devletleri'nde en büyük toplam miktarda satıldığı fiyat temelinde takdir edilir. Aşağıdakilerden hangisi, bu ABD satış fiyatından izin verilen bir İNDİRİMDİR?","hi":"कटौती मूल्य विधि के तहत, आयातित माल (आगे संसाधित नहीं) का मूल्यांकन उस कीमत के आधार पर किया जाता है जिस पर इसे संयुक्त राज्य अमेरिका में सबसे बड़ी कुल मात्रा में बेचा जाता है। निम्नलिखित में से कौन सा उस अमेरिकी विक्रय कीमत से एक अनुमत कटौती है?","ar":"بموجب طريقة القيمة الاستنتاجية، تُقدَّر البضائع المستوردة (غير المعالَجة أكثر) استنادًا إلى السعر الذي تُباع به في الولايات المتحدة بأكبر كمية إجمالية. أي مما يلي هو خصم مسموح به من سعر البيع الأمريكي ذلك؟"},"o":[{"en":"The commissions usually paid, or the usual addition for profit and general expenses, in connection with U.S. sales of merchandise of the same class or kind","es":"Las comisiones usualmente pagadas, o la adición usual por utilidad y gastos generales, en relación con las ventas en los EE. UU. de mercancía de la misma clase o tipo","ru":"Комиссии, обычно уплачиваемые, или обычная надбавка на прибыль и общие расходы в связи с продажами в США товаров того же класса или вида","tr":"Aynı sınıf veya türdeki malların ABD satışlarıyla bağlantılı olarak genellikle ödenen komisyonlar veya kâr ve genel giderler için olağan ilave","hi":"समान वर्ग या प्रकार के माल की अमेरिकी बिक्री के संबंध में आम तौर पर भुगतान किए गए कमीशन, या लाभ और सामान्य खर्चों के लिए सामान्य वृद्धि","ar":"العمولات المدفوعة عادةً، أو الإضافة المعتادة للربح والمصاريف العامة، المتعلقة بالمبيعات الأمريكية لبضائع من الصنف أو النوع نفسه"},{"en":"The cost of the assists the buyer supplied to the foreign producer","es":"El costo de los assists que el comprador suministró al productor extranjero","ru":"Стоимость assists, которые покупатель предоставил иностранному производителю","tr":"Alıcının yabancı üreticiye tedarik ettiği asistlerin (assist) maliyeti","hi":"खरीदार द्वारा विदेशी उत्पादक को आपूर्ति की गई सहायताओं की लागत","ar":"تكلفة المساعدات التي قدّمها المشتري إلى المنتِج الأجنبي"},{"en":"Any royalty the buyer pays to a third party unrelated to the U.S. sale","es":"Cualquier regalía que el comprador pague a un tercero no relacionado con la venta en los EE. UU.","ru":"Любой роялти, который покупатель уплачивает третьей стороне, не связанной с продажей в США","tr":"Alıcının, ABD satışıyla ilişkisi olmayan üçüncü bir tarafa ödediği herhangi bir telif (royalty)","hi":"खरीदार द्वारा अमेरिकी बिक्री से असंबंधित किसी तीसरे पक्ष को भुगतान की गई कोई रॉयल्टी","ar":"أي إتاوة يدفعها المشتري لطرف ثالث غير مرتبط بالبيع الأمريكي"},{"en":"The seller's anticipated profit on future shipments of the merchandise","es":"La utilidad anticipada del vendedor sobre embarques futuros de la mercancía","ru":"Ожидаемая прибыль продавца от будущих поставок товаров","tr":"Satıcının malların gelecekteki sevkiyatlarından beklenen kârı","hi":"माल के भविष्य के शिपमेंट पर विक्रेता का प्रत्याशित लाभ","ar":"ربح البائع المتوقَّع على الشحنات المستقبلية من البضائع"}],"e":{"en":"From the U.S. unit price in the greatest aggregate quantity, deductive value subtracts: commissions usually paid (or the usual profit and general expenses) for that class or kind; transportation and insurance costs; U.S. customs duties and Federal taxes; and (if further processed) the value added by processing. See 19 CFR 152.105(c) and (d).","es":"Del precio unitario en los EE. UU. en la mayor cantidad agregada, el valor deductivo resta: las comisiones usualmente pagadas (o la utilidad y gastos generales usuales) para esa clase o tipo; los costos de transporte y seguro; los derechos aduaneros de los EE. UU. e impuestos federales; y (si hay procesamiento adicional) el valor agregado por el procesamiento. Véase 19 CFR 152.105(c) y (d).","ru":"Из удельной цены в США в наибольшем совокупном количестве дедуктивная стоимость вычитает: комиссии, обычно уплачиваемые (или обычную прибыль и общие расходы) для данного класса или вида; расходы на транспортировку и страхование; таможенные пошлины США и федеральные налоги; и (если товары подвергнуты дальнейшей обработке) стоимость, добавленную обработкой. См. 19 CFR 152.105(c) и (d).","tr":"En büyük toplam miktardaki ABD birim fiyatından, indirgenmiş değer şunları çıkarır: o sınıf veya tür için genellikle ödenen komisyonlar (veya olağan kâr ve genel giderler); taşıma ve sigorta masrafları; ABD gümrük vergileri ve Federal vergiler; ve (daha fazla işlenmişse) işlemeyle eklenen değer. Bkz. 19 CFR 152.105(c) ve (d).","hi":"सबसे बड़ी कुल मात्रा में अमेरिकी इकाई कीमत से, कटौती मूल्य घटाता है: उस वर्ग या प्रकार के लिए आम तौर पर भुगतान किए गए कमीशन (या सामान्य लाभ और सामान्य खर्च); परिवहन और बीमा लागत; अमेरिकी सीमा शुल्क और संघीय कर; और (यदि आगे संसाधित हो) प्रसंस्करण द्वारा जोड़ा गया मूल्य। देखें 19 CFR 152.105(c) और (d)।","ar":"من سعر الوحدة الأمريكي بأكبر كمية إجمالية، تطرح القيمة الاستنتاجية: العمولات المدفوعة عادةً (أو الربح والمصاريف العامة المعتادة) لذلك الصنف أو النوع؛ وتكاليف النقل والتأمين؛ والرسوم الجمركية الأمريكية والضرائب الفيدرالية؛ و(إذا عُولِجت أكثر) القيمة المضافة بالمعالجة. انظر 19 CFR 152.105(c) و(d)."}},{"cat":"valuation","a":2,"q":{"en":"For converting a price stated in foreign currency to U.S. dollars for appraisement, the certified quarterly rate of exchange is generally used. When must the certified daily rate be used instead?","es":"Para convertir un precio expresado en moneda extranjera a dólares estadounidenses para efectos de avalúo, generalmente se usa el tipo de cambio trimestral certificado. ¿Cuándo debe usarse en su lugar el tipo de cambio diario certificado?","ru":"Для пересчёта цены, выраженной в иностранной валюте, в доллары США для целей оценки, как правило, используется удостоверенный квартальный курс обмена. Когда вместо него должен использоваться удостоверенный дневной курс?","tr":"Takdir için yabancı para birimiyle belirtilen bir fiyatı ABD dolarına çevirirken, genellikle onaylı üç aylık (quarterly) döviz kuru kullanılır. Onaylı günlük kur (daily rate) bunun yerine ne zaman kullanılmalıdır?","hi":"मूल्यांकन के लिए विदेशी मुद्रा में बताई गई कीमत को अमेरिकी डॉलर में परिवर्तित करने के लिए, आम तौर पर प्रमाणित त्रैमासिक विनिमय दर का उपयोग किया जाता है। प्रमाणित दैनिक दर का उपयोग इसके बजाय कब किया जाना चाहिए?","ar":"لتحويل سعر مذكور بعملة أجنبية إلى دولارات أمريكية لغرض التقدير، يُستخدَم عمومًا سعر الصرف الفصلي المعتمَد. متى يجب استخدام السعر اليومي المعتمَد بدلًا منه؟"},"o":[{"en":"Whenever the importer requests the daily rate in writing on the entry summary","es":"Siempre que el importador solicite el tipo diario por escrito en el resumen de entrada","ru":"Всякий раз, когда импортёр запрашивает дневной курс в письменной форме в итоговой декларации","tr":"İthalatçı giriş özetinde yazılı olarak günlük kuru talep ettiğinde","hi":"जब भी आयातक एंट्री सारांश पर लिखित रूप में दैनिक दर का अनुरोध करता है","ar":"كلما طلب المستورد السعر اليومي كتابةً على ملخص الإدخال"},{"en":"Only when the merchandise is appraised under computed value rather than transaction value","es":"Solo cuando la mercancía se valúa bajo el valor calculado en lugar del valor de transacción","ru":"Только когда товары оцениваются по расчётной стоимости, а не по стоимости сделки","tr":"Yalnızca mallar işlem değeri yerine hesaplanmış değer kapsamında takdir edildiğinde","hi":"केवल जब माल का मूल्यांकन लेनदेन मूल्य के बजाय परिकलित मूल्य के तहत किया जाता है","ar":"فقط عندما تُقدَّر البضائع بموجب القيمة المحسوبة بدلًا من قيمة المعاملة"},{"en":"When the certified daily rate for the date of exportation varies by 5 percent or more from the certified quarterly rate","es":"Cuando el tipo de cambio diario certificado para la fecha de exportación varía en un 5 por ciento o más respecto del tipo de cambio trimestral certificado","ru":"Когда удостоверенный дневной курс на дату вывоза отличается на 5 процентов или более от удостоверенного квартального курса","tr":"İhracat tarihine ilişkin onaylı günlük kur, onaylı üç aylık kurdan yüzde 5 veya daha fazla farklılık gösterdiğinde","hi":"जब निर्यात की तारीख के लिए प्रमाणित दैनिक दर प्रमाणित त्रैमासिक दर से 5 प्रतिशत या अधिक भिन्न होती है","ar":"عندما يختلف السعر اليومي المعتمَد لتاريخ التصدير بنسبة 5 بالمئة أو أكثر عن السعر الفصلي المعتمَد"},{"en":"When the date of exportation falls on the last business day of the calendar quarter","es":"Cuando la fecha de exportación cae en el último día hábil del trimestre calendario","ru":"Когда дата вывоза приходится на последний рабочий день календарного квартала","tr":"İhracat tarihi takvim çeyreğinin son iş gününe denk geldiğinde","hi":"जब निर्यात की तारीख कैलेंडर तिमाही के अंतिम कार्य दिवस पर पड़ती है","ar":"عندما يقع تاريخ التصدير في آخر يوم عمل من الربع التقويمي"}],"e":{"en":"The certified quarterly rate is used for the quarter, but if the certified daily rate for the date of exportation varies by 5 percent or more from the quarterly rate, the certified daily rate must be used. The conversion date is the date of exportation. See 19 CFR 159.34(b) and 159.32.","es":"El tipo de cambio trimestral certificado se usa para el trimestre, pero si el tipo de cambio diario certificado para la fecha de exportación varía en un 5 por ciento o más respecto del tipo trimestral, debe usarse el tipo de cambio diario certificado. La fecha de conversión es la fecha de exportación. Véase 19 CFR 159.34(b) y 159.32.","ru":"Удостоверенный квартальный курс используется в течение квартала, но если удостоверенный дневной курс на дату вывоза отличается на 5 процентов или более от квартального курса, должен использоваться удостоверенный дневной курс. Датой пересчёта является дата вывоза. См. 19 CFR 159.34(b) и 159.32.","tr":"Onaylı üç aylık kur, ilgili çeyrek için kullanılır, ancak ihracat tarihine ilişkin onaylı günlük kur, üç aylık kurdan yüzde 5 veya daha fazla farklılık gösteriyorsa onaylı günlük kur kullanılmalıdır. Dönüştürme tarihi, ihracat tarihidir. Bkz. 19 CFR 159.34(b) ve 159.32.","hi":"प्रमाणित त्रैमासिक दर का उपयोग उस तिमाही के लिए किया जाता है, लेकिन यदि निर्यात की तारीख के लिए प्रमाणित दैनिक दर त्रैमासिक दर से 5 प्रतिशत या अधिक भिन्न होती है, तो प्रमाणित दैनिक दर का उपयोग किया जाना चाहिए। रूपांतरण तिथि निर्यात की तारीख है। देखें 19 CFR 159.34(b) और 159.32।","ar":"يُستخدَم السعر الفصلي المعتمَد للربع، لكن إذا اختلف السعر اليومي المعتمَد لتاريخ التصدير بنسبة 5 بالمئة أو أكثر عن السعر الفصلي، فيجب استخدام السعر اليومي المعتمَد. وتاريخ التحويل هو تاريخ التصدير. انظر 19 CFR 159.34(b) و159.32."}},{"cat":"valuation","a":3,"q":{"en":"A buyer supplies a special tool to its foreign producer free of charge. The tool cost the buyer $24,000 and is expected to be used to produce 8,000 units total. The current entry covers 2,000 of those units. If the entire tool value is apportioned over the total expected production, what assist value should be added to this entry's transaction value?","es":"Un comprador suministra una herramienta especial a su productor extranjero gratuitamente. La herramienta le costó al comprador $24,000 y se espera que se use para producir 8,000 unidades en total. La entrada actual cubre 2,000 de esas unidades. Si el valor total de la herramienta se prorratea sobre la producción total esperada, ¿qué valor de assist debe sumarse al valor de transacción de esta entrada?","ru":"Покупатель предоставляет специальный инструмент своему иностранному производителю бесплатно. Инструмент обошёлся покупателю в $24,000 и, как ожидается, будет использоваться для производства в общей сложности 8,000 единиц. Текущая декларация охватывает 2,000 из этих единиц. Если вся стоимость инструмента распределяется на весь ожидаемый объём производства, какая стоимость assist должна быть добавлена к стоимости сделки по этой декларации?","tr":"Bir alıcı, yabancı üreticisine özel bir takımı ücretsiz olarak tedarik eder. Takım alıcıya $24,000'a mal olmuştur ve toplamda 8,000 birim üretmek için kullanılması beklenmektedir. Mevcut giriş, bu birimlerin 2,000'ini kapsamaktadır. Takımın tüm değeri toplam beklenen üretime tahsis edilirse, bu girişin işlem değerine hangi asist (assist) değeri eklenmelidir?","hi":"एक खरीदार अपने विदेशी उत्पादक को मुफ्त में एक विशेष उपकरण आपूर्ति करता है। उपकरण की खरीदार को $24,000 लागत आई और इसका उपयोग कुल 8,000 इकाइयों के उत्पादन के लिए होने की उम्मीद है। वर्तमान एंट्री उन इकाइयों में से 2,000 को कवर करती है। यदि संपूर्ण उपकरण मूल्य को कुल अपेक्षित उत्पादन पर आबंटित किया जाए, तो इस एंट्री के लेनदेन मूल्य में कौन सा सहायता मूल्य जोड़ा जाना चाहिए?","ar":"يقدّم مشترٍ أداة خاصة إلى منتِجه الأجنبي مجانًا. كلّفت الأداة المشتري $24,000 ومن المتوقَّع استخدامها لإنتاج 8,000 وحدة إجمالًا. يغطّي الإدخال الحالي 2,000 من تلك الوحدات. إذا وُزِّعت قيمة الأداة كاملةً على إجمالي الإنتاج المتوقَّع، ما هي قيمة المساعدة التي ينبغي إضافتها إلى قيمة المعاملة لهذا الإدخال؟"},"o":[{"en":"$3,000","es":"$3,000","ru":"$3,000","tr":"$3,000","hi":"$3,000","ar":"$3,000"},{"en":"$12,000","es":"$12,000","ru":"$12,000","tr":"$12,000","hi":"$12,000","ar":"$12,000"},{"en":"$24,000","es":"$24,000","ru":"$24,000","tr":"$24,000","hi":"$24,000","ar":"$24,000"},{"en":"$6,000","es":"$6,000","ru":"$6,000","tr":"$6,000","hi":"$6,000","ar":"$6,000"}],"e":{"en":"The value of an assist is apportioned to the imported merchandise in a reasonable manner. Per unit = $24,000 / 8,000 = $3 per unit; for 2,000 units = $6,000. See 19 CFR 152.103(b)(1)(iii) and 152.103(e) (apportionment of assist value).","es":"El valor de un assist se prorratea a la mercancía importada de manera razonable. Por unidad = $24,000 / 8,000 = $3 por unidad; para 2,000 unidades = $6,000. Véase 19 CFR 152.103(b)(1)(iii) y 152.103(e) (prorrateo del valor del assist).","ru":"Стоимость assist распределяется на импортированные товары разумным образом. На единицу = $24,000 / 8,000 = $3 за единицу; для 2,000 единиц = $6,000. См. 19 CFR 152.103(b)(1)(iii) и 152.103(e) (распределение стоимости assist).","tr":"Bir asistin (assist) değeri, ithal mallara makul bir şekilde tahsis edilir. Birim başına = $24,000 / 8,000 = birim başına $3; 2,000 birim için = $6,000. Bkz. 19 CFR 152.103(b)(1)(iii) ve 152.103(e) (asist değerinin tahsisi).","hi":"एक सहायता (assist) का मूल्य आयातित माल को उचित तरीके से आबंटित किया जाता है। प्रति इकाई = $24,000 / 8,000 = $3 प्रति इकाई; 2,000 इकाइयों के लिए = $6,000। देखें 19 CFR 152.103(b)(1)(iii) और 152.103(e) (सहायता मूल्य का आबंटन)।","ar":"تُوزَّع قيمة المساعدة على البضائع المستوردة بطريقة معقولة. لكل وحدة = $24,000 / 8,000 = $3 للوحدة؛ ولـ 2,000 وحدة = $6,000. انظر 19 CFR 152.103(b)(1)(iii) و152.103(e) (توزيع قيمة المساعدة)."}},{"cat":"valuation","a":0,"q":{"en":"A royalty or license fee paid by the buyer is added to the price actually paid or payable in determining transaction value ONLY when:","es":"Una regalía o derecho de licencia pagado por el comprador se suma al precio realmente pagado o por pagar al determinar el valor de transacción SOLO cuando:","ru":"Роялти или лицензионный платёж, уплачиваемый покупателем, добавляется к цене, фактически уплаченной или подлежащей уплате, при определении стоимости сделки ТОЛЬКО когда:","tr":"Alıcı tarafından ödenen bir telif (royalty) veya lisans ücreti, işlem değeri (transaction value) belirlenirken fiilen ödenen veya ödenecek fiyata YALNIZCA hangi durumda eklenir?","hi":"खरीदार द्वारा भुगतान की गई एक रॉयल्टी या लाइसेंस शुल्क लेनदेन मूल्य निर्धारित करने में वास्तव में भुगतान की गई या देय कीमत में केवल तभी जोड़ी जाती है जब:","ar":"تُضاف الإتاوة أو رسم الترخيص الذي يدفعه المشتري إلى السعر المدفوع فعليًا أو المستحَق الدفع عند تحديد قيمة المعاملة فقط عندما:"},"o":[{"en":"The buyer is required to pay it, directly or indirectly, as a condition of the sale of the imported merchandise for exportation to the United States","es":"El comprador está obligado a pagarlo, directa o indirectamente, como condición de la venta de la mercancía importada para exportación a los Estados Unidos","ru":"Покупатель обязан уплатить его, прямо или косвенно, как условие продажи импортированных товаров на экспорт в Соединённые Штаты","tr":"Alıcının, malların Amerika Birleşik Devletleri'ne ihracat için satışının bir koşulu olarak bunu doğrudan veya dolaylı olarak ödemesi gerektiğinde","hi":"खरीदार को इसका भुगतान, प्रत्यक्ष या अप्रत्यक्ष रूप से, संयुक्त राज्य अमेरिका को निर्यात के लिए आयातित माल की बिक्री की शर्त के रूप में करना आवश्यक हो","ar":"يكون المشتري ملزَمًا بدفعها، بشكل مباشر أو غير مباشر، كشرط لبيع البضائع المستوردة للتصدير إلى الولايات المتحدة"},{"en":"The royalty is paid to any third party, regardless of its relationship to the sale","es":"La regalía se paga a cualquier tercero, independientemente de su relación con la venta","ru":"Роялти уплачивается любой третьей стороне, независимо от её связи с продажей","tr":"Telifin, satışla ilişkisine bakılmaksızın herhangi bir üçüncü tarafa ödenmesi durumunda","hi":"रॉयल्टी किसी भी तीसरे पक्ष को भुगतान की जाती है, बिक्री से उसके संबंध की परवाह किए बिना","ar":"تُدفَع الإتاوة لأي طرف ثالث، بصرف النظر عن علاقته بالبيع"},{"en":"The royalty represents a charge for the right to reproduce the merchandise in the United States","es":"La regalía representa un cargo por el derecho a reproducir la mercancía en los Estados Unidos","ru":"Роялти представляет собой плату за право воспроизводить товары в Соединённых Штатах","tr":"Telifin, malları Amerika Birleşik Devletleri'nde çoğaltma hakkı için bir bedel temsil etmesi durumunda","hi":"रॉयल्टी संयुक्त राज्य अमेरिका में माल को पुनरुत्पादित करने के अधिकार के लिए एक शुल्क का प्रतिनिधित्व करती है","ar":"تمثّل الإتاوة رسمًا مقابل حق إعادة إنتاج البضائع في الولايات المتحدة"},{"en":"The royalty is paid in U.S. dollars rather than in foreign currency","es":"La regalía se paga en dólares estadounidenses en lugar de en moneda extranjera","ru":"Роялти уплачивается в долларах США, а не в иностранной валюте","tr":"Telifin yabancı para birimi yerine ABD doları olarak ödenmesi durumunda","hi":"रॉयल्टी विदेशी मुद्रा के बजाय अमेरिकी डॉलर में भुगतान की जाती है","ar":"تُدفَع الإتاوة بالدولار الأمريكي بدلًا من العملة الأجنبية"}],"e":{"en":"A royalty or license fee is added only when the buyer is required to pay it, directly or indirectly, as a condition of the sale of the imported merchandise for exportation to the U.S. Charges for the right to reproduce the merchandise in the U.S. are specifically not added. See 19 CFR 152.103(b)(1)(iv) and 152.103(c).","es":"Una regalía o derecho de licencia se suma solo cuando el comprador está obligado a pagarlo, directa o indirectamente, como condición de la venta de la mercancía importada para exportación a los EE. UU. Los cargos por el derecho a reproducir la mercancía en los EE. UU. específicamente no se suman. Véase 19 CFR 152.103(b)(1)(iv) y 152.103(c).","ru":"Роялти или лицензионный платёж добавляется только тогда, когда покупатель обязан уплатить его, прямо или косвенно, как условие продажи импортированных товаров на экспорт в США. Платежи за право воспроизводить товары в США специально не добавляются. См. 19 CFR 152.103(b)(1)(iv) и 152.103(c).","tr":"Bir telif (royalty) veya lisans ücreti yalnızca, alıcının malların Amerika Birleşik Devletleri'ne ihracat için satışının bir koşulu olarak bunu doğrudan veya dolaylı olarak ödemesi gerektiğinde eklenir. Malları Amerika Birleşik Devletleri'nde çoğaltma hakkı için olan bedeller özellikle eklenmez. Bkz. 19 CFR 152.103(b)(1)(iv) ve 152.103(c).","hi":"एक रॉयल्टी या लाइसेंस शुल्क केवल तभी जोड़ा जाता है जब खरीदार को इसका भुगतान, प्रत्यक्ष या अप्रत्यक्ष रूप से, संयुक्त राज्य अमेरिका को निर्यात के लिए आयातित माल की बिक्री की शर्त के रूप में करना आवश्यक हो। संयुक्त राज्य अमेरिका में माल को पुनरुत्पादित करने के अधिकार के लिए शुल्क विशेष रूप से नहीं जोड़े जाते। देखें 19 CFR 152.103(b)(1)(iv) और 152.103(c)।","ar":"تُضاف الإتاوة أو رسم الترخيص فقط عندما يكون المشتري ملزَمًا بدفعها، بشكل مباشر أو غير مباشر، كشرط لبيع البضائع المستوردة للتصدير إلى الولايات المتحدة. أما الرسوم مقابل حق إعادة إنتاج البضائع في الولايات المتحدة فلا تُضاف تحديدًا. انظر 19 CFR 152.103(b)(1)(iv) و152.103(c)."}},{"cat":"duties","a":0,"q":{"en":"An importer enters a shipment of goods that are a product of a country with which the United States has normal trade relations and no special trade-program eligibility. Which column of the Harmonized Tariff Schedule of the United States supplies the applicable duty rate?","es":"Un importador declara un embarque de mercancías que son producto de un país con el cual Estados Unidos mantiene relaciones comerciales normales y sin elegibilidad para ningún programa comercial especial. ¿Qué columna del Harmonized Tariff Schedule of the United States (HTSUS) suministra la tasa de derechos aplicable?","ru":"Импортер оформляет ввоз партии товаров, произведенных в стране, с которой Соединенные Штаты имеют нормальные торговые отношения и которая не имеет права на участие в каких-либо специальных торговых программах. Какая колонка Гармонизированного тарифного расписания США (HTSUS) задает применимую ставку пошлины?","tr":"Bir ithalatçı, Amerika Birleşik Devletleri'nin normal ticari ilişkilere sahip olduğu ve herhangi bir özel ticaret programı uygunluğu bulunmayan bir ülkenin ürünü olan bir sevkiyatı beyan ediyor. Uygulanacak vergi oranı, Harmonized Tariff Schedule of the United States (HTSUS) tarifesinin hangi sütunundan alınır?","hi":"एक आयातकर्ता ऐसे माल की एंट्री करता है जो किसी ऐसे देश का उत्पाद है जिसके साथ संयुक्त राज्य अमेरिका के सामान्य व्यापार संबंध (normal trade relations) हैं और जिसकी किसी विशेष व्यापार-कार्यक्रम के लिए कोई पात्रता नहीं है। Harmonized Tariff Schedule of the United States का कौन-सा कॉलम लागू शुल्क दर प्रदान करता है?","ar":"يُدخل مستورد شحنة من البضائع التي تُعدّ منتجاً لبلد تربطه بالولايات المتحدة علاقات تجارية طبيعية ولا يتمتع بأهلية للاستفادة من أي برنامج تجاري خاص. أي عمود من جدول التعريفة المنسّق للولايات المتحدة (HTSUS) يحدّد معدل الرسوم المطبّق؟"},"o":[{"en":"Column 1, General subcolumn","es":"Columna 1, subcolumna General","ru":"Колонка 1, подколонка General (Общая)","tr":"Column 1, General alt sütunu","hi":"Column 1, General उपकॉलम","ar":"Column 1, العمود الفرعي General"},{"en":"Column 1, Special subcolumn","es":"Columna 1, subcolumna Special","ru":"Колонка 1, подколонка Special (Специальная)","tr":"Column 1, Special alt sütunu","hi":"Column 1, Special उपकॉलम","ar":"Column 1, العمود الفرعي Special"},{"en":"Column 2","es":"Columna 2","ru":"Колонка 2","tr":"Column 2","hi":"Column 2","ar":"Column 2"},{"en":"Whichever of Column 1 General or Column 2 is lower","es":"La que sea menor entre la Columna 1 General o la Columna 2","ru":"Та из Колонки 1 General или Колонки 2, которая ниже","tr":"Column 1 General veya Column 2'den hangisi daha düşükse o","hi":"Column 1 General या Column 2 में से जो भी कम हो","ar":"أيٌّ من Column 1 General أو Column 2 يكون أقل"}],"e":{"en":"The Column 1 General (normal trade relations / most-favored-nation) rate applies to products of countries with NTR status that do not qualify for a Special program. The Column 1 Special subcolumn applies only when a specific preference program (e.g., USMCA, GSP) is claimed and met, and Column 2 applies to products of a short list of countries denied NTR (e.g., Cuba, North Korea). See HTSUS General Notes 3(a) and (b).","es":"La tasa de la Columna 1 General (relaciones comerciales normales / nación más favorecida) se aplica a los productos de países con estatus NTR que no califican para un programa Special. La subcolumna Special de la Columna 1 se aplica únicamente cuando se reclama y se cumple un programa de preferencia específico (por ejemplo, USMCA, GSP), y la Columna 2 se aplica a los productos de una breve lista de países a los que se les niega el estatus NTR (por ejemplo, Cuba, Corea del Norte). Véanse las General Notes 3(a) y (b) del HTSUS.","ru":"Ставка Колонки 1 General (нормальные торговые отношения / режим наибольшего благоприятствования) применяется к товарам стран со статусом NTR, которые не имеют права на участие в Специальной программе. Подколонка Колонки 1 Special применяется только тогда, когда заявляется и подтверждается конкретная преференциальная программа (например, USMCA, GSP), а Колонка 2 применяется к товарам короткого перечня стран, лишенных статуса NTR (например, Куба, Северная Корея). См. HTSUS General Notes 3(a) и (b).","tr":"Column 1 General (normal ticari ilişkiler / en çok kayrılan ülke) oranı, NTR statüsüne sahip olan ancak bir Special programa hak kazanmayan ülkelerin ürünlerine uygulanır. Column 1 Special alt sütunu yalnızca belirli bir tercih programı (örneğin USMCA, GSP) talep edildiğinde ve şartları karşılandığında geçerlidir; Column 2 ise NTR'den mahrum bırakılmış kısa bir ülke listesinin (örneğin Küba, Kuzey Kore) ürünlerine uygulanır. Bakınız HTSUS General Notes 3(a) ve (b).","hi":"Column 1 General (normal trade relations / most-favored-nation) दर उन देशों के उत्पादों पर लागू होती है जिनकी NTR स्थिति है और जो किसी Special कार्यक्रम के लिए पात्र नहीं हैं। Column 1 Special उपकॉलम केवल तभी लागू होता है जब कोई विशिष्ट वरीयता कार्यक्रम (जैसे USMCA, GSP) का दावा किया जाए और वह पूरा हो, और Column 2 उन कुछ चुनिंदा देशों के उत्पादों पर लागू होता है जिन्हें NTR से वंचित किया गया है (जैसे Cuba, North Korea)। देखें HTSUS General Notes 3(a) और (b)।","ar":"ينطبق معدل Column 1 General (العلاقات التجارية الطبيعية / الدولة الأولى بالرعاية) على منتجات البلدان التي تتمتع بوضع NTR والتي لا تستوفي شروط برنامج Special. ولا ينطبق العمود الفرعي Column 1 Special إلا عند المطالبة باستيفاء شروط برنامج تفضيلي محدد (مثل USMCA أو GSP). أما Column 2 فينطبق على منتجات قائمة قصيرة من البلدان المحرومة من وضع NTR (مثل كوبا وكوريا الشمالية). انظر HTSUS General Notes 3(a) و(b)."}},{"cat":"duties","a":3,"q":{"en":"Goods are classified under a tariff provision carrying a Column 1 General rate of \"6.5%.\" The merchandise has an appraised (entered) value of forty thousand dollars. What is the estimated ad valorem duty?","es":"Las mercancías se clasifican bajo una disposición arancelaria que tiene una tasa de la Columna 1 General de \"6.5%\". La mercancía tiene un valor avaluado (declarado) de cuarenta mil dólares. ¿Cuál es el derecho ad valorem estimado?","ru":"Товары классифицируются по тарифной позиции со ставкой Колонки 1 General \"6.5%\". Оцененная (заявленная) стоимость товара составляет сорок тысяч долларов. Какова расчетная адвалорная пошлина?","tr":"Mallar, Column 1 General oranı \"%6.5\" olan bir tarife hükmü altında sınıflandırılmıştır. Malların kıymeti (beyan edilen değeri) kırk bin dolardır. Tahmini ad valorem gümrük vergisi nedir?","hi":"माल को एक ऐसे टैरिफ प्रावधान के अंतर्गत वर्गीकृत किया गया है जिसकी Column 1 General दर \"6.5%\" है। माल का मूल्यांकित (एंटर किया गया) मूल्य चालीस हजार डॉलर है। अनुमानित ad valorem शुल्क क्या है?","ar":"تُصنَّف بضائع بموجب بند تعريفي يحمل معدل Column 1 General قدره \"6.5%\". تبلغ القيمة المقدَّرة (المُدخَلة) للبضاعة أربعين ألف دولار. ما هو الرسم القيمي التقديري؟"},"o":[{"en":"Two thousand four hundred dollars","es":"Dos mil cuatrocientos dólares","ru":"Две тысячи четыреста долларов","tr":"İki bin dört yüz dolar","hi":"दो हजार चार सौ डॉलर","ar":"ألفان وأربعمئة دولار"},{"en":"Two thousand five hundred ninety dollars","es":"Dos mil quinientos noventa dólares","ru":"Две тысячи пятьсот девяносто долларов","tr":"İki bin beş yüz doksan dolar","hi":"दो हजार पाँच सौ नब्बे डॉलर","ar":"ألفان وخمسمئة وتسعون دولاراً"},{"en":"Two thousand seven hundred sixty dollars","es":"Dos mil setecientos sesenta dólares","ru":"Две тысячи семьсот шестьдесят долларов","tr":"İki bin yedi yüz altmış dolar","hi":"दो हजार सात सौ साठ डॉलर","ar":"ألفان وسبعمئة وستون دولاراً"},{"en":"Two thousand six hundred dollars","es":"Dos mil seiscientos dólares","ru":"Две тысячи шестьсот долларов","tr":"İki bin altı yüz dolar","hi":"दो हजार छह सौ डॉलर","ar":"ألفان وستمئة دولار"}],"e":{"en":"An ad valorem duty is a percentage of the entered value. $40,000 x 0.065 = $2,600. Ad valorem rates are applied to the customs (transaction) value under 19 U.S.C. 1401a; the rate column is set by HTSUS General Note 3.","es":"Un derecho ad valorem es un porcentaje del valor declarado. $40,000 x 0.065 = $2,600. Las tasas ad valorem se aplican al valor aduanero (valor de transacción) conforme a 19 U.S.C. 1401a; la columna de tasa se establece según la General Note 3 del HTSUS.","ru":"Адвалорная пошлина представляет собой процент от заявленной стоимости. $40,000 x 0.065 = $2,600. Адвалорные ставки применяются к таможенной стоимости (стоимости сделки) согласно 19 U.S.C. 1401a; колонка ставок определяется HTSUS General Note 3.","tr":"Ad valorem gümrük vergisi, beyan edilen değerin bir yüzdesidir. $40,000 x 0.065 = $2,600. Ad valorem oranları, 19 U.S.C. 1401a uyarınca gümrük (işlem) değerine uygulanır; oran sütunu ise HTSUS General Note 3 tarafından belirlenir.","hi":"ad valorem शुल्क एंटर किए गए मूल्य का एक प्रतिशत होता है। $40,000 x 0.065 = $2,600। ad valorem दरें 19 U.S.C. 1401a के तहत कस्टम (लेनदेन) मूल्य पर लागू की जाती हैं; दर कॉलम HTSUS General Note 3 द्वारा निर्धारित होता है।","ar":"الرسم القيمي هو نسبة مئوية من القيمة المُدخَلة. ‎$40,000 x 0.065 = $2,600‎. تُطبَّق المعدلات القيمية على القيمة الجمركية (قيمة المعاملة) بموجب 19 U.S.C. 1401a؛ ويُحدَّد عمود المعدل بموجب HTSUS General Note 3."}},{"cat":"duties","a":2,"q":{"en":"A tariff provision reads \"4.8 cents per liter.\" An importer enters two thousand liters of the product, which has an entered value of nine thousand dollars. What is the duty owed, and what type of rate is this?","es":"Una disposición arancelaria indica \"4.8 cents per liter\". Un importador declara dos mil litros del producto, que tiene un valor declarado de nueve mil dólares. ¿Cuál es el derecho adeudado y qué tipo de tasa es esta?","ru":"Тарифная позиция гласит \"4.8 cents per liter\" (4,8 цента за литр). Импортер оформляет ввоз двух тысяч литров продукта, заявленная стоимость которого составляет девять тысяч долларов. Какова сумма причитающейся пошлины и какой это тип ставки?","tr":"Bir tarife hükmü \"litre başına 4.8 sent\" şeklindedir. Bir ithalatçı, beyan edilen değeri dokuz bin dolar olan üründen iki bin litre beyan ediyor. Ödenecek gümrük vergisi ne kadardır ve bu hangi tür bir orandır?","hi":"एक टैरिफ प्रावधान में लिखा है \"4.8 cents per liter\"। एक आयातकर्ता उत्पाद के दो हजार लीटर की एंट्री करता है, जिसका एंटर किया गया मूल्य नौ हजार डॉलर है। देय शुल्क क्या है, और यह किस प्रकार की दर है?","ar":"ينصّ بند تعريفي على \"4.8 cents per liter\". يُدخل مستورد ألفي لتر من المنتج، وتبلغ قيمته المُدخَلة تسعة آلاف دولار. ما هو الرسم المستحق، وما نوع هذا المعدل؟"},"o":[{"en":"Four hundred thirty-two dollars; an ad valorem duty","es":"Cuatrocientos treinta y dos dólares; un derecho ad valorem","ru":"Четыреста тридцать два доллара; адвалорная пошлина","tr":"Dört yüz otuz iki dolar; ad valorem gümrük vergisi","hi":"चार सौ बत्तीस डॉलर; एक ad valorem शुल्क","ar":"أربعمئة واثنان وثلاثون دولاراً؛ رسم قيمي"},{"en":"Ninety-six dollars; a compound duty","es":"Noventa y seis dólares; un derecho compuesto","ru":"Девяносто шесть долларов; комбинированная (compound) пошлина","tr":"Doksan altı dolar; bileşik (compound) gümrük vergisi","hi":"छियानवे डॉलर; एक संयुक्त (compound) शुल्क","ar":"ستة وتسعون دولاراً؛ رسم مركّب"},{"en":"Ninety-six dollars; a specific duty","es":"Noventa y seis dólares; un derecho específico","ru":"Девяносто шесть долларов; специфическая пошлина","tr":"Doksan altı dolar; spesifik (specific) gümrük vergisi","hi":"छियानवे डॉलर; एक विशिष्ट (specific) शुल्क","ar":"ستة وتسعون دولاراً؛ رسم نوعي"},{"en":"Four hundred thirty-two dollars; a specific duty","es":"Cuatrocientos treinta y dos dólares; un derecho específico","ru":"Четыреста тридцать два доллара; специфическая пошлина","tr":"Dört yüz otuz iki dolar; spesifik (specific) gümrük vergisi","hi":"चार सौ बत्तीस डॉलर; एक विशिष्ट (specific) शुल्क","ar":"أربعمئة واثنان وثلاثون دولاراً؛ رسم نوعي"}],"e":{"en":"A specific duty is assessed on a unit of quantity (here, per liter) regardless of value. 2,000 liters x $0.048 = $96.00. Value is irrelevant to a pure specific rate. See HTSUS General Statistical Note 4 and the rates of duty in the HTSUS.","es":"Un derecho específico se calcula sobre una unidad de cantidad (aquí, por litro) independientemente del valor. 2,000 litros x $0.048 = $96.00. El valor es irrelevante para una tasa específica pura. Véanse la General Statistical Note 4 del HTSUS y las tasas de derechos del HTSUS.","ru":"Специфическая пошлина начисляется на единицу количества (здесь — за литр) независимо от стоимости. 2,000 литров x $0.048 = $96.00. Стоимость не имеет значения для чисто специфической ставки. См. HTSUS General Statistical Note 4 и ставки пошлин в HTSUS.","tr":"Spesifik gümrük vergisi, değerden bağımsız olarak bir miktar birimi (burada litre başına) üzerinden tahakkuk ettirilir. 2,000 litre x $0.048 = $96.00. Saf bir spesifik oran için değer önemsizdir. Bakınız HTSUS General Statistical Note 4 ve HTSUS'taki vergi oranları.","hi":"विशिष्ट (specific) शुल्क मात्रा की इकाई पर (यहाँ, प्रति लीटर) मूल्य की परवाह किए बिना लगाया जाता है। 2,000 लीटर x $0.048 = $96.00। शुद्ध विशिष्ट दर के लिए मूल्य अप्रासंगिक है। देखें HTSUS General Statistical Note 4 और HTSUS में शुल्क की दरें।","ar":"يُفرض الرسم النوعي على وحدة من الكمية (هنا، لكل لتر) بصرف النظر عن القيمة. ‎2,000 liters x $0.048 = $96.00‎. القيمة غير ذات صلة بالمعدل النوعي الخالص. انظر HTSUS General Statistical Note 4 ومعدلات الرسوم في HTSUS."}},{"cat":"duties","a":1,"q":{"en":"A provision carries a compound rate of \"12% + 30 cents per kilogram.\" An importer enters a shipment with an entered value of ten thousand dollars and a net weight of five hundred kilograms. What is the total estimated duty?","es":"Una disposición lleva una tasa compuesta de \"12% + 30 cents per kilogram\". Un importador declara un embarque con un valor declarado de diez mil dólares y un peso neto de quinientos kilogramos. ¿Cuál es el derecho total estimado?","ru":"Позиция имеет комбинированную (compound) ставку \"12% + 30 cents per kilogram\" (12% + 30 центов за килограмм). Импортер оформляет ввоз партии с заявленной стоимостью десять тысяч долларов и чистым весом пятьсот килограммов. Какова общая расчетная пошлина?","tr":"Bir hüküm, \"%12 + kilogram başına 30 sent\" şeklinde bir bileşik (compound) oran taşımaktadır. Bir ithalatçı, beyan edilen değeri on bin dolar ve net ağırlığı beş yüz kilogram olan bir sevkiyat beyan ediyor. Toplam tahmini gümrük vergisi nedir?","hi":"एक प्रावधान में \"12% + 30 cents per kilogram\" की संयुक्त (compound) दर है। एक आयातकर्ता ऐसे माल की एंट्री करता है जिसका एंटर किया गया मूल्य दस हजार डॉलर और शुद्ध वजन पाँच सौ किलोग्राम है। कुल अनुमानित शुल्क क्या है?","ar":"يحمل بند معدلاً مركّباً قدره \"12% + 30 cents per kilogram\". يُدخل مستورد شحنة قيمتها المُدخَلة عشرة آلاف دولار ووزنها الصافي خمسمئة كيلوغرام. ما هو إجمالي الرسم التقديري؟"},"o":[{"en":"One thousand two hundred dollars","es":"Mil doscientos dólares","ru":"Одна тысяча двести долларов","tr":"Bin iki yüz dolar","hi":"एक हजार दो सौ डॉलर","ar":"ألف ومئتا دولار"},{"en":"One thousand three hundred fifty dollars","es":"Mil trescientos cincuenta dólares","ru":"Одна тысяча триста пятьдесят долларов","tr":"Bin üç yüz elli dolar","hi":"एक हजार तीन सौ पचास डॉलर","ar":"ألف وثلاثمئة وخمسون دولاراً"},{"en":"One thousand five hundred dollars","es":"Mil quinientos dólares","ru":"Одна тысяча пятьсот долларов","tr":"Bin beş yüz dolar","hi":"एक हजार पाँच सौ डॉलर","ar":"ألف وخمسمئة دولار"},{"en":"One thousand three hundred twenty dollars","es":"Mil trescientos veinte dólares","ru":"Одна тысяча триста двадцать долларов","tr":"Bin üç yüz yirmi dolar","hi":"एक हजार तीन सौ बीस डॉलर","ar":"ألف وثلاثمئة وعشرون دولاراً"}],"e":{"en":"A compound duty combines an ad valorem and a specific component. Ad valorem: $10,000 x 0.12 = $1,200. Specific: 500 kg x $0.30 = $150. Total = $1,350. Both components are added together. See the HTSUS rates of duty columns.","es":"Un derecho compuesto combina un componente ad valorem y uno específico. Ad valorem: $10,000 x 0.12 = $1,200. Específico: 500 kg x $0.30 = $150. Total = $1,350. Ambos componentes se suman. Véanse las columnas de tasas de derechos del HTSUS.","ru":"Комбинированная (compound) пошлина сочетает адвалорную и специфическую составляющие. Адвалорная: $10,000 x 0.12 = $1,200. Специфическая: 500 kg x $0.30 = $150. Итого = $1,350. Обе составляющие складываются. См. колонки ставок пошлин HTSUS.","tr":"Bileşik (compound) gümrük vergisi, bir ad valorem ve bir spesifik bileşeni birleştirir. Ad valorem: $10,000 x 0.12 = $1,200. Spesifik: 500 kg x $0.30 = $150. Toplam = $1,350. Her iki bileşen birbirine eklenir. Bakınız HTSUS vergi oranları sütunları.","hi":"संयुक्त (compound) शुल्क एक ad valorem और एक विशिष्ट घटक को जोड़ता है। ad valorem: $10,000 x 0.12 = $1,200। विशिष्ट: 500 kg x $0.30 = $150। कुल = $1,350। दोनों घटकों को एक साथ जोड़ा जाता है। देखें HTSUS शुल्क-दर कॉलम।","ar":"يجمع الرسم المركّب بين مكوّن قيمي ومكوّن نوعي. القيمي: ‎$10,000 x 0.12 = $1,200‎. النوعي: ‎500 kg x $0.30 = $150‎. الإجمالي = ‎$1,350‎. يُجمع المكوّنان معاً. انظر أعمدة معدلات الرسوم في HTSUS."}},{"cat":"duties","a":3,"q":{"en":"A formally entered shipment has an entered value of one hundred thousand dollars. Using the current ad valorem merchandise processing fee (MPF) rate, what MPF is owed?","es":"Un embarque declarado formalmente tiene un valor declarado de cien mil dólares. Usando la tasa ad valorem actual del merchandise processing fee (MPF), ¿qué MPF se adeuda?","ru":"Официально оформленная партия имеет заявленную стоимость сто тысяч долларов. С использованием текущей адвалорной ставки сбора за обработку товаров (MPF), какой MPF причитается?","tr":"Resmi olarak beyan edilen bir sevkiyatın beyan edilen değeri yüz bin dolardır. Güncel ad valorem merchandise processing fee (MPF) oranı kullanıldığında, ödenecek MPF ne kadardır?","hi":"औपचारिक रूप से एंटर किए गए माल का एंटर किया गया मूल्य एक लाख डॉलर है। वर्तमान ad valorem merchandise processing fee (MPF) दर का उपयोग करते हुए, कितना MPF देय है?","ar":"شحنة مُدخلة رسمياً قيمتها المُدخَلة مئة ألف دولار. باستخدام المعدل القيمي الحالي لرسم معالجة البضائع (MPF)، ما هو MPF المستحق؟"},"o":[{"en":"Three hundred thirty-three dollars and ninety cents","es":"Trescientos treinta y tres dólares con noventa centavos","ru":"Триста тридцать три доллара и девяносто центов","tr":"Üç yüz otuz üç dolar doksan sent","hi":"तीन सौ तैंतीस डॉलर और नब्बे सेंट","ar":"ثلاثمئة وثلاثة وثلاثون دولاراً وتسعون سنتاً"},{"en":"Six hundred fifty-one dollars and fifty cents","es":"Seiscientos cincuenta y un dólares con cincuenta centavos","ru":"Шестьсот пятьдесят один доллар и пятьдесят центов","tr":"Altı yüz elli bir dolar elli sent","hi":"छह सौ इक्यावन डॉलर और पचास सेंट","ar":"ستمئة وواحد وخمسون دولاراً وخمسون سنتاً"},{"en":"One hundred twenty-five dollars","es":"Ciento veinticinco dólares","ru":"Сто двадцать пять долларов","tr":"Yüz yirmi beş dolar","hi":"एक सौ पच्चीस डॉलर","ar":"مئة وخمسة وعشرون دولاراً"},{"en":"Three hundred forty-six dollars and forty cents","es":"Trescientos cuarenta y seis dólares con cuarenta centavos","ru":"Триста сорок шесть долларов и сорок центов","tr":"Üç yüz kırk altı dolar kırk sent","hi":"तीन सौ छियालीस डॉलर और चालीस सेंट","ar":"ثلاثمئة وستة وأربعون دولاراً وأربعون سنتاً"}],"e":{"en":"The MPF for formal entries is 0.3464% of the entered value, subject to a minimum and maximum. $100,000 x 0.003464 = $346.40, which falls between the FY2026 minimum of $33.58 and maximum of $651.50, so the calculated amount applies. See 19 CFR 24.23(b)(1).","es":"El MPF para las entradas formales es 0.3464% del valor declarado, sujeto a un mínimo y un máximo. $100,000 x 0.003464 = $346.40, que se encuentra entre el mínimo del FY2026 de $33.58 y el máximo de $651.50, por lo que se aplica el monto calculado. Véase 19 CFR 24.23(b)(1).","ru":"MPF для официальных оформлений (formal entries) составляет 0.3464% от заявленной стоимости, с учетом минимума и максимума. $100,000 x 0.003464 = $346.40, что находится между минимумом FY2026 в $33.58 и максимумом $651.50, поэтому применяется рассчитанная сумма. См. 19 CFR 24.23(b)(1).","tr":"Resmi beyanlar için MPF, beyan edilen değerin %0.3464'üdür ve bir asgari ile azami tutara tabidir. $100,000 x 0.003464 = $346.40; bu tutar FY2026 asgari değeri olan $33.58 ile azami değeri olan $651.50 arasında kaldığından, hesaplanan tutar uygulanır. Bakınız 19 CFR 24.23(b)(1).","hi":"औपचारिक एंट्री के लिए MPF एंटर किए गए मूल्य का 0.3464% है, जो एक न्यूनतम और अधिकतम के अधीन है। $100,000 x 0.003464 = $346.40, जो FY2026 के न्यूनतम $33.58 और अधिकतम $651.50 के बीच आता है, इसलिए गणना की गई राशि लागू होती है। देखें 19 CFR 24.23(b)(1)।","ar":"يبلغ MPF للإدخالات الرسمية 0.3464% من القيمة المُدخَلة، رهناً بحد أدنى وحد أقصى. ‎$100,000 x 0.003464 = $346.40‎، وهو يقع بين الحد الأدنى للسنة المالية FY2026 البالغ ‎$33.58‎ والحد الأقصى البالغ ‎$651.50‎، فينطبق المبلغ المحسوب. انظر 19 CFR 24.23(b)(1)."}},{"cat":"duties","a":0,"q":{"en":"A formal entry has an entered value of five thousand dollars. Applying the current MPF rate and its minimum, what MPF is due (FY2026 amounts)?","es":"Una entrada formal tiene un valor declarado de cinco mil dólares. Aplicando la tasa actual del MPF y su mínimo, ¿qué MPF se adeuda (montos del FY2026)?","ru":"Официальное оформление имеет заявленную стоимость пять тысяч долларов. С применением текущей ставки MPF и ее минимума, какой MPF причитается (суммы FY2026)?","tr":"Resmi bir beyanın beyan edilen değeri beş bin dolardır. Güncel MPF oranı ve asgari tutarı uygulandığında, ödenecek MPF ne kadardır (FY2026 tutarları)?","hi":"एक औपचारिक एंट्री का एंटर किया गया मूल्य पाँच हजार डॉलर है। वर्तमान MPF दर और उसके न्यूनतम को लागू करते हुए, कितना MPF देय है (FY2026 राशियाँ)?","ar":"إدخال رسمي قيمته المُدخَلة خمسة آلاف دولار. بتطبيق المعدل الحالي لـ MPF وحدّه الأدنى، ما هو MPF المستحق (مبالغ FY2026)؟"},"o":[{"en":"Thirty-three dollars and fifty-eight cents","es":"Treinta y tres dólares con cincuenta y ocho centavos","ru":"Тридцать три доллара и пятьдесят восемь центов","tr":"Otuz üç dolar elli sekiz sent","hi":"तैंतीस डॉलर और अट्ठावन सेंट","ar":"ثلاثة وثلاثون دولاراً وثمانية وخمسون سنتاً"},{"en":"Seventeen dollars and thirty-two cents","es":"Diecisiete dólares con treinta y dos centavos","ru":"Семнадцать долларов и тридцать два цента","tr":"On yedi dolar otuz iki sent","hi":"सत्रह डॉलर और बत्तीस सेंट","ar":"سبعة عشر دولاراً واثنان وثلاثون سنتاً"},{"en":"Thirty-two dollars and seventy-one cents","es":"Treinta y dos dólares con setenta y un centavos","ru":"Тридцать два доллара и семьдесят один цент","tr":"Otuz iki dolar yetmiş bir sent","hi":"बत्तीस डॉलर और इकहत्तर सेंट","ar":"اثنان وثلاثون دولاراً وواحد وسبعون سنتاً"},{"en":"Twenty-five dollars","es":"Veinticinco dólares","ru":"Двадцать пять долларов","tr":"Yirmi beş dolar","hi":"पच्चीस डॉलर","ar":"خمسة وعشرون دولاراً"}],"e":{"en":"0.3464% of $5,000 = $17.32, which is below the formal-entry MPF minimum. The minimum (effective October 1, 2025, for FY2026) is $33.58, so the floor amount applies. See 19 CFR 24.23(b)(1).","es":"0.3464% de $5,000 = $17.32, que está por debajo del mínimo del MPF para entradas formales. El mínimo (vigente a partir del October 1, 2025, para el FY2026) es $33.58, por lo que se aplica el monto piso. Véase 19 CFR 24.23(b)(1).","ru":"0.3464% от $5,000 = $17.32, что ниже минимума MPF для официального оформления. Минимум (действует с October 1, 2025, для FY2026) составляет $33.58, поэтому применяется нижняя пороговая сумма. См. 19 CFR 24.23(b)(1).","tr":"$5,000'in %0.3464'ü = $17.32; bu tutar resmi beyan MPF asgari değerinin altındadır. Asgari tutar (FY2026 için 1 Ekim 2025'ten itibaren geçerli) $33.58 olduğundan, taban tutarı uygulanır. Bakınız 19 CFR 24.23(b)(1).","hi":"$5,000 का 0.3464% = $17.32, जो औपचारिक-एंट्री MPF न्यूनतम से कम है। न्यूनतम (FY2026 के लिए October 1, 2025 से प्रभावी) $33.58 है, इसलिए न्यूनतम राशि लागू होती है। देखें 19 CFR 24.23(b)(1)।","ar":"‎0.3464% من ‎$5,000 = $17.32‎، وهو أدنى من الحد الأدنى لـ MPF للإدخال الرسمي. الحد الأدنى (النافذ اعتباراً من October 1, 2025 للسنة المالية FY2026) هو ‎$33.58‎، فينطبق مبلغ الحد الأدنى. انظر 19 CFR 24.23(b)(1)."}},{"cat":"duties","a":2,"q":{"en":"A formal entry has an entered value of three hundred thousand dollars. Applying the current MPF rate and its cap, what MPF is due (FY2026 amounts)?","es":"Una entrada formal tiene un valor declarado de trescientos mil dólares. Aplicando la tasa actual del MPF y su tope, ¿qué MPF se adeuda (montos del FY2026)?","ru":"Официальное оформление имеет заявленную стоимость триста тысяч долларов. С применением текущей ставки MPF и ее предельного потолка, какой MPF причитается (суммы FY2026)?","tr":"Resmi bir beyanın beyan edilen değeri üç yüz bin dolardır. Güncel MPF oranı ve üst sınırı uygulandığında, ödenecek MPF ne kadardır (FY2026 tutarları)?","hi":"एक औपचारिक एंट्री का एंटर किया गया मूल्य तीन लाख डॉलर है। वर्तमान MPF दर और उसकी अधिकतम सीमा को लागू करते हुए, कितना MPF देय है (FY2026 राशियाँ)?","ar":"إدخال رسمي قيمته المُدخَلة ثلاثمئة ألف دولار. بتطبيق المعدل الحالي لـ MPF وحدّه الأقصى، ما هو MPF المستحق (مبالغ FY2026)؟"},"o":[{"en":"One thousand thirty-nine dollars and twenty cents","es":"Mil treinta y nueve dólares con veinte centavos","ru":"Одна тысяча тридцать девять долларов и двадцать центов","tr":"Bin otuz dokuz dolar yirmi sent","hi":"एक हजार उनतालीस डॉलर और बीस सेंट","ar":"ألف وتسعة وثلاثون دولاراً وعشرون سنتاً"},{"en":"Six hundred thirty-four dollars and sixty-two cents","es":"Seiscientos treinta y cuatro dólares con sesenta y dos centavos","ru":"Шестьсот тридцать четыре доллара и шестьдесят два цента","tr":"Altı yüz otuz dört dolar altmış iki sent","hi":"छह सौ चौंतीस डॉलर और बासठ सेंट","ar":"ستمئة وأربعة وثلاثون دولاراً واثنان وستون سنتاً"},{"en":"Six hundred fifty-one dollars and fifty cents","es":"Seiscientos cincuenta y un dólares con cincuenta centavos","ru":"Шестьсот пятьдесят один доллар и пятьдесят центов","tr":"Altı yüz elli bir dolar elli sent","hi":"छह सौ इक्यावन डॉलर और पचास सेंट","ar":"ستمئة وواحد وخمسون دولاراً وخمسون سنتاً"},{"en":"Three hundred forty-six dollars and forty cents","es":"Trescientos cuarenta y seis dólares con cuarenta centavos","ru":"Триста сорок шесть долларов и сорок центов","tr":"Üç yüz kırk altı dolar kırk sent","hi":"तीन सौ छियालीस डॉलर और चालीस सेंट","ar":"ثلاثمئة وستة وأربعون دولاراً وأربعون سنتاً"}],"e":{"en":"0.3464% of $300,000 = $1,039.20, which exceeds the formal-entry MPF maximum. The FY2026 maximum (effective October 1, 2025) is $651.50, so the cap applies. The prior-year cap of $634.62 is a distractor. See 19 CFR 24.23(b)(1).","es":"0.3464% de $300,000 = $1,039.20, que excede el máximo del MPF para entradas formales. El máximo del FY2026 (vigente a partir del October 1, 2025) es $651.50, por lo que se aplica el tope. El tope del año anterior de $634.62 es un distractor. Véase 19 CFR 24.23(b)(1).","ru":"0.3464% от $300,000 = $1,039.20, что превышает максимум MPF для официального оформления. Максимум FY2026 (действует с October 1, 2025) составляет $651.50, поэтому применяется потолок. Прошлогодний потолок $634.62 является отвлекающим вариантом. См. 19 CFR 24.23(b)(1).","tr":"$300,000'in %0.3464'ü = $1,039.20; bu tutar resmi beyan MPF azami değerini aşmaktadır. FY2026 azami tutarı (1 Ekim 2025'ten itibaren geçerli) $651.50 olduğundan, üst sınır uygulanır. Önceki yılın üst sınırı olan $634.62 bir şaşırtmacadır. Bakınız 19 CFR 24.23(b)(1).","hi":"$300,000 का 0.3464% = $1,039.20, जो औपचारिक-एंट्री MPF अधिकतम से अधिक है। FY2026 अधिकतम (October 1, 2025 से प्रभावी) $651.50 है, इसलिए अधिकतम सीमा लागू होती है। पिछले वर्ष की $634.62 सीमा एक भ्रामक विकल्प है। देखें 19 CFR 24.23(b)(1)।","ar":"‎0.3464% من ‎$300,000 = $1,039.20‎، وهو يتجاوز الحد الأقصى لـ MPF للإدخال الرسمي. الحد الأقصى للسنة المالية FY2026 (النافذ اعتباراً من October 1, 2025) هو ‎$651.50‎، فينطبق الحد الأقصى. أما الحد الأقصى للسنة السابقة البالغ ‎$634.62‎ فهو خيار مُضلِّل. انظر 19 CFR 24.23(b)(1)."}},{"cat":"duties","a":1,"q":{"en":"A shipment of commercial cargo arrives by ocean vessel at a U.S. port subject to the harbor maintenance fee. The cargo's value is eighty thousand dollars. What is the harbor maintenance fee (HMF)?","es":"Un embarque de carga comercial llega por buque oceánico a un puerto de Estados Unidos sujeto al harbor maintenance fee. El valor de la carga es ochenta mil dólares. ¿Cuál es el harbor maintenance fee (HMF)?","ru":"Партия коммерческого груза прибывает морским судном в порт США, подпадающий под сбор за содержание гавани (HMF). Стоимость груза составляет восемьдесят тысяч долларов. Каков сбор за содержание гавани (HMF)?","tr":"Ticari bir yük sevkiyatı, harbor maintenance fee'ye tabi bir ABD limanına deniz yoluyla (gemiyle) ulaşıyor. Yükün değeri seksen bin dolardır. Harbor maintenance fee (HMF) ne kadardır?","hi":"वाणिज्यिक माल का एक शिपमेंट समुद्री जहाज से एक U.S. बंदरगाह पर पहुँचता है जो harbor maintenance fee के अधीन है। माल का मूल्य अस्सी हजार डॉलर है। harbor maintenance fee (HMF) क्या है?","ar":"تصل شحنة من البضائع التجارية بواسطة سفينة بحرية إلى ميناء أمريكي خاضع لرسم صيانة الموانئ. تبلغ قيمة البضاعة ثمانين ألف دولار. ما هو رسم صيانة الموانئ (HMF)؟"},"o":[{"en":"Two hundred seventy-seven dollars and twelve cents","es":"Doscientos setenta y siete dólares con doce centavos","ru":"Двести семьдесят семь долларов и двенадцать центов","tr":"İki yüz yetmiş yedi dolar on iki sent","hi":"दो सौ सतहत्तर डॉलर और बारह सेंट","ar":"مئتان وسبعة وسبعون دولاراً واثنا عشر سنتاً"},{"en":"One hundred dollars","es":"Cien dólares","ru":"Сто долларов","tr":"Yüz dolar","hi":"एक सौ डॉलर","ar":"مئة دولار"},{"en":"Three hundred forty-six dollars and forty cents","es":"Trescientos cuarenta y seis dólares con cuarenta centavos","ru":"Триста сорок шесть долларов и сорок центов","tr":"Üç yüz kırk altı dolar kırk sent","hi":"तीन सौ छियालीस डॉलर और चालीस सेंट","ar":"ثلاثمئة وستة وأربعون دولاراً وأربعون سنتاً"},{"en":"Ten dollars","es":"Diez dólares","ru":"Десять долларов","tr":"On dolar","hi":"दस डॉलर","ar":"عشرة دولارات"}],"e":{"en":"The HMF is 0.125% of the value of the commercial cargo and, unlike the MPF, has no minimum or maximum. $80,000 x 0.00125 = $100.00. The HMF applies to cargo arriving by vessel, not by air. See 19 CFR 24.24(b).","es":"El HMF es 0.125% del valor de la carga comercial y, a diferencia del MPF, no tiene mínimo ni máximo. $80,000 x 0.00125 = $100.00. El HMF se aplica a la carga que llega por buque, no por aire. Véase 19 CFR 24.24(b).","ru":"HMF составляет 0.125% от стоимости коммерческого груза и, в отличие от MPF, не имеет ни минимума, ни максимума. $80,000 x 0.00125 = $100.00. HMF применяется к грузам, прибывающим судном, а не по воздуху. См. 19 CFR 24.24(b).","tr":"HMF, ticari yükün değerinin %0.125'idir ve MPF'nin aksine asgari veya azami tutarı yoktur. $80,000 x 0.00125 = $100.00. HMF, hava yoluyla değil, gemiyle ulaşan yüke uygulanır. Bakınız 19 CFR 24.24(b).","hi":"HMF वाणिज्यिक माल के मूल्य का 0.125% है और, MPF के विपरीत, इसका कोई न्यूनतम या अधिकतम नहीं है। $80,000 x 0.00125 = $100.00। HMF जहाज से पहुँचने वाले माल पर लागू होता है, हवाई माल पर नहीं। देखें 19 CFR 24.24(b)।","ar":"يبلغ HMF 0.125% من قيمة البضائع التجارية، وخلافاً لـ MPF لا يخضع لحد أدنى أو أقصى. ‎$80,000 x 0.00125 = $100.00‎. ينطبق HMF على البضائع الواصلة بالسفن، لا بالجو. انظر 19 CFR 24.24(b)."}},{"cat":"duties","a":0,"q":{"en":"Which statement correctly distinguishes the merchandise processing fee from the harbor maintenance fee?","es":"¿Qué afirmación distingue correctamente el merchandise processing fee del harbor maintenance fee?","ru":"Какое утверждение правильно отличает сбор за обработку товаров (MPF) от сбора за содержание гавани (HMF)?","tr":"Aşağıdaki ifadelerden hangisi, merchandise processing fee'yi harbor maintenance fee'den doğru şekilde ayırt etmektedir?","hi":"कौन-सा कथन merchandise processing fee को harbor maintenance fee से सही ढंग से अलग करता है?","ar":"أي عبارة تميّز بشكل صحيح رسم معالجة البضائع عن رسم صيانة الموانئ؟"},"o":[{"en":"The MPF for formal entries has a minimum and maximum, while the HMF (0.125%) has neither","es":"El MPF para entradas formales tiene un mínimo y un máximo, mientras que el HMF (0.125%) no tiene ninguno de los dos","ru":"MPF для официальных оформлений имеет минимум и максимум, тогда как HMF (0.125%) не имеет ни того, ни другого","tr":"Resmi beyanlar için MPF'nin bir asgari ve azami tutarı vardır; HMF (%0.125) ise ne asgari ne de azami tutara sahiptir","hi":"औपचारिक एंट्री के लिए MPF का एक न्यूनतम और अधिकतम होता है, जबकि HMF (0.125%) का कोई भी नहीं होता","ar":"يخضع MPF للإدخالات الرسمية لحد أدنى وحد أقصى، بينما لا يخضع HMF (0.125%) لأيٍّ منهما"},{"en":"Both fees have a statutory minimum and maximum per entry","es":"Ambas tarifas tienen un mínimo y un máximo legal por entrada","ru":"Оба сбора имеют установленный законом минимум и максимум на одно оформление","tr":"Her iki ücretin de beyan başına yasal bir asgari ve azami tutarı vardır","hi":"दोनों शुल्कों का प्रति एंट्री एक वैधानिक न्यूनतम और अधिकतम होता है","ar":"يخضع كلا الرسمين لحد أدنى وحد أقصى قانوني لكل إدخال"},{"en":"The HMF applies to both vessel and air shipments; the MPF applies only to vessel shipments","es":"El HMF se aplica tanto a embarques por buque como por aire; el MPF se aplica solo a embarques por buque","ru":"HMF применяется как к морским, так и к авиационным отправлениям; MPF применяется только к морским отправлениям","tr":"HMF hem gemi hem hava sevkiyatlarına uygulanır; MPF yalnızca gemi sevkiyatlarına uygulanır","hi":"HMF जहाज और हवाई दोनों शिपमेंट पर लागू होता है; MPF केवल जहाज शिपमेंट पर लागू होता है","ar":"ينطبق HMF على الشحنات البحرية والجوية معاً؛ بينما ينطبق MPF على الشحنات البحرية فقط"},{"en":"The MPF is 0.125% and the HMF is 0.3464% of value","es":"El MPF es 0.125% y el HMF es 0.3464% del valor","ru":"MPF составляет 0.125%, а HMF — 0.3464% от стоимости","tr":"MPF değerin %0.125'i, HMF ise %0.3464'üdür","hi":"MPF मूल्य का 0.125% है और HMF 0.3464% है","ar":"يبلغ MPF نسبة 0.125% بينما يبلغ HMF نسبة 0.3464% من القيمة"}],"e":{"en":"The formal-entry MPF is 0.3464% with a per-entry minimum and maximum, whereas the HMF is a flat 0.125% of cargo value with no floor or ceiling. The HMF applies to waterborne cargo, not air. See 19 CFR 24.23(b)(1) and 19 CFR 24.24.","es":"El MPF para entradas formales es 0.3464% con un mínimo y un máximo por entrada, mientras que el HMF es un 0.125% fijo del valor de la carga sin piso ni techo. El HMF se aplica a la carga transportada por agua, no por aire. Véanse 19 CFR 24.23(b)(1) y 19 CFR 24.24.","ru":"MPF для официального оформления составляет 0.3464% с минимумом и максимумом на одно оформление, тогда как HMF — это фиксированные 0.125% от стоимости груза без нижнего или верхнего предела. HMF применяется к грузам, перевозимым по воде, а не по воздуху. См. 19 CFR 24.23(b)(1) и 19 CFR 24.24.","tr":"Resmi beyan MPF'si, beyan başına bir asgari ve azami tutara sahip %0.3464 oranındadır; HMF ise yük değerinin sabit %0.125'i olup taban veya tavanı yoktur. HMF, hava yoluyla değil su yoluyla taşınan yüke uygulanır. Bakınız 19 CFR 24.23(b)(1) ve 19 CFR 24.24.","hi":"औपचारिक-एंट्री MPF 0.3464% है जिसका प्रति एंट्री एक न्यूनतम और अधिकतम होता है, जबकि HMF माल मूल्य का एक समान 0.125% है जिसका कोई न्यूनतम या अधिकतम नहीं है। HMF जलमार्ग से आने वाले माल पर लागू होता है, हवाई पर नहीं। देखें 19 CFR 24.23(b)(1) और 19 CFR 24.24।","ar":"يبلغ MPF للإدخال الرسمي 0.3464% مع حد أدنى وحد أقصى لكل إدخال، بينما HMF رسم ثابت قدره 0.125% من قيمة البضاعة دون حد أدنى أو أقصى. وينطبق HMF على البضائع المنقولة بحراً، لا جواً. انظر 19 CFR 24.23(b)(1) و19 CFR 24.24."}},{"cat":"duties","a":3,"q":{"en":"Antidumping duties (ADD) are imposed to remedy which condition, and on what basis are the cash-deposit rates generally established?","es":"Los derechos antidumping (ADD) se imponen para remediar qué condición, ¿y sobre qué base se establecen generalmente las tasas de depósito en efectivo?","ru":"Антидемпинговые пошлины (ADD) вводятся для устранения какого условия, и на какой основе обычно устанавливаются ставки денежного депозита?","tr":"Antidumping vergileri (ADD) hangi durumu gidermek için uygulanır ve nakit teminat oranları genellikle hangi esasa göre belirlenir?","hi":"Antidumping शुल्क (ADD) किस स्थिति को ठीक करने के लिए लगाए जाते हैं, और cash-deposit दरें आम तौर पर किस आधार पर निर्धारित की जाती हैं?","ar":"تُفرض رسوم مكافحة الإغراق (ADD) لمعالجة أي حالة، وعلى أي أساس تُحدَّد عموماً معدلات الإيداع النقدي؟"},"o":[{"en":"Foreign government subsidies; based on the net countervailable subsidy","es":"Subsidios de un gobierno extranjero; con base en el subsidio neto compensable","ru":"Субсидии иностранного правительства; на основе чистой компенсируемой субсидии","tr":"Yabancı hükümet sübvansiyonları; net telafi edilebilir sübvansiyon esasına göre","hi":"विदेशी सरकार की सब्सिडी; शुद्ध countervailable सब्सिडी के आधार पर","ar":"إعانات الحكومة الأجنبية؛ استناداً إلى صافي الإعانة القابلة للتعويض"},{"en":"National-security threats; based on a flat 25% surcharge","es":"Amenazas a la seguridad nacional; con base en un recargo fijo del 25%","ru":"Угрозы национальной безопасности; на основе фиксированной надбавки в 25%","tr":"Ulusal güvenlik tehditleri; sabit %25 ek vergi esasına göre","hi":"राष्ट्रीय-सुरक्षा खतरे; एक समान 25% अधिभार के आधार पर","ar":"التهديدات للأمن القومي؛ استناداً إلى رسم إضافي ثابت قدره 25%"},{"en":"Import surges; based on a tariff-rate quota over-quota rate","es":"Aumentos repentinos de importaciones; con base en la tasa por encima del cupo de un contingente arancelario","ru":"Резкий рост импорта; на основе сверхквотной ставки тарифной квоты","tr":"İthalat dalgalanmaları; tarife kotası kota üstü oranı esasına göre","hi":"आयात में उछाल; tariff-rate quota की over-quota दर के आधार पर","ar":"موجات الواردات المفاجئة؛ استناداً إلى معدل تجاوز الحصة في حصة معدل التعريفة"},{"en":"Sales at less than fair value (below normal value); based on the dumping margin","es":"Ventas por debajo del valor justo (por debajo del valor normal); con base en el margen de dumping","ru":"Продажи по цене ниже справедливой стоимости (ниже нормальной стоимости); на основе демпинговой маржи","tr":"Adil değerin altında satışlar (normal değerin altında); dumping marjı esasına göre","hi":"उचित मूल्य से कम पर बिक्री (सामान्य मूल्य से नीचे); dumping मार्जिन के आधार पर","ar":"البيع بأقل من القيمة العادلة (دون القيمة الطبيعية)؛ استناداً إلى هامش الإغراق"}],"e":{"en":"Antidumping duties offset sales of foreign merchandise in the U.S. at less than fair value (below normal value), and the duty is set by the dumping margin. Countervailing duties, by contrast, offset foreign subsidies. The cases are administered by Commerce (margins) and the ITC (injury), with CBP collecting deposits. See 19 U.S.C. 1673 and 19 CFR part 351.","es":"Los derechos antidumping compensan las ventas de mercancía extranjera en Estados Unidos por debajo del valor justo (por debajo del valor normal), y el derecho se establece según el margen de dumping. Los derechos compensatorios, en cambio, compensan los subsidios extranjeros. Los casos son administrados por el Department of Commerce (márgenes) y la ITC (daño), con CBP cobrando los depósitos. Véanse 19 U.S.C. 1673 y 19 CFR part 351.","ru":"Антидемпинговые пошлины компенсируют продажи иностранных товаров в США по цене ниже справедливой стоимости (ниже нормальной стоимости), и пошлина устанавливается по демпинговой марже. Компенсационные пошлины (CVD), напротив, компенсируют иностранные субсидии. Дела ведут Министерство торговли (маржа) и ITC (ущерб), а CBP взимает депозиты. См. 19 U.S.C. 1673 и 19 CFR part 351.","tr":"Antidumping vergileri, yabancı malların ABD'de adil değerin altında (normal değerin altında) satışını telafi eder ve vergi, dumping marjı tarafından belirlenir. Buna karşılık, countervailing (telafi edici) vergiler yabancı sübvansiyonları telafi eder. Davalar Commerce (marjlar) ve ITC (zarar) tarafından yürütülür; teminatları ise CBP tahsil eder. Bakınız 19 U.S.C. 1673 ve 19 CFR part 351.","hi":"Antidumping शुल्क U.S. में विदेशी माल की उचित मूल्य से कम (सामान्य मूल्य से नीचे) बिक्री की भरपाई करते हैं, और शुल्क dumping मार्जिन द्वारा निर्धारित होता है। इसके विपरीत, countervailing शुल्क विदेशी सब्सिडी की भरपाई करते हैं। इन मामलों का प्रशासन Commerce (मार्जिन) और ITC (क्षति) द्वारा किया जाता है, जबकि CBP जमा राशि एकत्र करता है। देखें 19 U.S.C. 1673 और 19 CFR part 351।","ar":"تعوّض رسوم مكافحة الإغراق بيع البضائع الأجنبية في الولايات المتحدة بأقل من القيمة العادلة (دون القيمة الطبيعية)، ويُحدَّد الرسم بهامش الإغراق. أما رسوم التعويض، فتعوّض الإعانات الأجنبية. وتدير القضايا وزارة التجارة (الهوامش) ولجنة التجارة الدولية ITC (الضرر)، مع قيام CBP بتحصيل الإيداعات. انظر 19 U.S.C. 1673 و19 CFR part 351."}},{"cat":"duties","a":1,"q":{"en":"Merchandise is subject to an antidumping duty order. At the time of entry, the broker must deposit estimated antidumping duties. Which statement about these duties is correct?","es":"La mercancía está sujeta a una orden de derechos antidumping. Al momento de la entrada, el agente debe depositar los derechos antidumping estimados. ¿Qué afirmación sobre estos derechos es correcta?","ru":"Товары подпадают под приказ об антидемпинговой пошлине. На момент оформления брокер должен внести депозит расчетных антидемпинговых пошлин. Какое утверждение об этих пошлинах верно?","tr":"Mallar bir antidumping vergi emrine tabidir. Beyan anında, gümrük müşaviri (broker) tahmini antidumping vergilerini teminat olarak yatırmalıdır. Bu vergilerle ilgili hangi ifade doğrudur?","hi":"माल एक antidumping शुल्क आदेश के अधीन है। एंट्री के समय, ब्रोकर को अनुमानित antidumping शुल्क जमा करना होता है। इन शुल्कों के बारे में कौन-सा कथन सही है?","ar":"تخضع بضاعة لأمر فرض رسوم مكافحة إغراق. عند الإدخال، يجب على الوسيط إيداع رسوم مكافحة الإغراق التقديرية. أي عبارة عن هذه الرسوم صحيحة؟"},"o":[{"en":"ADD cash deposits are credited against, and reduce, the regular Column 1 duty owed","es":"Los depósitos en efectivo de ADD se acreditan contra, y reducen, el derecho regular de la Columna 1 adeudado","ru":"Денежные депозиты ADD засчитываются в счет обычной пошлины Колонки 1 и уменьшают ее","tr":"ADD nakit teminatları, ödenmesi gereken normal Column 1 vergisinden mahsup edilir ve onu azaltır","hi":"ADD cash deposits को नियमित Column 1 देय शुल्क के बदले में क्रेडिट किया जाता है, और उसे कम करते हैं","ar":"تُقيَّد الإيداعات النقدية لـ ADD لصالح رسم Column 1 العادي المستحق وتخفّضه"},{"en":"ADD is collected in addition to any applicable regular customs duties, MPF, and HMF","es":"El ADD se cobra adicionalmente a cualquier derecho aduanero regular aplicable, el MPF y el HMF","ru":"ADD взимается в дополнение к любым применимым обычным таможенным пошлинам, MPF и HMF","tr":"ADD, uygulanabilir normal gümrük vergilerine, MPF ve HMF'ye ek olarak tahsil edilir","hi":"ADD किसी भी लागू नियमित कस्टम शुल्क, MPF, और HMF के अतिरिक्त एकत्र किया जाता है","ar":"تُحصَّل ADD إضافةً إلى أي رسوم جمركية عادية مطبّقة، و MPF، و HMF"},{"en":"ADD is exempt from collection until the entry is liquidated","es":"El ADD está exento de cobro hasta que se liquide la entrada","ru":"ADD освобождается от взимания до ликвидации оформления","tr":"ADD, beyan kesinleştirilene (likidasyon) kadar tahsilattan muaftır","hi":"एंट्री के परिसमापन तक ADD संग्रह से छूट प्राप्त है","ar":"تُعفى ADD من التحصيل إلى حين تصفية الإدخال"},{"en":"ADD replaces the MPF on entries subject to an order","es":"El ADD reemplaza el MPF en las entradas sujetas a una orden","ru":"ADD заменяет MPF при оформлениях, подпадающих под приказ","tr":"ADD, bir emre tabi beyanlarda MPF'nin yerini alır","hi":"आदेश के अधीन एंट्री पर ADD, MPF का स्थान ले लेता है","ar":"تحلّ ADD محل MPF في الإدخالات الخاضعة لأمر"}],"e":{"en":"Antidumping (and countervailing) duties are assessed in addition to normal customs duties and applicable fees such as the MPF and HMF; they do not offset or replace them. Estimated ADD/CVD is deposited at entry and finalized at liquidation after any administrative review. See 19 U.S.C. 1673 and 19 CFR part 351.","es":"Los derechos antidumping (y compensatorios) se calculan adicionalmente a los derechos aduaneros normales y a tarifas aplicables como el MPF y el HMF; no los compensan ni los reemplazan. El ADD/CVD estimado se deposita en la entrada y se finaliza en la liquidación tras cualquier revisión administrativa. Véanse 19 U.S.C. 1673 y 19 CFR part 351.","ru":"Антидемпинговые (и компенсационные) пошлины начисляются в дополнение к обычным таможенным пошлинам и применимым сборам, таким как MPF и HMF; они не компенсируют и не заменяют их. Расчетные ADD/CVD депонируются при оформлении и окончательно определяются при ликвидации после любой административной проверки. См. 19 U.S.C. 1673 и 19 CFR part 351.","tr":"Antidumping (ve countervailing) vergileri, normal gümrük vergilerine ve MPF ile HMF gibi geçerli ücretlere ek olarak tahakkuk ettirilir; bunları mahsup etmez veya yerlerini almaz. Tahmini ADD/CVD beyanda teminat olarak yatırılır ve herhangi bir idari incelemenin ardından kesinleştirme (likidasyon) sırasında nihai hale getirilir. Bakınız 19 U.S.C. 1673 ve 19 CFR part 351.","hi":"Antidumping (और countervailing) शुल्क सामान्य कस्टम शुल्क और MPF तथा HMF जैसे लागू शुल्कों के अतिरिक्त लगाए जाते हैं; वे उनकी भरपाई नहीं करते या उनका स्थान नहीं लेते। अनुमानित ADD/CVD एंट्री के समय जमा किया जाता है और किसी भी प्रशासनिक समीक्षा के बाद परिसमापन पर अंतिम रूप दिया जाता है। देखें 19 U.S.C. 1673 और 19 CFR part 351।","ar":"تُفرض رسوم مكافحة الإغراق (والتعويض) إضافةً إلى الرسوم الجمركية العادية والرسوم المطبّقة مثل MPF و HMF؛ ولا تعوّضها أو تحلّ محلها. وتُودَع ADD/CVD التقديرية عند الإدخال وتُحسم نهائياً عند التصفية بعد أي مراجعة إدارية. انظر 19 U.S.C. 1673 و19 CFR part 351."}},{"cat":"duties","a":2,"q":{"en":"An importer wishes to enter merchandise subject to a quota. Under an ABSOLUTE quota, what happens to merchandise presented for entry after the quota quantity for the period has been reached?","es":"Un importador desea declarar mercancía sujeta a un contingente. Bajo un contingente ABSOLUTO, ¿qué sucede con la mercancía presentada para entrada después de que se haya alcanzado la cantidad del contingente para el período?","ru":"Импортер желает оформить ввоз товаров, подпадающих под квоту. При АБСОЛЮТНОЙ квоте что происходит с товарами, представленными к оформлению после того, как количество квоты за период было достигнуто?","tr":"Bir ithalatçı, bir kotaya tabi malları beyan etmek istiyor. MUTLAK (absolute) bir kota kapsamında, dönem için belirlenen kota miktarına ulaşıldıktan sonra beyan için sunulan mallara ne olur?","hi":"एक आयातकर्ता quota के अधीन माल की एंट्री करना चाहता है। एक ABSOLUTE quota के तहत, अवधि के लिए quota मात्रा पूरी हो जाने के बाद एंट्री के लिए प्रस्तुत माल का क्या होता है?","ar":"يرغب مستورد في إدخال بضاعة خاضعة لحصة. في ظل حصة مطلقة (ABSOLUTE)، ماذا يحدث للبضاعة المقدَّمة للإدخال بعد بلوغ كمية الحصة المخصّصة للفترة؟"},"o":[{"en":"It may enter at a higher over-quota duty rate","es":"Puede entrar a una tasa de derechos más alta por encima del cupo","ru":"Они могут быть ввезены по более высокой сверхквотной ставке пошлины","tr":"Daha yüksek bir kota üstü vergi oranıyla girebilir","hi":"यह अधिक over-quota शुल्क दर पर एंटर हो सकता है","ar":"يجوز إدخالها بمعدل رسوم أعلى لتجاوز الحصة"},{"en":"It enters duty-free until the next period opens","es":"Entra libre de derechos hasta que se abra el siguiente período","ru":"Они ввозятся беспошлинно до открытия следующего периода","tr":"Bir sonraki dönem açılana kadar vergisiz olarak girebilir","hi":"अगली अवधि शुरू होने तक यह शुल्क-मुक्त एंटर होता है","ar":"تُدخَل معفاةً من الرسوم إلى أن تُفتح الفترة التالية"},{"en":"No further quantity may be entered for consumption during that period; it may be warehoused, exported, or destroyed","es":"No puede entrarse ninguna cantidad adicional para consumo durante ese período; puede almacenarse, exportarse o destruirse","ru":"В течение этого периода никакое дополнительное количество не может быть оформлено для потребления; товары могут быть помещены на склад, экспортированы или уничтожены","tr":"O dönem boyunca tüketim için başka miktar girilemez; mallar antrepoya konabilir, ihraç edilebilir veya imha edilebilir","hi":"उस अवधि के दौरान उपभोग के लिए कोई और मात्रा एंटर नहीं की जा सकती; इसे warehouse में रखा जा सकता है, निर्यात किया जा सकता है, या नष्ट किया जा सकता है","ar":"لا يجوز إدخال أي كمية إضافية للاستهلاك خلال تلك الفترة؛ ويجوز إيداعها في مستودع أو تصديرها أو إتلافها"},{"en":"It enters at the Column 2 rate","es":"Entra a la tasa de la Columna 2","ru":"Они ввозятся по ставке Колонки 2","tr":"Column 2 oranıyla girebilir","hi":"यह Column 2 दर पर एंटर होता है","ar":"تُدخَل بمعدل Column 2"}],"e":{"en":"An absolute (quantitative) quota permits no entries for consumption beyond the set quantity once it is filled; excess merchandise must be held in a bonded warehouse or foreign-trade zone, exported, or destroyed. A tariff-rate quota, by contrast, allows unlimited quantity but at a higher over-quota rate. See 19 CFR part 132.","es":"Un contingente absoluto (cuantitativo) no permite entradas para consumo más allá de la cantidad establecida una vez que se ha llenado; la mercancía excedente debe mantenerse en un almacén afianzado o zona de comercio exterior, exportarse o destruirse. Un contingente arancelario, en cambio, permite cantidad ilimitada pero a una tasa más alta por encima del cupo. Véase 19 CFR part 132.","ru":"Абсолютная (количественная) квота не допускает оформления для потребления сверх установленного количества, как только оно исчерпано; избыточные товары должны храниться на таможенном складе или в зоне внешней торговли (FTZ), экспортироваться или уничтожаться. Тарифная квота, напротив, допускает неограниченное количество, но по более высокой сверхквотной ставке. См. 19 CFR part 132.","tr":"Mutlak (miktarsal) kota, dolduktan sonra belirlenen miktarın ötesinde tüketim için hiçbir beyana izin vermez; fazla mallar bir gümrük antreposunda veya foreign-trade zone'da tutulmalı, ihraç edilmeli veya imha edilmelidir. Buna karşılık tarife kotası, sınırsız miktara izin verir ancak daha yüksek bir kota üstü oranla. Bakınız 19 CFR part 132.","hi":"एक absolute (मात्रात्मक) quota, एक बार भर जाने पर, निर्धारित मात्रा से अधिक उपभोग के लिए कोई एंट्री की अनुमति नहीं देता; अतिरिक्त माल को bonded warehouse या foreign-trade zone में रखा जाना चाहिए, निर्यात किया जाना चाहिए, या नष्ट किया जाना चाहिए। इसके विपरीत, एक tariff-rate quota असीमित मात्रा की अनुमति देता है लेकिन अधिक over-quota दर पर। देखें 19 CFR part 132।","ar":"لا تسمح الحصة المطلقة (الكمّية) بأي إدخالات للاستهلاك تتجاوز الكمية المحددة بمجرد استيفائها؛ ويجب الاحتفاظ بالبضاعة الزائدة في مستودع جمركي مضمون أو منطقة تجارة خارجية FTZ، أو تصديرها، أو إتلافها. أما حصة معدل التعريفة فتسمح بكمية غير محدودة لكن بمعدل أعلى لتجاوز الحصة. انظر 19 CFR part 132."}},{"cat":"duties","a":3,"q":{"en":"Imported components are used to manufacture an article in the United States, and the finished article is then exported. What type of drawback is available, and what is the general time limit?","es":"Se usan componentes importados para fabricar un artículo en Estados Unidos, y el artículo terminado se exporta después. ¿Qué tipo de drawback está disponible y cuál es el límite de tiempo general?","ru":"Импортированные компоненты используются для изготовления изделия в Соединенных Штатах, после чего готовое изделие экспортируется. Какой тип возврата пошлин (drawback) доступен, и каков общий срок?","tr":"İthal edilen bileşenler, Amerika Birleşik Devletleri'nde bir ürün imal etmek için kullanılıyor ve bitmiş ürün daha sonra ihraç ediliyor. Ne tür bir gümrük vergisi iadesi (drawback) mevcuttur ve genel süre sınırı nedir?","hi":"आयातित घटकों का उपयोग संयुक्त राज्य अमेरिका में एक वस्तु के निर्माण के लिए किया जाता है, और फिर तैयार वस्तु को निर्यात किया जाता है। किस प्रकार का drawback (शुल्क वापसी) उपलब्ध है, और सामान्य समय-सीमा क्या है?","ar":"تُستخدَم مكوّنات مستورَدة لتصنيع مادة في الولايات المتحدة، ثم تُصدَّر المادة المصنوعة. ما نوع استرداد الرسوم (drawback) المتاح، وما الحد الزمني العام؟"},"o":[{"en":"Unused merchandise drawback; the goods must be exported within three years of importation","es":"Drawback de mercancía no usada; las mercancías deben exportarse dentro de los tres años posteriores a la importación","ru":"Возврат за неиспользованные товары (unused merchandise drawback); товары должны быть экспортированы в течение трех лет с момента импорта","tr":"Kullanılmamış mal iadesi (unused merchandise drawback); malların ithalattan itibaren üç yıl içinde ihraç edilmesi gerekir","hi":"unused merchandise drawback; माल को आयात के तीन वर्ष के भीतर निर्यात किया जाना चाहिए","ar":"استرداد رسوم البضاعة غير المستخدمة؛ يجب تصدير البضائع خلال ثلاث سنوات من الاستيراد"},{"en":"Rejected merchandise drawback; the article must be exported within three years of importation","es":"Drawback de mercancía rechazada; el artículo debe exportarse dentro de los tres años posteriores a la importación","ru":"Возврат за отбракованные товары (rejected merchandise drawback); изделие должно быть экспортировано в течение трех лет с момента импорта","tr":"Reddedilmiş mal iadesi (rejected merchandise drawback); ürünün ithalattan itibaren üç yıl içinde ihraç edilmesi gerekir","hi":"rejected merchandise drawback; वस्तु को आयात के तीन वर्ष के भीतर निर्यात किया जाना चाहिए","ar":"استرداد رسوم البضاعة المرفوضة؛ يجب تصدير المادة خلال ثلاث سنوات من الاستيراد"},{"en":"Manufacturing drawback; the article must be exported within two years and the claim filed within three years of exportation","es":"Drawback de manufactura; el artículo debe exportarse dentro de dos años y la reclamación presentarse dentro de tres años de la exportación","ru":"Производственный возврат (manufacturing drawback); изделие должно быть экспортировано в течение двух лет, а требование подано в течение трех лет с момента экспорта","tr":"İmalat iadesi (manufacturing drawback); ürünün iki yıl içinde ihraç edilmesi ve talebin ihracattan itibaren üç yıl içinde sunulması gerekir","hi":"manufacturing drawback; वस्तु को दो वर्ष के भीतर निर्यात किया जाना चाहिए और दावा निर्यात के तीन वर्ष के भीतर दाखिल किया जाना चाहिए","ar":"استرداد رسوم التصنيع؛ يجب تصدير المادة خلال سنتين وتقديم المطالبة خلال ثلاث سنوات من التصدير"},{"en":"Manufacturing drawback; the article must be exported or destroyed within five years of importation, and the claim filed within five years of importation","es":"Drawback de manufactura; el artículo debe exportarse o destruirse dentro de los cinco años posteriores a la importación, y la reclamación presentarse dentro de los cinco años posteriores a la importación","ru":"Производственный возврат (manufacturing drawback); изделие должно быть экспортировано или уничтожено в течение пяти лет с момента импорта, а требование подано в течение пяти лет с момента импорта","tr":"İmalat iadesi (manufacturing drawback); ürünün ithalattan itibaren beş yıl içinde ihraç edilmesi veya imha edilmesi ve talebin ithalattan itibaren beş yıl içinde sunulması gerekir","hi":"manufacturing drawback; वस्तु को आयात के पाँच वर्ष के भीतर निर्यात या नष्ट किया जाना चाहिए, और दावा आयात के पाँच वर्ष के भीतर दाखिल किया जाना चाहिए","ar":"استرداد رسوم التصنيع؛ يجب تصدير المادة أو إتلافها خلال خمس سنوات من الاستيراد، وتقديم المطالبة خلال خمس سنوات من الاستيراد"}],"e":{"en":"Manufacturing drawback (19 U.S.C. 1313(a)/(b)) applies when imported merchandise is used to make an exported or destroyed article. Under the modernized rules, the exportation/destruction and the filing of the claim must occur within five years of the date of importation of the designated merchandise. See 19 U.S.C. 1313(r) and 19 CFR part 190 (subpart B).","es":"El drawback de manufactura (reintegro de derechos) (19 U.S.C. 1313(a)/(b)) se aplica cuando se usa mercancía importada para fabricar un artículo exportado o destruido. Conforme a las reglas modernizadas, la exportación/destrucción y la presentación de la reclamación deben ocurrir dentro de los cinco años posteriores a la fecha de importación de la mercancía designada. Véanse 19 U.S.C. 1313(r) y 19 CFR part 190 (subpart B).","ru":"Производственный возврат (manufacturing drawback) (19 U.S.C. 1313(a)/(b)) применяется, когда импортированные товары используются для изготовления экспортируемого или уничтожаемого изделия. Согласно модернизированным правилам, экспорт/уничтожение и подача требования должны произойти в течение пяти лет с даты импорта обозначенных товаров. См. 19 U.S.C. 1313(r) и 19 CFR part 190 (subpart B).","tr":"İmalat iadesi (manufacturing drawback) (19 U.S.C. 1313(a)/(b)), ithal edilen malların ihraç edilen veya imha edilen bir ürün yapmak için kullanıldığı durumlarda geçerlidir. Modernize edilmiş kurallar uyarınca, ihracat/imha ile talebin sunulması, belirlenen malın ithalat tarihinden itibaren beş yıl içinde gerçekleşmelidir. Bakınız 19 U.S.C. 1313(r) ve 19 CFR part 190 (subpart B).","hi":"manufacturing drawback (19 U.S.C. 1313(a)/(b)) तब लागू होता है जब आयातित माल का उपयोग एक निर्यातित या नष्ट की गई वस्तु बनाने के लिए किया जाता है। आधुनिकीकृत नियमों के तहत, निर्यात/विनाश और दावे की दाखिल करना निर्दिष्ट माल के आयात की तारीख के पाँच वर्ष के भीतर होना चाहिए। देखें 19 U.S.C. 1313(r) और 19 CFR part 190 (subpart B)।","ar":"ينطبق استرداد رسوم التصنيع (manufacturing drawback) بموجب 19 U.S.C. 1313(a)/(b) عند استخدام بضاعة مستورَدة لصنع مادة مصدَّرة أو مُتلَفة. وبموجب القواعد المحدَّثة، يجب أن يقع التصدير/الإتلاف وتقديم المطالبة خلال خمس سنوات من تاريخ استيراد البضاعة المعيّنة. انظر 19 U.S.C. 1313(r) و19 CFR part 190 (subpart B)."}},{"cat":"duties","a":0,"q":{"en":"An importer pays duties, taxes, and fees on goods, then exports the identical goods without using them in the United States. The importer files an unused merchandise drawback claim. What portion of the eligible duties, taxes, and fees may be refunded?","es":"Un importador paga derechos, impuestos y tarifas sobre mercancías, y luego exporta las mercancías idénticas sin haberlas usado en Estados Unidos. El importador presenta una reclamación de drawback por mercancía no usada. ¿Qué porción de los derechos, impuestos y tarifas elegibles puede reembolsarse?","ru":"Импортер уплачивает пошлины, налоги и сборы за товары, затем экспортирует те же самые товары, не использовав их в Соединенных Штатах. Импортер подает требование о возврате за неиспользованные товары (unused merchandise drawback). Какая часть подлежащих возврату пошлин, налогов и сборов может быть возвращена?","tr":"Bir ithalatçı, mallar üzerinden vergileri, vergileri (taxes) ve ücretleri öder, ardından aynı malları Amerika Birleşik Devletleri'nde kullanmadan ihraç eder. İthalatçı, kullanılmamış mal iadesi (unused merchandise drawback) talebinde bulunur. Uygun vergilerin, vergilerin (taxes) ve ücretlerin ne kadarlık kısmı iade edilebilir?","hi":"एक आयातकर्ता माल पर शुल्क, कर और फीस का भुगतान करता है, फिर संयुक्त राज्य अमेरिका में उनका उपयोग किए बिना समान माल को निर्यात करता है। आयातकर्ता एक unused merchandise drawback दावा दाखिल करता है। पात्र शुल्क, कर और फीस का कितना हिस्सा वापस किया जा सकता है?","ar":"يدفع مستورد الرسوم والضرائب والأتعاب على بضائع، ثم يصدّر البضائع نفسها دون استخدامها في الولايات المتحدة. ويقدّم المستورد مطالبة باسترداد رسوم البضاعة غير المستخدمة. ما الجزء الذي يجوز ردّه من الرسوم والضرائب والأتعاب المؤهلة؟"},"o":[{"en":"Ninety-nine percent","es":"Noventa y nueve por ciento","ru":"Девяносто девять процентов","tr":"Yüzde doksan dokuz","hi":"निन्यानवे प्रतिशत","ar":"تسعة وتسعون بالمئة"},{"en":"One hundred percent","es":"Cien por ciento","ru":"Сто процентов","tr":"Yüzde yüz","hi":"एक सौ प्रतिशत","ar":"مئة بالمئة"},{"en":"Ninety percent","es":"Noventa por ciento","ru":"Девяносто процентов","tr":"Yüzde doksan","hi":"नब्बे प्रतिशत","ar":"تسعون بالمئة"},{"en":"Ninety-five percent","es":"Noventa y cinco por ciento","ru":"Девяносто пять процентов","tr":"Yüzde doksan beş","hi":"पंचानवे प्रतिशत","ar":"خمسة وتسعون بالمئة"}],"e":{"en":"Drawback, including unused merchandise drawback under 19 U.S.C. 1313(j), refunds 99 percent of the duties, taxes, and fees paid on the imported merchandise (CBP retains 1 percent). Eligible amounts can include ordinary duties, certain Section 301 duties, MPF, and HMF. See 19 U.S.C. 1313(l) and 19 CFR part 190.","es":"El drawback (reintegro de derechos), incluido el drawback de mercancía no usada conforme a 19 U.S.C. 1313(j), reembolsa el 99 por ciento de los derechos, impuestos y tarifas pagados sobre la mercancía importada (CBP retiene el 1 por ciento). Los montos elegibles pueden incluir derechos ordinarios, ciertos derechos de la Section 301, el MPF y el HMF. Véanse 19 U.S.C. 1313(l) y 19 CFR part 190.","ru":"Возврат пошлин (drawback), включая возврат за неиспользованные товары согласно 19 U.S.C. 1313(j), возвращает 99 процентов пошлин, налогов и сборов, уплаченных за импортированные товары (CBP удерживает 1 процент). Подлежащие возврату суммы могут включать обычные пошлины, некоторые пошлины Section 301, MPF и HMF. См. 19 U.S.C. 1313(l) и 19 CFR part 190.","tr":"19 U.S.C. 1313(j) kapsamındaki kullanılmamış mal iadesi (unused merchandise drawback) dahil olmak üzere drawback, ithal edilen mallar üzerinden ödenen vergilerin, vergilerin (taxes) ve ücretlerin yüzde 99'unu iade eder (CBP yüzde 1'ini alıkoyar). Uygun tutarlar; olağan vergileri, belirli Section 301 vergilerini, MPF ve HMF'yi içerebilir. Bakınız 19 U.S.C. 1313(l) ve 19 CFR part 190.","hi":"drawback (शुल्क वापसी), जिसमें 19 U.S.C. 1313(j) के तहत unused merchandise drawback शामिल है, आयातित माल पर भुगतान किए गए शुल्क, कर और फीस का 99 प्रतिशत वापस करता है (CBP 1 प्रतिशत रखता है)। पात्र राशियों में सामान्य शुल्क, कुछ Section 301 शुल्क, MPF, और HMF शामिल हो सकते हैं। देखें 19 U.S.C. 1313(l) और 19 CFR part 190।","ar":"يردّ استرداد الرسوم، بما فيه استرداد رسوم البضاعة غير المستخدمة بموجب 19 U.S.C. 1313(j)، نسبة 99 بالمئة من الرسوم والضرائب والأتعاب المدفوعة على البضاعة المستورَدة (تحتفظ CBP بنسبة 1 بالمئة). ويمكن أن تشمل المبالغ المؤهلة الرسوم العادية، وبعض رسوم Section 301، و MPF، و HMF. انظر 19 U.S.C. 1313(l) و19 CFR part 190."}},{"cat":"duties","a":3,"q":{"en":"Merchandise was entered and duty-paid, but it does not conform to the buyer's specifications and is exported without having been used. Which drawback type applies, and what is the controlling time limit for exportation or destruction?","es":"La mercancía fue declarada y se pagaron sus derechos, pero no se ajusta a las especificaciones del comprador y se exporta sin haber sido usada. ¿Qué tipo de drawback aplica y cuál es el límite de tiempo determinante para la exportación o destrucción?","ru":"Товары были оформлены с уплатой пошлины, но они не соответствуют спецификациям покупателя и экспортируются, не будучи использованными. Какой тип возврата пошлин (drawback) применяется, и каков определяющий срок для экспорта или уничтожения?","tr":"Mallar beyan edilip vergileri ödenmiş, ancak alıcının spesifikasyonlarına uymadığı ve kullanılmadan ihraç edildiği ortaya çıkıyor. Hangi drawback türü geçerlidir ve ihracat veya imha için belirleyici süre sınırı nedir?","hi":"माल एंटर किया गया और शुल्क-चुकता था, लेकिन यह खरीदार के विनिर्देशों के अनुरूप नहीं है और उपयोग किए बिना निर्यात किया जाता है। कौन-सा drawback प्रकार लागू होता है, और निर्यात या विनाश के लिए नियंत्रक समय-सीमा क्या है?","ar":"أُدخلت بضاعة ودُفعت رسومها، لكنها لا تطابق مواصفات المشتري وتُصدَّر دون استخدامها. أي نوع من استرداد الرسوم ينطبق، وما الحد الزمني الحاكم للتصدير أو الإتلاف؟"},"o":[{"en":"Substitution manufacturing drawback; within five years of importation","es":"Drawback de manufactura por sustitución; dentro de los cinco años posteriores a la importación","ru":"Замещающий производственный возврат (substitution manufacturing drawback); в течение пяти лет с момента импорта","tr":"İkame imalat iadesi (substitution manufacturing drawback); ithalattan itibaren beş yıl içinde","hi":"substitution manufacturing drawback; आयात के पाँच वर्ष के भीतर","ar":"استرداد رسوم التصنيع بالاستبدال؛ خلال خمس سنوات من الاستيراد"},{"en":"Rejected merchandise drawback; the goods must be exported or destroyed within three years after the date of importation","es":"Drawback de mercancía rechazada; las mercancías deben exportarse o destruirse dentro de los tres años posteriores a la fecha de importación","ru":"Возврат за отбракованные товары (rejected merchandise drawback); товары должны быть экспортированы или уничтожены в течение трех лет после даты импорта","tr":"Reddedilmiş mal iadesi (rejected merchandise drawback); malların ithalat tarihinden itibaren üç yıl içinde ihraç edilmesi veya imha edilmesi gerekir","hi":"rejected merchandise drawback; माल को आयात की तारीख के बाद तीन वर्ष के भीतर निर्यात या नष्ट किया जाना चाहिए","ar":"استرداد رسوم البضاعة المرفوضة؛ يجب تصدير البضائع أو إتلافها خلال ثلاث سنوات بعد تاريخ الاستيراد"},{"en":"Direct identification unused merchandise drawback; within two years of importation","es":"Drawback de mercancía no usada por identificación directa; dentro de los dos años posteriores a la importación","ru":"Возврат за неиспользованные товары с прямой идентификацией (direct identification unused merchandise drawback); в течение двух лет с момента импорта","tr":"Doğrudan tanımlama kullanılmamış mal iadesi (direct identification unused merchandise drawback); ithalattan itibaren iki yıl içinde","hi":"direct identification unused merchandise drawback; आयात के दो वर्ष के भीतर","ar":"استرداد رسوم البضاعة غير المستخدمة بالتحديد المباشر؛ خلال سنتين من الاستيراد"},{"en":"Rejected merchandise drawback; the goods must be exported within five years after the date of importation","es":"Drawback de mercancía rechazada; las mercancías deben exportarse dentro de los cinco años posteriores a la fecha de importación","ru":"Возврат за отбракованные товары (rejected merchandise drawback); товары должны быть экспортированы в течение пяти лет после даты импорта","tr":"Reddedilmiş mal iadesi (rejected merchandise drawback); malların ithalat tarihinden itibaren beş yıl içinde ihraç edilmesi gerekir","hi":"rejected merchandise drawback; माल को आयात की तारीख के बाद पाँच वर्ष के भीतर निर्यात किया जाना चाहिए","ar":"استرداد رسوم البضاعة المرفوضة؛ يجب تصدير البضائع خلال خمس سنوات بعد تاريخ الاستيراد"}],"e":{"en":"Rejected merchandise drawback under 19 U.S.C. 1313(c) covers duty-paid goods that do not conform to sample or specifications, were shipped without consent, or were defective at importation. The merchandise must be exported or destroyed under CBP supervision within five years (modernized law, 19 CFR 190.42 / 19 USC 1313(c)) after the date of importation. See 19 U.S.C. 1313(c) and 19 CFR part 190 (subpart D).","es":"El drawback de mercancía rechazada conforme a 19 U.S.C. 1313(c) cubre las mercancías con derechos pagados que no se ajustan a la muestra o las especificaciones, fueron enviadas sin consentimiento o estaban defectuosas al momento de la importación. La mercancía debe exportarse o destruirse bajo supervisión de CBP dentro de los cinco años (ley modernizada, 19 CFR 190.42 / 19 USC 1313(c)) posteriores a la fecha de importación. Véanse 19 U.S.C. 1313(c) y 19 CFR part 190 (subpart D).","ru":"Возврат за отбракованные товары (rejected merchandise drawback) согласно 19 U.S.C. 1313(c) охватывает товары с уплаченной пошлиной, которые не соответствуют образцу или спецификациям, были отгружены без согласия или были дефектными при импорте. Товары должны быть экспортированы или уничтожены под надзором CBP в течение пяти лет (модернизированное законодательство, 19 CFR 190.42 / 19 USC 1313(c)) после даты импорта. См. 19 U.S.C. 1313(c) и 19 CFR part 190 (subpart D).","tr":"19 U.S.C. 1313(c) kapsamındaki reddedilmiş mal iadesi (rejected merchandise drawback); numuneye veya spesifikasyonlara uymayan, rıza olmadan sevk edilen veya ithalat anında kusurlu olan, vergisi ödenmiş malları kapsar. Mallar, CBP gözetimi altında ithalat tarihinden itibaren beş yıl içinde (modernize edilmiş yasa, 19 CFR 190.42 / 19 USC 1313(c)) ihraç edilmeli veya imha edilmelidir. Bakınız 19 U.S.C. 1313(c) ve 19 CFR part 190 (subpart D).","hi":"19 U.S.C. 1313(c) के तहत rejected merchandise drawback उन शुल्क-चुकता माल को कवर करता है जो नमूने या विनिर्देशों के अनुरूप नहीं हैं, सहमति के बिना भेजे गए थे, या आयात के समय दोषपूर्ण थे। माल को CBP की देखरेख में आयात की तारीख के बाद पाँच वर्ष के भीतर (आधुनिकीकृत कानून, 19 CFR 190.42 / 19 USC 1313(c)) निर्यात या नष्ट किया जाना चाहिए। देखें 19 U.S.C. 1313(c) और 19 CFR part 190 (subpart D)।","ar":"يشمل استرداد رسوم البضاعة المرفوضة (rejected merchandise drawback) بموجب 19 U.S.C. 1313(c) البضائع المدفوعة رسومها التي لا تطابق العينة أو المواصفات، أو شُحنت دون موافقة، أو كانت معيبة عند الاستيراد. ويجب تصدير البضاعة أو إتلافها تحت إشراف CBP خلال خمس سنوات (القانون المحدَّث، 19 CFR 190.42 / 19 USC 1313(c)) بعد تاريخ الاستيراد. انظر 19 U.S.C. 1313(c) و19 CFR part 190 (subpart D)."}},{"cat":"compliance","a":1,"q":{"en":"A licensed individual broker who is an employee of a corporate broker wants to file entries on the corporation's behalf at a port located outside the corporation's home district. Under the current regulations, what authorization permits the corporate broker to transact customs business throughout the customs territory of the United States?","es":"Un agente de aduanas individual con licencia que es empleado de un agente corporativo desea presentar entradas en nombre de la corporación en un puerto ubicado fuera del distrito de origen de la corporación. Conforme a la normativa actual, ¿qué autorización permite al agente corporativo realizar negocios aduaneros en todo el territorio aduanero de Estados Unidos?","ru":"Лицензированный индивидуальный брокер, являющийся работником корпоративного брокера, хочет подавать оформления от имени корпорации в порту, расположенном за пределами родного округа корпорации. Согласно действующим нормам, какое разрешение позволяет корпоративному брокеру вести таможенную деятельность на всей таможенной территории Соединенных Штатов?","tr":"Bir kurumsal gümrük müşaviri (corporate broker) bünyesinde çalışan, lisanslı bir bireysel gümrük müşaviri, şirketin ana bölgesi (district) dışında bulunan bir limanda şirket adına beyanlar sunmak istiyor. Mevcut düzenlemeler kapsamında, kurumsal gümrük müşavirinin Amerika Birleşik Devletleri gümrük bölgesinin tamamında gümrük işlemleri yürütmesine hangi yetki izin verir?","hi":"एक लाइसेंस-प्राप्त व्यक्तिगत ब्रोकर जो एक कॉर्पोरेट ब्रोकर का कर्मचारी है, कॉर्पोरेशन की ओर से कॉर्पोरेशन के home district के बाहर स्थित एक बंदरगाह पर एंट्री दाखिल करना चाहता है। वर्तमान नियमों के तहत, कौन-सा प्राधिकरण कॉर्पोरेट ब्रोकर को संयुक्त राज्य अमेरिका के पूरे कस्टम क्षेत्र में customs business करने की अनुमति देता है?","ar":"يرغب وسيط فرد مرخَّص يعمل لدى وسيط مؤسسي في تقديم إدخالات نيابةً عن المؤسسة في ميناء يقع خارج المنطقة الإدارية الأم للمؤسسة. بموجب اللوائح الحالية، ما التفويض الذي يتيح للوسيط المؤسسي مزاولة الأعمال الجمركية في جميع أنحاء الإقليم الجمركي للولايات المتحدة؟"},"o":[{"en":"A separate district permit must be obtained for each port of entry where the broker files","es":"Debe obtenerse un permiso de distrito separado para cada puerto de entrada donde el agente presente declaraciones","ru":"Для каждого порта ввоза, где брокер подает оформления, необходимо получить отдельное окружное разрешение","tr":"Gümrük müşavirinin beyan sunduğu her giriş limanı için ayrı bir bölge (district) izni alınmalıdır","hi":"जहाँ ब्रोकर दाखिल करता है, उस प्रत्येक port of entry के लिए एक अलग district permit प्राप्त करना होगा","ar":"يجب الحصول على تصريح منطقة منفصل لكل ميناء دخول يقدّم فيه الوسيط"},{"en":"A single national permit issued under 19 CFR 111.19","es":"Un único permiso nacional emitido conforme a 19 CFR 111.19","ru":"Единое национальное разрешение, выдаваемое согласно 19 CFR 111.19","tr":"19 CFR 111.19 kapsamında verilen tek bir ulusal izin (national permit)","hi":"19 CFR 111.19 के तहत जारी एक एकल national permit","ar":"تصريح وطني واحد يصدر بموجب 19 CFR 111.19"},{"en":"The individual employee's broker license alone, with no permit needed","es":"La licencia de agente del empleado individual por sí sola, sin necesidad de permiso","ru":"Только брокерская лицензия самого индивидуального работника, без необходимости разрешения","tr":"Tek başına bireysel çalışanın gümrük müşaviri lisansı, herhangi bir izne gerek yoktur","hi":"अकेले व्यक्तिगत कर्मचारी का ब्रोकर लाइसेंस, बिना किसी permit की आवश्यकता के","ar":"رخصة الموظف الفرد للوساطة وحدها، دون حاجة إلى تصريح"},{"en":"A waiver of permit requirements granted by the port director at each location","es":"Una exención de los requisitos de permiso otorgada por el director del puerto en cada ubicación","ru":"Освобождение от требований к разрешению, предоставляемое директором порта в каждом месте","tr":"Her bir konumda liman müdürü tarafından verilen izin gerekliliklerinden feragat","hi":"प्रत्येक स्थान पर port director द्वारा प्रदान की गई permit आवश्यकताओं की छूट","ar":"تنازل عن متطلبات التصريح يمنحه مدير الميناء في كل موقع"}],"e":{"en":"Under 19 CFR 111.19, a national permit authorizes a broker to conduct customs business throughout the customs territory of the United States. The 2022 modernization rule eliminated district permits, so a single national permit now covers all ports. A license alone does not authorize transacting customs business; a permit is also required.","es":"Conforme a 19 CFR 111.19, un permiso nacional autoriza a un agente a realizar negocios aduaneros en todo el territorio aduanero de Estados Unidos. La regla de modernización de 2022 eliminó los permisos de distrito, por lo que un único permiso nacional ahora cubre todos los puertos. Una licencia por sí sola no autoriza a realizar negocios aduaneros; también se requiere un permiso.","ru":"Согласно 19 CFR 111.19, национальное разрешение уполномочивает брокера вести таможенную деятельность на всей таможенной территории Соединенных Штатов. Правило модернизации 2022 года упразднило окружные разрешения, поэтому единое национальное разрешение теперь охватывает все порты. Одна лицензия не уполномочивает вести таможенную деятельность; также требуется разрешение.","tr":"19 CFR 111.19 kapsamında, bir ulusal izin (national permit), bir gümrük müşavirinin Amerika Birleşik Devletleri gümrük bölgesinin tamamında gümrük işlemleri yürütmesine yetki verir. 2022 modernizasyon kuralı bölge (district) izinlerini kaldırdığından, artık tek bir ulusal izin tüm limanları kapsar. Tek başına bir lisans, gümrük işlemleri yürütmeye yetki vermez; ayrıca bir izin de gereklidir.","hi":"19 CFR 111.19 के तहत, एक national permit ब्रोकर को संयुक्त राज्य अमेरिका के पूरे कस्टम क्षेत्र में customs business करने के लिए अधिकृत करता है। 2022 के आधुनिकीकरण नियम ने district permits को समाप्त कर दिया, इसलिए अब एक एकल national permit सभी बंदरगाहों को कवर करता है। अकेला लाइसेंस customs business करने के लिए अधिकृत नहीं करता; एक permit की भी आवश्यकता होती है।","ar":"بموجب 19 CFR 111.19، يُفوّض التصريح الوطني الوسيط بمزاولة الأعمال الجمركية في جميع أنحاء الإقليم الجمركي للولايات المتحدة. وقد ألغت قاعدة التحديث لعام 2022 تصاريح المناطق، فأصبح التصريح الوطني الواحد يغطي جميع الموانئ. ولا تخوّل الرخصة وحدها مزاولة الأعمال الجمركية؛ بل يلزم تصريح أيضاً."}},{"cat":"compliance","a":1,"q":{"en":"Which statement most accurately distinguishes a customs broker's license from a permit?","es":"¿Qué afirmación distingue con mayor precisión la licencia de un agente de aduanas de su permiso?","ru":"Какое утверждение наиболее точно отличает лицензию таможенного брокера от разрешения?","tr":"Aşağıdaki ifadelerden hangisi, bir gümrük müşavirinin lisansını izninden en doğru şekilde ayırt eder?","hi":"कौन-सा कथन एक customs broker के लाइसेंस को permit से सबसे सटीक रूप से अलग करता है?","ar":"أي عبارة تميّز بدقة أكبر رخصة الوسيط الجمركي عن تصريحه؟"},"o":[{"en":"A license authorizes a person to transact customs business at a specific port, while a permit authorizes nationwide activity","es":"Una licencia autoriza a una persona a realizar negocios aduaneros en un puerto específico, mientras que un permiso autoriza la actividad a nivel nacional","ru":"Лицензия уполномочивает лицо вести таможенную деятельность в конкретном порту, тогда как разрешение уполномочивает на деятельность по всей стране","tr":"Lisans, bir kişiye belirli bir limanda gümrük işlemleri yürütme yetkisi verirken, izin ülke çapında faaliyete yetki verir","hi":"एक लाइसेंस किसी व्यक्ति को एक विशिष्ट बंदरगाह पर customs business करने के लिए अधिकृत करता है, जबकि एक permit देशव्यापी गतिविधि के लिए अधिकृत करता है","ar":"تخوّل الرخصة الشخص مزاولة الأعمال الجمركية في ميناء محدد، بينما يخوّل التصريح النشاط على المستوى الوطني"},{"en":"A license confers the personal authority to engage in customs business, while a permit authorizes the licensee or organization to actually conduct that business","es":"Una licencia confiere la autoridad personal para dedicarse a negocios aduaneros, mientras que un permiso autoriza al titular de la licencia o a la organización a realizar efectivamente ese negocio","ru":"Лицензия предоставляет личное право заниматься таможенной деятельностью, тогда как разрешение уполномочивает лицензиата или организацию фактически вести эту деятельность","tr":"Lisans, kişiye gümrük işlemlerine girişme şeklindeki kişisel yetkiyi verirken, izin lisans sahibine veya kuruluşa bu işi fiilen yürütme yetkisi verir","hi":"एक लाइसेंस customs business में संलग्न होने का व्यक्तिगत अधिकार प्रदान करता है, जबकि एक permit लाइसेंसधारी या संगठन को वास्तव में वह व्यवसाय करने के लिए अधिकृत करता है","ar":"تمنح الرخصة الصلاحية الشخصية لممارسة الأعمال الجمركية، بينما يخوّل التصريح المرخَّص له أو المنظمة المزاولة الفعلية لتلك الأعمال"},{"en":"A permit is issued only to individuals, while a license is issued only to organizations","es":"Un permiso se emite solo a individuos, mientras que una licencia se emite solo a organizaciones","ru":"Разрешение выдается только физическим лицам, тогда как лицензия выдается только организациям","tr":"İzin yalnızca bireylere verilirken, lisans yalnızca kuruluşlara verilir","hi":"एक permit केवल व्यक्तियों को जारी किया जाता है, जबकि एक लाइसेंस केवल संगठनों को जारी किया जाता है","ar":"يُصدَر التصريح للأفراد فقط، بينما تُصدَر الرخصة للمنظمات فقط"},{"en":"A license must be renewed annually, while a permit is valid for the life of the holder","es":"Una licencia debe renovarse anualmente, mientras que un permiso es válido por toda la vida del titular","ru":"Лицензия должна продлеваться ежегодно, тогда как разрешение действительно в течение всей жизни держателя","tr":"Lisans yıllık olarak yenilenmelidir, izin ise sahibinin ömrü boyunca geçerlidir","hi":"एक लाइसेंस को सालाना नवीनीकृत किया जाना चाहिए, जबकि एक permit धारक के जीवनकाल के लिए वैध होता है","ar":"يجب تجديد الرخصة سنوياً، بينما يكون التصريح صالحاً مدى حياة حامله"}],"e":{"en":"Under 19 CFR Part 111, the license (111.11 et seq.) grants a person or organization the authority to engage in customs business, while the permit (111.19) is the separate authorization required to actually conduct that business. Both individuals and organizations can hold licenses and permits; neither is renewed annually (status reports are triennial under 111.30).","es":"Conforme a 19 CFR Part 111, la licencia (111.11 y siguientes) otorga a una persona u organización la autoridad para dedicarse a negocios aduaneros, mientras que el permiso (111.19) es la autorización separada requerida para realizar efectivamente ese negocio. Tanto los individuos como las organizaciones pueden tener licencias y permisos; ninguno se renueva anualmente (los informes de estatus son trienales conforme a 111.30).","ru":"Согласно 19 CFR Part 111, лицензия (111.11 и далее) предоставляет лицу или организации право заниматься таможенной деятельностью, тогда как разрешение (111.19) является отдельным полномочием, необходимым для фактического ведения этой деятельности. И физические лица, и организации могут иметь лицензии и разрешения; ни одно из них не продлевается ежегодно (отчеты о статусе подаются раз в три года согласно 111.30).","tr":"19 CFR Part 111 kapsamında, lisans (111.11 ve devamı) bir kişiye veya kuruluşa gümrük işlemlerine girişme yetkisi verirken, izin (111.19) bu işi fiilen yürütmek için gerekli olan ayrı bir yetkidir. Hem bireyler hem de kuruluşlar lisans ve izin sahibi olabilir; hiçbiri yıllık olarak yenilenmez (durum raporları 111.30 uyarınca üç yılda birdir).","hi":"19 CFR Part 111 के तहत, लाइसेंस (111.11 et seq.) किसी व्यक्ति या संगठन को customs business में संलग्न होने का अधिकार देता है, जबकि permit (111.19) वास्तव में वह व्यवसाय करने के लिए आवश्यक अलग प्राधिकरण है। व्यक्ति और संगठन दोनों लाइसेंस और permits धारण कर सकते हैं; इनमें से कोई भी सालाना नवीनीकृत नहीं होता (status reports 111.30 के तहत त्रैवार्षिक हैं)।","ar":"بموجب 19 CFR Part 111، تمنح الرخصة (111.11 وما يليها) الشخص أو المنظمة صلاحية ممارسة الأعمال الجمركية، بينما التصريح (111.19) هو التفويض المنفصل اللازم للمزاولة الفعلية لتلك الأعمال. ويمكن للأفراد والمنظمات حيازة الرخص والتصاريح؛ ولا يُجدَّد أيٌّ منهما سنوياً (تقارير الحالة تُقدَّم كل ثلاث سنوات بموجب 111.30)."}},{"cat":"compliance","a":2,"q":{"en":"An applicant for an individual customs broker license must satisfy several statutory requirements. Which of the following is NOT a requirement to obtain an individual license under 19 CFR 111.11?","es":"Un solicitante de una licencia individual de agente de aduanas debe cumplir varios requisitos legales. ¿Cuál de los siguientes NO es un requisito para obtener una licencia individual conforme a 19 CFR 111.11?","ru":"Заявитель на получение индивидуальной лицензии таможенного брокера должен удовлетворять нескольким установленным законом требованиям. Что из перечисленного НЕ является требованием для получения индивидуальной лицензии согласно 19 CFR 111.11?","tr":"Bir bireysel gümrük müşaviri lisansı başvuru sahibi, çeşitli yasal gereklilikleri karşılamalıdır. Aşağıdakilerden hangisi 19 CFR 111.11 kapsamında bireysel bir lisans almak için gerekli DEĞİLDİR?","hi":"एक व्यक्तिगत customs broker लाइसेंस के आवेदक को कई वैधानिक आवश्यकताओं को पूरा करना होता है। 19 CFR 111.11 के तहत व्यक्तिगत लाइसेंस प्राप्त करने के लिए निम्नलिखित में से कौन-सी आवश्यकता नहीं है?","ar":"يجب على طالب رخصة وسيط جمركي فردي استيفاء عدة متطلبات قانونية. أي مما يلي ليس شرطاً للحصول على رخصة فردية بموجب 19 CFR 111.11؟"},"o":[{"en":"Be a citizen of the United States","es":"Ser ciudadano de Estados Unidos","ru":"Быть гражданином Соединенных Штатов","tr":"Amerika Birleşik Devletleri vatandaşı olmak","hi":"संयुक्त राज्य अमेरिका का नागरिक होना","ar":"أن يكون مواطناً من مواطني الولايات المتحدة"},{"en":"Attain the age of 21 prior to submission of the application","es":"Cumplir 21 años de edad antes de la presentación de la solicitud","ru":"Достичь возраста 21 года до подачи заявления","tr":"Başvurunun sunulmasından önce 21 yaşını doldurmak","hi":"आवेदन जमा करने से पहले 21 वर्ष की आयु प्राप्त करना","ar":"أن يبلغ سن 21 قبل تقديم الطلب"},{"en":"Have at least three years of prior experience as a customs broker employee","es":"Tener al menos tres años de experiencia previa como empleado de un agente de aduanas","ru":"Иметь не менее трех лет предшествующего опыта работы в качестве сотрудника таможенного брокера","tr":"Gümrük müşaviri çalışanı olarak en az üç yıl önceden deneyime sahip olmak","hi":"customs broker कर्मचारी के रूप में कम से कम तीन वर्ष का पूर्व अनुभव होना","ar":"أن يكون لديه ما لا يقل عن ثلاث سنوات من الخبرة السابقة كموظف لدى وسيط جمركي"},{"en":"Not be an officer or employee of the United States Government","es":"No ser funcionario ni empleado del Gobierno de Estados Unidos","ru":"Не быть должностным лицом или работником Правительства Соединенных Штатов","tr":"Amerika Birleşik Devletleri Hükümetinin bir memuru veya çalışanı olmamak","hi":"संयुक्त राज्य सरकार का अधिकारी या कर्मचारी न होना","ar":"ألا يكون مسؤولاً أو موظفاً في حكومة الولايات المتحدة"}],"e":{"en":"Under 19 CFR 111.11(a), an individual applicant must be a U.S. citizen, be 21 years old before applying, not be a Federal officer or employee, demonstrate good moral character, and have passed the examination. There is no minimum prior-experience requirement to obtain the license.","es":"Conforme a 19 CFR 111.11(a), un solicitante individual debe ser ciudadano de Estados Unidos, tener 21 años antes de solicitar, no ser funcionario ni empleado federal, demostrar buen carácter moral y haber aprobado el examen. No existe un requisito mínimo de experiencia previa para obtener la licencia.","ru":"Согласно 19 CFR 111.11(a), индивидуальный заявитель должен быть гражданином США, достичь возраста 21 года до подачи заявления, не быть федеральным должностным лицом или работником, продемонстрировать добропорядочный нравственный облик и сдать экзамен. Требования к минимальному предшествующему опыту для получения лицензии нет.","tr":"19 CFR 111.11(a) kapsamında, bireysel bir başvuru sahibi ABD vatandaşı olmalı, başvurmadan önce 21 yaşında olmalı, bir Federal memur veya çalışan olmamalı, iyi ahlaki karakter sergilemeli ve sınavı geçmiş olmalıdır. Lisans almak için asgari önceden deneyim gerekliliği yoktur.","hi":"19 CFR 111.11(a) के तहत, एक व्यक्तिगत आवेदक को U.S. नागरिक होना चाहिए, आवेदन से पहले 21 वर्ष का होना चाहिए, Federal अधिकारी या कर्मचारी नहीं होना चाहिए, अच्छे नैतिक चरित्र का प्रदर्शन करना चाहिए, और परीक्षा उत्तीर्ण की होनी चाहिए। लाइसेंस प्राप्त करने के लिए कोई न्यूनतम पूर्व-अनुभव आवश्यकता नहीं है।","ar":"بموجب 19 CFR 111.11(a)، يجب أن يكون الطالب الفرد مواطناً أمريكياً، وأن يبلغ 21 عاماً قبل التقديم، وألا يكون مسؤولاً أو موظفاً اتحادياً، وأن يثبت حسن الخلق، وأن يكون قد اجتاز الامتحان. ولا يوجد شرط حدّ أدنى للخبرة السابقة للحصول على الرخصة."}},{"cat":"compliance","a":0,"q":{"en":"Regarding the written examination for an individual broker's license, which statement is correct under 19 CFR 111.13?","es":"Respecto al examen escrito para una licencia individual de agente, ¿qué afirmación es correcta conforme a 19 CFR 111.13?","ru":"Относительно письменного экзамена на получение индивидуальной брокерской лицензии, какое утверждение верно согласно 19 CFR 111.13?","tr":"Bir bireysel gümrük müşaviri lisansı için yazılı sınavla ilgili olarak, 19 CFR 111.13 kapsamında hangi ifade doğrudur?","hi":"एक व्यक्तिगत ब्रोकर लाइसेंस के लिए लिखित परीक्षा के संबंध में, 19 CFR 111.13 के तहत कौन-सा कथन सही है?","ar":"فيما يتعلق بالامتحان التحريري لرخصة الوسيط الفردي، أي عبارة صحيحة بموجب 19 CFR 111.13؟"},"o":[{"en":"An applicant must attain a grade of 75 percent or higher to pass the examination","es":"Un solicitante debe obtener una calificación de 75 por ciento o más para aprobar el examen","ru":"Заявитель должен набрать оценку 75 процентов или выше, чтобы сдать экзамен","tr":"Bir başvuru sahibi, sınavı geçmek için yüzde 75 veya daha yüksek bir not almalıdır","hi":"आवेदक को परीक्षा उत्तीर्ण करने के लिए 75 प्रतिशत या उससे अधिक का ग्रेड प्राप्त करना होगा","ar":"يجب أن يحصل الطالب على درجة 75 بالمئة أو أعلى لاجتياز الامتحان"},{"en":"The examination is offered three times per year and a passing grade of 70 percent is required","es":"El examen se ofrece tres veces al año y se requiere una calificación aprobatoria del 70 por ciento","ru":"Экзамен проводится три раза в год, и проходной балл составляет 70 процентов","tr":"Sınav yılda üç kez yapılır ve geçer not olarak yüzde 70 gerekir","hi":"परीक्षा वर्ष में तीन बार आयोजित की जाती है और 70 प्रतिशत का उत्तीर्ण ग्रेड आवश्यक है","ar":"يُقدَّم الامتحان ثلاث مرات في السنة وتُشترط درجة نجاح قدرها 70 بالمئة"},{"en":"Only individuals who are already employed by a licensed broker are eligible to sit for the examination","es":"Solo los individuos que ya están empleados por un agente con licencia son elegibles para presentar el examen","ru":"Только лица, уже трудоустроенные у лицензированного брокера, имеют право сдавать экзамен","tr":"Sınava girmeye yalnızca halihazırda lisanslı bir gümrük müşaviri tarafından istihdam edilen bireyler uygundur","hi":"केवल वे व्यक्ति जो पहले से ही एक लाइसेंस-प्राप्त ब्रोकर द्वारा नियोजित हैं, परीक्षा में बैठने के लिए पात्र हैं","ar":"لا يحقّ سوى للأفراد العاملين بالفعل لدى وسيط مرخَّص التقدّم لأداء الامتحان"},{"en":"An applicant must be at least 21 years old on the date of the examination to be eligible to take it","es":"Un solicitante debe tener al menos 21 años en la fecha del examen para ser elegible para presentarlo","ru":"Заявитель должен быть не моложе 21 года на дату экзамена, чтобы иметь право его сдавать","tr":"Bir başvuru sahibi, sınava girmeye uygun olmak için sınav tarihinde en az 21 yaşında olmalıdır","hi":"परीक्षा देने के पात्र होने के लिए आवेदक को परीक्षा की तारीख पर कम से कम 21 वर्ष का होना चाहिए","ar":"يجب أن يكون الطالب قد بلغ 21 عاماً على الأقل في تاريخ الامتحان ليحقّ له أداؤه"}],"e":{"en":"Under 19 CFR 111.11(a)(4) and 111.13, an applicant must attain a grade of at least 75 percent on the examination. The exam is generally given twice a year (the fourth Wednesday in April and October). One need not be employed by a broker to sit for the exam, and the age 21 requirement applies to obtaining the license, not taking the exam.","es":"Conforme a 19 CFR 111.11(a)(4) y 111.13, un solicitante debe obtener una calificación de al menos 75 por ciento en el examen. El examen generalmente se aplica dos veces al año (el cuarto miércoles de abril y de octubre). No es necesario estar empleado por un agente para presentar el examen, y el requisito de los 21 años aplica para obtener la licencia, no para presentar el examen.","ru":"Согласно 19 CFR 111.11(a)(4) и 111.13, заявитель должен набрать оценку не менее 75 процентов на экзамене. Экзамен обычно проводится дважды в год (четвертая среда апреля и октября). Не обязательно быть трудоустроенным у брокера, чтобы сдавать экзамен, а требование о возрасте 21 года применяется к получению лицензии, а не к сдаче экзамена.","tr":"19 CFR 111.11(a)(4) ve 111.13 kapsamında, bir başvuru sahibi sınavda en az yüzde 75 not almalıdır. Sınav genellikle yılda iki kez yapılır (Nisan ve Ekim aylarının dördüncü Çarşamba günü). Sınava girmek için bir gümrük müşaviri tarafından istihdam edilmek gerekli değildir ve 21 yaş gerekliliği, sınava girmek için değil, lisans almak için geçerlidir.","hi":"19 CFR 111.11(a)(4) और 111.13 के तहत, एक आवेदक को परीक्षा में कम से कम 75 प्रतिशत का ग्रेड प्राप्त करना होगा। परीक्षा आम तौर पर वर्ष में दो बार दी जाती है (April और October का चौथा Wednesday)। परीक्षा में बैठने के लिए किसी ब्रोकर द्वारा नियोजित होने की आवश्यकता नहीं है, और 21 वर्ष की आयु की आवश्यकता लाइसेंस प्राप्त करने पर लागू होती है, परीक्षा देने पर नहीं।","ar":"بموجب 19 CFR 111.11(a)(4) و111.13، يجب أن يحصل الطالب على درجة لا تقلّ عن 75 بالمئة في الامتحان. ويُقدَّم الامتحان عموماً مرتين في السنة (يوم الأربعاء الرابع من April وOctober). ولا يلزم أن يكون الشخص موظفاً لدى وسيط لأداء الامتحان، وينطبق شرط سن 21 على الحصول على الرخصة لا على أداء الامتحان."}},{"cat":"compliance","a":1,"q":{"en":"A freight forwarder asks a licensed broker to handle entries for an importer of record that the forwarder serves. How must the broker obtain its power of attorney to comply with 19 CFR 111.36?","es":"Un agente de carga (freight forwarder) le pide a un agente de aduanas con licencia que maneje las entradas de un importador registrado al que el agente de carga atiende. ¿Cómo debe obtener el agente de aduanas su power of attorney para cumplir con 19 CFR 111.36?","ru":"Экспедитор просит лицензированного брокера оформить ввоз для импортера-получателя (importer of record), которого обслуживает экспедитор. Как брокер должен получить свою доверенность (POA) для соблюдения 19 CFR 111.36?","tr":"Bir freight forwarder (nakliye komisyoncusu), lisanslı bir gümrük müşavirinden, hizmet verdiği bir importer of record (kayıtlı ithalatçı) için beyanları işlemesini istiyor. 19 CFR 111.36'ya uymak için gümrük müşaviri vekaletini (power of attorney) nasıl almalıdır?","hi":"एक freight forwarder एक लाइसेंस-प्राप्त ब्रोकर से एक importer of record के लिए एंट्री संभालने को कहता है जिसकी forwarder सेवा करता है। 19 CFR 111.36 का पालन करने के लिए ब्रोकर को अपना power of attorney कैसे प्राप्त करना चाहिए?","ar":"يطلب وكيل شحن من وسيط مرخَّص معالجة إدخالات لمستورد مسجَّل يخدمه الوكيل. كيف يجب على الوسيط الحصول على توكيله الرسمي (POA) امتثالاً لـ 19 CFR 111.36؟"},"o":[{"en":"The broker may accept a power of attorney from the freight forwarder acting as the importer's agent","es":"El agente de aduanas puede aceptar un power of attorney del agente de carga actuando como representante del importador","ru":"Брокер может принять доверенность от экспедитора, действующего в качестве агента импортера","tr":"Gümrük müşaviri, ithalatçının vekili olarak hareket eden freight forwarder'dan bir vekaletname kabul edebilir","hi":"ब्रोकर आयातकर्ता के एजेंट के रूप में कार्य करने वाले freight forwarder से power of attorney स्वीकार कर सकता है","ar":"يجوز للوسيط قبول توكيل رسمي من وكيل الشحن بوصفه وكيلاً للمستورد"},{"en":"The broker must execute a customs power of attorney directly with the importer of record, not through the freight forwarder","es":"El agente de aduanas debe ejecutar un power of attorney aduanero directamente con el importador registrado, no a través del agente de carga","ru":"Брокер должен оформить таможенную доверенность непосредственно с импортером-получателем (importer of record), а не через экспедитора","tr":"Gümrük müşaviri, freight forwarder aracılığıyla değil, doğrudan importer of record ile bir gümrük vekaletnamesi (POA) düzenlemelidir","hi":"ब्रोकर को सीधे importer of record के साथ एक customs power of attorney निष्पादित करना चाहिए, freight forwarder के माध्यम से नहीं","ar":"يجب على الوسيط إبرام توكيل رسمي جمركي مباشرةً مع المستورد المسجَّل، لا عبر وكيل الشحن"},{"en":"No power of attorney is required because the forwarder already holds one from the importer","es":"No se requiere power of attorney porque el agente de carga ya tiene uno del importador","ru":"Доверенность не требуется, поскольку у экспедитора уже есть доверенность от импортера","tr":"Vekaletname gerekli değildir, çünkü forwarder zaten ithalatçıdan bir tane almıştır","hi":"किसी power of attorney की आवश्यकता नहीं है क्योंकि forwarder के पास पहले से ही आयातकर्ता से एक है","ar":"لا يلزم توكيل رسمي لأن الوكيل يحوز بالفعل توكيلاً من المستورد"},{"en":"The broker may rely on a sub-power of attorney that the forwarder issues from its own master power of attorney","es":"El agente de aduanas puede basarse en un sub-power of attorney que el agente de carga emite a partir de su propio power of attorney maestro","ru":"Брокер может полагаться на субдоверенность, которую экспедитор выдает на основе своей собственной генеральной доверенности","tr":"Gümrük müşaviri, forwarder'ın kendi ana vekaletnamesinden düzenlediği bir alt vekaletnameye (sub-power of attorney) dayanabilir","hi":"ब्रोकर एक sub-power of attorney पर भरोसा कर सकता है जो forwarder अपने स्वयं के master power of attorney से जारी करता है","ar":"يجوز للوسيط الاعتماد على توكيل فرعي يصدره الوكيل من توكيله الرئيسي الخاص"}],"e":{"en":"Under 19 CFR 111.36(c)(3), when a broker transacts business as the agent of an importer of record, it must execute a customs power of attorney directly with that importer of record (or drawback claimant), and not via a freight forwarder or other third party. The agreement also may not bar direct communication between the broker and the importer.","es":"Conforme a 19 CFR 111.36(c)(3), cuando un agente de aduanas realiza negocios como representante de un importador registrado, debe ejecutar un power of attorney aduanero directamente con ese importador registrado (o reclamante de drawback), y no a través de un agente de carga u otro tercero. El acuerdo tampoco puede prohibir la comunicación directa entre el agente de aduanas y el importador.","ru":"Согласно 19 CFR 111.36(c)(3), когда брокер ведет деятельность в качестве агента импортера-получателя (importer of record), он должен оформить таможенную доверенность непосредственно с этим импортером-получателем (или заявителем на возврат пошлин), а не через экспедитора или иную третью сторону. Соглашение также не может запрещать прямое общение между брокером и импортером.","tr":"19 CFR 111.36(c)(3) kapsamında, bir gümrük müşaviri bir importer of record'un vekili olarak iş yürüttüğünde, doğrudan o importer of record (veya drawback talep eden) ile bir gümrük vekaletnamesi (POA) düzenlemeli, bir freight forwarder veya başka bir üçüncü taraf aracılığıyla değil. Anlaşma ayrıca gümrük müşaviri ile ithalatçı arasındaki doğrudan iletişimi de engelleyemez.","hi":"19 CFR 111.36(c)(3) के तहत, जब एक ब्रोकर एक importer of record के एजेंट के रूप में व्यवसाय करता है, तो उसे सीधे उस importer of record (या drawback claimant) के साथ एक customs power of attorney निष्पादित करना चाहिए, न कि किसी freight forwarder या अन्य तृतीय पक्ष के माध्यम से। समझौता ब्रोकर और आयातकर्ता के बीच सीधे संचार पर रोक भी नहीं लगा सकता।","ar":"بموجب 19 CFR 111.36(c)(3)، عندما يزاول وسيط الأعمال بوصفه وكيلاً لمستورد مسجَّل، يجب أن يبرم توكيلاً رسمياً جمركياً مباشرةً مع ذلك المستورد المسجَّل (أو مطالِب استرداد الرسوم)، لا عبر وكيل شحن أو طرف ثالث آخر. كما لا يجوز أن يمنع الاتفاق التواصل المباشر بين الوسيط والمستورد."}},{"cat":"compliance","a":1,"q":{"en":"A power of attorney executed by a partnership in favor of a customs broker is dated March 1, 2024, and contains no expiration date. For how long is that power of attorney valid?","es":"Un power of attorney ejecutado por una sociedad colectiva a favor de un agente de aduanas tiene fecha del March 1, 2024, y no contiene fecha de vencimiento. ¿Por cuánto tiempo es válido ese power of attorney?","ru":"Доверенность (POA), оформленная товариществом в пользу таможенного брокера, датирована March 1, 2024, и не содержит срока истечения. Как долго эта доверенность действительна?","tr":"Bir ortaklık (partnership) tarafından bir gümrük müşaviri lehine düzenlenen bir vekaletname (POA) 1 Mart 2024 tarihlidir ve herhangi bir sona erme tarihi içermemektedir. Bu vekaletname ne kadar süreyle geçerlidir?","hi":"एक साझेदारी (partnership) द्वारा एक customs broker के पक्ष में निष्पादित एक power of attorney की तारीख March 1, 2024 है, और इसमें कोई समाप्ति तिथि नहीं है। वह power of attorney कितने समय तक वैध है?","ar":"توكيل رسمي (POA) أبرمته شراكة لصالح وسيط جمركي مؤرَّخ في March 1, 2024، ولا يتضمّن تاريخ انتهاء. لأي مدة يكون هذا التوكيل الرسمي صالحاً؟"},"o":[{"en":"It is valid for an unlimited period because it states no expiration","es":"Es válido por un período ilimitado porque no establece vencimiento","ru":"Она действительна неограниченный срок, поскольку не указывает срока истечения","tr":"Sona erme tarihi belirtmediğinden sınırsız bir süre için geçerlidir","hi":"यह असीमित अवधि के लिए वैध है क्योंकि इसमें कोई समाप्ति नहीं बताई गई है","ar":"صالح لمدة غير محدودة لأنه لا يذكر تاريخ انتهاء"},{"en":"It is valid for a period not to exceed 2 years from the date of execution","es":"Es válido por un período que no exceda 2 años desde la fecha de ejecución","ru":"Она действительна на срок, не превышающий 2 года с даты оформления","tr":"Düzenleme tarihinden itibaren 2 yılı aşmayan bir süre için geçerlidir","hi":"यह निष्पादन की तारीख से 2 वर्ष से अधिक नहीं की अवधि के लिए वैध है","ar":"صالح لمدة لا تتجاوز سنتين من تاريخ الإبرام"},{"en":"It is valid for 5 years, matching the broker's recordkeeping retention period","es":"Es válido por 5 años, coincidiendo con el período de retención de registros del agente","ru":"Она действительна 5 лет, совпадая со сроком хранения документов брокера","tr":"Gümrük müşavirinin kayıt saklama süresine uygun olarak 5 yıl geçerlidir","hi":"यह 5 वर्ष के लिए वैध है, जो ब्रोकर की रिकॉर्ड-रखरखाव प्रतिधारण अवधि से मेल खाता है","ar":"صالح لمدة 5 سنوات، مطابقةً لمدة الاحتفاظ بالسجلات لدى الوسيط"},{"en":"It is valid for 3 years, corresponding to the triennial reporting cycle","es":"Es válido por 3 años, correspondiente al ciclo de informes trienales","ru":"Она действительна 3 года, соответствуя трехлетнему циклу отчетности","tr":"Üç yıllık raporlama döngüsüne karşılık gelecek şekilde 3 yıl geçerlidir","hi":"यह 3 वर्ष के लिए वैध है, जो त्रैवार्षिक रिपोर्टिंग चक्र के अनुरूप है","ar":"صالح لمدة 3 سنوات، بما يوافق دورة الإبلاغ كل ثلاث سنوات"}],"e":{"en":"Under 19 CFR 141.34, a power of attorney issued by a partnership is limited to a period not to exceed 2 years from the date of execution; all other powers of attorney may be granted for an unlimited period. The 5-year retention rule (111.23) and the 3-year status cycle (111.30) are unrelated to POA duration.","es":"Conforme a 19 CFR 141.34, un power of attorney emitido por una sociedad colectiva se limita a un período que no exceda 2 años desde la fecha de ejecución; todos los demás powers of attorney pueden otorgarse por un período ilimitado. La regla de retención de 5 años (111.23) y el ciclo de estatus de 3 años (111.30) no están relacionados con la duración del POA.","ru":"Согласно 19 CFR 141.34, доверенность, выданная товариществом, ограничена сроком, не превышающим 2 года с даты оформления; все остальные доверенности могут выдаваться на неограниченный срок. Правило о 5-летнем хранении (111.23) и 3-летний цикл статуса (111.30) не связаны со сроком действия POA.","tr":"19 CFR 141.34 kapsamında, bir ortaklık (partnership) tarafından düzenlenen bir vekaletname (POA), düzenleme tarihinden itibaren 2 yılı aşmayan bir süreyle sınırlıdır; diğer tüm vekaletnameler sınırsız bir süre için verilebilir. 5 yıllık saklama kuralı (111.23) ve 3 yıllık durum döngüsü (111.30), POA süresiyle ilgisizdir.","hi":"19 CFR 141.34 के तहत, एक साझेदारी द्वारा जारी किया गया power of attorney निष्पादन की तारीख से 2 वर्ष से अधिक नहीं की अवधि तक सीमित है; अन्य सभी powers of attorney असीमित अवधि के लिए दिए जा सकते हैं। 5-वर्षीय प्रतिधारण नियम (111.23) और 3-वर्षीय स्थिति चक्र (111.30) POA की अवधि से असंबंधित हैं।","ar":"بموجب 19 CFR 141.34، يقتصر التوكيل الرسمي الصادر عن شراكة على مدة لا تتجاوز سنتين من تاريخ الإبرام؛ أما سائر التوكيلات الرسمية فيجوز منحها لمدة غير محدودة. وقاعدة الاحتفاظ لمدة 5 سنوات (111.23) ودورة الحالة كل 3 سنوات (111.30) لا صلة لهما بمدة POA."}},{"cat":"compliance","a":2,"q":{"en":"Under 19 CFR 141.36, a power of attorney executed by a nonresident principal will NOT be accepted unless which condition is met?","es":"Conforme a 19 CFR 141.36, un power of attorney ejecutado por un mandante no residente NO será aceptado a menos que se cumpla qué condición?","ru":"Согласно 19 CFR 141.36, доверенность (POA), оформленная нерезидентом-доверителем, НЕ будет принята, если не выполнено какое условие?","tr":"19 CFR 141.36 kapsamında, yurt dışında mukim bir asıl (nonresident principal) tarafından düzenlenen bir vekaletname (POA), hangi koşul karşılanmadıkça kabul edilMEZ?","hi":"19 CFR 141.36 के तहत, एक गैर-निवासी प्रधान (nonresident principal) द्वारा निष्पादित power of attorney तब तक स्वीकार नहीं किया जाएगा जब तक कि कौन-सी शर्त पूरी न हो?","ar":"بموجب 19 CFR 141.36، لن يُقبل توكيل رسمي (POA) أبرمه موكِّل غير مقيم ما لم يُستوفَ أي شرط؟"},"o":[{"en":"The power of attorney is filed in advance with the processing Center","es":"El power of attorney se presenta por anticipado ante el Center que lo procesa","ru":"Доверенность заранее подается в обрабатывающий Центр (Center)","tr":"Vekaletname, işlemleri yürüten Center'a önceden sunulur","hi":"power of attorney processing Center के पास अग्रिम रूप से दाखिल किया गया हो","ar":"أن يُودَع التوكيل الرسمي مسبقاً لدى Center المعالج"},{"en":"The nonresident principal posts a separate single-transaction bond","es":"El mandante no residente constituye una fianza separada de transacción única","ru":"Нерезидент-доверитель вносит отдельную гарантию на разовую сделку (single-transaction bond)","tr":"Yurt dışında mukim asıl, ayrı bir tek işlem teminatı (single-transaction bond) yatırır","hi":"गैर-निवासी प्रधान एक अलग single-transaction bond जमा करे","ar":"أن يقدّم الموكِّل غير المقيم سند ضمان منفصل لمعاملة واحدة"},{"en":"The agent designated in the power of attorney is a resident authorized to accept service of process on behalf of the nonresident","es":"El representante designado en el power of attorney es un residente autorizado para aceptar la notificación de procesos legales en nombre del no residente","ru":"Агент, назначенный в доверенности, является резидентом, уполномоченным принимать судебные извещения от имени нерезидента","tr":"Vekaletnamede belirlenen vekil, yurt dışında mukim olan adına tebligat (service of process) kabul etmeye yetkili, ülkede mukim bir kişidir","hi":"power of attorney में नामित एजेंट एक निवासी हो जो गैर-निवासी की ओर से service of process स्वीकार करने के लिए अधिकृत हो","ar":"أن يكون الوكيل المعيَّن في التوكيل الرسمي مقيماً مفوّضاً بقبول تبليغ الإجراءات القضائية نيابةً عن غير المقيم"},{"en":"The power of attorney is limited to a single entry and expires after one year","es":"El power of attorney se limita a una sola entrada y vence después de un año","ru":"Доверенность ограничена одним оформлением и истекает через один год","tr":"Vekaletname tek bir beyanla sınırlıdır ve bir yıl sonra sona erer","hi":"power of attorney एक एकल एंट्री तक सीमित हो और एक वर्ष बाद समाप्त हो जाए","ar":"أن يقتصر التوكيل الرسمي على إدخال واحد وأن ينتهي بعد سنة واحدة"}],"e":{"en":"Under 19 CFR 141.36, a power of attorney from a nonresident principal is not accepted unless the designated agent is a resident who is authorized to accept service of process against the nonresident. POAs need not be filed with CBP (141.46), and there is no special bond or one-entry/one-year limitation imposed by this rule.","es":"Conforme a 19 CFR 141.36, un power of attorney de un mandante no residente no se acepta a menos que el representante designado sea un residente autorizado para aceptar la notificación de procesos legales contra el no residente. Los POA no necesitan presentarse ante CBP (141.46), y esta regla no impone ninguna fianza especial ni limitación de una entrada/un año.","ru":"Согласно 19 CFR 141.36, доверенность от нерезидента-доверителя не принимается, если назначенный агент не является резидентом, уполномоченным принимать судебные извещения в отношении нерезидента. Доверенности не обязательно подавать в CBP (141.46), и данное правило не накладывает специальной гарантии или ограничения в одно оформление / один год.","tr":"19 CFR 141.36 kapsamında, yurt dışında mukim bir asıldan (nonresident principal) gelen bir vekaletname (POA), belirlenen vekil, yurt dışında mukim olana karşı tebligat (service of process) kabul etmeye yetkili, ülkede mukim bir kişi olmadıkça kabul edilmez. POA'ların CBP'ye sunulması gerekmez (141.46) ve bu kural tarafından dayatılan özel bir teminat veya tek beyan/bir yıl sınırlaması yoktur.","hi":"19 CFR 141.36 के तहत, एक गैर-निवासी प्रधान से power of attorney तब तक स्वीकार नहीं किया जाता जब तक कि नामित एजेंट एक निवासी न हो जो गैर-निवासी के विरुद्ध service of process स्वीकार करने के लिए अधिकृत हो। POAs को CBP के पास दाखिल करने की आवश्यकता नहीं है (141.46), और इस नियम द्वारा कोई विशेष bond या एक-एंट्री/एक-वर्ष की सीमा नहीं लगाई गई है।","ar":"بموجب 19 CFR 141.36، لا يُقبل التوكيل الرسمي من موكِّل غير مقيم ما لم يكن الوكيل المعيَّن مقيماً مفوّضاً بقبول تبليغ الإجراءات القضائية ضد غير المقيم. ولا يلزم إيداع التوكيلات الرسمية لدى CBP (141.46)، ولا تفرض هذه القاعدة سند ضمان خاصاً أو قيد إدخال واحد/سنة واحدة."}},{"cat":"compliance","a":2,"q":{"en":"In assessing whether a broker is exercising 'responsible supervision and control,' which of the following would CBP consider under 19 CFR 111.28?","es":"Al evaluar si un agente de aduanas ejerce 'supervisión y control responsables', ¿cuál de los siguientes consideraría CBP conforme a 19 CFR 111.28?","ru":"При оценке того, осуществляет ли брокер 'ответственный надзор и контроль', что из перечисленного CBP будет учитывать согласно 19 CFR 111.28?","tr":"Bir gümrük müşavirinin 'sorumlu gözetim ve kontrol' (responsible supervision and control) uygulayıp uygulamadığını değerlendirirken, CBP 19 CFR 111.28 kapsamında aşağıdakilerden hangisini dikkate alır?","hi":"यह आकलन करने में कि क्या एक ब्रोकर 'responsible supervision and control' का प्रयोग कर रहा है, 19 CFR 111.28 के तहत CBP निम्नलिखित में से किस पर विचार करेगा?","ar":"عند تقييم ما إذا كان الوسيط يمارس \"الإشراف والرقابة المسؤولين\"، أي مما يلي ستأخذه CBP في الاعتبار بموجب 19 CFR 111.28؟"},"o":[{"en":"Only the total dollar value of duties the broker remits to CBP each year","es":"Únicamente el valor total en dólares de los derechos que el agente remite a CBP cada año","ru":"Только общую сумму пошлин в долларах, которую брокер перечисляет в CBP ежегодно","tr":"Yalnızca gümrük müşavirinin her yıl CBP'ye aktardığı toplam vergi tutarını","hi":"केवल उन शुल्कों का कुल डॉलर मूल्य जो ब्रोकर हर साल CBP को भेजता है","ar":"فقط إجمالي القيمة الدولارية للرسوم التي يحوّلها الوسيط إلى CBP كل عام"},{"en":"Solely whether the broker maintains a physical office in every port served","es":"Únicamente si el agente mantiene una oficina física en cada puerto atendido","ru":"Исключительно то, поддерживает ли брокер физический офис в каждом обслуживаемом порту","tr":"Yalnızca gümrük müşavirinin hizmet verdiği her limanda fiziksel bir ofis bulundurup bulundurmadığını","hi":"केवल यह कि क्या ब्रोकर हर सेवित बंदरगाह में एक भौतिक कार्यालय बनाए रखता है","ar":"فقط ما إذا كان الوسيط يحتفظ بمكتب مادي في كل ميناء يخدمه"},{"en":"A range of factors including the broker's reject rate, training provided to employees, and the availability of a qualifying broker for consultation","es":"Una gama de factores que incluye la tasa de rechazo del agente, la capacitación brindada a los empleados y la disponibilidad de un agente calificado para consulta","ru":"Ряд факторов, включая долю отклонений (reject rate) у брокера, обучение, предоставляемое работникам, и доступность квалифицированного брокера для консультаций","tr":"Gümrük müşavirinin ret oranı, çalışanlara verilen eğitim ve danışma için nitelikli bir gümrük müşavirinin bulunabilirliği dahil bir dizi faktörü","hi":"कारकों की एक श्रृंखला जिसमें ब्रोकर की reject rate, कर्मचारियों को प्रदान किया गया प्रशिक्षण, और परामर्श के लिए एक योग्य ब्रोकर की उपलब्धता शामिल है","ar":"مجموعة من العوامل تشمل معدل الرفض لدى الوسيط، والتدريب المقدَّم للموظفين، وتوافر وسيط مؤهَّل للاستشارة"},{"en":"Exclusively the number of years the qualifying broker has held a license","es":"Exclusivamente el número de años que el agente calificado ha tenido una licencia","ru":"Исключительно количество лет, в течение которых квалифицированный брокер имеет лицензию","tr":"Yalnızca nitelikli gümrük müşavirinin lisansa kaç yıldır sahip olduğunu","hi":"केवल वर्षों की संख्या जिनके लिए योग्य ब्रोकर के पास लाइसेंस रहा है","ar":"حصراً عدد السنوات التي حاز فيها الوسيط المؤهِّل الرخصة"}],"e":{"en":"Under 19 CFR 111.28(a), CBP weighs numerous non-exclusive factors, such as the reject rate for the broker's transactions, training and written instructions provided to employees, the availability of a licensed broker for employee consultation, audit frequency, and the qualifying broker's involvement. No single factor (duties paid, office locations, or years licensed) is dispositive.","es":"Conforme a 19 CFR 111.28(a), CBP pondera numerosos factores no exclusivos, como la tasa de rechazo de las transacciones del agente, la capacitación e instrucciones escritas brindadas a los empleados, la disponibilidad de un agente con licencia para consulta de los empleados, la frecuencia de auditorías y la participación del agente calificado. Ningún factor por sí solo (derechos pagados, ubicaciones de oficinas o años con licencia) es determinante.","ru":"Согласно 19 CFR 111.28(a), CBP взвешивает многочисленные неисчерпывающие факторы, такие как доля отклонений (reject rate) по сделкам брокера, обучение и письменные инструкции, предоставляемые работникам, доступность лицензированного брокера для консультаций работников, частота аудита и вовлеченность квалифицированного брокера. Ни один отдельный фактор (уплаченные пошлины, расположение офисов или стаж лицензии) не является определяющим.","tr":"19 CFR 111.28(a) kapsamında, CBP; gümrük müşavirinin işlemlerine ilişkin ret oranı, çalışanlara verilen eğitim ve yazılı talimatlar, çalışanların danışması için lisanslı bir gümrük müşavirinin bulunabilirliği, denetim sıklığı ve nitelikli gümrük müşavirinin katılımı gibi çok sayıda münhasır olmayan faktörü tartar. Hiçbir tek faktör (ödenen vergiler, ofis konumları veya lisans yılı) belirleyici değildir.","hi":"19 CFR 111.28(a) के तहत, CBP कई गैर-विशिष्ट कारकों को तौलता है, जैसे ब्रोकर के लेनदेन के लिए reject rate, कर्मचारियों को प्रदान किए गए प्रशिक्षण और लिखित निर्देश, कर्मचारी परामर्श के लिए एक लाइसेंस-प्राप्त ब्रोकर की उपलब्धता, audit आवृत्ति, और योग्य ब्रोकर की भागीदारी। कोई एकल कारक (चुकाए गए शुल्क, कार्यालय स्थान, या लाइसेंस के वर्ष) निर्णायक नहीं है।","ar":"بموجب 19 CFR 111.28(a)، توازن CBP بين عوامل عديدة غير حصرية، مثل معدل الرفض لمعاملات الوسيط، والتدريب والتعليمات المكتوبة المقدَّمة للموظفين، وتوافر وسيط مرخَّص لاستشارة الموظفين، وتواتر التدقيق، ومدى مشاركة الوسيط المؤهِّل. ولا يكون أي عامل منفرد (الرسوم المدفوعة، أو مواقع المكاتب، أو سنوات الترخيص) حاسماً."}},{"cat":"compliance","a":1,"q":{"en":"A corporation that hires a new employee to assist in transacting customs business must report certain employee information to CBP. Under 19 CFR 111.28, within what time frame must the broker notify CBP of a newly hired employee?","es":"Una corporación que contrata a un nuevo empleado para ayudar a realizar negocios aduaneros debe reportar cierta información del empleado a CBP. Conforme a 19 CFR 111.28, ¿dentro de qué plazo debe el agente notificar a CBP sobre un empleado recién contratado?","ru":"Корпорация, нанимающая нового работника для содействия ведению таможенной деятельности, должна сообщить определенную информацию о работнике в CBP. Согласно 19 CFR 111.28, в какой срок брокер должен уведомить CBP о вновь нанятом работнике?","tr":"Gümrük işlemlerinin yürütülmesine yardımcı olmak üzere yeni bir çalışan işe alan bir şirket, belirli çalışan bilgilerini CBP'ye bildirmelidir. 19 CFR 111.28 kapsamında, gümrük müşaviri yeni işe alınan bir çalışanı CBP'ye hangi süre içinde bildirmelidir?","hi":"एक कॉर्पोरेशन जो customs business करने में सहायता के लिए एक नए कर्मचारी को नियुक्त करता है, उसे कुछ कर्मचारी जानकारी CBP को रिपोर्ट करनी होती है। 19 CFR 111.28 के तहत, ब्रोकर को किस समय-सीमा के भीतर नए नियुक्त कर्मचारी के बारे में CBP को सूचित करना चाहिए?","ar":"يجب على مؤسسة توظّف موظفاً جديداً للمساعدة في مزاولة الأعمال الجمركية إبلاغ CBP بمعلومات معيّنة عن الموظف. بموجب 19 CFR 111.28، خلال أي إطار زمني يجب على الوسيط إخطار CBP بموظف عُيِّن حديثاً؟"},"o":[{"en":"Within 10 calendar days of the hire","es":"Dentro de 10 días calendario de la contratación","ru":"В течение 10 календарных дней с момента найма","tr":"İşe alımdan itibaren 10 takvim günü içinde","hi":"नियुक्ति के 10 कैलेंडर दिनों के भीतर","ar":"خلال 10 أيام تقويمية من التعيين"},{"en":"Within 30 calendar days of the hire","es":"Dentro de 30 días calendario de la contratación","ru":"В течение 30 календарных дней с момента найма","tr":"İşe alımdan itibaren 30 takvim günü içinde","hi":"नियुक्ति के 30 कैलेंडर दिनों के भीतर","ar":"خلال 30 يوماً تقويمياً من التعيين"},{"en":"Within 60 calendar days of the hire","es":"Dentro de 60 días calendario de la contratación","ru":"В течение 60 календарных дней с момента найма","tr":"İşe alımdan itibaren 60 takvim günü içinde","hi":"नियुक्ति के 60 कैलेंडर दिनों के भीतर","ar":"خلال 60 يوماً تقويمياً من التعيين"},{"en":"Only once per year, in the annual employee list","es":"Solo una vez al año, en la lista anual de empleados","ru":"Только один раз в год, в ежегодном списке работников","tr":"Yalnızca yılda bir kez, yıllık çalışan listesinde","hi":"केवल वर्ष में एक बार, वार्षिक कर्मचारी सूची में","ar":"مرة واحدة فقط في السنة، ضمن قائمة الموظفين السنوية"}],"e":{"en":"Under 19 CFR 111.28(b), a broker must submit to CBP a list of employee information and must report new hires, terminations, and changes within 30 calendar days. (Contrast this with the 10-day rule in 111.30 for changes in the broker's own address or organization.)","es":"Conforme a 19 CFR 111.28(b), un agente debe presentar a CBP una lista de información de empleados y debe reportar nuevas contrataciones, despidos y cambios dentro de 30 días calendario. (Compárese esto con la regla de 10 días en 111.30 para cambios en la propia dirección u organización del agente).","ru":"Согласно 19 CFR 111.28(b), брокер должен представить в CBP список информации о работниках и обязан сообщать о новых наймах, увольнениях и изменениях в течение 30 календарных дней. (Сравните это с правилом 10 дней в 111.30 для изменений в собственном адресе или организации брокера.)","tr":"19 CFR 111.28(b) kapsamında, bir gümrük müşaviri CBP'ye bir çalışan bilgisi listesi sunmalı ve yeni işe alımları, işten çıkarmaları ve değişiklikleri 30 takvim günü içinde bildirmelidir. (Bunu, gümrük müşavirinin kendi adresindeki veya organizasyonundaki değişiklikler için 111.30'daki 10 günlük kuralla karşılaştırın.)","hi":"19 CFR 111.28(b) के तहत, एक ब्रोकर को CBP को कर्मचारी जानकारी की एक सूची प्रस्तुत करनी होती है और नई नियुक्तियों, समाप्तियों और परिवर्तनों को 30 कैलेंडर दिनों के भीतर रिपोर्ट करना होता है। (इसकी तुलना ब्रोकर के अपने पते या संगठन में परिवर्तनों के लिए 111.30 में 10-दिन के नियम से करें।)","ar":"بموجب 19 CFR 111.28(b)، يجب على الوسيط تقديم قائمة بمعلومات الموظفين إلى CBP، والإبلاغ عن التعيينات الجديدة وإنهاءات الخدمة والتغييرات خلال 30 يوماً تقويمياً. (قارن ذلك بقاعدة 10 أيام في 111.30 للتغييرات في عنوان الوسيط نفسه أو تنظيمه.)"}},{"cat":"compliance","a":1,"q":{"en":"Except for powers of attorney, for how long must a broker retain the records described in 19 CFR 111.23, and from what event does the period run?","es":"Salvo los powers of attorney, ¿por cuánto tiempo debe un agente de aduanas conservar los registros descritos en 19 CFR 111.23, y a partir de qué evento corre el período?","ru":"За исключением доверенностей, как долго брокер должен хранить документы, описанные в 19 CFR 111.23, и от какого события отсчитывается срок?","tr":"Vekaletnameler hariç olmak üzere, bir gümrük müşaviri 19 CFR 111.23'te tanımlanan kayıtları ne kadar süreyle saklamalıdır ve bu süre hangi olaydan itibaren başlar?","hi":"powers of attorney को छोड़कर, एक ब्रोकर को 19 CFR 111.23 में वर्णित रिकॉर्ड कितने समय तक रखने चाहिए, और यह अवधि किस घटना से शुरू होती है?","ar":"باستثناء التوكيلات الرسمية، إلى متى يجب على الوسيط الاحتفاظ بالسجلات الموصوفة في 19 CFR 111.23، ومن أي حدث تبدأ المدة؟"},"o":[{"en":"Three years after the date the triennial status report is filed","es":"Tres años después de la fecha en que se presenta el informe de estatus trienal","ru":"Три года после даты подачи трехлетнего отчета о статусе","tr":"Üç yıllık durum raporunun sunulduğu tarihten itibaren üç yıl","hi":"त्रैवार्षिक status report दाखिल करने की तारीख के तीन वर्ष बाद","ar":"ثلاث سنوات بعد تاريخ تقديم تقرير الحالة الذي يُقدَّم كل ثلاث سنوات"},{"en":"Five years after the date of entry","es":"Cinco años después de la fecha de entrada","ru":"Пять лет после даты оформления (entry)","tr":"Beyan tarihinden itibaren beş yıl","hi":"एंट्री की तारीख के पाँच वर्ष बाद","ar":"خمس سنوات بعد تاريخ الإدخال"},{"en":"Six years after the close of the calendar year in which the entry was filed","es":"Seis años después del cierre del año calendario en que se presentó la entrada","ru":"Шесть лет после окончания календарного года, в котором было подано оформление","tr":"Beyanın sunulduğu takvim yılının kapanmasından itibaren altı yıl","hi":"उस कैलेंडर वर्ष की समाप्ति के छह वर्ष बाद जिसमें एंट्री दाखिल की गई थी","ar":"ست سنوات بعد انتهاء السنة التقويمية التي قُدِّم فيها الإدخال"},{"en":"Indefinitely, until CBP authorizes destruction in writing","es":"Indefinidamente, hasta que CBP autorice la destrucción por escrito","ru":"Бессрочно, пока CBP не разрешит уничтожение в письменной форме","tr":"Süresiz olarak, CBP imha için yazılı izin verene kadar","hi":"अनिश्चित काल तक, जब तक CBP लिखित रूप में विनाश को अधिकृत न करे","ar":"إلى أجل غير مسمّى، إلى أن تأذن CBP بالإتلاف كتابةً"}],"e":{"en":"Under 19 CFR 111.23(b), records (other than powers of attorney) must be retained for at least 5 years after the date of entry. Powers of attorney have their own rule (retained until revoked, then 5 years after revocation or after the client ceases to be active, whichever is later). The 6-year/close-of-year period applies to certain other recordkeeping contexts, not 111.23.","es":"Conforme a 19 CFR 111.23(b), los registros (distintos de los powers of attorney) deben conservarse durante al menos 5 años después de la fecha de entrada. Los powers of attorney tienen su propia regla (conservados hasta su revocación y luego 5 años después de la revocación o de que el cliente deje de estar activo, lo que ocurra más tarde). El período de 6 años/cierre de año aplica a ciertos otros contextos de conservación de registros, no a 111.23.","ru":"Согласно 19 CFR 111.23(b), документы (кроме доверенностей) должны храниться не менее 5 лет после даты оформления (entry). Доверенности имеют собственное правило (хранятся до отзыва, затем 5 лет после отзыва или после того, как клиент перестает быть активным, в зависимости от того, что наступит позже). Срок 6 лет / окончание года применяется к некоторым другим контекстам ведения документации, а не к 111.23.","tr":"19 CFR 111.23(b) kapsamında, kayıtlar (vekaletnameler hariç) beyan tarihinden itibaren en az 5 yıl saklanmalıdır. Vekaletnamelerin kendine ait bir kuralı vardır (iptal edilene kadar saklanır, ardından iptalden sonra 5 yıl veya müşterinin aktif olmayı bırakmasından sonra 5 yıl, hangisi daha sonraysa). 6 yıl/yıl kapanışı süresi, 111.23'e değil, belirli diğer kayıt saklama bağlamlarına uygulanır.","hi":"19 CFR 111.23(b) के तहत, रिकॉर्ड (powers of attorney के अलावा) को एंट्री की तारीख के बाद कम से कम 5 वर्ष तक रखा जाना चाहिए। Powers of attorney का अपना नियम है (रद्द होने तक रखे जाते हैं, फिर रद्दीकरण के 5 वर्ष बाद या ग्राहक के सक्रिय न रहने के बाद, जो भी बाद में हो)। 6-वर्ष/वर्ष-समाप्ति अवधि कुछ अन्य रिकॉर्ड-रखरखाव संदर्भों पर लागू होती है, 111.23 पर नहीं।","ar":"بموجب 19 CFR 111.23(b)، يجب الاحتفاظ بالسجلات (عدا التوكيلات الرسمية) لمدة لا تقل عن 5 سنوات بعد تاريخ الإدخال. وللتوكيلات الرسمية قاعدتها الخاصة (تُحفظ إلى أن تُلغى، ثم 5 سنوات بعد الإلغاء أو بعد توقّف نشاط العميل، أيهما أبعد). وتنطبق مدة 6 سنوات/انتهاء السنة على سياقات حفظ سجلات أخرى معيّنة، لا على 111.23."}},{"cat":"compliance","a":1,"q":{"en":"Under 19 CFR 111.23, where must a licensed broker maintain the originals of the records required by Part 111, including records stored in electronic format?","es":"Conforme a 19 CFR 111.23, ¿dónde debe un agente de aduanas con licencia conservar los originales de los registros requeridos por la Part 111, incluidos los registros almacenados en formato electrónico?","ru":"Согласно 19 CFR 111.23, где лицензированный брокер должен хранить оригиналы документов, требуемых Part 111, включая документы в электронном формате?","tr":"19 CFR 111.23 kapsamında, lisanslı bir gümrük müşaviri, elektronik formatta saklananlar dahil olmak üzere Part 111 tarafından gerekli kılınan kayıtların asıllarını nerede saklamalıdır?","hi":"19 CFR 111.23 के तहत, एक लाइसेंस-प्राप्त ब्रोकर को Part 111 द्वारा आवश्यक रिकॉर्ड के मूल (originals), जिसमें इलेक्ट्रॉनिक प्रारूप में संग्रहीत रिकॉर्ड शामिल हैं, कहाँ बनाए रखने चाहिए?","ar":"بموجب 19 CFR 111.23، أين يجب على الوسيط المرخَّص الاحتفاظ بأصول السجلات المطلوبة بموجب Part 111، بما فيها السجلات المحفوظة بصيغة إلكترونية؟"},"o":[{"en":"At the broker's office of record only, never in electronic form","es":"Únicamente en la oficina de registro del agente, nunca en forma electrónica","ru":"Только в учетном офисе брокера, никогда в электронной форме","tr":"Yalnızca gümrük müşavirinin kayıtlı ofisinde, asla elektronik biçimde değil","hi":"केवल ब्रोकर के office of record पर, कभी भी इलेक्ट्रॉनिक रूप में नहीं","ar":"في مكتب الوسيط المسجَّل فقط، وليس بصيغة إلكترونية أبداً"},{"en":"Within the customs territory of the United States","es":"Dentro del territorio aduanero de Estados Unidos","ru":"В пределах таможенной территории Соединенных Штатов","tr":"Amerika Birleşik Devletleri gümrük bölgesi içinde","hi":"संयुक्त राज्य अमेरिका के कस्टम क्षेत्र के भीतर","ar":"داخل الإقليم الجمركي للولايات المتحدة"},{"en":"At any location worldwide, provided the records are retrievable within 30 days","es":"En cualquier ubicación del mundo, siempre que los registros puedan recuperarse dentro de 30 días","ru":"В любом месте по всему миру, при условии, что документы доступны для извлечения в течение 30 дней","tr":"Kayıtların 30 gün içinde erişilebilir olması şartıyla, dünya çapında herhangi bir konumda","hi":"दुनिया में कहीं भी, बशर्ते रिकॉर्ड 30 दिनों के भीतर पुनर्प्राप्त किए जा सकें","ar":"في أي موقع حول العالم، شريطة إمكانية استرجاع السجلات خلال 30 يوماً"},{"en":"Only at a CBP-approved bonded warehouse","es":"Únicamente en un almacén afianzado aprobado por CBP","ru":"Только на утвержденном CBP таможенном складе","tr":"Yalnızca CBP onaylı bir gümrük antreposunda","hi":"केवल एक CBP-अनुमोदित bonded warehouse पर","ar":"فقط في مستودع جمركي مضمون معتمد من CBP"}],"e":{"en":"Under 19 CFR 111.23(a), a broker must maintain the originals of records, including any records stored in electronic formats, within the customs territory of the United States, in accordance with Part 111 and Part 163. Records may be kept electronically and need not be confined to a single office or a bonded warehouse.","es":"Conforme a 19 CFR 111.23(a), un agente debe conservar los originales de los registros, incluidos los registros almacenados en formatos electrónicos, dentro del territorio aduanero de Estados Unidos, de acuerdo con la Part 111 y la Part 163. Los registros pueden conservarse electrónicamente y no necesitan limitarse a una sola oficina o a un almacén afianzado.","ru":"Согласно 19 CFR 111.23(a), брокер должен хранить оригиналы документов, включая любые документы в электронном формате, в пределах таможенной территории Соединенных Штатов, в соответствии с Part 111 и Part 163. Документы могут храниться в электронном виде и не обязаны ограничиваться одним офисом или таможенным складом.","tr":"19 CFR 111.23(a) kapsamında, bir gümrük müşaviri, elektronik formatlarda saklanan kayıtlar dahil olmak üzere kayıtların asıllarını, Part 111 ve Part 163 uyarınca Amerika Birleşik Devletleri gümrük bölgesi içinde saklamalıdır. Kayıtlar elektronik olarak tutulabilir ve tek bir ofisle veya bir gümrük antreposuyla sınırlı olması gerekmez.","hi":"19 CFR 111.23(a) के तहत, एक ब्रोकर को रिकॉर्ड के मूल, जिसमें इलेक्ट्रॉनिक प्रारूपों में संग्रहीत कोई भी रिकॉर्ड शामिल है, Part 111 और Part 163 के अनुसार संयुक्त राज्य अमेरिका के कस्टम क्षेत्र के भीतर बनाए रखना चाहिए। रिकॉर्ड इलेक्ट्रॉनिक रूप से रखे जा सकते हैं और उन्हें एक एकल कार्यालय या bonded warehouse तक सीमित रखने की आवश्यकता नहीं है।","ar":"بموجب 19 CFR 111.23(a)، يجب على الوسيط الاحتفاظ بأصول السجلات، بما فيها أي سجلات محفوظة بصيغ إلكترونية، داخل الإقليم الجمركي للولايات المتحدة، وفقاً لـ Part 111 وPart 163. ويجوز حفظ السجلات إلكترونياً ولا يلزم حصرها في مكتب واحد أو مستودع جمركي مضمون."}},{"cat":"compliance","a":0,"q":{"en":"When a broker receives client funds to pay duties to the Government but does not receive them until after the due date, what does 19 CFR 111.29 require the broker to do?","es":"Cuando un agente de aduanas recibe fondos del cliente para pagar derechos al Gobierno pero no los recibe sino hasta después de la fecha de vencimiento, ¿qué exige 19 CFR 111.29 que haga el agente?","ru":"Когда брокер получает средства клиента для уплаты пошлин Правительству, но получает их только после установленного срока, что требует от брокера 19 CFR 111.29?","tr":"Bir gümrük müşaviri, Hükümete vergi ödemek üzere müşteri fonlarını alır ancak bunları ödeme tarihinden sonraya kadar almazsa, 19 CFR 111.29 gümrük müşavirinin ne yapmasını gerektirir?","hi":"जब एक ब्रोकर सरकार को शुल्क का भुगतान करने के लिए ग्राहक के धन प्राप्त करता है लेकिन उन्हें देय तिथि के बाद तक प्राप्त नहीं करता, तो 19 CFR 111.29 ब्रोकर से क्या करने की आवश्यकता रखता है?","ar":"عندما يتلقّى وسيط أموال عميل لدفع رسوم للحكومة لكنه لا يتلقّاها إلا بعد تاريخ الاستحقاق، ماذا يقتضي 19 CFR 111.29 من الوسيط فعله؟"},"o":[{"en":"Pay the funds to the Government within 5 working days from receipt","es":"Pagar los fondos al Gobierno dentro de 5 días hábiles desde su recepción","ru":"Уплатить средства Правительству в течение 5 рабочих дней с момента получения","tr":"Fonları, alındığı tarihten itibaren 5 iş günü içinde Hükümete ödemek","hi":"प्राप्ति से 5 कार्य दिवसों के भीतर सरकार को धन का भुगतान करना","ar":"دفع الأموال للحكومة خلال 5 أيام عمل من تسلّمها"},{"en":"Hold the funds for 30 days and then remit them with the next entry","es":"Conservar los fondos por 30 días y luego remitirlos con la siguiente entrada","ru":"Удерживать средства 30 дней, а затем перечислить их со следующим оформлением","tr":"Fonları 30 gün tutup ardından bir sonraki beyanla birlikte aktarmak","hi":"धन को 30 दिनों तक रखना और फिर उसे अगली एंट्री के साथ भेजना","ar":"الاحتفاظ بالأموال 30 يوماً ثم تحويلها مع الإدخال التالي"},{"en":"Return the funds to the client and instruct the client to pay CBP directly","es":"Devolver los fondos al cliente e indicarle que pague directamente a CBP","ru":"Вернуть средства клиенту и поручить клиенту уплатить CBP напрямую","tr":"Fonları müşteriye iade etmek ve müşteriye doğrudan CBP'ye ödeme yapmasını söylemek","hi":"धन ग्राहक को वापस करना और ग्राहक को सीधे CBP को भुगतान करने का निर्देश देना","ar":"إعادة الأموال إلى العميل وإرشاده إلى الدفع لـ CBP مباشرةً"},{"en":"Deposit the funds in an interest-bearing escrow account until the next quarter","es":"Depositar los fondos en una cuenta de garantía que devengue intereses hasta el siguiente trimestre","ru":"Внести средства на процентный счет условного депонирования (эскроу) до следующего квартала","tr":"Fonları bir sonraki çeyreğe kadar faiz getiren bir emanet (escrow) hesabına yatırmak","hi":"अगली तिमाही तक धन को एक ब्याज-वाले escrow खाते में जमा करना","ar":"إيداع الأموال في حساب ضمان مُدِرّ للفائدة إلى الربع التالي"}],"e":{"en":"Under 19 CFR 111.29(a), a broker must pay duties, taxes, or other debts owed to the Government on or before the due date; if the broker receives client funds after that date, it must transmit the funds to the Government within 5 working days of receipt. The broker must also advise clients that they may pay CBP directly.","es":"Conforme a 19 CFR 111.29(a), un agente debe pagar los derechos, impuestos u otras deudas adeudadas al Gobierno en o antes de la fecha de vencimiento; si el agente recibe fondos del cliente después de esa fecha, debe transmitir los fondos al Gobierno dentro de 5 días hábiles desde su recepción. El agente también debe informar a los clientes que pueden pagar directamente a CBP.","ru":"Согласно 19 CFR 111.29(a), брокер должен уплатить пошлины, налоги или иные долги перед Правительством в установленный срок или до него; если брокер получает средства клиента после этой даты, он должен перечислить средства Правительству в течение 5 рабочих дней с момента получения. Брокер также должен уведомить клиентов о том, что они могут уплатить CBP напрямую.","tr":"19 CFR 111.29(a) kapsamında, bir gümrük müşaviri, Hükümete borçlu olunan vergileri, vergileri (taxes) veya diğer borçları ödeme tarihinde veya öncesinde ödemelidir; gümrük müşaviri müşteri fonlarını bu tarihten sonra alırsa, fonları alındıktan itibaren 5 iş günü içinde Hükümete aktarmalıdır. Gümrük müşaviri ayrıca müşterilere doğrudan CBP'ye ödeme yapabileceklerini de bildirmelidir.","hi":"19 CFR 111.29(a) के तहत, एक ब्रोकर को सरकार को देय शुल्क, कर, या अन्य ऋण देय तिथि पर या उससे पहले भुगतान करना चाहिए; यदि ब्रोकर उस तारीख के बाद ग्राहक का धन प्राप्त करता है, तो उसे प्राप्ति के 5 कार्य दिवसों के भीतर सरकार को धन भेजना चाहिए। ब्रोकर को ग्राहकों को यह भी सलाह देनी चाहिए कि वे सीधे CBP को भुगतान कर सकते हैं।","ar":"بموجب 19 CFR 111.29(a)، يجب على الوسيط دفع الرسوم أو الضرائب أو غيرها من الديون المستحقة للحكومة في تاريخ الاستحقاق أو قبله؛ وإذا تلقّى الوسيط أموال العميل بعد ذلك التاريخ، وجب عليه تحويل الأموال إلى الحكومة خلال 5 أيام عمل من تسلّمها. ويجب على الوسيط أيضاً إبلاغ العملاء بأنه يجوز لهم الدفع لـ CBP مباشرةً."}},{"cat":"compliance","a":1,"q":{"en":"Each broker must file a triennial status report with CBP. Which statement correctly describes the timing and consequence rules under 19 CFR 111.30 (as modernized)?","es":"Cada agente de aduanas debe presentar un informe de estatus trienal ante CBP. ¿Qué afirmación describe correctamente las reglas de plazos y consecuencias conforme a 19 CFR 111.30 (según su modernización)?","ru":"Каждый брокер должен подавать в CBP трехлетний отчет о статусе. Какое утверждение правильно описывает правила о сроках и последствиях согласно 19 CFR 111.30 (в модернизированном виде)?","tr":"Her gümrük müşaviri, CBP'ye üç yılda bir durum raporu (triennial status report) sunmalıdır. Hangi ifade, 19 CFR 111.30 (modernize edilmiş haliyle) kapsamındaki zamanlama ve sonuç kurallarını doğru şekilde tanımlamaktadır?","hi":"प्रत्येक ब्रोकर को CBP के पास एक त्रैवार्षिक status report दाखिल करनी होती है। कौन-सा कथन 19 CFR 111.30 (आधुनिकीकृत) के तहत समय और परिणाम नियमों का सही वर्णन करता है?","ar":"يجب على كل وسيط تقديم تقرير حالة كل ثلاث سنوات إلى CBP. أي عبارة تصف بشكل صحيح قواعد التوقيت والنتائج بموجب 19 CFR 111.30 (بصيغته المحدَّثة)؟"},"o":[{"en":"The report is due July 1 of each third year, and late filing results in an automatic monetary penalty of $1,000","es":"El informe vence el July 1 de cada tercer año, y la presentación tardía resulta en una multa monetaria automática de $1,000","ru":"Отчет подается до July 1 каждого третьего года, и просрочка подачи влечет автоматический денежный штраф в размере $1,000","tr":"Rapor her üçüncü yılın 1 Temmuz'unda sunulur ve geç sunum, $1,000 tutarında otomatik bir para cezasıyla sonuçlanır","hi":"रिपोर्ट प्रत्येक तीसरे वर्ष की July 1 को देय है, और देर से दाखिल करने पर $1,000 का स्वचालित मौद्रिक जुर्माना लगता है","ar":"يُستحقّ التقرير في July 1 من كل سنة ثالثة، ويترتّب على التقديم المتأخر غرامة مالية تلقائية قدرها $1,000"},{"en":"The report is due February 1 of each third year, and failure to file by March 1 suspends the license by operation of law","es":"El informe vence el February 1 de cada tercer año, y no presentarlo antes del March 1 suspende la licencia por imperio de la ley","ru":"Отчет подается до February 1 каждого третьего года, и непредставление к March 1 приостанавливает действие лицензии в силу закона","tr":"Rapor her üçüncü yılın 1 Şubat'ında sunulur ve 1 Mart'a kadar sunulmaması lisansı kanun gereği askıya alır","hi":"रिपोर्ट प्रत्येक तीसरे वर्ष की February 1 को देय है, और March 1 तक दाखिल करने में विफलता कानून के संचालन द्वारा लाइसेंस को निलंबित कर देती है","ar":"يُستحقّ التقرير في February 1 من كل سنة ثالثة، ويؤدي عدم التقديم بحلول March 1 إلى تعليق الرخصة بحكم القانون"},{"en":"The report is due annually on the anniversary of license issuance, with a 90-day grace period","es":"El informe vence anualmente en el aniversario de la emisión de la licencia, con un período de gracia de 90 días","ru":"Отчет подается ежегодно в годовщину выдачи лицензии, с льготным периодом в 90 дней","tr":"Rapor, lisansın verildiği tarihin yıldönümünde her yıl, 90 günlük bir ek süreyle sunulur","hi":"रिपोर्ट लाइसेंस जारी होने की वर्षगांठ पर सालाना देय है, जिसमें 90-दिन की रियायत अवधि है","ar":"يُستحقّ التقرير سنوياً في ذكرى إصدار الرخصة، مع مهلة سماح قدرها 90 يوماً"},{"en":"The report is due February 1 each year, and failure to file results in immediate revocation without any opportunity for reinstatement","es":"El informe vence el February 1 de cada año, y no presentarlo resulta en revocación inmediata sin oportunidad alguna de reinstalación","ru":"Отчет подается до February 1 каждого года, и непредставление влечет немедленный отзыв без какой-либо возможности восстановления","tr":"Rapor her yıl 1 Şubat'ta sunulur ve sunulmaması, yeniden tesis imkanı olmaksızın derhal iptalle sonuçlanır","hi":"रिपोर्ट प्रत्येक वर्ष February 1 को देय है, और दाखिल करने में विफलता के परिणामस्वरूप बहाली के किसी अवसर के बिना तत्काल निरस्तीकरण होता है","ar":"يُستحقّ التقرير في February 1 كل سنة، ويؤدي عدم التقديم إلى الإلغاء الفوري دون أي فرصة لإعادة الاعتبار"}],"e":{"en":"Under 19 CFR 111.30(d), the triennial status report is due on February 1 of each third year. If a broker fails to file by March 1 of the reporting year, the license is suspended by operation of law; if the broker still has not filed and paid within 60 days of the suspension, the license is revoked by operation of law without prejudice to applying for a new one.","es":"Conforme a 19 CFR 111.30(d), el informe de estatus trienal vence el February 1 de cada tercer año. Si un agente no lo presenta antes del March 1 del año de informe, la licencia queda suspendida por imperio de la ley; si el agente aún no ha presentado y pagado dentro de los 60 días de la suspensión, la licencia se revoca por imperio de la ley sin perjuicio de poder solicitar una nueva.","ru":"Согласно 19 CFR 111.30(d), трехлетний отчет о статусе подается до February 1 каждого третьего года. Если брокер не подает отчет к March 1 отчетного года, действие лицензии приостанавливается в силу закона; если брокер по-прежнему не подал отчет и не уплатил в течение 60 дней с момента приостановления, лицензия отзывается в силу закона без ущерба для права подать заявление на новую.","tr":"19 CFR 111.30(d) kapsamında, üç yılda bir durum raporu (triennial status report) her üçüncü yılın 1 Şubat'ında sunulur. Bir gümrük müşaviri raporlama yılının 1 Mart'ına kadar sunmazsa, lisans kanun gereği (by operation of law) askıya alınır; gümrük müşaviri askıdan itibaren 60 gün içinde hâlâ sunmamış ve ödememişse, lisans, yeni bir lisans için başvurma hakkına halel gelmeksizin kanun gereği iptal edilir.","hi":"19 CFR 111.30(d) के तहत, त्रैवार्षिक status report प्रत्येक तीसरे वर्ष की February 1 को देय है। यदि एक ब्रोकर रिपोर्टिंग वर्ष की March 1 तक दाखिल करने में विफल रहता है, तो लाइसेंस कानून के संचालन द्वारा निलंबित हो जाता है; यदि ब्रोकर अभी भी निलंबन के 60 दिनों के भीतर दाखिल और भुगतान नहीं करता है, तो लाइसेंस कानून के संचालन द्वारा निरस्त हो जाता है, बिना नए के लिए आवेदन करने में पूर्वाग्रह के।","ar":"بموجب 19 CFR 111.30(d)، يُستحقّ تقرير الحالة الذي يُقدَّم كل ثلاث سنوات في February 1 من كل سنة ثالثة. وإذا تخلّف الوسيط عن التقديم بحلول March 1 من سنة الإبلاغ، تُعلَّق الرخصة بحكم القانون؛ وإذا ظلّ الوسيط دون تقديم ودفع خلال 60 يوماً من التعليق، تُلغى الرخصة بحكم القانون دون المساس بحق التقدّم لرخصة جديدة."}},{"cat":"compliance","a":1,"q":{"en":"What is the maximum aggregate monetary penalty that may be assessed against a licensed broker under 19 CFR 111.91 for one or more of the grounds listed in 19 CFR 111.53(a) through (g)?","es":"¿Cuál es la multa monetaria agregada máxima que puede imponerse a un agente de aduanas con licencia conforme a 19 CFR 111.91 por uno o más de los motivos enumerados en 19 CFR 111.53(a) a (g)?","ru":"Каков максимальный совокупный денежный штраф, который может быть наложен на лицензированного брокера согласно 19 CFR 111.91 за одно или несколько оснований, перечисленных в 19 CFR 111.53(a)–(g)?","tr":"19 CFR 111.53(a) ila (g)'de sıralanan gerekçelerden biri veya birkaçı nedeniyle, 19 CFR 111.91 kapsamında lisanslı bir gümrük müşavirine uygulanabilecek azami toplam para cezası nedir?","hi":"19 CFR 111.53(a) से (g) में सूचीबद्ध एक या अधिक आधारों के लिए 19 CFR 111.91 के तहत एक लाइसेंस-प्राप्त ब्रोकर पर लगाया जा सकने वाला अधिकतम कुल मौद्रिक जुर्माना क्या है?","ar":"ما الحد الأقصى للغرامة المالية الإجمالية التي يجوز فرضها على وسيط مرخَّص بموجب 19 CFR 111.91 عن سبب أو أكثر من الأسباب المدرجة في 19 CFR 111.53(a) إلى (g)؟"},"o":[{"en":"$10,000","es":"$10,000","ru":"$10,000","tr":"$10,000","hi":"$10,000","ar":"$10,000"},{"en":"$30,000","es":"$30,000","ru":"$30,000","tr":"$30,000","hi":"$30,000","ar":"$30,000"},{"en":"$100,000","es":"$100,000","ru":"$100,000","tr":"$100,000","hi":"$100,000","ar":"$100,000"},{"en":"An amount equal to twice the duties lost to the Government","es":"Un monto igual al doble de los derechos perdidos por el Gobierno","ru":"Сумма, равная двойному размеру пошлин, потерянных Правительством","tr":"Hükümetin kaybettiği vergilerin iki katına eşit bir tutar","hi":"सरकार को हुई शुल्क हानि के दोगुने के बराबर राशि","ar":"مبلغ يعادل ضعف الرسوم التي خسرتها الحكومة"}],"e":{"en":"Under 19 CFR 111.91(a), a broker may be assessed a monetary penalty in an amount not to exceed an aggregate of $30,000 for one or more of the reasons set forth in 19 CFR 111.53(a) through (g). A non-broker faces up to $10,000 per transaction (also capped at a $30,000 aggregate). There is no twice-the-duties formula in this section.","es":"Conforme a 19 CFR 111.91(a), a un agente puede imponérsele una multa monetaria por un monto que no exceda un agregado de $30,000 por uno o más de los motivos establecidos en 19 CFR 111.53(a) a (g). Una persona que no sea agente enfrenta hasta $10,000 por transacción (también con tope de $30,000 agregados). No existe una fórmula del doble de los derechos en esta sección.","ru":"Согласно 19 CFR 111.91(a), на брокера может быть наложен денежный штраф в размере, не превышающем в совокупности $30,000 за одну или несколько причин, изложенных в 19 CFR 111.53(a)–(g). Не-брокеру грозит до $10,000 за сделку (также с совокупным потолком $30,000). В данном разделе нет формулы двойного размера пошлин.","tr":"19 CFR 111.91(a) kapsamında, bir gümrük müşavirine, 19 CFR 111.53(a) ila (g)'de belirtilen nedenlerden biri veya birkaçı için toplam $30,000'i aşmayan bir tutarda para cezası uygulanabilir. Gümrük müşaviri olmayan bir kişi, işlem başına $10,000'e kadar (yine $30,000'lik toplamla sınırlı) ceza ile karşı karşıyadır. Bu bölümde vergilerin iki katı şeklinde bir formül yoktur.","hi":"19 CFR 111.91(a) के तहत, 19 CFR 111.53(a) से (g) में निर्धारित एक या अधिक कारणों के लिए एक ब्रोकर पर कुल $30,000 से अधिक नहीं की राशि का मौद्रिक जुर्माना लगाया जा सकता है। एक गैर-ब्रोकर को प्रति लेनदेन $10,000 तक का सामना करना पड़ता है (कुल $30,000 पर भी सीमित)। इस खंड में शुल्क-के-दोगुने का कोई सूत्र नहीं है।","ar":"بموجب 19 CFR 111.91(a)، يجوز فرض غرامة مالية على الوسيط بمبلغ لا يتجاوز إجمالاً ‎$30,000‎ عن سبب أو أكثر من الأسباب المبيّنة في 19 CFR 111.53(a) إلى (g). أما غير الوسيط فيواجه ما يصل إلى ‎$10,000‎ لكل معاملة (وبحد أقصى إجمالي قدره ‎$30,000‎ أيضاً). ولا توجد صيغة ضعف الرسوم في هذا القسم."}},{"cat":"compliance","a":1,"q":{"en":"Which of the following is an enumerated ground on which CBP may suspend or revoke a customs broker's license or permit under 19 CFR 111.53?","es":"¿Cuál de los siguientes es un motivo enumerado por el cual CBP puede suspender o revocar la licencia o permiso de un agente de aduanas conforme a 19 CFR 111.53?","ru":"Что из перечисленного является прямо указанным основанием, по которому CBP может приостановить или отозвать лицензию или разрешение таможенного брокера согласно 19 CFR 111.53?","tr":"Aşağıdakilerden hangisi, CBP'nin 19 CFR 111.53 kapsamında bir gümrük müşavirinin lisansını veya iznini askıya alabileceği veya iptal edebileceği sayılı gerekçelerden biridir?","hi":"निम्नलिखित में से कौन-सा एक गणित आधार है जिस पर CBP 19 CFR 111.53 के तहत एक customs broker के लाइसेंस या permit को निलंबित या निरस्त कर सकता है?","ar":"أي مما يلي يُعدّ سبباً منصوصاً عليه يجوز بموجبه لـ CBP تعليق أو إلغاء رخصة وسيط جمركي أو تصريحه بموجب 19 CFR 111.53؟"},"o":[{"en":"Charging a client a fee that exceeds the broker's published rate schedule","es":"Cobrarle a un cliente una tarifa que excede el listado de tarifas publicado del agente","ru":"Взимание с клиента платы, превышающей опубликованный тарифный перечень брокера","tr":"Bir müşteriye, gümrük müşavirinin yayımlanmış fiyat tarifesini aşan bir ücret talep etmek","hi":"किसी ग्राहक से ऐसी फीस वसूलना जो ब्रोकर की प्रकाशित दर अनुसूची से अधिक हो","ar":"تقاضي رسم من عميل يتجاوز جدول الأسعار المنشور للوسيط"},{"en":"Knowingly employing a person convicted of a felony without written approval from CBP","es":"Emplear a sabiendas a una persona condenada por un delito grave sin la aprobación escrita de CBP","ru":"Заведомый наем лица, осужденного за тяжкое преступление (felony), без письменного одобрения CBP","tr":"CBP'nin yazılı onayı olmadan, bir suçtan (felony) mahkûm olmuş bir kişiyi bilerek istihdam etmek","hi":"CBP से लिखित अनुमोदन के बिना किसी अपराध (felony) के दोषी व्यक्ति को जानबूझकर नियोजित करना","ar":"تشغيل شخص أُدين بجناية عن علم دون موافقة كتابية من CBP"},{"en":"Filing an entry summary more than five business days after the merchandise is released","es":"Presentar un resumen de entrada más de cinco días hábiles después de que se libera la mercancía","ru":"Подача итоговой декларации (entry summary) более чем через пять рабочих дней после выпуска товаров","tr":"Malların serbest bırakılmasından beş iş gününden fazla süre sonra bir entry summary sunmak","hi":"माल जारी होने के पाँच कार्य दिवसों से अधिक बाद एक entry summary दाखिल करना","ar":"تقديم بيان إدخال بعد أكثر من خمسة أيام عمل من الإفراج عن البضاعة"},{"en":"Maintaining a single national permit instead of separate district permits","es":"Mantener un único permiso nacional en lugar de permisos de distrito separados","ru":"Наличие единого национального разрешения вместо отдельных окружных разрешений","tr":"Ayrı bölge (district) izinleri yerine tek bir ulusal izin (national permit) bulundurmak","hi":"अलग district permits के बजाय एक एकल national permit बनाए रखना","ar":"الاحتفاظ بتصريح وطني واحد بدلاً من تصاريح مناطق منفصلة"}],"e":{"en":"Under 19 CFR 111.53(e), knowingly employing, or continuing to employ, a person convicted of a felony without CBP's written approval is a ground for suspension or revocation. Other grounds include false material statements, certain criminal convictions, violating CBP laws, aiding violations, and defrauding clients. The other options are not enumerated 111.53 grounds, and a single national permit is the current norm.","es":"Conforme a 19 CFR 111.53(e), emplear a sabiendas, o continuar empleando, a una persona condenada por un delito grave sin la aprobación escrita de CBP es un motivo de suspensión o revocación. Otros motivos incluyen declaraciones materiales falsas, ciertas condenas penales, infringir las leyes de CBP, ayudar a infracciones y defraudar a los clientes. Las demás opciones no son motivos enumerados en 111.53, y un único permiso nacional es la norma actual.","ru":"Согласно 19 CFR 111.53(e), заведомый наем или продолжение найма лица, осужденного за тяжкое преступление (felony), без письменного одобрения CBP является основанием для приостановления или отзыва. Другие основания включают ложные существенные заявления, определенные уголовные судимости, нарушение законов CBP, содействие нарушениям и обман клиентов. Остальные варианты не являются прямо указанными основаниями 111.53, а единое национальное разрешение является текущей нормой.","tr":"19 CFR 111.53(e) kapsamında, bir suçtan (felony) mahkûm olmuş bir kişiyi CBP'nin yazılı onayı olmadan bilerek istihdam etmek veya istihdam etmeye devam etmek, askıya alma veya iptal için bir gerekçedir. Diğer gerekçeler arasında esaslı yanlış beyanlar, belirli cezai mahkumiyetler, CBP yasalarını ihlal etmek, ihlallere yardım etmek ve müşterileri dolandırmak yer alır. Diğer seçenekler 111.53'te sayılı gerekçeler değildir ve tek bir ulusal izin mevcut normdur.","hi":"19 CFR 111.53(e) के तहत, CBP के लिखित अनुमोदन के बिना किसी अपराध (felony) के दोषी व्यक्ति को जानबूझकर नियोजित करना, या नियोजित रखना, निलंबन या निरस्तीकरण का एक आधार है। अन्य आधारों में झूठे भौतिक बयान, कुछ आपराधिक दोषसिद्धियाँ, CBP कानूनों का उल्लंघन, उल्लंघनों में सहायता, और ग्राहकों को धोखा देना शामिल हैं। अन्य विकल्प 111.53 के गणित आधार नहीं हैं, और एक एकल national permit वर्तमान मानदंड है।","ar":"بموجب 19 CFR 111.53(e)، يُعدّ تشغيل شخص أُدين بجناية، أو الاستمرار في تشغيله، عن علم ودون موافقة كتابية من CBP، سبباً للتعليق أو الإلغاء. وتشمل أسباباً أخرى البيانات الجوهرية الكاذبة، وبعض الإدانات الجنائية، ومخالفة قوانين CBP، والمساعدة على المخالفات، والاحتيال على العملاء. أما الخيارات الأخرى فليست أسباباً منصوصاً عليها في 111.53، والتصريح الوطني الواحد هو المعتمَد حالياً."}},{"cat":"trade","a":1,"q":{"en":"An importer brings in unmarked aluminum sheet that a U.S. fabricator will cut and form into finished window frames having a new name, character, and use before retail sale. Under the marking regulations, who is treated as the ultimate purchaser of the imported aluminum sheet, and what marking is required?","es":"Un importador trae lámina de aluminio sin marcar que un fabricante estadounidense cortará y conformará en marcos de ventana terminados que tendrán un nuevo nombre, carácter y uso antes de la venta minorista. Conforme a la normativa de marcado, ¿quién es considerado el comprador final de la lámina de aluminio importada, y qué marcado se requiere?","ru":"Импортер ввозит немаркированный алюминиевый лист, который американский производитель будет резать и формовать в готовые оконные рамы с новым наименованием, характером и назначением до розничной продажи. Согласно правилам маркировки, кто рассматривается как конечный покупатель импортированного алюминиевого листа, и какая маркировка требуется?","tr":"Bir ithalatçı, bir ABD imalatçısının perakende satıştan önce kesip şekillendirerek yeni bir isim, karakter ve kullanıma sahip bitmiş pencere çerçevelerine dönüştüreceği işaretsiz alüminyum levha getiriyor. İşaretleme düzenlemeleri kapsamında, ithal edilen alüminyum levhanın nihai alıcısı (ultimate purchaser) kim olarak kabul edilir ve hangi işaretleme gereklidir?","hi":"एक आयातकर्ता बिना अंकन वाली aluminum sheet लाता है जिसे एक U.S. fabricator खुदरा बिक्री से पहले काटकर और आकार देकर एक नए नाम, चरित्र और उपयोग वाले तैयार window frames में बदल देगा। अंकन नियमों के तहत, आयातित aluminum sheet का ultimate purchaser किसे माना जाता है, और कौन-सा अंकन आवश्यक है?","ar":"يستورد مستورد ألواح ألمنيوم غير موسومة سيقوم مصنّع أمريكي بقطعها وتشكيلها إلى إطارات نوافذ مكتملة لها اسم وطابع واستخدام جديدة قبل البيع بالتجزئة. بموجب لوائح الوسم، من يُعامَل بوصفه المشتري النهائي لألواح الألمنيوم المستورَدة، وما الوسم المطلوب؟"},"o":[{"en":"The retail consumer is the ultimate purchaser, so each finished window frame must be individually marked with the country of origin of the aluminum.","es":"El consumidor minorista es el comprador final, por lo que cada marco de ventana terminado debe marcarse individualmente con el país de origen del aluminio.","ru":"Конечным покупателем является розничный потребитель, поэтому каждая готовая оконная рама должна быть индивидуально маркирована страной происхождения алюминия.","tr":"Nihai alıcı perakende tüketicidir, dolayısıyla her bitmiş pencere çerçevesi, alüminyumun menşe ülkesi (country of origin) ile ayrı ayrı işaretlenmelidir.","hi":"खुदरा उपभोक्ता ultimate purchaser है, इसलिए प्रत्येक तैयार window frame को aluminum के मूल देश के साथ व्यक्तिगत रूप से अंकित किया जाना चाहिए।","ar":"المستهلك بالتجزئة هو المشتري النهائي، لذا يجب وسم كل إطار نافذة مكتمل بشكل فردي ببلد منشأ الألمنيوم."},{"en":"The U.S. fabricator is the ultimate purchaser; the imported sheet need not be individually marked, but the outermost containers in which it is imported must be marked.","es":"El fabricante estadounidense es el comprador final; la lámina importada no necesita marcarse individualmente, pero los contenedores más externos en los que se importa deben marcarse.","ru":"Конечным покупателем является американский производитель; импортированный лист не обязательно маркировать индивидуально, но внешние контейнеры, в которых он импортируется, должны быть маркированы.","tr":"ABD imalatçısı nihai alıcıdır; ithal edilen levhanın ayrı ayrı işaretlenmesi gerekmez, ancak içinde ithal edildiği en dıştaki kaplar işaretlenmelidir.","hi":"U.S. fabricator ultimate purchaser है; आयातित sheet को व्यक्तिगत रूप से अंकित करने की आवश्यकता नहीं है, लेकिन जिन सबसे बाहरी कंटेनरों में इसे आयात किया जाता है उन्हें अंकित किया जाना चाहिए।","ar":"المصنّع الأمريكي هو المشتري النهائي؛ فلا يلزم وسم الألواح المستورَدة بشكل فردي، لكن يجب وسم الحاويات الخارجية التي تُستورَد فيها."},{"en":"The importer is the ultimate purchaser, and no marking of any kind is required because the goods are not for resale in their imported form.","es":"El importador es el comprador final, y no se requiere marcado de ningún tipo porque las mercancías no son para reventa en su forma importada.","ru":"Конечным покупателем является импортер, и никакой маркировки не требуется, поскольку товары не предназначены для перепродажи в их импортированном виде.","tr":"İthalatçı nihai alıcıdır ve mallar ithal edildikleri haliyle yeniden satış için olmadığından hiçbir şekilde işaretleme gerekmez.","hi":"आयातकर्ता ultimate purchaser है, और किसी भी प्रकार के अंकन की आवश्यकता नहीं है क्योंकि माल अपने आयातित रूप में पुनर्विक्रय के लिए नहीं है।","ar":"المستورد هو المشتري النهائي، ولا يلزم أي وسم لأن البضائع ليست للبيع بصيغتها المستورَدة."},{"en":"CBP is the ultimate purchaser, so the goods may be released only after a marking duty of 10 percent is paid.","es":"CBP es el comprador final, por lo que las mercancías pueden liberarse solo después de pagar un derecho de marcado del 10 por ciento.","ru":"Конечным покупателем является CBP, поэтому товары могут быть выпущены только после уплаты маркировочной пошлины в размере 10 процентов.","tr":"Nihai alıcı CBP'dir, dolayısıyla mallar ancak yüzde 10'luk bir işaretleme vergisi ödendikten sonra serbest bırakılabilir.","hi":"CBP ultimate purchaser है, इसलिए माल केवल 10 प्रतिशत के marking duty का भुगतान करने के बाद ही जारी किया जा सकता है।","ar":"CBP هي المشتري النهائي، فلا يجوز الإفراج عن البضائع إلا بعد دفع رسم وسم قدره 10 بالمئة."}],"e":{"en":"Under 19 CFR 134.35, when an imported article is substantially transformed in the U.S. into an article with a new name, character, or use, the U.S. manufacturer/processor is the ultimate purchaser. The transformed article need not be individually marked, but the outermost containers of the imported articles must be marked (per 19 CFR 134.35 and the ultimate-purchaser definition in 19 CFR 134.1).","es":"Conforme a 19 CFR 134.35, cuando un artículo importado se transforma sustancialmente en Estados Unidos en un artículo con un nuevo nombre, carácter o uso, el fabricante/procesador estadounidense es el comprador final. El artículo transformado no necesita marcarse individualmente, pero los contenedores más externos de los artículos importados deben marcarse (según 19 CFR 134.35 y la definición de comprador final en 19 CFR 134.1).","ru":"Согласно 19 CFR 134.35, когда импортированное изделие подвергается существенной трансформации (substantial transformation) в США в изделие с новым наименованием, характером или назначением, конечным покупателем является американский производитель/переработчик. Трансформированное изделие не обязательно маркировать индивидуально, но внешние контейнеры импортированных изделий должны быть маркированы (согласно 19 CFR 134.35 и определению конечного покупателя в 19 CFR 134.1).","tr":"19 CFR 134.35 kapsamında, ithal edilen bir ürün ABD'de yeni bir isim, karakter veya kullanıma sahip bir ürüne esaslı şekilde dönüştürüldüğünde (substantially transformed), ABD imalatçısı/işleyicisi nihai alıcıdır (ultimate purchaser). Dönüştürülen ürünün ayrı ayrı işaretlenmesi gerekmez, ancak ithal edilen ürünlerin en dıştaki kapları işaretlenmelidir (19 CFR 134.35 ve 19 CFR 134.1'deki nihai alıcı tanımı uyarınca).","hi":"19 CFR 134.35 के तहत, जब एक आयातित वस्तु को U.S. में पर्याप्त रूप से रूपांतरित (substantially transformed) करके एक नए नाम, चरित्र, या उपयोग वाली वस्तु में बदल दिया जाता है, तो U.S. निर्माता/प्रोसेसर ultimate purchaser होता है। रूपांतरित वस्तु को व्यक्तिगत रूप से अंकित करने की आवश्यकता नहीं है, लेकिन आयातित वस्तुओं के सबसे बाहरी कंटेनरों को अंकित किया जाना चाहिए (19 CFR 134.35 और 19 CFR 134.1 में ultimate-purchaser की परिभाषा के अनुसार)।","ar":"بموجب 19 CFR 134.35، عندما تخضع مادة مستورَدة لتحوّل جوهري في الولايات المتحدة إلى مادة لها اسم أو طابع أو استخدام جديد، يكون المصنّع/المعالِج الأمريكي هو المشتري النهائي. ولا يلزم وسم المادة المتحوّلة بشكل فردي، لكن يجب وسم الحاويات الخارجية للمواد المستورَدة (وفق 19 CFR 134.35 وتعريف المشتري النهائي في 19 CFR 134.1)."}},{"cat":"trade","a":3,"q":{"en":"Imported articles arrive that were not legibly marked with the country of origin at the time of importation. The importer does not export, destroy, or properly mark the goods under CBP supervision before liquidation. What is the consequence under 19 U.S.C. 1304 / 19 CFR Part 134?","es":"Llegan artículos importados que no estaban marcados de forma legible con el país de origen al momento de la importación. El importador no exporta, destruye ni marca debidamente las mercancías bajo supervisión de CBP antes de la liquidación. ¿Cuál es la consecuencia conforme a 19 U.S.C. 1304 / 19 CFR Part 134?","ru":"Прибывают импортированные изделия, которые на момент импорта не были разборчиво маркированы страной происхождения. Импортер не экспортирует, не уничтожает и не маркирует надлежащим образом товары под надзором CBP до ликвидации. Каковы последствия согласно 19 U.S.C. 1304 / 19 CFR Part 134?","tr":"İthalat anında menşe ülkesi (country of origin) ile okunaklı şekilde işaretlenmemiş ithal mallar geliyor. İthalatçı, malları kesinleştirme (likidasyon) öncesinde CBP gözetimi altında ihraç etmiyor, imha etmiyor veya uygun şekilde işaretlemiyor. 19 U.S.C. 1304 / 19 CFR Part 134 kapsamında sonuç nedir?","hi":"ऐसी आयातित वस्तुएँ पहुँचती हैं जो आयात के समय मूल देश के साथ सुपाठ्य रूप से अंकित नहीं थीं। आयातकर्ता परिसमापन से पहले CBP की देखरेख में माल को निर्यात, नष्ट, या ठीक से अंकित नहीं करता। 19 U.S.C. 1304 / 19 CFR Part 134 के तहत क्या परिणाम होता है?","ar":"تصل مواد مستورَدة لم تكن موسومة بوضوح ببلد المنشأ وقت الاستيراد. ولا يقوم المستورد بتصدير البضائع أو إتلافها أو وسمها على نحو سليم تحت إشراف CBP قبل التصفية. ما العاقبة بموجب 19 U.S.C. 1304 / 19 CFR Part 134؟"},"o":[{"en":"The goods are automatically seized and forfeited as a prohibited importation.","es":"Las mercancías se incautan y decomisan automáticamente como una importación prohibida.","ru":"Товары автоматически изымаются и конфискуются как запрещенный к ввозу импорт.","tr":"Mallar, yasak bir ithalat olarak otomatik olarak el konulur ve müsadere edilir.","hi":"माल को एक निषिद्ध आयात के रूप में स्वचालित रूप से जब्त और जब्ती (forfeit) कर लिया जाता है।","ar":"تُضبَط البضائع وتُصادَر تلقائياً بوصفها استيراداً محظوراً."},{"en":"A flat penalty equal to twice the appraised value is assessed as a section 592 penalty.","es":"Se impone una multa fija igual al doble del valor avaluado como una multa de la section 592.","ru":"Налагается фиксированный штраф, равный двойной оцененной стоимости, как штраф по разделу 592.","tr":"section 592 cezası olarak, takdir edilen değerin iki katına eşit sabit bir ceza tahakkuk ettirilir.","hi":"मूल्यांकित मूल्य के दोगुने के बराबर एक समान जुर्माना एक section 592 जुर्माने के रूप में लगाया जाता है।","ar":"تُفرض غرامة ثابتة تعادل ضعف القيمة المقدَّرة بوصفها غرامة section 592."},{"en":"The entry is rejected and the merchandise must be returned to the country of export within 15 days.","es":"La entrada se rechaza y la mercancía debe devolverse al país de exportación dentro de 15 días.","ru":"Оформление отклоняется, и товары должны быть возвращены в страну экспорта в течение 15 дней.","tr":"Beyan reddedilir ve mallar 15 gün içinde ihracat ülkesine iade edilmelidir.","hi":"एंट्री को अस्वीकार कर दिया जाता है और माल को 15 दिनों के भीतर निर्यात के देश में वापस किया जाना चाहिए।","ar":"يُرفَض الإدخال ويجب إعادة البضاعة إلى بلد التصدير خلال 15 يوماً."},{"en":"A marking duty of 10 percent ad valorem is assessed in addition to any other applicable duty.","es":"Se impone un derecho de marcado del 10 por ciento ad valorem adicional a cualquier otro derecho aplicable.","ru":"Налагается маркировочная пошлина в размере 10 процентов адвалорно в дополнение к любой другой применимой пошлине.","tr":"Diğer uygulanabilir vergilere ek olarak yüzde 10 ad valorem işaretleme vergisi tahakkuk ettirilir.","hi":"किसी भी अन्य लागू शुल्क के अतिरिक्त 10 प्रतिशत ad valorem का एक marking duty लगाया जाता है।","ar":"يُفرَض رسم وسم قيمي قدره 10 بالمئة إضافةً إلى أي رسم آخر مطبّق."}],"e":{"en":"Under 19 U.S.C. 1304(i) and 19 CFR 134.2, articles not properly marked at importation that are not exported, destroyed, or marked under CBP supervision prior to liquidation are subject to a marking duty of 10 percent ad valorem, in addition to any other duty. This is a special marking duty, not a 592 penalty or seizure.","es":"Conforme a 19 U.S.C. 1304(i) y 19 CFR 134.2, los artículos que no están debidamente marcados al momento de la importación y que no se exportan, destruyen ni marcan bajo supervisión de CBP antes de la liquidación están sujetos a un derecho de marcado del 10 por ciento ad valorem, adicional a cualquier otro derecho. Este es un derecho especial de marcado, no una multa de la 592 ni una incautación.","ru":"Согласно 19 U.S.C. 1304(i) и 19 CFR 134.2, изделия, не маркированные надлежащим образом при импорте, которые не были экспортированы, уничтожены или маркированы под надзором CBP до ликвидации, подлежат маркировочной пошлине в размере 10 процентов адвалорно, в дополнение к любой другой пошлине. Это специальная маркировочная пошлина, а не штраф по разделу 592 и не изъятие.","tr":"19 U.S.C. 1304(i) ve 19 CFR 134.2 kapsamında, ithalat anında uygun şekilde işaretlenmemiş ve kesinleştirme (likidasyon) öncesinde CBP gözetimi altında ihraç edilmeyen, imha edilmeyen veya işaretlenmeyen ürünler, diğer herhangi bir vergiye ek olarak yüzde 10 ad valorem işaretleme vergisine tabidir. Bu özel bir işaretleme vergisidir, 592 cezası veya el koyma değildir.","hi":"19 U.S.C. 1304(i) और 19 CFR 134.2 के तहत, आयात के समय ठीक से अंकित न की गई वस्तुएँ जिन्हें परिसमापन से पहले CBP की देखरेख में निर्यात, नष्ट, या अंकित नहीं किया जाता, किसी भी अन्य शुल्क के अतिरिक्त 10 प्रतिशत ad valorem के marking duty के अधीन हैं। यह एक विशेष marking duty है, न कि 592 जुर्माना या जब्ती।","ar":"بموجب 19 U.S.C. 1304(i) و19 CFR 134.2، تخضع المواد غير الموسومة على نحو سليم عند الاستيراد، والتي لا تُصدَّر أو تُتلَف أو تُوسَم تحت إشراف CBP قبل التصفية، لرسم وسم قيمي قدره 10 بالمئة، إضافةً إلى أي رسم آخر. وهذا رسم وسم خاص، وليس غرامة 592 أو ضبطاً."}},{"cat":"trade","a":2,"q":{"en":"Which of the following articles falls under the J-list (19 CFR 134.33) and is therefore excepted from individual country-of-origin marking, with only its outermost container required to be marked?","es":"¿Cuál de los siguientes artículos cae bajo la J-list (19 CFR 134.33) y por lo tanto está exceptuado del marcado individual de país de origen, requiriéndose marcar solo su contenedor más externo?","ru":"Что из перечисленного подпадает под J-list (19 CFR 134.33) и потому исключается из индивидуальной маркировки страной происхождения, при этом маркировке подлежит только его внешний контейнер?","tr":"Aşağıdaki ürünlerden hangisi J-list'in (19 CFR 134.33) kapsamına girer ve bu nedenle ayrı menşe ülkesi (country of origin) işaretlemesinden muaftır; yalnızca en dıştaki kabının işaretlenmesi gerekir?","hi":"निम्नलिखित में से कौन-सी वस्तु J-list (19 CFR 134.33) के अंतर्गत आती है और इसलिए व्यक्तिगत मूल-देश अंकन से छूट प्राप्त है, जिसमें केवल इसके सबसे बाहरी कंटेनर को अंकित करना आवश्यक है?","ar":"أي من المواد التالية يقع ضمن J-list (19 CFR 134.33) ويكون بذلك مستثنى من وسم بلد المنشأ الفردي، مع الاكتفاء بوسم حاويته الخارجية؟"},"o":[{"en":"A pair of imported leather shoes sold at retail in a labeled box.","es":"Un par de zapatos de cuero importados vendidos al menudeo en una caja etiquetada.","ru":"Пара импортированных кожаных туфель, продаваемых в розницу в маркированной коробке.","tr":"Etiketli bir kutuda perakende satılan ithal bir çift deri ayakkabı.","hi":"एक लेबल वाले डिब्बे में खुदरा बिक्री में बेचे गए आयातित चमड़े के जूतों की एक जोड़ी।","ar":"زوج من الأحذية الجلدية المستورَدة يُباع بالتجزئة في علبة موسومة."},{"en":"An imported wristwatch movement assembled abroad.","es":"Un movimiento de reloj de pulsera importado ensamblado en el extranjero.","ru":"Импортированный часовой механизм, собранный за рубежом.","tr":"Yurt dışında monte edilmiş ithal bir kol saati mekanizması.","hi":"विदेश में असेंबल किया गया एक आयातित wristwatch movement।","ar":"حركة ساعة يد مستورَدة مجمَّعة في الخارج."},{"en":"Imported screws (nuts and bolts) of a type listed on the J-list.","es":"Tornillos importados (tuercas y pernos) de un tipo listado en la J-list.","ru":"Импортированные винты (гайки и болты) того типа, что указан в J-list.","tr":"J-list'te listelenen türden ithal vidalar (somunlar ve cıvatalar).","hi":"J-list पर सूचीबद्ध प्रकार के आयातित screws (nuts और bolts)।","ar":"براغي مستورَدة (صواميل ومسامير ملولبة) من النوع المدرَج على J-list."},{"en":"An imported electric motor incorporated into a U.S.-assembled appliance.","es":"Un motor eléctrico importado incorporado a un electrodoméstico ensamblado en Estados Unidos.","ru":"Импортированный электродвигатель, встроенный в собранный в США бытовой прибор.","tr":"ABD'de monte edilen bir cihaza dahil edilmiş ithal bir elektrik motoru.","hi":"एक U.S.-असेंबल किए गए उपकरण में शामिल एक आयातित electric motor।","ar":"محرك كهربائي مستورَد مُدمَج في جهاز مجمَّع في الولايات المتحدة."}],"e":{"en":"The J-list in 19 CFR 134.33 enumerates articles that are excepted from individual marking (Customs has determined marking is impracticable or the article is of a class historically exempt), such as screws, nuts, bolts, eggs, and similar items. Only the containers reaching the ultimate purchaser must be marked. Shoes and watch movements are not J-list exceptions.","es":"La J-list en 19 CFR 134.33 enumera artículos que están exceptuados del marcado individual (Customs ha determinado que el marcado es impracticable o que el artículo pertenece a una clase históricamente exenta), tales como tornillos, tuercas, pernos, huevos y artículos similares. Solo los contenedores que llegan al comprador final deben marcarse. Los zapatos y los movimientos de reloj no son excepciones de la J-list.","ru":"J-list в 19 CFR 134.33 перечисляет изделия, исключенные из индивидуальной маркировки (Таможня определила, что маркировка нецелесообразна или изделие относится к категории, исторически освобожденной), такие как винты, гайки, болты, яйца и подобные предметы. Маркировке подлежат только контейнеры, доходящие до конечного покупателя. Туфли и часовые механизмы не являются исключениями J-list.","tr":"19 CFR 134.33'teki J-list, ayrı işaretlemeden muaf tutulan ürünleri (Gümrük, işaretlemenin pratik olmadığını veya ürünün tarihsel olarak muaf bir sınıfa ait olduğunu belirlemiştir) sıralar; bunlar arasında vidalar, somunlar, cıvatalar, yumurtalar ve benzeri kalemler bulunur. Yalnızca nihai alıcıya ulaşan kapların işaretlenmesi gerekir. Ayakkabılar ve saat mekanizmaları J-list istisnaları değildir.","hi":"19 CFR 134.33 में J-list उन वस्तुओं को सूचीबद्ध करती है जिन्हें व्यक्तिगत अंकन से छूट प्राप्त है (Customs ने निर्धारित किया है कि अंकन अव्यावहारिक है या वस्तु एक ऐसी श्रेणी की है जो ऐतिहासिक रूप से छूट प्राप्त है), जैसे screws, nuts, bolts, अंडे, और इसी तरह की वस्तुएँ। केवल ultimate purchaser तक पहुँचने वाले कंटेनरों को अंकित किया जाना चाहिए। जूते और watch movements J-list अपवाद नहीं हैं।","ar":"تعدّد J-list في 19 CFR 134.33 المواد المستثناة من الوسم الفردي (حيث قرّرت الجمارك أن الوسم غير عملي أو أن المادة من فئة معفاة تاريخياً)، مثل البراغي والصواميل والمسامير الملولبة والبيض وما شابهها. ولا يلزم وسم سوى الحاويات التي تصل إلى المشتري النهائي. أما الأحذية وحركات الساعات فليست من استثناءات J-list."}},{"cat":"trade","a":1,"q":{"en":"An importer wishes to claim USMCA preferential tariff treatment for goods imported from Mexico. Regarding the certification of origin under 19 CFR Part 182, which statement is correct?","es":"Un importador desea reclamar trato arancelario preferencial bajo el USMCA para mercancías importadas de México. Respecto a la certificación de origen conforme a 19 CFR Part 182, ¿qué afirmación es correcta?","ru":"Импортер желает заявить преференциальный тарифный режим USMCA для товаров, импортируемых из Мексики. Относительно сертификата происхождения согласно 19 CFR Part 182, какое утверждение верно?","tr":"Bir ithalatçı, Meksika'dan ithal edilen mallar için USMCA tercihli tarife muamelesi talep etmek istiyor. 19 CFR Part 182 kapsamında menşe sertifikasyonu (certification of origin) ile ilgili olarak hangi ifade doğrudur?","hi":"एक आयातकर्ता Mexico से आयातित माल के लिए USMCA अधिमान्य टैरिफ उपचार का दावा करना चाहता है। 19 CFR Part 182 के तहत certification of origin के संबंध में, कौन-सा कथन सही है?","ar":"يرغب مستورد في المطالبة بالمعاملة التعريفية التفضيلية بموجب USMCA لبضائع مستورَدة من المكسيك. فيما يتعلق بشهادة المنشأ بموجب 19 CFR Part 182، أي عبارة صحيحة؟"},"o":[{"en":"The certification must be made on CBP Form 434 and may be completed only by the exporter or producer.","es":"La certificación debe hacerse en el CBP Form 434 y solo puede completarla el exportador o el productor.","ru":"Сертификация должна оформляться на CBP Form 434 и может быть заполнена только экспортером или производителем.","tr":"Sertifikasyon CBP Form 434 üzerinde yapılmalıdır ve yalnızca ihracatçı veya üretici tarafından tamamlanabilir.","hi":"certification CBP Form 434 पर की जानी चाहिए और केवल exporter या producer द्वारा ही पूरी की जा सकती है।","ar":"يجب إعداد الشهادة على CBP Form 434 ولا يجوز إكمالها إلا من المصدّر أو المنتج."},{"en":"The certification need not be in a prescribed format and may be completed by the importer, exporter, or producer.","es":"La certificación no necesita tener un formato prescrito y puede completarla el importador, el exportador o el productor.","ru":"Сертификация не обязана иметь установленный формат и может быть заполнена импортером, экспортером или производителем.","tr":"Sertifikasyonun belirli bir formatta olması gerekmez ve ithalatçı, ihracatçı veya üretici tarafından tamamlanabilir.","hi":"certification को किसी निर्धारित प्रारूप में होने की आवश्यकता नहीं है और इसे importer, exporter, या producer द्वारा पूरा किया जा सकता है।","ar":"لا يلزم أن تكون الشهادة بصيغة محددة ويجوز إكمالها من المستورد أو المصدّر أو المنتج."},{"en":"Only the producer may complete the certification, and it must accompany the goods at the time of entry.","es":"Solo el productor puede completar la certificación, y esta debe acompañar a las mercancías al momento de la entrada.","ru":"Только производитель может заполнить сертификацию, и она должна сопровождать товары на момент оформления.","tr":"Sertifikasyonu yalnızca üretici tamamlayabilir ve beyan anında mallara eşlik etmelidir.","hi":"केवल producer ही certification पूरी कर सकता है, और यह एंट्री के समय माल के साथ होनी चाहिए।","ar":"لا يجوز إكمال الشهادة إلا من المنتج، ويجب أن ترافق البضائع وقت الإدخال."},{"en":"A certification is not required if the goods are valued under $2,500; otherwise only the exporter may certify.","es":"No se requiere certificación si las mercancías tienen un valor inferior a $2,500; de lo contrario, solo el exportador puede certificar.","ru":"Сертификация не требуется, если товары оценены менее чем в $2,500; в противном случае сертифицировать может только экспортер.","tr":"Mallar $2,500'ün altında değerlendiyse sertifikasyon gerekmez; aksi takdirde yalnızca ihracatçı sertifikalandırabilir.","hi":"यदि माल का मूल्य $2,500 से कम है तो certification आवश्यक नहीं है; अन्यथा केवल exporter ही प्रमाणित कर सकता है।","ar":"لا تُشترط الشهادة إذا كانت قيمة البضائع دون $2,500؛ وإلا فلا يجوز التصديق إلا من المصدّر."}],"e":{"en":"Under USMCA (Article 5.2) and 19 CFR 182.12, the certification of origin need not be in a prescribed format (no required form) and may be completed by the importer, exporter, or producer. This differs from NAFTA, which used CBP Form 434 and did not allow importer certification.","es":"Conforme al USMCA (Article 5.2) y 19 CFR 182.12, la certificación de origen no necesita tener un formato prescrito (no hay formulario requerido) y puede completarla el importador, el exportador o el productor. Esto difiere del NAFTA, que usaba el CBP Form 434 y no permitía la certificación por parte del importador.","ru":"Согласно USMCA (Article 5.2) и 19 CFR 182.12, сертификат происхождения не обязан иметь установленный формат (нет обязательной формы) и может быть заполнен импортером, экспортером или производителем. Это отличается от NAFTA, где использовалась CBP Form 434 и не допускалась сертификация импортером.","tr":"USMCA (Article 5.2) ve 19 CFR 182.12 kapsamında, menşe sertifikasyonunun (certification of origin) belirli bir formatta olması gerekmez (gerekli bir form yoktur) ve ithalatçı, ihracatçı veya üretici tarafından tamamlanabilir. Bu, CBP Form 434 kullanan ve ithalatçı sertifikasyonuna izin vermeyen NAFTA'dan farklıdır.","hi":"USMCA (Article 5.2) और 19 CFR 182.12 के तहत, certification of origin को किसी निर्धारित प्रारूप में होने की आवश्यकता नहीं है (कोई आवश्यक फॉर्म नहीं) और इसे importer, exporter, या producer द्वारा पूरा किया जा सकता है। यह NAFTA से अलग है, जो CBP Form 434 का उपयोग करता था और importer प्रमाणन की अनुमति नहीं देता था।","ar":"بموجب USMCA (Article 5.2) و19 CFR 182.12، لا يلزم أن تكون شهادة المنشأ بصيغة محددة (لا نموذج مطلوب) ويجوز إكمالها من المستورد أو المصدّر أو المنتج. ويختلف ذلك عن NAFTA، الذي كان يستخدم CBP Form 434 ولا يسمح بتصديق المستورد."}},{"cat":"trade","a":2,"q":{"en":"Foreign merchandise is admitted to a foreign-trade zone, and the operator timely files an application on the admission form to fix its tariff classification and rate of duty as of that date so that later manufacturing in the zone will not change them. What FTZ status has been elected?","es":"Mercancía extranjera se admite a una zona de comercio exterior (FTZ), y el operador presenta oportunamente una solicitud en el formulario de admisión para fijar su clasificación arancelaria y tasa de derechos a esa fecha, de modo que la manufactura posterior en la zona no las cambie. ¿Qué estatus de FTZ se ha elegido?","ru":"Иностранные товары допускаются в зону внешней торговли (FTZ), и оператор своевременно подает заявление на форме допуска, чтобы зафиксировать их тарифную классификацию и ставку пошлины по состоянию на эту дату, так чтобы последующее производство в зоне их не изменило. Какой статус FTZ был выбран?","tr":"Yabancı mallar bir foreign-trade zone'a kabul ediliyor ve işletici, bölgede daha sonra yapılacak imalatın bunları değiştirmemesi için tarife sınıflandırmasını ve vergi oranını o tarih itibarıyla sabitlemek üzere kabul formu üzerinde zamanında bir başvuru sunuyor. Hangi FTZ statüsü seçilmiştir?","hi":"विदेशी माल को एक foreign-trade zone में प्रवेश दिया जाता है, और ऑपरेटर admission form पर समय पर एक आवेदन दाखिल करता है ताकि उसके tariff classification और शुल्क दर को उस तारीख के अनुसार स्थिर किया जा सके, ताकि zone में बाद का निर्माण उन्हें न बदले। कौन-सा FTZ status चुना गया है?","ar":"تُدخَل بضاعة أجنبية إلى منطقة تجارة خارجية، ويقدّم المشغّل في الوقت المناسب طلباً على نموذج الإدخال لتثبيت تصنيفها التعريفي ومعدل رسومها اعتباراً من ذلك التاريخ بحيث لا يغيّرهما التصنيع اللاحق في المنطقة. أي وضع FTZ تمّ اختياره؟"},"o":[{"en":"Zone-restricted status.","es":"Estatus restringido de zona.","ru":"Зонально-ограниченный статус (zone-restricted status).","tr":"Zone-restricted status (bölge kısıtlamalı statü).","hi":"Zone-restricted status।","ar":"الوضع المقيّد بالمنطقة (Zone-restricted)."},{"en":"Nonprivileged foreign status.","es":"Estatus extranjero no privilegiado.","ru":"Непривилегированный иностранный статус (nonprivileged foreign status).","tr":"Nonprivileged foreign status (ayrıcalıklı olmayan yabancı statü).","hi":"Nonprivileged foreign status।","ar":"الوضع الأجنبي غير المميَّز (Nonprivileged foreign)."},{"en":"Privileged foreign status.","es":"Estatus extranjero privilegiado.","ru":"Привилегированный иностранный статус (privileged foreign status).","tr":"Privileged foreign status (ayrıcalıklı yabancı statü).","hi":"Privileged foreign status।","ar":"الوضع الأجنبي المميَّز (Privileged foreign)."},{"en":"Domestic status.","es":"Estatus doméstico.","ru":"Внутренний статус (domestic status).","tr":"Domestic status (yerli statü).","hi":"Domestic status।","ar":"الوضع المحلي (Domestic)."}],"e":{"en":"Under 19 CFR 146.41, privileged foreign status is elected by application (on the CBP Form 214 admission application, before any manipulation/manufacture that changes the tariff classification). It fixes the tariff classification and duty rate as of the date of the application, regardless of later processing in the zone.","es":"Conforme a 19 CFR 146.41, el estatus extranjero privilegiado se elige mediante solicitud (en la solicitud de admisión CBP Form 214, antes de cualquier manipulación/manufactura que cambie la clasificación arancelaria). Fija la clasificación arancelaria y la tasa de derechos a la fecha de la solicitud, independientemente del procesamiento posterior en la zona.","ru":"Согласно 19 CFR 146.41, привилегированный иностранный статус (privileged foreign status) выбирается путем подачи заявления (на заявлении о допуске CBP Form 214, до какой-либо манипуляции/производства, изменяющего тарифную классификацию). Он фиксирует тарифную классификацию и ставку пошлины по состоянию на дату заявления, независимо от последующей переработки в зоне.","tr":"19 CFR 146.41 kapsamında, privileged foreign status (ayrıcalıklı yabancı statü), başvuru ile (tarife sınıflandırmasını değiştiren herhangi bir manipülasyon/imalattan önce CBP Form 214 kabul başvurusu üzerinde) seçilir. Tarife sınıflandırmasını ve vergi oranını, bölgede daha sonra yapılacak işlemden bağımsız olarak başvuru tarihi itibarıyla sabitler.","hi":"19 CFR 146.41 के तहत, privileged foreign status को आवेदन द्वारा चुना जाता है (CBP Form 214 admission application पर, किसी ऐसे manipulation/manufacture से पहले जो tariff classification को बदलता है)। यह tariff classification और शुल्क दर को आवेदन की तारीख के अनुसार स्थिर कर देता है, zone में बाद की प्रोसेसिंग की परवाह किए बिना।","ar":"بموجب 19 CFR 146.41، يُختار الوضع الأجنبي المميَّز بطلب (على طلب الإدخال CBP Form 214، قبل أي معالجة/تصنيع يغيّر التصنيف التعريفي). ويثبّت التصنيف التعريفي ومعدل الرسوم اعتباراً من تاريخ الطلب، بصرف النظر عن المعالجة اللاحقة في المنطقة."}},{"cat":"trade","a":2,"q":{"en":"Merchandise is taken into a foreign-trade zone for the sole purpose of exportation (or storage pending exportation, or destruction). Which FTZ status applies, and what is its key restriction?","es":"Se introduce mercancía a una zona de comercio exterior (FTZ) con el único propósito de exportación (o almacenamiento en espera de exportación, o destrucción). ¿Qué estatus de FTZ aplica, y cuál es su restricción clave?","ru":"Товары ввозятся в зону внешней торговли (FTZ) исключительно с целью экспорта (либо хранения в ожидании экспорта, либо уничтожения). Какой статус FTZ применяется, и каково его ключевое ограничение?","tr":"Mallar yalnızca ihracat (veya ihracat beklemedeki depolama ya da imha) amacıyla bir foreign-trade zone'a alınıyor. Hangi FTZ statüsü geçerlidir ve temel kısıtlaması nedir?","hi":"माल को केवल निर्यात के उद्देश्य से (या निर्यात के लंबित भंडारण, या विनाश के लिए) एक foreign-trade zone में लिया जाता है। कौन-सा FTZ status लागू होता है, और इसका मुख्य प्रतिबंध क्या है?","ar":"تُؤخَذ بضاعة إلى منطقة تجارة خارجية لغرض التصدير حصراً (أو التخزين تمهيداً للتصدير، أو الإتلاف). أي وضع FTZ ينطبق، وما قيده الأساسي؟"},"o":[{"en":"Nonprivileged foreign status; it may be entered for consumption at the nonprivileged duty rate at any time.","es":"Estatus extranjero no privilegiado; puede declararse para consumo a la tasa de derechos no privilegiada en cualquier momento.","ru":"Непривилегированный иностранный статус; они могут быть оформлены для потребления по непривилегированной ставке пошлины в любое время.","tr":"Nonprivileged foreign status; herhangi bir zamanda ayrıcalıksız vergi oranıyla tüketim için beyan edilebilir.","hi":"Nonprivileged foreign status; इसे किसी भी समय nonprivileged शुल्क दर पर उपभोग के लिए एंटर किया जा सकता है।","ar":"الوضع الأجنبي غير المميَّز؛ يجوز إدخالها للاستهلاك بمعدل الرسوم غير المميَّز في أي وقت."},{"en":"Privileged foreign status; its classification is frozen but it may freely enter U.S. commerce.","es":"Estatus extranjero privilegiado; su clasificación queda congelada pero puede entrar libremente al comercio de Estados Unidos.","ru":"Привилегированный иностранный статус; их классификация зафиксирована, но они могут свободно поступать в торговый оборот США.","tr":"Privileged foreign status; sınıflandırması dondurulur ancak serbestçe ABD ticaretine girebilir.","hi":"Privileged foreign status; इसका classification स्थिर है लेकिन यह स्वतंत्र रूप से U.S. वाणिज्य में प्रवेश कर सकता है।","ar":"الوضع الأجنبي المميَّز؛ يُثبَّت تصنيفها لكن يجوز إدخالها بحرية إلى التجارة الأمريكية."},{"en":"Zone-restricted status; it generally may not be returned to U.S. customs territory for domestic consumption.","es":"Estatus restringido de zona; generalmente no puede devolverse al territorio aduanero de Estados Unidos para consumo doméstico.","ru":"Зонально-ограниченный статус; они, как правило, не могут быть возвращены на таможенную территорию США для внутреннего потребления.","tr":"Zone-restricted status; genellikle yurt içi tüketim için ABD gümrük bölgesine geri getirilemez.","hi":"Zone-restricted status; इसे आम तौर पर घरेलू उपभोग के लिए U.S. कस्टम क्षेत्र में वापस नहीं किया जा सकता।","ar":"الوضع المقيّد بالمنطقة؛ لا يجوز عموماً إعادتها إلى الإقليم الجمركي الأمريكي للاستهلاك المحلي."},{"en":"Domestic status; it is treated as already entered for consumption and bears no restriction.","es":"Estatus doméstico; se trata como ya declarada para consumo y no tiene ninguna restricción.","ru":"Внутренний статус; они рассматриваются как уже оформленные для потребления и не несут ограничений.","tr":"Domestic status; halihazırda tüketim için beyan edilmiş gibi muamele görür ve hiçbir kısıtlama taşımaz.","hi":"Domestic status; इसे पहले से ही उपभोग के लिए एंटर किया गया माना जाता है और इस पर कोई प्रतिबंध नहीं है।","ar":"الوضع المحلي؛ تُعامَل كأنها أُدخلت بالفعل للاستهلاك ولا تخضع لأي قيد."}],"e":{"en":"Under 19 CFR 146.44, merchandise taken into a zone for exportation, storage pending exportation, or destruction is given zone-restricted status on application. Such merchandise may not be removed to U.S. customs territory for domestic consumption except where the FTZ Board finds the return to be in the public interest.","es":"Conforme a 19 CFR 146.44, la mercancía introducida a una zona para exportación, almacenamiento en espera de exportación o destrucción recibe estatus restringido de zona mediante solicitud. Dicha mercancía no puede trasladarse al territorio aduanero de Estados Unidos para consumo doméstico, excepto cuando el FTZ Board determine que el retorno es de interés público.","ru":"Согласно 19 CFR 146.44, товары, ввезенные в зону для экспорта, хранения в ожидании экспорта или уничтожения, получают зонально-ограниченный статус (zone-restricted status) по заявлению. Такие товары не могут быть перемещены на таможенную территорию США для внутреннего потребления, за исключением случаев, когда Совет FTZ признает возврат соответствующим общественным интересам.","tr":"19 CFR 146.44 kapsamında, ihracat, ihracat beklemedeki depolama veya imha amacıyla bir bölgeye alınan mallara, başvuru üzerine zone-restricted status (bölge kısıtlamalı statü) verilir. Bu tür mallar, FTZ Board'un iadeyi kamu yararına bulduğu durumlar dışında, yurt içi tüketim için ABD gümrük bölgesine geri taşınamaz.","hi":"19 CFR 146.44 के तहत, निर्यात, निर्यात के लंबित भंडारण, या विनाश के लिए zone में लिए गए माल को आवेदन पर zone-restricted status दिया जाता है। ऐसे माल को घरेलू उपभोग के लिए U.S. कस्टम क्षेत्र में नहीं हटाया जा सकता, सिवाय जहाँ FTZ Board यह पाता है कि वापसी जनहित में है।","ar":"بموجب 19 CFR 146.44، تُمنَح البضاعة المأخوذة إلى منطقة بغرض التصدير أو التخزين تمهيداً للتصدير أو الإتلاف الوضع المقيّد بالمنطقة بناءً على طلب. ولا يجوز نقل هذه البضاعة إلى الإقليم الجمركي الأمريكي للاستهلاك المحلي إلا حيث يجد مجلس FTZ أن إعادتها تخدم المصلحة العامة."}},{"cat":"trade","a":3,"q":{"en":"On a CBP bond, the named importer of record whose obligations are secured by the bond is referred to as the principal, and the bonding company guaranteeing those obligations to CBP is the surety. Which of the following is true under 19 CFR Part 113?","es":"En una fianza de CBP, el importador registrado nombrado cuyas obligaciones están garantizadas por la fianza se denomina el principal, y la compañía afianzadora que garantiza esas obligaciones ante CBP es el fiador (surety). ¿Cuál de las siguientes afirmaciones es verdadera conforme a 19 CFR Part 113?","ru":"В таможенной гарантии (bond) CBP поименованный импортер-получатель (importer of record), чьи обязательства обеспечены гарантией, именуется принципалом (principal), а гарантийная компания, гарантирующая эти обязательства перед CBP, является поручителем (surety). Что из перечисленного верно согласно 19 CFR Part 113?","tr":"Bir CBP teminatında (bond), yükümlülükleri teminatla güvence altına alınan, adı geçen importer of record (kayıtlı ithalatçı) asıl (principal) olarak adlandırılır ve bu yükümlülükleri CBP'ye garanti eden teminat şirketi kefildir (surety). 19 CFR Part 113 kapsamında aşağıdakilerden hangisi doğrudur?","hi":"एक CBP bond पर, नामित importer of record जिसके दायित्व bond द्वारा सुरक्षित हैं, उसे principal कहा जाता है, और bonding कंपनी जो उन दायित्वों की CBP को गारंटी देती है, surety है। 19 CFR Part 113 के तहत निम्नलिखित में से कौन-सा सत्य है?","ar":"في سند ضمان CBP، يُشار إلى المستورد المسجَّل المسمّى الذي يضمن السند التزاماته بوصفه الموكِّل (principal)، وتُعدّ شركة الضمان التي تكفل تلك الالتزامات لـ CBP الكفيل (surety). أي مما يلي صحيح بموجب 19 CFR Part 113؟"},"o":[{"en":"The same corporation may act as both principal and surety on the bond to reduce cost.","es":"La misma corporación puede actuar como principal y como fiador en la fianza para reducir costos.","ru":"Одна и та же корпорация может выступать одновременно принципалом и поручителем по гарантии для снижения затрат.","tr":"Aynı şirket, maliyeti azaltmak için teminatta hem asıl hem de kefil olarak hareket edebilir.","hi":"वही कॉर्पोरेशन लागत कम करने के लिए bond पर principal और surety दोनों के रूप में कार्य कर सकता है।","ar":"يجوز للشركة نفسها أن تتصرّف كموكِّل وكفيل معاً على السند لخفض التكلفة."},{"en":"A continuous bond secures only one specified entry, while a single transaction bond covers all entries for one year.","es":"Una fianza continua garantiza solo una entrada específica, mientras que una fianza de transacción única cubre todas las entradas durante un año.","ru":"Непрерывная гарантия (continuous bond) обеспечивает только одно указанное оформление, тогда как гарантия на разовую сделку (single transaction bond) покрывает все оформления за один год.","tr":"Bir sürekli teminat (continuous bond) yalnızca belirtilen bir beyanı güvence altına alırken, tek işlem teminatı (single transaction bond) bir yıl boyunca tüm beyanları kapsar.","hi":"एक continuous bond केवल एक निर्दिष्ट एंट्री को सुरक्षित करता है, जबकि एक single transaction bond एक वर्ष के लिए सभी एंट्री को कवर करता है।","ar":"يضمن السند المستمر إدخالاً واحداً محدداً فقط، بينما يغطي سند المعاملة الواحدة جميع الإدخالات لمدة سنة."},{"en":"Only CBP, not the surety, is liable to importers for losses arising from a defaulted entry.","es":"Solo CBP, y no el fiador, es responsable ante los importadores por las pérdidas derivadas de una entrada en incumplimiento.","ru":"Только CBP, а не поручитель, несет ответственность перед импортерами за убытки, возникающие из-за неисполненного оформления.","tr":"Temerrüde düşmüş bir beyandan kaynaklanan zararlardan dolayı ithalatçılara karşı yalnızca CBP, kefil değil, sorumludur.","hi":"केवल CBP, surety नहीं, एक डिफ़ॉल्ट एंट्री से उत्पन्न नुकसान के लिए आयातकर्ताओं के प्रति उत्तरदायी है।","ar":"CBP وحدها، لا الكفيل، مسؤولة تجاه المستوردين عن الخسائر الناشئة عن إدخال متعثّر."},{"en":"The same person or corporation may not be both principal and surety on a bond.","es":"La misma persona o corporación no puede ser a la vez principal y fiador en una fianza.","ru":"Одно и то же лицо или корпорация не может быть одновременно принципалом и поручителем по гарантии.","tr":"Aynı kişi veya şirket, bir teminatta hem asıl hem de kefil olamaz.","hi":"वही व्यक्ति या कॉर्पोरेशन एक bond पर principal और surety दोनों नहीं हो सकता।","ar":"لا يجوز أن يكون الشخص أو الشركة نفسها موكِّلاً وكفيلاً على السند معاً."}],"e":{"en":"Under 19 CFR Part 113 (subpart D), the same person, partnership, or corporation cannot be both principal and surety on the same bond. A single transaction bond secures one transaction; a continuous bond secures multiple transactions over a one-year (renewable) period -- the reverse of option B.","es":"Conforme a 19 CFR Part 113 (subpart D), la misma persona, sociedad colectiva o corporación no puede ser a la vez principal y fiador en la misma fianza. Una fianza de transacción única garantiza una transacción; una fianza continua garantiza múltiples transacciones durante un período de un año (renovable), lo inverso de la opción B.","ru":"Согласно 19 CFR Part 113 (subpart D), одно и то же лицо, товарищество или корпорация не может быть одновременно принципалом и поручителем по одной и той же гарантии. Гарантия на разовую сделку (single transaction bond) обеспечивает одну сделку; непрерывная гарантия (continuous bond) обеспечивает множество сделок в течение годового (возобновляемого) периода — обратное варианту B.","tr":"19 CFR Part 113 (subpart D) kapsamında, aynı kişi, ortaklık veya şirket aynı teminatta hem asıl (principal) hem de kefil (surety) olamaz. Tek işlem teminatı (single transaction bond) bir işlemi güvence altına alır; sürekli teminat (continuous bond) ise bir yıllık (yenilenebilir) süre boyunca birden çok işlemi güvence altına alır -- B seçeneğinin tersi.","hi":"19 CFR Part 113 (subpart D) के तहत, वही व्यक्ति, साझेदारी, या कॉर्पोरेशन एक ही bond पर principal और surety दोनों नहीं हो सकता। एक single transaction bond एक लेनदेन को सुरक्षित करता है; एक continuous bond एक वर्ष (नवीकरणीय) अवधि में कई लेनदेन को सुरक्षित करता है -- विकल्प B के विपरीत।","ar":"بموجب 19 CFR Part 113 (subpart D)، لا يجوز أن يكون الشخص أو الشراكة أو الشركة نفسها موكِّلاً وكفيلاً على السند نفسه. ويضمن سند المعاملة الواحدة معاملة واحدة؛ بينما يضمن السند المستمر معاملات متعددة على مدى فترة سنة واحدة (قابلة للتجديد) — عكس الخيار B."}},{"cat":"trade","a":3,"q":{"en":"An importer expects to make numerous entries at multiple ports throughout the year and wants the most cost-effective bond arrangement. Which bond type is appropriate, and how long is it generally effective under 19 CFR Part 113?","es":"Un importador espera realizar numerosas entradas en múltiples puertos a lo largo del año y desea el arreglo de fianza más rentable. ¿Qué tipo de fianza es apropiado, y por cuánto tiempo es generalmente efectivo conforme a 19 CFR Part 113?","ru":"Импортер ожидает совершить многочисленные оформления в нескольких портах в течение года и хочет наиболее экономичную схему гарантирования. Какой тип гарантии (bond) подходит, и как долго она обычно действует согласно 19 CFR Part 113?","tr":"Bir ithalatçı, yıl boyunca birden çok limanda çok sayıda beyan yapmayı bekliyor ve en uygun maliyetli teminat düzenlemesini istiyor. Hangi teminat türü uygundur ve 19 CFR Part 113 kapsamında genellikle ne kadar süreyle geçerlidir?","hi":"एक आयातकर्ता पूरे वर्ष कई बंदरगाहों पर अनेक एंट्री करने की उम्मीद करता है और सबसे लागत-प्रभावी bond व्यवस्था चाहता है। कौन-सा bond प्रकार उपयुक्त है, और 19 CFR Part 113 के तहत यह आम तौर पर कितने समय तक प्रभावी रहता है?","ar":"يتوقّع مستورد إجراء إدخالات عديدة في موانئ متعددة على مدار السنة ويريد ترتيب سند الضمان الأكثر فعالية من حيث التكلفة. أي نوع من السندات مناسب، وإلى متى يكون نافذاً عموماً بموجب 19 CFR Part 113؟"},"o":[{"en":"A single transaction bond, effective for the life of the one entry it secures.","es":"Una fianza de transacción única, efectiva por la vida de la única entrada que garantiza.","ru":"Гарантия на разовую сделку (single transaction bond), действующая в течение срока одного оформления, которое она обеспечивает.","tr":"Tek işlem teminatı (single transaction bond), güvence altına aldığı tek beyanın ömrü boyunca geçerli.","hi":"एक single transaction bond, जो एक एंट्री के जीवनकाल के लिए प्रभावी है जिसे यह सुरक्षित करता है।","ar":"سند معاملة واحدة، نافذ طوال عمر الإدخال الوحيد الذي يضمنه."},{"en":"A single transaction bond, effective for one year and automatically renewing.","es":"Una fianza de transacción única, efectiva por un año y de renovación automática.","ru":"Гарантия на разовую сделку (single transaction bond), действующая один год и автоматически возобновляемая.","tr":"Tek işlem teminatı (single transaction bond), bir yıl geçerli ve otomatik olarak yenilenen.","hi":"एक single transaction bond, जो एक वर्ष के लिए प्रभावी है और स्वचालित रूप से नवीनीकृत होता है।","ar":"سند معاملة واحدة، نافذ لمدة سنة ويتجدّد تلقائياً."},{"en":"A continuous bond, effective only at the single port where it is filed.","es":"Una fianza continua, efectiva solo en el único puerto donde se presenta.","ru":"Непрерывная гарантия (continuous bond), действующая только в одном порту, где она подана.","tr":"Sürekli teminat (continuous bond), yalnızca sunulduğu tek limanda geçerli.","hi":"एक continuous bond, जो केवल उस एकल बंदरगाह पर प्रभावी है जहाँ इसे दाखिल किया जाता है।","ar":"سند مستمر، نافذ فقط في الميناء الوحيد المُودَع فيه."},{"en":"A continuous bond, effective for one year from its effective date and each succeeding annual period until terminated.","es":"Una fianza continua, efectiva por un año a partir de su fecha de vigencia y por cada período anual sucesivo hasta su terminación.","ru":"Непрерывная гарантия (continuous bond), действующая один год с даты вступления в силу и каждый последующий годовой период до прекращения.","tr":"Sürekli teminat (continuous bond), yürürlük tarihinden itibaren bir yıl ve sona erdirilene kadar her takip eden yıllık dönem için geçerli.","hi":"एक continuous bond, जो अपनी प्रभावी तिथि से एक वर्ष के लिए और प्रत्येक बाद की वार्षिक अवधि के लिए तब तक प्रभावी है जब तक समाप्त न किया जाए।","ar":"سند مستمر، نافذ لمدة سنة من تاريخ نفاذه ولكل فترة سنوية تالية إلى أن يُنهى."}],"e":{"en":"Under 19 CFR 113.11-113.12, a continuous bond secures multiple transactions and remains in force for one year beginning with the effective date, and for each succeeding annual period, or until terminated. It applies nationally, making it cost-effective for high-volume importers.","es":"Conforme a 19 CFR 113.11-113.12, una fianza continua garantiza múltiples transacciones y permanece en vigor por un año a partir de la fecha de vigencia, y por cada período anual sucesivo, o hasta su terminación. Se aplica a nivel nacional, lo que la hace rentable para importadores de alto volumen.","ru":"Согласно 19 CFR 113.11–113.12, непрерывная гарантия (continuous bond) обеспечивает множество сделок и остается в силе в течение одного года, начиная с даты вступления в силу, и в каждый последующий годовой период, или до прекращения. Она действует на всей территории страны, что делает ее экономичной для импортеров с большим объемом.","tr":"19 CFR 113.11-113.12 kapsamında, sürekli teminat (continuous bond) birden çok işlemi güvence altına alır ve yürürlük tarihinden başlayarak bir yıl boyunca ve her takip eden yıllık dönem için veya sona erdirilene kadar geçerli kalır. Ulusal düzeyde uygulanır, bu da yüksek hacimli ithalatçılar için onu uygun maliyetli kılar.","hi":"19 CFR 113.11-113.12 के तहत, एक continuous bond कई लेनदेन को सुरक्षित करता है और प्रभावी तिथि से शुरू होकर एक वर्ष के लिए, और प्रत्येक बाद की वार्षिक अवधि के लिए, या समाप्त होने तक प्रभावी रहता है। यह राष्ट्रीय स्तर पर लागू होता है, जो इसे उच्च-मात्रा वाले आयातकर्ताओं के लिए लागत-प्रभावी बनाता है।","ar":"بموجب 19 CFR 113.11-113.12، يضمن السند المستمر معاملات متعددة ويظلّ نافذاً لمدة سنة تبدأ بتاريخ النفاذ، ولكل فترة سنوية تالية، أو إلى أن يُنهى. وينطبق على المستوى الوطني، مما يجعله فعّالاً من حيث التكلفة للمستوردين ذوي الحجم الكبير."}},{"cat":"trade","a":0,"q":{"en":"A shipment arrives at the port of New York but the importer wants to clear and enter it for consumption at an inland port (e.g., Chicago). Which in-bond movement type is used to move the merchandise under bond to the inland port for entry there?","es":"Un embarque llega al puerto de Nueva York pero el importador desea despacharlo y declararlo para consumo en un puerto interior (por ejemplo, Chicago). ¿Qué tipo de movimiento in-bond se usa para mover la mercancía bajo fianza al puerto interior para declararla allí?","ru":"Партия прибывает в порт Нью-Йорк, но импортер хочет растаможить и оформить ее для потребления во внутреннем порту (например, в Чикаго). Какой тип перемещения под гарантией (in-bond) используется для перемещения товаров под гарантией во внутренний порт для оформления там?","tr":"Bir sevkiyat New York limanına geliyor ancak ithalatçı bunu bir iç limandan (örneğin Chicago) gümrükleyip tüketim için beyan etmek istiyor. Malları teminat altında iç limana orada beyan edilmek üzere taşımak için hangi in-bond hareket türü kullanılır?","hi":"एक शिपमेंट port of New York पर पहुँचता है लेकिन आयातकर्ता इसे एक अंतर्देशीय बंदरगाह (जैसे Chicago) पर उपभोग के लिए क्लियर और एंटर करना चाहता है। माल को bond के तहत अंतर्देशीय बंदरगाह तक वहाँ एंट्री के लिए ले जाने के लिए किस in-bond संचलन प्रकार का उपयोग किया जाता है?","ar":"تصل شحنة إلى ميناء نيويورك لكن المستورد يريد تخليصها وإدخالها للاستهلاك في ميناء داخلي (مثل شيكاغو). أي نوع من حركة النقل تحت الضمان (in-bond) يُستخدَم لنقل البضاعة تحت الضمان إلى الميناء الداخلي لإدخالها هناك؟"},"o":[{"en":"Immediate Transportation (I.T.) entry.","es":"Entrada de Immediate Transportation (I.T.).","ru":"Оформление немедленной транспортировки (Immediate Transportation, I.T.).","tr":"Immediate Transportation (I.T.) beyanı.","hi":"Immediate Transportation (I.T.) एंट्री।","ar":"إدخال النقل الفوري (Immediate Transportation - I.T.)."},{"en":"Transportation and Exportation (T&E) entry.","es":"Entrada de Transportation and Exportation (T&E).","ru":"Оформление транспортировки и экспорта (Transportation and Exportation, T&E).","tr":"Transportation and Exportation (T&E) beyanı.","hi":"Transportation and Exportation (T&E) एंट्री।","ar":"إدخال النقل والتصدير (Transportation and Exportation - T&E)."},{"en":"Immediate Exportation (I.E.) entry.","es":"Entrada de Immediate Exportation (I.E.).","ru":"Оформление немедленного экспорта (Immediate Exportation, I.E.).","tr":"Immediate Exportation (I.E.) beyanı.","hi":"Immediate Exportation (I.E.) एंट्री।","ar":"إدخال التصدير الفوري (Immediate Exportation - I.E.)."},{"en":"Warehouse withdrawal for transportation.","es":"Retiro de almacén para transportación.","ru":"Изъятие со склада для транспортировки (warehouse withdrawal for transportation).","tr":"Taşıma için antrepodan çekim (warehouse withdrawal for transportation).","hi":"परिवहन के लिए warehouse withdrawal।","ar":"سحب من المستودع لغرض النقل."}],"e":{"en":"Under 19 CFR Part 18, an Immediate Transportation (I.T.) in-bond entry moves merchandise under bond from the port of arrival to another U.S. port where it will be entered. A T&E moves goods in-bond to a port for exportation; an I.E. exports goods directly from the port of arrival without further inland transit.","es":"Conforme a 19 CFR Part 18, una entrada in-bond de Immediate Transportation (I.T.) mueve la mercancía bajo fianza desde el puerto de llegada a otro puerto de Estados Unidos donde se declarará. Una T&E mueve las mercancías in-bond a un puerto para su exportación; una I.E. exporta las mercancías directamente desde el puerto de llegada sin tránsito interior adicional.","ru":"Согласно 19 CFR Part 18, оформление немедленной транспортировки под гарантией (Immediate Transportation, I.T.) перемещает товары под гарантией из порта прибытия в другой порт США, где они будут оформлены. T&E перемещает товары под гарантией в порт для экспорта; I.E. экспортирует товары непосредственно из порта прибытия без дальнейшего внутреннего транзита.","tr":"19 CFR Part 18 kapsamında, bir Immediate Transportation (I.T.) in-bond beyanı, malları teminat altında varış limanından beyan edilecekleri başka bir ABD limanına taşır. Bir T&E, malları ihracat için bir limana in-bond olarak taşır; bir I.E. ise malları daha fazla iç taşıma olmaksızın varış limanından doğrudan ihraç eder.","hi":"19 CFR Part 18 के तहत, एक Immediate Transportation (I.T.) in-bond एंट्री माल को bond के तहत पहुँचने के बंदरगाह से दूसरे U.S. बंदरगाह तक ले जाती है जहाँ इसे एंटर किया जाएगा। एक T&E माल को निर्यात के लिए एक बंदरगाह तक in-bond ले जाती है; एक I.E. माल को आगे के अंतर्देशीय पारगमन के बिना पहुँचने के बंदरगाह से सीधे निर्यात करती है।","ar":"بموجب 19 CFR Part 18، ينقل إدخال النقل الفوري (I.T.) تحت الضمان البضاعة من ميناء الوصول إلى ميناء أمريكي آخر حيث ستُدخَل. أما T&E فينقل البضائع تحت الضمان إلى ميناء بغرض التصدير؛ وأما I.E. فيصدّر البضائع مباشرةً من ميناء الوصول دون نقل داخلي إضافي."}},{"cat":"trade","a":2,"q":{"en":"Foreign merchandise lands at a U.S. port and the consignee decides to ship it under bond to a different U.S. port for export from there, with no intention of entering it into U.S. commerce. Which in-bond movement applies under 19 CFR Part 18?","es":"Mercancía extranjera arriba a un puerto de Estados Unidos y el consignatario decide enviarla bajo fianza a un puerto diferente de Estados Unidos para exportarla desde allí, sin intención de introducirla al comercio de Estados Unidos. ¿Qué movimiento in-bond aplica conforme a 19 CFR Part 18?","ru":"Иностранные товары прибывают в порт США, и грузополучатель решает отправить их под гарантией в другой порт США для экспорта оттуда, не намереваясь вводить их в торговый оборот США. Какое перемещение под гарантией (in-bond) применяется согласно 19 CFR Part 18?","tr":"Yabancı mallar bir ABD limanına iniyor ve alıcı, bunları ABD ticaretine sokma niyeti olmaksızın, oradan ihraç edilmek üzere farklı bir ABD limanına teminat altında göndermeye karar veriyor. 19 CFR Part 18 kapsamında hangi in-bond hareketi uygulanır?","hi":"विदेशी माल एक U.S. बंदरगाह पर उतरता है और consignee इसे वहाँ से निर्यात के लिए एक अलग U.S. बंदरगाह तक bond के तहत भेजने का निर्णय लेता है, इसे U.S. वाणिज्य में एंटर करने के किसी इरादे के बिना। 19 CFR Part 18 के तहत कौन-सा in-bond संचलन लागू होता है?","ar":"تَرسو بضاعة أجنبية في ميناء أمريكي ويقرّر المرسَل إليه شحنها تحت الضمان إلى ميناء أمريكي مختلف لتصديرها من هناك، دون نية إدخالها إلى التجارة الأمريكية. أي حركة نقل تحت الضمان تنطبق بموجب 19 CFR Part 18؟"},"o":[{"en":"Immediate Exportation (I.E.), since the goods will leave from the port of arrival.","es":"Immediate Exportation (I.E.), ya que las mercancías saldrán desde el puerto de llegada.","ru":"Немедленный экспорт (Immediate Exportation, I.E.), поскольку товары покинут страну из порта прибытия.","tr":"Immediate Exportation (I.E.), çünkü mallar varış limanından ayrılacaktır.","hi":"Immediate Exportation (I.E.), क्योंकि माल पहुँचने के बंदरगाह से रवाना होगा।","ar":"التصدير الفوري (I.E.)، لأن البضائع ستغادر من ميناء الوصول."},{"en":"Immediate Transportation (I.T.), since the goods move to another port.","es":"Immediate Transportation (I.T.), ya que las mercancías se mueven a otro puerto.","ru":"Немедленная транспортировка (Immediate Transportation, I.T.), поскольку товары перемещаются в другой порт.","tr":"Immediate Transportation (I.T.), çünkü mallar başka bir limana taşınır.","hi":"Immediate Transportation (I.T.), क्योंकि माल दूसरे बंदरगाह तक जाता है।","ar":"النقل الفوري (I.T.)، لأن البضائع تنتقل إلى ميناء آخر."},{"en":"Transportation and Exportation (T&E), since the goods move in-bond to another port and are then exported.","es":"Transportation and Exportation (T&E), ya que las mercancías se mueven in-bond a otro puerto y luego se exportan.","ru":"Транспортировка и экспорт (Transportation and Exportation, T&E), поскольку товары перемещаются под гарантией в другой порт и затем экспортируются.","tr":"Transportation and Exportation (T&E), çünkü mallar in-bond olarak başka bir limana taşınır ve ardından ihraç edilir.","hi":"Transportation and Exportation (T&E), क्योंकि माल in-bond दूसरे बंदरगाह तक जाता है और फिर निर्यात किया जाता है।","ar":"النقل والتصدير (T&E)، لأن البضائع تنتقل تحت الضمان إلى ميناء آخر ثم تُصدَّر."},{"en":"Permanent Exhibition entry, since the goods are not entered for consumption.","es":"Entrada de Exhibición Permanente, ya que las mercancías no se declaran para consumo.","ru":"Оформление постоянной выставки (Permanent Exhibition), поскольку товары не оформляются для потребления.","tr":"Kalıcı Sergi beyanı (Permanent Exhibition entry), çünkü mallar tüketim için beyan edilmez.","hi":"Permanent Exhibition एंट्री, क्योंकि माल उपभोग के लिए एंटर नहीं किया गया है।","ar":"إدخال المعرض الدائم، لأن البضائع لا تُدخَل للاستهلاك."}],"e":{"en":"Under 19 CFR Part 18 (subpart D), a Transportation and Exportation (T&E) entry covers merchandise transported in-bond from the port of arrival to another U.S. port for exportation. An I.E. would export the goods from the port of arrival itself without inland movement.","es":"Conforme a 19 CFR Part 18 (subpart D), una entrada de Transportation and Exportation (T&E) cubre la mercancía transportada in-bond desde el puerto de llegada a otro puerto de Estados Unidos para su exportación. Una I.E. exportaría las mercancías desde el propio puerto de llegada sin movimiento interior.","ru":"Согласно 19 CFR Part 18 (subpart D), оформление транспортировки и экспорта (Transportation and Exportation, T&E) охватывает товары, перевозимые под гарантией из порта прибытия в другой порт США для экспорта. I.E. экспортировало бы товары из самого порта прибытия без внутреннего перемещения.","tr":"19 CFR Part 18 (subpart D) kapsamında, bir Transportation and Exportation (T&E) beyanı, varış limanından ihracat için başka bir ABD limanına in-bond olarak taşınan malları kapsar. Bir I.E. ise malları, iç hareket olmaksızın varış limanının kendisinden ihraç eder.","hi":"19 CFR Part 18 (subpart D) के तहत, एक Transportation and Exportation (T&E) एंट्री उस माल को कवर करती है जो पहुँचने के बंदरगाह से दूसरे U.S. बंदरगाह तक निर्यात के लिए in-bond परिवहन किया जाता है। एक I.E. माल को बिना अंतर्देशीय संचलन के पहुँचने के बंदरगाह से ही निर्यात करेगी।","ar":"بموجب 19 CFR Part 18 (subpart D)، يغطي إدخال النقل والتصدير (T&E) البضاعة المنقولة تحت الضمان من ميناء الوصول إلى ميناء أمريكي آخر بغرض التصدير. أما I.E. فيصدّر البضائع من ميناء الوصول نفسه دون نقل داخلي."}},{"cat":"trade","a":3,"q":{"en":"An importer is bringing a shipment of commercially packaged human food into the United States. Beyond CBP's requirements, which Partner Government Agency requirement most directly applies before the food can be admitted?","es":"Un importador está trayendo un embarque de alimento humano empacado comercialmente a Estados Unidos. Más allá de los requisitos de CBP, ¿qué requisito de una Partner Government Agency aplica más directamente antes de que el alimento pueda admitirse?","ru":"Импортер ввозит партию коммерчески упакованных продуктов питания для человека в Соединенные Штаты. Помимо требований CBP, какое требование Партнерского правительственного агентства (PGA) наиболее непосредственно применяется до того, как продукты могут быть допущены?","tr":"Bir ithalatçı, ticari ambalajlı insan gıdasından oluşan bir sevkiyatı Amerika Birleşik Devletleri'ne getiriyor. CBP'nin gerekliliklerinin ötesinde, gıdanın kabul edilebilmesi için en doğrudan hangi Partner Government Agency (PGA) gerekliliği geçerlidir?","hi":"एक आयातकर्ता संयुक्त राज्य अमेरिका में वाणिज्यिक रूप से पैकेज्ड मानव भोजन का एक शिपमेंट ला रहा है। CBP की आवश्यकताओं से परे, भोजन को प्रवेश दिए जाने से पहले कौन-सी Partner Government Agency आवश्यकता सबसे सीधे लागू होती है?","ar":"يستورد مستورد شحنة من الأغذية البشرية المعبّأة تجارياً إلى الولايات المتحدة. إلى جانب متطلبات CBP، أي متطلب من متطلبات وكالة حكومية شريكة (PGA) ينطبق بشكل مباشر أكثر قبل أن يُسمح بدخول الغذاء؟"},"o":[{"en":"An EPA pesticide registration notice must be filed for the food.","es":"Debe presentarse un aviso de registro de pesticidas de la EPA para el alimento.","ru":"Должно быть подано уведомление о регистрации пестицида EPA для продуктов.","tr":"Gıda için bir EPA pestisit kayıt bildirimi sunulmalıdır.","hi":"भोजन के लिए एक EPA pesticide registration नोटिस दाखिल किया जाना चाहिए।","ar":"يجب تقديم إشعار تسجيل مبيد آفات لدى EPA للغذاء."},{"en":"A Fish and Wildlife Service Form 3-177 declaration must be filed.","es":"Debe presentarse una declaración Form 3-177 del Fish and Wildlife Service.","ru":"Должна быть подана декларация Fish and Wildlife Service по Form 3-177.","tr":"Bir Fish and Wildlife Service Form 3-177 beyanı sunulmalıdır.","hi":"एक Fish and Wildlife Service Form 3-177 घोषणा दाखिल की जानी चाहिए।","ar":"يجب تقديم إقرار Fish and Wildlife Service Form 3-177."},{"en":"A USDA APHIS plant pest permit is required for all packaged human food.","es":"Se requiere un permiso de plaga vegetal de USDA APHIS para todo alimento humano empacado.","ru":"Для всех упакованных продуктов питания для человека требуется разрешение USDA APHIS на ввоз растительных вредителей.","tr":"Tüm ambalajlı insan gıdası için bir USDA APHIS bitki zararlısı izni gereklidir.","hi":"सभी पैकेज्ड मानव भोजन के लिए एक USDA APHIS plant pest permit आवश्यक है।","ar":"يلزم تصريح آفات نباتية من USDA APHIS لجميع الأغذية البشرية المعبّأة."},{"en":"FDA Prior Notice of the imported food shipment must be submitted and confirmed.","es":"Debe presentarse y confirmarse el FDA Prior Notice del embarque de alimento importado.","ru":"Должно быть подано и подтверждено предварительное уведомление FDA (Prior Notice) о ввозимой партии продуктов питания.","tr":"İthal edilen gıda sevkiyatına ilişkin FDA Prior Notice (Ön Bildirim) sunulmalı ve onaylanmalıdır.","hi":"आयातित भोजन शिपमेंट की FDA Prior Notice प्रस्तुत और पुष्टि की जानी चाहिए।","ar":"يجب تقديم Prior Notice من FDA لشحنة الغذاء المستورَدة وتأكيده."}],"e":{"en":"Under the FDA's authority (21 CFR Part 1, Subpart I, implementing the Bioterrorism Act), Prior Notice must be submitted to and confirmed by FDA for food for humans or animals imported or offered for import. CBP enforces admissibility, but the controlling PGA requirement for food is FDA Prior Notice. Form 3-177 is a Fish and Wildlife wildlife declaration, not a general food requirement.","es":"Bajo la autoridad de la FDA (21 CFR Part 1, Subpart I, que implementa la Bioterrorism Act), debe presentarse y ser confirmado por la FDA el Prior Notice para alimentos para humanos o animales importados u ofrecidos para importación. CBP hace cumplir la admisibilidad, pero el requisito determinante de la PGA para los alimentos es el FDA Prior Notice. El Form 3-177 es una declaración de vida silvestre del Fish and Wildlife, no un requisito general de alimentos.","ru":"В рамках полномочий FDA (21 CFR Part 1, Subpart I, реализующий Bioterrorism Act) предварительное уведомление (Prior Notice) должно быть подано в FDA и подтверждено им для продуктов питания для людей или животных, импортируемых или предлагаемых к импорту. CBP обеспечивает соблюдение допустимости ввоза, но определяющим требованием PGA для продуктов питания является Prior Notice FDA. Form 3-177 — это декларация Fish and Wildlife на дикую природу, а не общее требование к продуктам питания.","tr":"FDA'nın yetkisi kapsamında (Bioterrorism Act'i uygulayan 21 CFR Part 1, Subpart I), ithal edilen veya ithal için sunulan insan ya da hayvan gıdaları için FDA'ya Prior Notice (Ön Bildirim) sunulmalı ve FDA tarafından onaylanmalıdır. CBP kabul edilebilirliği uygular, ancak gıda için belirleyici PGA gerekliliği FDA Prior Notice'tir. Form 3-177, genel bir gıda gerekliliği değil, bir Fish and Wildlife yaban hayatı beyanıdır.","hi":"FDA के प्राधिकरण के तहत (21 CFR Part 1, Subpart I, Bioterrorism Act को लागू करते हुए), मानव या पशु के लिए आयातित या आयात के लिए प्रस्तुत भोजन के लिए FDA को Prior Notice प्रस्तुत और पुष्टि की जानी चाहिए। CBP प्रवेश-योग्यता लागू करता है, लेकिन भोजन के लिए नियंत्रक PGA आवश्यकता FDA Prior Notice है। Form 3-177 एक Fish and Wildlife वन्यजीव घोषणा है, सामान्य भोजन आवश्यकता नहीं।","ar":"بموجب صلاحية FDA (21 CFR Part 1, Subpart I، تنفيذاً لـ Bioterrorism Act)، يجب تقديم Prior Notice إلى FDA وتأكيده بشأن الأغذية المخصّصة للبشر أو الحيوانات المستورَدة أو المعروضة للاستيراد. وتنفّذ CBP أحكام الأهلية للدخول، لكن متطلب PGA الحاكم للغذاء هو FDA Prior Notice. أما Form 3-177 فهو إقرار حياة برية لدى Fish and Wildlife، وليس متطلباً عاماً للغذاء."}},{"cat":"trade","a":0,"q":{"en":"A broker is clearing an importation of live tropical aquarium fish and certain wildlife-derived products. Which Partner Government Agency's declaration requirement is most directly implicated, and what form is typically used?","es":"Un agente de aduanas está despachando una importación de peces tropicales vivos de acuario y ciertos productos derivados de vida silvestre. ¿El requisito de declaración de qué Partner Government Agency está más directamente implicado, y qué formulario se usa típicamente?","ru":"Брокер растаможивает ввоз живых тропических аквариумных рыб и определенных продуктов, полученных из дикой природы. Требование о декларации какого Партнерского правительственного агентства (PGA) наиболее непосредственно затрагивается, и какая форма обычно используется?","tr":"Bir gümrük müşaviri, canlı tropikal akvaryum balıkları ve belirli yaban hayatı kaynaklı ürünlerden oluşan bir ithalatı gümrüklüyor. En doğrudan hangi Partner Government Agency'nin beyan gerekliliği söz konusudur ve tipik olarak hangi form kullanılır?","hi":"एक ब्रोकर जीवित उष्णकटिबंधीय aquarium मछलियों और कुछ वन्यजीव-व्युत्पन्न उत्पादों के आयात को क्लियर कर रहा है। किस Partner Government Agency की घोषणा आवश्यकता सबसे सीधे निहित है, और आम तौर पर कौन-सा फॉर्म उपयोग किया जाता है?","ar":"يخلّص وسيط استيراد أسماك زينة استوائية حيّة وبعض المنتجات المشتقّة من الحياة البرية. أي متطلب إقرار لدى وكالة حكومية شريكة (PGA) يتعلق بالأمر بشكل مباشر أكثر، وما النموذج المستخدَم عادةً؟"},"o":[{"en":"U.S. Fish and Wildlife Service; Declaration for Importation or Exportation of Fish or Wildlife (Form 3-177).","es":"U.S. Fish and Wildlife Service; Declaration for Importation or Exportation of Fish or Wildlife (Form 3-177).","ru":"U.S. Fish and Wildlife Service; Декларация на ввоз или вывоз рыбы или дикой природы (Form 3-177).","tr":"U.S. Fish and Wildlife Service; Declaration for Importation or Exportation of Fish or Wildlife (Form 3-177).","hi":"U.S. Fish and Wildlife Service; Declaration for Importation or Exportation of Fish or Wildlife (Form 3-177)।","ar":"U.S. Fish and Wildlife Service؛ إقرار استيراد أو تصدير الأسماك أو الحياة البرية (Form 3-177)."},{"en":"Consumer Product Safety Commission; a certificate of conformity.","es":"Consumer Product Safety Commission; un certificado de conformidad.","ru":"Consumer Product Safety Commission; сертификат соответствия.","tr":"Consumer Product Safety Commission; bir uygunluk belgesi.","hi":"Consumer Product Safety Commission; एक certificate of conformity।","ar":"Consumer Product Safety Commission؛ شهادة مطابقة."},{"en":"Environmental Protection Agency; EPA Form 3520-1.","es":"Environmental Protection Agency; EPA Form 3520-1.","ru":"Environmental Protection Agency; EPA Form 3520-1.","tr":"Environmental Protection Agency; EPA Form 3520-1.","hi":"Environmental Protection Agency; EPA Form 3520-1।","ar":"Environmental Protection Agency؛ EPA Form 3520-1."},{"en":"USDA Agricultural Marketing Service; a PPQ Form 587 permit.","es":"USDA Agricultural Marketing Service; un permiso PPQ Form 587.","ru":"USDA Agricultural Marketing Service; разрешение PPQ Form 587.","tr":"USDA Agricultural Marketing Service; bir PPQ Form 587 izni.","hi":"USDA Agricultural Marketing Service; एक PPQ Form 587 permit।","ar":"USDA Agricultural Marketing Service؛ تصريح PPQ Form 587."}],"e":{"en":"Imports of fish and wildlife (including many live aquatic organisms and wildlife-derived products) are regulated by the U.S. Fish and Wildlife Service, which generally requires a Declaration for Importation or Exportation of Fish or Wildlife (FWS Form 3-177). EPA Form 3520-1 applies to motor vehicles/engines; CPSC certificates apply to consumer products.","es":"Las importaciones de peces y vida silvestre (incluidos muchos organismos acuáticos vivos y productos derivados de vida silvestre) están reguladas por el U.S. Fish and Wildlife Service, que generalmente requiere una Declaration for Importation or Exportation of Fish or Wildlife (FWS Form 3-177). El EPA Form 3520-1 aplica a vehículos automotores/motores; los certificados de la CPSC aplican a productos de consumo.","ru":"Импорт рыбы и дикой природы (включая многие живые водные организмы и продукты, полученные из дикой природы) регулируется U.S. Fish and Wildlife Service, который обычно требует Декларацию на ввоз или вывоз рыбы или дикой природы (FWS Form 3-177). EPA Form 3520-1 применяется к автотранспортным средствам/двигателям; сертификаты CPSC применяются к потребительским товарам.","tr":"Balık ve yaban hayatı ithalatı (birçok canlı su organizması ve yaban hayatı kaynaklı ürün dahil) U.S. Fish and Wildlife Service tarafından düzenlenir ve genellikle bir Declaration for Importation or Exportation of Fish or Wildlife (FWS Form 3-177) gerektirir. EPA Form 3520-1, motorlu taşıtlara/motorlara uygulanır; CPSC belgeleri ise tüketici ürünlerine uygulanır.","hi":"मछली और वन्यजीव (जिसमें कई जीवित जलीय जीव और वन्यजीव-व्युत्पन्न उत्पाद शामिल हैं) के आयात को U.S. Fish and Wildlife Service द्वारा विनियमित किया जाता है, जिसके लिए आम तौर पर एक Declaration for Importation or Exportation of Fish or Wildlife (FWS Form 3-177) आवश्यक होती है। EPA Form 3520-1 motor vehicles/engines पर लागू होता है; CPSC certificates उपभोक्ता उत्पादों पर लागू होते हैं।","ar":"تخضع واردات الأسماك والحياة البرية (بما في ذلك كثير من الكائنات المائية الحيّة والمنتجات المشتقّة من الحياة البرية) لتنظيم U.S. Fish and Wildlife Service، التي تشترط عموماً إقرار استيراد أو تصدير الأسماك أو الحياة البرية (FWS Form 3-177). أما EPA Form 3520-1 فينطبق على المركبات/المحركات الآلية؛ وشهادات CPSC تنطبق على المنتجات الاستهلاكية."}},{"cat":"trade","a":1,"q":{"en":"A trademark owner whose mark is registered with the USPTO wants CBP to detain and seize infringing imports at the border. What is the threshold step required for CBP border enforcement under 19 CFR Part 133?","es":"Un titular de una marca registrada cuya marca está registrada en la USPTO quiere que CBP detenga e incaute importaciones infractoras en la frontera. ¿Cuál es el paso umbral requerido para la aplicación fronteriza de CBP conforme a 19 CFR Part 133?","ru":"Владелец товарного знака, чей знак зарегистрирован в USPTO, хочет, чтобы CBP задерживала и изымала контрафактный импорт на границе. Каков пороговый шаг, необходимый для пограничного контроля CBP согласно 19 CFR Part 133?","tr":"Markası USPTO'da tescilli olan bir marka sahibi, CBP'nin ihlal eden ithalatı sınırda alıkoymasını ve el koymasını istiyor. 19 CFR Part 133 kapsamında CBP sınır uygulaması için gereken eşik adım nedir?","hi":"एक ट्रेडमार्क मालिक जिसका चिह्न USPTO के साथ पंजीकृत है, चाहता है कि CBP सीमा पर उल्लंघनकारी आयातों को रोके और जब्त करे। 19 CFR Part 133 के तहत CBP सीमा प्रवर्तन के लिए आवश्यक सीमा-कदम क्या है?","ar":"يرغب مالك علامة تجارية مسجَّلة لدى USPTO في أن تحتجز CBP الواردات المخالِفة وتضبطها عند الحدود. ما الخطوة الأولية المطلوبة لإنفاذ CBP الحدودي بموجب 19 CFR Part 133؟"},"o":[{"en":"Filing a civil infringement suit in federal district court before any CBP action can occur.","es":"Presentar una demanda civil por infracción ante un tribunal federal de distrito antes de que pueda ocurrir cualquier acción de CBP.","ru":"Подача гражданского иска о нарушении в федеральный окружной суд до того, как могут быть предприняты какие-либо действия CBP.","tr":"Herhangi bir CBP işlemi gerçekleşmeden önce federal bölge mahkemesinde bir hukuk ihlal davası açmak.","hi":"किसी भी CBP कार्रवाई के होने से पहले federal district court में एक civil infringement मुकदमा दाखिल करना।","ar":"رفع دعوى مدنية بالمخالفة في محكمة اتحادية ابتدائية قبل أن يتسنّى أي إجراء من CBP."},{"en":"Recording the registered trademark with CBP through its e-Recordation program.","es":"Registrar la marca registrada ante CBP a través de su programa e-Recordation.","ru":"Регистрация зарегистрированного товарного знака в CBP через ее программу e-Recordation.","tr":"Tescilli markayı, e-Recordation programı aracılığıyla CBP'ye kaydettirmek.","hi":"CBP के साथ इसके e-Recordation कार्यक्रम के माध्यम से पंजीकृत ट्रेडमार्क को recording करना।","ar":"تسجيل العلامة التجارية المسجَّلة لدى CBP عبر برنامج e-Recordation الخاص بها."},{"en":"Obtaining an exclusion order from the International Trade Commission under Section 337.","es":"Obtener una orden de exclusión de la International Trade Commission conforme a la Section 337.","ru":"Получение запретительного приказа от Комиссии по международной торговле (ITC) согласно Section 337.","tr":"Section 337 kapsamında International Trade Commission'dan bir dışlama emri (exclusion order) almak.","hi":"Section 337 के तहत International Trade Commission से एक exclusion order प्राप्त करना।","ar":"الحصول على أمر استبعاد من International Trade Commission بموجب Section 337."},{"en":"Posting a single transaction bond equal to the value of the suspected counterfeit goods.","es":"Constituir una fianza de transacción única igual al valor de las mercancías presuntamente falsificadas.","ru":"Внесение гарантии на разовую сделку (single transaction bond), равной стоимости предполагаемых контрафактных товаров.","tr":"Şüpheli sahte malların değerine eşit bir tek işlem teminatı (single transaction bond) yatırmak.","hi":"संदिग्ध नकली माल के मूल्य के बराबर एक single transaction bond जमा करना।","ar":"تقديم سند معاملة واحدة يعادل قيمة البضائع المقلَّدة المشتبه بها."}],"e":{"en":"Under 19 CFR Part 133 (subpart A), CBP border enforcement of trademarks (and copyrights) requires that the USPTO-registered mark be recorded with CBP via its recordation/e-Recordation program. Recordation, not litigation or an ITC order, is the threshold for routine CBP detention/seizure of infringing goods.","es":"Conforme a 19 CFR Part 133 (subpart A), la aplicación fronteriza de CBP respecto a marcas (y derechos de autor) requiere que la marca registrada en la USPTO sea registrada ante CBP a través de su programa de registro/e-Recordation. El registro, no el litigio ni una orden de la ITC, es el umbral para la detención/incautación de rutina de mercancías infractoras por parte de CBP.","ru":"Согласно 19 CFR Part 133 (subpart A), пограничный контроль CBP в отношении товарных знаков (и авторских прав) требует, чтобы зарегистрированный в USPTO знак был зарегистрирован в CBP через ее программу регистрации/e-Recordation. Регистрация, а не судебный процесс или приказ ITC, является пороговым условием для обычного задержания/изъятия CBP контрафактных товаров.","tr":"19 CFR Part 133 (subpart A) kapsamında, markaların (ve telif haklarının) CBP sınır uygulaması, USPTO'da tescilli markanın CBP'ye kayıt/e-Recordation programı aracılığıyla kaydedilmesini gerektirir. İhlal eden malların olağan CBP alıkonması/el konması için eşik, dava veya bir ITC emri değil, kayıttır.","hi":"19 CFR Part 133 (subpart A) के तहत, ट्रेडमार्क (और copyrights) के CBP सीमा प्रवर्तन के लिए आवश्यक है कि USPTO-पंजीकृत चिह्न को CBP के साथ इसके recordation/e-Recordation कार्यक्रम के माध्यम से recorded किया जाए। Recordation, न कि मुकदमेबाजी या एक ITC order, उल्लंघनकारी माल की नियमित CBP रोकथाम/जब्ती के लिए सीमा-कदम है।","ar":"بموجب 19 CFR Part 133 (subpart A)، يقتضي إنفاذ CBP الحدودي للعلامات التجارية (وحقوق النشر) أن تكون العلامة المسجَّلة لدى USPTO مسجَّلةً لدى CBP عبر برنامج التسجيل/e-Recordation الخاص بها. فالتسجيل، لا التقاضي أو أمر ITC، هو الخطوة الأولية للاحتجاز/الضبط الاعتيادي من CBP للبضائع المخالِفة."}},{"cat":"trade","a":2,"q":{"en":"CBP examines a shipment and determines the articles bear a counterfeit version of a trademark that is registered and recorded with CBP, and the recordation owner has not consented to the importation. Absent consent, what is CBP's action under 19 CFR Part 133?","es":"CBP examina un embarque y determina que los artículos llevan una versión falsificada de una marca que está registrada y inscrita ante CBP, y el titular del registro no ha consentido la importación. En ausencia de consentimiento, ¿cuál es la acción de CBP conforme a 19 CFR Part 133?","ru":"CBP досматривает партию и определяет, что изделия несут контрафактную версию товарного знака, который зарегистрирован и внесен в реестр CBP, при этом владелец регистрации не дал согласия на ввоз. При отсутствии согласия каковы действия CBP согласно 19 CFR Part 133?","tr":"CBP bir sevkiyatı inceliyor ve ürünlerin, CBP'de tescilli ve kayıtlı bir markanın sahte bir versiyonunu taşıdığını ve kayıt sahibinin ithalata rıza göstermediğini belirliyor. Rıza yokluğunda, CBP'nin 19 CFR Part 133 kapsamındaki işlemi nedir?","hi":"CBP एक शिपमेंट की जाँच करता है और निर्धारित करता है कि वस्तुओं पर एक ऐसे ट्रेडमार्क का नकली संस्करण है जो CBP के साथ पंजीकृत और recorded है, और recordation मालिक ने आयात के लिए सहमति नहीं दी है। सहमति के अभाव में, 19 CFR Part 133 के तहत CBP की कार्रवाई क्या है?","ar":"تفحص CBP شحنة وتقرّر أن المواد تحمل نسخة مقلَّدة من علامة تجارية مسجَّلة ومسجَّلة لدى CBP، وأن مالك التسجيل لم يوافق على الاستيراد. في غياب الموافقة، ما إجراء CBP بموجب 19 CFR Part 133؟"},"o":[{"en":"Release the goods after assessment of a 10 percent marking duty.","es":"Liberar las mercancías tras la imposición de un derecho de marcado del 10 por ciento.","ru":"Выпустить товары после начисления маркировочной пошлины в размере 10 процентов.","tr":"Yüzde 10'luk bir işaretleme vergisinin tahakkukundan sonra malları serbest bırakır.","hi":"10 प्रतिशत marking duty के आकलन के बाद माल जारी करना।","ar":"الإفراج عن البضائع بعد فرض رسم وسم قدره 10 بالمئة."},{"en":"Permit the importer to obliterate the mark and then enter the goods for consumption.","es":"Permitir al importador borrar la marca y luego declarar las mercancías para consumo.","ru":"Разрешить импортеру удалить знак и затем оформить товары для потребления.","tr":"İthalatçının markayı silmesine ve ardından malları tüketim için beyan etmesine izin verir.","hi":"आयातकर्ता को चिह्न मिटाने और फिर माल को उपभोग के लिए एंटर करने की अनुमति देना।","ar":"السماح للمستورد بطمس العلامة ثم إدخال البضائع للاستهلاك."},{"en":"Seize the merchandise and, absent the owner's written consent, forfeit it under the customs laws.","es":"Incautar la mercancía y, en ausencia del consentimiento escrito del titular, decomisarla conforme a las leyes aduaneras.","ru":"Изъять товары и, при отсутствии письменного согласия владельца, конфисковать их согласно таможенному законодательству.","tr":"Mallara el koyar ve sahibinin yazılı rızası yokluğunda, gümrük yasaları uyarınca müsadere eder.","hi":"माल को जब्त करना और, मालिक की लिखित सहमति के अभाव में, कस्टम कानूनों के तहत उसे जब्ती (forfeit) करना।","ar":"ضبط البضاعة و، في غياب الموافقة الكتابية للمالك، مصادرتها بموجب القوانين الجمركية."},{"en":"Detain the goods for 30 days and then release them if no court order is obtained.","es":"Detener las mercancías por 30 días y luego liberarlas si no se obtiene una orden judicial.","ru":"Задержать товары на 30 дней и затем выпустить их, если не будет получен судебный приказ.","tr":"Malları 30 gün alıkoyar ve ardından herhangi bir mahkeme kararı alınmazsa serbest bırakır.","hi":"माल को 30 दिनों के लिए रोकना और फिर यदि कोई court order प्राप्त न हो तो उसे जारी करना।","ar":"احتجاز البضائع 30 يوماً ثم الإفراج عنها إذا لم يصدر أمر قضائي."}],"e":{"en":"Under 19 CFR 133.21, merchandise bearing a counterfeit mark (a mark identical to or substantially indistinguishable from a registered, recorded mark) is seized and, absent the written consent of the recordation owner, forfeited in accordance with the customs laws. Counterfeit-mark goods are treated more strictly than merely confusingly similar (infringing) goods.","es":"Conforme a 19 CFR 133.21, la mercancía que lleva una marca falsificada (una marca idéntica o sustancialmente indistinguible de una marca registrada e inscrita) se incauta y, en ausencia del consentimiento escrito del titular del registro, se decomisa de acuerdo con las leyes aduaneras. Las mercancías con marca falsificada reciben un trato más estricto que las mercancías meramente similares de manera confusa (infractoras).","ru":"Согласно 19 CFR 133.21, товары, несущие контрафактный знак (знак, идентичный или практически неотличимый от зарегистрированного, внесенного в реестр знака), изымаются и, при отсутствии письменного согласия владельца регистрации, конфискуются в соответствии с таможенным законодательством. Товары с контрафактным знаком рассматриваются строже, чем товары, лишь смешиваемо схожие (нарушающие).","tr":"19 CFR 133.21 kapsamında, sahte bir marka (tescilli, kayıtlı bir markayla aynı veya esaslı olarak ayırt edilemez bir marka) taşıyan mallara el konulur ve kayıt sahibinin yazılı rızası yokluğunda, gümrük yasaları uyarınca müsadere edilir. Sahte markalı mallar, yalnızca karıştırılacak derecede benzer (ihlal eden) mallardan daha katı şekilde ele alınır.","hi":"19 CFR 133.21 के तहत, एक नकली चिह्न (एक पंजीकृत, recorded चिह्न के समान या काफी हद तक अप्रभेद्य चिह्न) वाला माल जब्त किया जाता है और, recordation मालिक की लिखित सहमति के अभाव में, कस्टम कानूनों के अनुसार जब्ती (forfeit) किया जाता है। नकली-चिह्न माल को केवल भ्रामक रूप से समान (उल्लंघनकारी) माल की तुलना में अधिक सख्ती से व्यवहार किया जाता है।","ar":"بموجب 19 CFR 133.21، تُضبَط البضاعة الحاملة لعلامة مقلَّدة (علامة مطابقة أو لا يمكن تمييزها جوهرياً عن علامة مسجَّلة ومسجَّلة لدى CBP) و، في غياب الموافقة الكتابية لمالك التسجيل، تُصادَر وفقاً للقوانين الجمركية. وتُعامَل بضائع العلامات المقلَّدة بصرامة أكبر من البضائع المتشابهة إلى حدّ مربك (المخالِفة) فحسب."}},{"cat":"trade","a":2,"q":{"en":"An importer discovers it underpaid duties due to a classification error and, before CBP has commenced or notified it of any investigation, voluntarily reports the violation and tenders the lost duties. Under 19 CFR 162.74, what is the principal benefit of a valid prior disclosure?","es":"Un importador descubre que pagó derechos de menos debido a un error de clasificación y, antes de que CBP haya iniciado o le haya notificado de cualquier investigación, reporta voluntariamente la infracción y entrega los derechos perdidos. Conforme a 19 CFR 162.74, ¿cuál es el principal beneficio de una divulgación previa (prior disclosure) válida?","ru":"Импортер обнаруживает, что недоплатил пошлины из-за ошибки классификации, и до того, как CBP начала или уведомила его о каком-либо расследовании, добровольно сообщает о нарушении и вносит потерянные пошлины. Согласно 19 CFR 162.74, в чем основная выгода действительного предварительного раскрытия (prior disclosure)?","tr":"Bir ithalatçı, bir sınıflandırma hatası nedeniyle vergileri eksik ödediğini keşfediyor ve CBP herhangi bir soruşturma başlatmadan veya kendisine bildirmeden önce, ihlali gönüllü olarak bildirip kaybedilen vergileri ödüyor. 19 CFR 162.74 kapsamında, geçerli bir önceden açıklamanın (prior disclosure) temel faydası nedir?","hi":"एक आयातकर्ता पता लगाता है कि उसने classification त्रुटि के कारण शुल्क कम चुकाया, और, CBP द्वारा किसी जाँच को शुरू करने या उसे सूचित करने से पहले, स्वेच्छा से उल्लंघन की रिपोर्ट करता है और खोए हुए शुल्क प्रस्तुत करता है। 19 CFR 162.74 के तहत, एक वैध prior disclosure का प्रमुख लाभ क्या है?","ar":"يكتشف مستورد أنه دفع رسوماً أقل من المستحقّ بسبب خطأ في التصنيف، وقبل أن تبدأ CBP أي تحقيق أو تخطره به، يبلّغ طوعاً عن المخالفة ويسدّد الرسوم المفقودة. بموجب 19 CFR 162.74، ما الفائدة الرئيسية للإفصاح المسبق الصحيح؟"},"o":[{"en":"All duties owed are waived entirely as a reward for self-reporting.","es":"Todos los derechos adeudados se condonan por completo como recompensa por autorreportarse.","ru":"Все причитающиеся пошлины полностью прощаются в качестве вознаграждения за самостоятельное сообщение.","tr":"Kendini bildirmenin ödülü olarak borçlu olunan tüm vergiler tamamen affedilir.","hi":"स्व-रिपोर्टिंग के पुरस्कार के रूप में सभी देय शुल्क पूरी तरह से माफ कर दिए जाते हैं।","ar":"يُعفى من جميع الرسوم المستحقة بالكامل مكافأةً على الإبلاغ الذاتي."},{"en":"It eliminates any possibility of a penalty regardless of the level of culpability.","es":"Elimina toda posibilidad de multa sin importar el nivel de culpabilidad.","ru":"Оно устраняет любую возможность штрафа независимо от степени виновности.","tr":"Kusur düzeyinden bağımsız olarak herhangi bir ceza olasılığını ortadan kaldırır.","hi":"यह दोषीता के स्तर की परवाह किए बिना किसी भी जुर्माने की संभावना को समाप्त कर देता है।","ar":"يلغي أي احتمال لفرض غرامة بصرف النظر عن مستوى الذنب."},{"en":"It substantially limits the penalty (e.g., for negligence/gross negligence, to the interest on the loss of duties), provided the actual loss of duties is also tendered.","es":"Limita sustancialmente la multa (por ejemplo, en caso de negligencia/negligencia grave, al interés sobre la pérdida de derechos), siempre que también se entregue la pérdida real de derechos.","ru":"Оно существенно ограничивает штраф (например, при небрежности/грубой небрежности — до процентов на сумму потери пошлин), при условии, что также вносится фактическая сумма потери пошлин.","tr":"Cezayı önemli ölçüde sınırlar (örneğin, ihmal/ağır ihmal için, vergi kaybına ilişkin faizle), gerçek vergi kaybının da ödenmesi şartıyla.","hi":"यह जुर्माने को काफी हद तक सीमित कर देता है (जैसे, negligence/gross negligence के लिए, शुल्क हानि पर ब्याज तक), बशर्ते वास्तविक शुल्क हानि भी प्रस्तुत की जाए।","ar":"يحدّ بشكل كبير من الغرامة (مثلاً، في حالة الإهمال/الإهمال الجسيم، إلى الفائدة على خسارة الرسوم)، شريطة سداد خسارة الرسوم الفعلية أيضاً."},{"en":"It converts a fraud violation into a negligence violation but does not affect the penalty amount.","es":"Convierte una infracción por fraude en una infracción por negligencia pero no afecta el monto de la multa.","ru":"Оно превращает нарушение в форме мошенничества в нарушение в форме небрежности, но не влияет на размер штрафа.","tr":"Bir dolandırıcılık (fraud) ihlalini bir ihmal ihlaline dönüştürür ancak ceza tutarını etkilemez.","hi":"यह एक fraud उल्लंघन को एक negligence उल्लंघन में बदल देता है लेकिन जुर्माने की राशि को प्रभावित नहीं करता।","ar":"يحوّل مخالفة الاحتيال إلى مخالفة إهمال لكنه لا يؤثر في مقدار الغرامة."}],"e":{"en":"Under 19 U.S.C. 1592(c)(4) and 19 CFR 162.74, a valid prior disclosure (made before CBP commences/notifies of a formal investigation), with tender of the actual loss of duties, sharply limits the penalty. For negligence and gross negligence the penalty is limited to the interest on the loss of revenue; for fraud it is reduced to the duty loss (or, for non-revenue cases, a percentage of value). It does not waive the duties themselves.","es":"Conforme a 19 U.S.C. 1592(c)(4) y 19 CFR 162.74, una divulgación previa (prior disclosure) válida (hecha antes de que CBP inicie/notifique una investigación formal), con la entrega de la pérdida real de derechos, limita drásticamente la multa. Para la negligencia y la negligencia grave, la multa se limita al interés sobre la pérdida de ingresos; para el fraude se reduce a la pérdida de derechos (o, en casos sin pérdida de ingresos, a un porcentaje del valor). No condona los derechos en sí.","ru":"Согласно 19 U.S.C. 1592(c)(4) и 19 CFR 162.74, действительное предварительное раскрытие (prior disclosure), сделанное до того, как CBP начинает/уведомляет о формальном расследовании, с внесением фактической суммы потери пошлин, резко ограничивает штраф. При небрежности и грубой небрежности штраф ограничивается процентами на сумму потери доходов; при мошенничестве он снижается до суммы потери пошлин (или, для случаев, не связанных с доходами, до процента от стоимости). Оно не отменяет сами пошлины.","tr":"19 U.S.C. 1592(c)(4) ve 19 CFR 162.74 kapsamında, geçerli bir önceden açıklama (prior disclosure) (CBP resmi bir soruşturma başlatmadan/bildirmeden önce yapılan), gerçek vergi kaybının ödenmesiyle birlikte, cezayı keskin şekilde sınırlar. İhmal ve ağır ihmal için ceza, gelir kaybına ilişkin faizle sınırlıdır; dolandırıcılık (fraud) için ise vergi kaybına indirilir (veya gelir dışı durumlarda, değerin bir yüzdesine). Bu, vergilerin kendisini ortadan kaldırmaz.","hi":"19 U.S.C. 1592(c)(4) और 19 CFR 162.74 के तहत, एक वैध prior disclosure (CBP द्वारा औपचारिक जाँच शुरू/सूचित करने से पहले की गई), वास्तविक शुल्क हानि की प्रस्तुति के साथ, जुर्माने को तेजी से सीमित कर देती है। negligence और gross negligence के लिए जुर्माना राजस्व हानि पर ब्याज तक सीमित है; fraud के लिए इसे शुल्क हानि तक घटा दिया जाता है (या, गैर-राजस्व मामलों के लिए, मूल्य के एक प्रतिशत तक)। यह शुल्कों को स्वयं माफ नहीं करता।","ar":"بموجب 19 U.S.C. 1592(c)(4) و19 CFR 162.74، يحدّ الإفصاح المسبق الصحيح (المُقدَّم قبل أن تبدأ CBP تحقيقاً رسمياً أو تخطر به)، مع سداد خسارة الرسوم الفعلية، من الغرامة حدّاً كبيراً. ففي حالة الإهمال والإهمال الجسيم تقتصر الغرامة على الفائدة على خسارة الإيرادات؛ وفي حالة الاحتيال تُخفَّض إلى خسارة الرسوم (أو، في القضايا غير الإيرادية، نسبة مئوية من القيمة). ولا يعفي ذلك من الرسوم نفسها."}}]};
